/* ── API client (Phase 1.5) ─────────────────────────────────────────── */
/* Same-origin fetch wrapper. The proxy serves both UI and API. */

import { invoke } from '@tauri-apps/api/core';
import { isTauri } from '@/lib/tauri-detect';

let baseUrl: string | null = null;

async function initBaseUrl(): Promise<void> {
  try {
    if (isTauri) {
      // Retry with backoff in case the Node backend hasn't finished starting yet.
      // The backend starts the HTTP listener in the same tick, but the Tauri
      // WebView can load the SPA before the health check succeeds.
      for (let i = 0; i < 6; i++) {
        const status: string = await invoke<string>('proxy_status');
        if (status.startsWith('ok:')) {
          baseUrl = `http://127.0.0.1:${status.split(':')[1]}`;
          return;
        }
        // Linear backoff: 200ms, 400ms, 600ms, … — ~4.2 s total before giving up
        await new Promise(r => setTimeout(r, 200 * (i + 1)));
      }
    }
  } catch { /* not in Tauri production mode — dev proxy handles routing */ }
}

const ready = initBaseUrl();

/** Await by modules that make raw fetch calls (e.g. gateway health poll). */
export async function whenReady(): Promise<string | null> {
  await ready;
  return baseUrl;
}

export class ApiError extends Error {
  constructor(public status: number, public code: string, message: string) {
    super(message);
    this.name = 'ApiError';
  }
}

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  await ready;
  const url = baseUrl ? `${baseUrl}${path}` : path;
  const res = await fetch(url, {
    ...init,
    headers: {
      'Content-Type': 'application/json',
      ...(init?.headers ?? {}),
    },
  });
  if (!res.ok) {
    let code = 'unknown';
    let message = res.statusText;
    try {
      const data = await res.json();
      code = data?.error?.code ?? code;
      message = data?.error?.message ?? message;
    } catch { /* keep defaults */ }
    throw new ApiError(res.status, code, message);
  }
  if (res.status === 204) return undefined as T;
  return res.json() as Promise<T>;
}

export const api = {
  get:    <T>(path: string)                 => request<T>(path),
  post:   <T>(path: string, body?: unknown) => request<T>(path, { method: 'POST',   body: body !== undefined ? JSON.stringify(body) : undefined }),
  put:    <T>(path: string, body?: unknown) => request<T>(path, { method: 'PUT',    body: body !== undefined ? JSON.stringify(body) : undefined }),
  patch:  <T>(path: string, body?: unknown) => request<T>(path, { method: 'PATCH',  body: body !== undefined ? JSON.stringify(body) : undefined }),
  delete: <T>(path: string)                 => request<T>(path, { method: 'DELETE' }),
};

/* ── useProviderHealth ─ light hook for the green online dot ──────── */
/* Polls /api/providers/health every 60s and exposes a map keyed by     */
/* provider name. Backend caches results for 30s, so this is cheap.      */

import { useEffect, useState, useCallback } from 'react';
import { api } from './client';

export interface ProviderHealth {
  provider: string;
  online: boolean;
  lastSuccessAt: number | null;
  latencyMs: number | null;
  error?: string;
}

interface ProviderHealthResponse {
  results: ProviderHealth[];
  at: number;
}

export function useProviderHealth(pollMs = 60_000) {
  const [health, setHealth] = useState<ProviderHealth[]>([]);
  const [loaded, setLoaded] = useState(false);

  const refresh = useCallback(async (force = false) => {
    try {
      const qs = force ? '?force=1' : '';
      const res = await api.get<ProviderHealthResponse>(`/api/providers/health${qs}`);
      setHealth(res.results || []);
      setLoaded(true);
    } catch (err) {
      // Network error or backend not running — don't blow up the UI
      setLoaded(true);
    }
  }, []);

  useEffect(() => {
    refresh(false);
    if (pollMs <= 0) return;
    const id = window.setInterval(() => refresh(false), pollMs);
    return () => window.clearInterval(id);
  }, [refresh, pollMs]);

  const byProvider = new Map(health.map(h => [h.provider, h]));
  return { health, byProvider, loaded, refresh };
}

import type { LiveSTT } from './liveSTT';

interface SpeechRecognitionResultLike {
  isFinal: boolean;
  0: { transcript: string };
}

interface SpeechRecognitionEventLike extends Event {
  resultIndex: number;
  results: ArrayLike<SpeechRecognitionResultLike>;
}

interface SpeechRecognitionErrorLike extends Event {
  error: string;
  message?: string;
}

interface SpeechRecognitionLike extends EventTarget {
  lang: string;
  continuous: boolean;
  interimResults: boolean;
  onresult: ((e: SpeechRecognitionEventLike) => void) | null;
  onerror: ((e: SpeechRecognitionErrorLike) => void) | null;
  onend: (() => void) | null;
  start(): void;
  stop(): void;
}

export class WebSpeechSTT implements LiveSTT {
  private recognition: SpeechRecognitionLike | null = null;
  private partialListeners = new Set<(text: string) => void>();
  private finalListeners = new Set<(text: string) => void>();
  private errorListeners = new Set<(err: Error) => void>();

  async start(): Promise<void> {
    const Ctor = window.SpeechRecognition ?? window.webkitSpeechRecognition;
    if (!Ctor) throw new Error('Web Speech API not available');
    const r = new Ctor() as unknown as SpeechRecognitionLike;
    r.lang = 'en-US';
    r.continuous = true;
    r.interimResults = true;
    r.onresult = (e) => {
      let interim = '';
      let finalText = '';
      for (let i = e.resultIndex; i < e.results.length; i++) {
        const result = e.results[i];
        if (result.isFinal) finalText += result[0].transcript;
        else interim += result[0].transcript;
      }
      if (interim) this.partialListeners.forEach((cb) => cb(interim));
      if (finalText) this.finalListeners.forEach((cb) => cb(finalText));
    };
    r.onerror = (e) => {
      this.errorListeners.forEach((cb) => cb(new Error(e.error || 'speech_error')));
    };
    r.start();
    this.recognition = r;
  }

  async stop(): Promise<void> {
    this.recognition?.stop();
    this.recognition = null;
  }

  onPartial(callback: (text: string) => void): () => void {
    this.partialListeners.add(callback);
    return () => this.partialListeners.delete(callback);
  }

  onFinal(callback: (text: string) => void): () => void {
    this.finalListeners.add(callback);
    return () => this.finalListeners.delete(callback);
  }

  onError(callback: (err: Error) => void): () => void {
    this.errorListeners.add(callback);
    return () => this.errorListeners.delete(callback);
  }
}

