/* ── AgentTree ─────────────────────────────────────────────────────────── */
/* Hierarchical view of sub-agent jobs for a session. Driven by the        */
/* /api/agents/tree endpoint.                                               */

import { useEffect, useState } from 'react';
import { ChevronRight, ChevronDown, Bot, Loader2, Check, X, AlertTriangle, StopCircle } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Badge } from '@/components/ui/badge';

export type AgentNode = {
  id: string;
  parentId: string | null;
  sessionId: string | null;
  agentId: string;
  parentAgentId: string | null;
  depth: number;
  task: string;
  status: 'running' | 'completed' | 'failed' | 'blocked';
  scope: string | null;
  startedAt: string;
  updatedAt: string;
  completedAt: string | null;
  resultSummary: string | null;
};

type TreeResponse = {
  root: AgentNode;
  children: Record<string, { root: AgentNode; children: Record<string, { root: AgentNode; children: Record<string, any> }> }>;
};

type Props = {
  rootId: string | null;
  maxDepth?: number;
  onSelect?: (node: AgentNode) => void;
};

async function fetchTree(rootId: string, maxDepth: number): Promise<TreeResponse | null> {
  try {
    const r = await fetch(`/api/agents/tree?root=${encodeURIComponent(rootId)}&maxDepth=${maxDepth}`);
    if (!r.ok) return null;
    return r.json();
  } catch (_) {
    return null;
  }
}

const STATUS_BADGE: Record<AgentNode['status'], { label: string; Icon: typeof Loader2; cls: string }> = {
  running:   { label: 'running',   Icon: Loader2,     cls: 'border-info/40 text-info' },
  completed: { label: 'completed', Icon: Check,       cls: 'border-success/40 text-success' },
  failed:    { label: 'failed',    Icon: AlertTriangle, cls: 'border-danger/40 text-danger' },
  blocked:   { label: 'blocked',   Icon: StopCircle,  cls: 'border-warning/40 text-warning' },
};

export function AgentTree({ rootId, maxDepth = 4, onSelect }: Props) {
  const [tree, setTree] = useState<TreeResponse | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!rootId) {
      setTree(null);
      return;
    }
    let cancelled = false;
    const tick = async () => {
      setLoading(true);
      const next = await fetchTree(rootId, maxDepth);
      if (cancelled) return;
      setTree(next);
      setLoading(false);
    };
    tick();
    const t = setInterval(tick, 3000);
    return () => {
      cancelled = true;
      clearInterval(t);
    };
  }, [rootId, maxDepth]);

  if (!rootId) return null;
  if (loading && !tree) return <div className="text-xs text-muted-foreground p-3">Loading agent tree…</div>;
  if (!tree) return <div className="text-xs text-muted-foreground p-3">No agent tree available.</div>;

  return (
    <div className="text-xs" data-testid="agent-tree">
      <TreeNode node={tree.root} childrenMap={tree.children} depth={0} onSelect={onSelect} defaultOpen />
    </div>
  );
}

type Subtree = { root: AgentNode; children: Record<string, Subtree> };

function TreeNode({
  node,
  childrenMap,
  depth,
  onSelect,
  defaultOpen = false,
}: {
  node: AgentNode;
  childrenMap: Record<string, Subtree>;
  depth: number;
  onSelect?: (n: AgentNode) => void;
  defaultOpen?: boolean;
}) {
  const [open, setOpen] = useState(defaultOpen);
  const childIds = Object.keys(childrenMap);
  const hasChildren = childIds.length > 0;
  const badge = STATUS_BADGE[node.status] || STATUS_BADGE.running;
  const Icon = badge.Icon;

  return (
    <div className="space-y-0.5">
      <div
        className={cn(
          'group flex items-start gap-2 rounded-md px-2 py-1.5 hover:bg-accent/30 cursor-pointer',
          depth === 0 && 'bg-accent/10'
        )}
        onClick={() => onSelect?.(node)}
        data-status={node.status}
      >
        <button
          type="button"
          className="mt-0.5 text-muted-foreground hover:text-foreground"
          onClick={(e) => {
            e.stopPropagation();
            setOpen((o) => !o);
          }}
          aria-label={open ? 'Collapse' : 'Expand'}
        >
          {hasChildren ? (
            open ? <ChevronDown className="h-3.5 w-3.5" /> : <ChevronRight className="h-3.5 w-3.5" />
          ) : (
            <span className="inline-block w-3.5" />
          )}
        </button>
        <Bot className="mt-0.5 h-3.5 w-3.5 text-muted-foreground flex-none" />
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <span className="font-medium truncate">{node.agentId}</span>
            <Badge variant="outline" className={cn('text-[9px]', badge.cls)}>
              {badge.label}
            </Badge>
            <span className="text-[9px] text-muted-foreground/60">d{node.depth}</span>
            {node.scope && <span className="text-[9px] text-muted-foreground/60">· {node.scope}</span>}
          </div>
          <p className="text-[10px] text-muted-foreground/80 line-clamp-2">{node.task}</p>
        </div>
        <Icon className={cn('h-3.5 w-3.5 flex-none', node.status === 'running' && 'animate-spin')} />
      </div>
      {open && hasChildren && (
        <div className="ml-3 border-l border-border/40 pl-2 space-y-0.5">
          {childIds.map((cid) => (
            <TreeNode
              key={cid}
              node={childrenMap[cid].root}
              childrenMap={childrenMap[cid].children}
              depth={depth + 1}
              onSelect={onSelect}
            />
          ))}
        </div>
      )}
    </div>
  );
}

export default AgentTree;

/* ── ClarifyTool ─ floating question/answer popup ────────────────── */
/* Lifted from an inline panel into a centered floating card matching   */
/* the ZCode reference:                                                   */
/*   • fixed-position overlay with dark backdrop                        */
/*   • top: synthesized-context breadcrumb + pagination arrows + X      */
/*   • question in larger text                                          */
/*   • numbered choice badges (1, 2, 3, 4) in 22×22 rounded-md          */
/*   • "Something else" input + Skip button (bottom row)                 */
/*   • footer hint: "A. tap a number · Enter to send · Esc to close"    */
/*                                                                       */
/* Supports two data shapes (additive, backward compatible):             */
/*   1. legacy single-question:  { question, choices? }                  */
/*   2. new multi-question:      { questions: [{question, choices?}],     */
/*                                currentIndex?, contextSummary? }        */
/*                                                                       */
/* Keyboard:                                                              */
/*   • 1-9    → select the choice at that index                          */
/*   • ← / →  → paginate between questions in a multi-question flow      */
/*   • Enter  → submit the freeform input (when focused)                 */
/*   • Esc    → close (sends a "User skipped" stub to the model)         */

import { useState, useEffect, useCallback, useRef, type FormEvent, type KeyboardEvent as ReactKeyboardEvent } from 'react';
import { ChevronLeft, ChevronRight, X, Paperclip, SkipForward } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';

export interface ClarifyQuestion {
  question: string;
  choices?: string[];
}

export interface ClarifyPayload {
  /** Legacy single-question mode. */
  question?: string;
  choices?: string[];
  /** Multi-question mode. Wins over the legacy fields when present. */
  questions?: ClarifyQuestion[];
  /** 0-indexed; managed by the popup. */
  currentIndex?: number;
  /** Header line above the question: "Synthesized user context to craft …". */
  contextSummary?: string;
  /** Already-answered (set on the message after submit). */
  answer?: string;
}

export interface ClarifyToolProps {
  /** Full clarify payload (preferred). */
  payload?: ClarifyPayload;
  /** Legacy convenience props. If `payload` is provided these are ignored. */
  question?: string;
  choices?: string[];
  /** Submit handler. Receives a single string:
   *   • the answer directly, for single-question flows
   *   • a JSON-stringified `{ [questionIndex]: answer }` record, for multi-question
   */
  onSubmit: (answer: string) => void;
  /** Esc / X close — submits a "User skipped" stub so the model knows to proceed. */
  onDismiss?: () => void;
  submitting?: boolean;
  /** Optional title override; defaults to "What would you like to do next?" */
  title?: string;
}

export function ClarifyTool({
  payload,
  question,
  choices,
  onSubmit,
  onDismiss,
  submitting = false,
  title,
}: ClarifyToolProps) {
  // Normalise to the multi-question shape (legacy single question becomes a 1-item list)
  const questions: ClarifyQuestion[] = payload?.questions && payload.questions.length > 0
    ? payload.questions
    : [{ question: payload?.question ?? question ?? '', choices: payload?.choices ?? choices }];
  const contextSummary = payload?.contextSummary;
  const totalQuestions = questions.length;
  const [currentIndex, setCurrentIndex] = useState(
    Math.max(0, Math.min(totalQuestions - 1, payload?.currentIndex ?? 0))
  );
  const [answers, setAnswers] = useState<Record<number, string>>({});
  const [draft, setDraft] = useState('');
  const [selectedChoice, setSelectedChoice] = useState<string | null>(null);
  const inputRef = useRef<HTMLInputElement | null>(null);

  const current = questions[currentIndex];
  const isLast = currentIndex === totalQuestions - 1;

  // Keyboard: Esc / ← / → / 1-9
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (submitting) return;
      if (e.key === 'Escape') {
        e.preventDefault();
        handleDismiss();
        return;
      }
      // Don't hijack typing in the input
      const tag = (e.target as HTMLElement | null)?.tagName;
      if (tag === 'INPUT' || tag === 'TEXTAREA') {
        if (e.key === 'Enter' && (e.target as HTMLElement) === inputRef.current) {
          e.preventDefault();
          submitFreeform();
        }
        return;
      }
      if (e.key === 'ArrowLeft' && currentIndex > 0) {
        e.preventDefault();
        setCurrentIndex(i => i - 1);
        setSelectedChoice(null);
        setDraft('');
      } else if (e.key === 'ArrowRight' && currentIndex < totalQuestions - 1) {
        e.preventDefault();
        setCurrentIndex(i => i + 1);
        setSelectedChoice(null);
        setDraft('');
      } else if (/^[1-9]$/.test(e.key)) {
        const idx = parseInt(e.key, 10) - 1;
        if (current.choices && idx < current.choices.length) {
          e.preventDefault();
          pickChoice(current.choices[idx]);
        }
      }
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentIndex, totalQuestions, current?.choices, submitting]);

  const pickChoice = useCallback(
    (choice: string) => {
      if (submitting) return;
      setSelectedChoice(choice);
      const next = { ...answers, [currentIndex]: choice };
      setAnswers(next);
      if (isLast) {
        // Submit a structured record for multi-question (so the model can
        // see the answers indexed), or the plain string for single-question.
        onSubmit(totalQuestions === 1 ? choice : JSON.stringify(next));
      } else {
        // Advance to the next question after a brief delay so the user
        // can see the selection highlight first.
        window.setTimeout(() => {
          setCurrentIndex(i => Math.min(totalQuestions - 1, i + 1));
          setSelectedChoice(null);
          setDraft('');
        }, 200);
      }
    },
    [answers, currentIndex, isLast, onSubmit, submitting, totalQuestions]
  );

  const submitFreeform = useCallback(() => {
    const trimmed = draft.trim();
    if (!trimmed || submitting) return;
    const next = { ...answers, [currentIndex]: trimmed };
    if (totalQuestions === 1) onSubmit(trimmed);
    else onSubmit(JSON.stringify(next));
  }, [answers, currentIndex, draft, onSubmit, submitting, totalQuestions]);

  const handleSubmit = useCallback((e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    submitFreeform();
  }, [submitFreeform]);

  const handleDismiss = useCallback(() => {
    if (onDismiss) onDismiss();
    else {
      // Default behaviour: tell the model to proceed
      onSubmit('User skipped');
    }
  }, [onDismiss, onSubmit]);

  if (!current || !current.question) return null;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-150"
      role="dialog"
      aria-modal="true"
      aria-label="Clarification"
    >
      <div
        className="w-full max-w-md rounded-2xl shadow-2xl overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-200"
        style={{ backgroundColor: '#1c1c1c', border: '0.5px solid rgba(255,255,255,0.07)' }}
      >
        {/* Top row: context breadcrumb + pagination + X close */}
        <div className="flex items-center justify-between px-4 pt-3 pb-1 text-[11.5px]">
          <button
            type="button"
            onClick={() => {/* TODO: open the full context summary */}}
            className="text-muted-foreground hover:text-foreground truncate text-left flex-1 min-w-0"
          >
            {contextSummary ?? title ?? 'Synthesized user context to craft a personalized response'} <span aria-hidden>›</span>
          </button>
          <div className="flex items-center gap-1.5 ml-2 shrink-0 text-muted-foreground">
            {totalQuestions > 1 && (
              <>
                <button
                  type="button"
                  onClick={() => { setCurrentIndex(i => Math.max(0, i - 1)); setSelectedChoice(null); setDraft(''); }}
                  disabled={currentIndex === 0}
                  className="p-0.5 rounded hover:bg-white/10 disabled:opacity-30 disabled:cursor-not-allowed"
                  aria-label="Previous question"
                >
                  <ChevronLeft size={14} />
                </button>
                <span className="font-mono tabular-nums text-[11px]">
                  {currentIndex + 1} of {totalQuestions}
                </span>
                <button
                  type="button"
                  onClick={() => { setCurrentIndex(i => Math.min(totalQuestions - 1, i + 1)); setSelectedChoice(null); setDraft(''); }}
                  disabled={isLast}
                  className="p-0.5 rounded hover:bg-white/10 disabled:opacity-30 disabled:cursor-not-allowed"
                  aria-label="Next question"
                >
                  <ChevronRight size={14} />
                </button>
              </>
            )}
            <button
              type="button"
              onClick={handleDismiss}
              className="p-0.5 rounded hover:bg-white/10 ml-1"
              aria-label="Close"
            >
              <X size={14} />
            </button>
          </div>
        </div>

        {/* Question */}
        <div className="px-4 pt-2 pb-3">
          <h2 className="text-[15px] font-medium leading-snug text-foreground">
            {current.question}
          </h2>
        </div>

        {/* Numbered choice list */}
        {current.choices && current.choices.length > 0 && (
          <div className="px-3 pb-1">
            {current.choices.map((choice, i) => (
              <button
                type="button"
                key={`${currentIndex}-${i}-${choice}`}
                onClick={() => pickChoice(choice)}
                disabled={submitting}
                className={cn(
                  'w-full flex items-center gap-3 px-1 py-2 text-left text-[13.5px] text-foreground/90',
                  'hover:bg-white/[0.04] rounded-md transition-colors',
                  'border-b border-white/[0.04] last:border-b-0',
                  'disabled:opacity-50 disabled:cursor-not-allowed',
                  selectedChoice === choice && 'bg-white/[0.06]'
                )}
                data-clarify-choice
              >
                <span
                  aria-hidden
                  className="grid size-[22px] shrink-0 place-items-center rounded-md text-[11px] font-medium tabular-nums"
                  style={{ backgroundColor: 'rgba(255,255,255,0.06)', color: 'rgba(255,255,255,0.55)' }}
                >
                  {i + 1}
                </span>
                <span className="flex-1 wrap-anywhere">{choice}</span>
              </button>
            ))}
          </div>
        )}

        {/* Bottom: "Something else" input + Skip */}
        <form onSubmit={handleSubmit} className="flex items-center gap-2 px-3 py-3 border-t border-white/[0.06]">
          <Paperclip aria-hidden size={12} className="text-muted-foreground/60 shrink-0" />
          <span className="text-[12px] text-muted-foreground/80 shrink-0">Something else</span>
          <input
            ref={inputRef}
            type="text"
            value={draft}
            onChange={(e) => setDraft(e.target.value)}
            placeholder="Type your answer…"
            disabled={submitting}
            className="flex-1 min-w-0 bg-transparent text-[12.5px] text-foreground placeholder:text-muted-foreground/40 focus:outline-none"
          />
          <button
            type="button"
            onClick={handleDismiss}
            disabled={submitting}
            className="text-[12px] text-muted-foreground hover:text-foreground px-1.5 py-0.5 rounded disabled:opacity-50"
          >
            <SkipForward aria-hidden size={12} className="inline mr-0.5" />
            Skip
          </button>
        </form>

        {/* Footer hint */}
        <div className="px-4 pb-3 text-[10px] text-muted-foreground/50 select-none">
          tap a number · Enter to send · Esc to close
        </div>
      </div>
    </div>
  );
}

/**
 * Thin wrapper for inline use (kept for backward compatibility).
 * Mounts the popup but skips the dark backdrop so it looks embedded.
 */
export function ClarifyToolInline(props: ClarifyToolProps) {
  // Strip the fixed-position overlay; render the card only.
  return (
    <div className="my-2">
      <ClarifyTool {...props} />
    </div>
  );
}

/* ── DiffView ─ inline unified / line-based diff renderer ─────────── */
/* Renders a diff in the same style as the ZCode reference:              */
/*   • line numbers in a muted right-aligned column                      */
/*   • removed lines: rgba(248,113,113,0.09) bg + 2-px #f87171 border    */
/*   • added   lines: rgba(74,222,128,0.09) bg + 2-px #4ade80 border    */
/*   • container:  rgba(0,0,0,0.3) on the already-dark surface           */
/*   • ─── N more lines ─── truncation after `maxLines`                  */
/*                                                                       */
/* Accepts either:                                                        */
/*   1. a pre-formatted unified diff string (`diff` prop), or            */
/*   2. an `oldContent` / `newContent` pair (computes the diff inline),  */
/*   3. a `null` / `undefined` (renders nothing).                        */

import { useMemo } from 'react';
import { cn } from '@/lib/utils';

export type DiffLineKind = 'context' | 'added' | 'removed';

export interface DiffLine {
  kind: DiffLineKind;
  text: string;
  oldLine?: number;
  newLine?: number;
}

/**
 * Line-based diff between two files. Uses common-prefix + common-suffix,
 * which handles the common case of "change a few lines in the middle of
 * an otherwise-unchanged file" — the typical shape of a tool-driven edit.
 */
function splitLines(text: string): string[] {
  // Equivalent of String.prototype.splitlines(), which isn't in our ES target.
  // Drops the trailing empty that split('\n') adds when the input doesn't
  // end with a newline; keeps an actual trailing empty line if the input is
  // a single '\n' (which splitlines() would also return [] for).
  if (text === '') return [];
  const lines = text.split('\n');
  if (lines.length > 0 && lines[lines.length - 1] === '' && !text.endsWith('\n')) {
    lines.pop();
  }
  return lines;
}

export function diffLines(oldText: string, newText: string): DiffLine[] {
  const oldLines = splitLines(oldText);
  const newLines = splitLines(newText);

  let prefix = 0;
  const maxPrefix = Math.min(oldLines.length, newLines.length);
  while (prefix < maxPrefix && oldLines[prefix] === newLines[prefix]) {
    prefix++;
  }

  let suffix = 0;
  const maxSuffix = Math.min(oldLines.length - prefix, newLines.length - prefix);
  while (
    suffix < maxSuffix &&
    oldLines[oldLines.length - 1 - suffix] === newLines[newLines.length - 1 - suffix]
  ) {
    suffix++;
  }

  const out: DiffLine[] = [];

  for (let i = 0; i < prefix; i++) {
    out.push({ kind: 'context', text: oldLines[i], oldLine: i + 1, newLine: i + 1 });
  }
  for (let i = prefix; i < oldLines.length - suffix; i++) {
    out.push({ kind: 'removed', text: oldLines[i], oldLine: i + 1 });
  }
  for (let i = prefix; i < newLines.length - suffix; i++) {
    out.push({ kind: 'added', text: newLines[i], newLine: i + 1 });
  }
  for (let i = suffix; i > 0; i--) {
    const oldIdx = oldLines.length - i;
    const newIdx = newLines.length - i;
    out.push({ kind: 'context', text: oldLines[oldIdx], oldLine: oldIdx + 1, newLine: newIdx + 1 });
  }

  return out;
}

/** Parse a unified-diff string (the output of `git diff`, `diff -u`, etc.) into DiffLine[]. */
export function parseUnifiedDiff(text: string): DiffLine[] {
  const lines = text.split('\n');
  const out: DiffLine[] = [];
  let oldLine = 0;
  let newLine = 0;
  let inHunk = false;

  for (const raw of lines) {
    if (raw.startsWith('--- ') || raw.startsWith('+++ ')) continue;
    if (raw.startsWith('@@')) {
      // Hunk header: @@ -oldStart,oldCount +newStart,newCount @@ optional section
      const m = raw.match(/^@@ -(\d+)(?:,\d+)? \+(\d+)(?:,\d+)? @@/);
      if (m) {
        oldLine = parseInt(m[1], 10);
        newLine = parseInt(m[2], 10);
        inHunk = true;
      }
      continue;
    }
    if (!inHunk) continue;

    if (raw.startsWith('+')) {
      out.push({ kind: 'added', text: raw.slice(1), newLine: newLine++ });
    } else if (raw.startsWith('-')) {
      out.push({ kind: 'removed', text: raw.slice(1), oldLine: oldLine++ });
    } else if (raw.startsWith(' ') || raw === '') {
      out.push({
        kind: 'context',
        text: raw.startsWith(' ') ? raw.slice(1) : raw,
        oldLine: oldLine++,
        newLine: newLine++,
      });
    }
  }

  return out;
}

export interface DiffViewProps {
  /** Pre-formatted unified diff string. Wins over oldContent/newContent. */
  diff?: string;
  /** Old file content. Used with newContent to compute the diff. */
  oldContent?: string;
  /** New file content. */
  newContent?: string;
  /** Maximum number of lines to render before showing the "─── N more lines ───" truncation. Default: 40. */
  maxLines?: number;
  className?: string;
}

export function DiffView({ diff, oldContent, newContent, maxLines = 40, className }: DiffViewProps) {
  const lines = useMemo<DiffLine[]>(() => {
    if (diff) return parseUnifiedDiff(diff);
    if (oldContent !== undefined && newContent !== undefined) {
      return diffLines(oldContent, newContent);
    }
    return [];
  }, [diff, oldContent, newContent]);

  const counts = useMemo(() => {
    let added = 0;
    let removed = 0;
    for (const l of lines) {
      if (l.kind === 'added') added++;
      else if (l.kind === 'removed') removed++;
    }
    return { added, removed };
  }, [lines]);

  if (lines.length === 0) return null;

  const visible = lines.slice(0, maxLines);
  const hidden = lines.length - visible.length;

  return (
    <div
      className={cn(
        'rounded-md overflow-x-auto my-1.5 font-mono text-[11px] leading-[1.55]',
        'bg-black/30 border border-white/[0.04]',
        className
      )}
      role="region"
      aria-label={`Diff: +${counts.added} -${counts.removed}`}
    >
      {visible.map((line, i) => (
        <DiffLineRow key={i} line={line} />
      ))}
      {hidden > 0 && (
        <div className="text-[10px] text-zinc-500 text-center py-1.5 select-none">
          ─── {hidden} more line{hidden === 1 ? '' : 's'} ───
        </div>
      )}
    </div>
  );
}

function DiffLineRow({ line }: { line: DiffLine }) {
  const lineNumber = line.kind === 'removed' ? line.oldLine : line.newLine;
  const prefix = line.kind === 'added' ? '+' : line.kind === 'removed' ? '-' : ' ';

  return (
    <div className="flex hover:bg-white/[0.025]">
      <span
        className={cn(
          'text-zinc-500 text-right min-w-[2.25rem] pr-2 select-none tabular-nums shrink-0',
          'border-r border-white/[0.04]'
        )}
      >
        {lineNumber ?? ''}
      </span>
      <span
        className={cn(
          'px-1.5 border-l-2 flex-1 whitespace-pre',
          line.kind === 'added' &&
            'border-success text-success',
          line.kind === 'removed' &&
            'border-danger text-danger',
          line.kind === 'context' && 'border-transparent text-zinc-300'
        )}
        style={
          line.kind === 'added'
            ? { backgroundColor: 'rgba(74,222,128,0.09)' }
            : line.kind === 'removed'
              ? { backgroundColor: 'rgba(248,113,113,0.09)' }
              : undefined
        }
      >
        <span className="opacity-50 select-none">{prefix}</span> {line.text || ' '}
      </span>
    </div>
  );
}

import { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { useQuery } from '@tanstack/react-query';
import { api } from '@/api/client';
import { Search, ZoomIn, ZoomOut, Maximize2, RotateCcw } from 'lucide-react';
import { cn } from '@/lib/utils';

interface GraphEntity {
  id: string;
  type: string;
  name: string;
  confidence?: number;
  score?: number;
}

interface GraphRelation {
  id: string;
  from: string;
  to: string;
  type: string;
  fromName?: string;
  toName?: string;
  score?: number;
}

interface GraphSearchResult {
  stats: { counts: { entities: number; relations: number; observations: number }; entityTypes: Record<string, number> };
  search: { entities: GraphEntity[]; relations: GraphRelation[] };
}

const TYPE_COLORS: Record<string, string> = {
  project: '#3b82f6',
  projectInfo: '#60a5fa',
  concept: '#8b5cf6',
  tool: '#f59e0b',
  integration: '#10b981',
  userPreference: '#ec4899',
  userDetail: '#f472b6',
  workflowRule: '#ef4444',
  checkpointTopic: '#06b6d4',
  sessionTemp: '#6366f1',
  path: '#78716c',
  memory: '#f97316',
};

function getColor(type: string): string {
  return TYPE_COLORS[type] || '#6b7280';
}

interface Node {
  id: string;
  label: string;
  type: string;
  x: number;
  y: number;
  vx: number;
  vy: number;
  score: number;
}

interface Edge {
  source: string;
  target: string;
  label: string;
}

export function KnowledgeGraph({ className }: { className?: string }) {
  const [query, setQuery] = useState('');
  const [selectedNode, setSelectedNode] = useState<string | null>(null);
  const [zoom, setZoom] = useState(1);
  const [offset, setOffset] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const svgRef = useRef<SVGSVGElement>(null);
  const nodesRef = useRef<Map<string, Node>>(new Map());

  const { data, isLoading } = useQuery<GraphSearchResult>({
    queryKey: ['brain-graph-search', query],
    queryFn: () => api.get<GraphSearchResult>(`/api/brain/graph?q=${encodeURIComponent(query)}&limit=50`),
    enabled: query.trim().length > 0,
  });

  const nodes = useMemo(() => {
    if (!data?.search?.entities) return [];
    return data.search.entities.map(e => {
      const existing = nodesRef.current.get(e.id);
      return {
        id: e.id,
        label: e.name.replace(/_/g, ' ').replace(/^ent_/, '').substring(0, 30),
        type: e.type,
        x: existing?.x ?? Math.random() * 600 + 100,
        y: existing?.y ?? Math.random() * 400 + 100,
        vx: 0,
        vy: 0,
        score: e.score || 1,
      };
    });
  }, [data?.search?.entities]);

  const edges = useMemo(() => {
    if (!data?.search?.relations) return [];
    return data.search.relations.map(r => ({
      source: r.from,
      target: r.to,
      label: r.type.replace(/_/g, ' '),
    }));
  }, [data?.search?.relations]);

  // Force simulation
  useEffect(() => {
    if (nodes.length === 0) return;

    const nodeMap = new Map(nodes.map(n => [n.id, { ...n }]));
    nodesRef.current = nodeMap;

    let animId: number;
    const tick = () => {
      const ns = Array.from(nodeMap.values());

      // Repulsion between nodes
      for (let i = 0; i < ns.length; i++) {
        for (let j = i + 1; j < ns.length; j++) {
          const dx = ns[j].x - ns[i].x;
          const dy = ns[j].y - ns[i].y;
          const dist = Math.sqrt(dx * dx + dy * dy) || 1;
          const force = 800 / (dist * dist);
          const fx = (dx / dist) * force;
          const fy = (dy / dist) * force;
          ns[i].vx -= fx;
          ns[i].vy -= fy;
          ns[j].vx += fx;
          ns[j].vy += fy;
        }
      }

      // Attraction along edges
      for (const edge of edges) {
        const s = nodeMap.get(edge.source);
        const t = nodeMap.get(edge.target);
        if (!s || !t) continue;
        const dx = t.x - s.x;
        const dy = t.y - s.y;
        const dist = Math.sqrt(dx * dx + dy * dy) || 1;
        const force = (dist - 120) * 0.01;
        const fx = (dx / dist) * force;
        const fy = (dy / dist) * force;
        s.vx += fx;
        s.vy += fy;
        t.vx -= fx;
        t.vy -= fy;
      }

      // Center gravity
      for (const n of ns) {
        n.vx += (400 - n.x) * 0.001;
        n.vy += (300 - n.y) * 0.001;
        n.vx *= 0.85;
        n.vy *= 0.85;
        n.x += n.vx;
        n.y += n.vy;
        n.x = Math.max(20, Math.min(780, n.x));
        n.y = Math.max(20, Math.min(580, n.y));
      }

      nodesRef.current = nodeMap;
      animId = requestAnimationFrame(tick);
    };

    animId = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(animId);
  }, [nodes.length, edges.length]);

  const handleWheel = useCallback((e: React.WheelEvent) => {
    e.preventDefault();
    setZoom(z => Math.max(0.3, Math.min(3, z - e.deltaY * 0.001)));
  }, []);

  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    if (e.target === svgRef.current) {
      setIsDragging(true);
      setDragStart({ x: e.clientX - offset.x, y: e.clientY - offset.y });
    }
  }, [offset]);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (isDragging) {
      setOffset({ x: e.clientX - dragStart.x, y: e.clientY - dragStart.y });
    }
  }, [isDragging, dragStart]);

  const handleMouseUp = useCallback(() => setIsDragging(false), []);

  const resetView = () => { setZoom(1); setOffset({ x: 0, y: 0 }); };

  const selectedEntity = data?.search?.entities?.find(e => e.id === selectedNode);

  return (
    <div className={cn('flex flex-col h-full', className)}>
      {/* Search bar */}
      <div className="p-3 border-b border-border/30">
        <div className="relative">
          <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 size-3.5 text-muted-foreground/50" />
          <input
            value={query}
            onChange={e => setQuery(e.target.value)}
            placeholder="Search entities (e.g. 'project', 'user', 'tool')..."
            className="w-full pl-8 pr-3 py-1.5 text-xs bg-muted/30 rounded-md border-none outline-none text-foreground placeholder:text-muted-foreground/50"
          />
        </div>
      </div>

      {/* Graph area */}
      <div className="flex-1 relative overflow-hidden bg-[#0a0a0f]">
        {isLoading && (
          <div className="absolute inset-0 flex items-center justify-center z-10">
            <div className="space-y-2">
              {Array.from({ length: 4 }).map((_, i) => (
                <div key={i} className="h-4 rounded bg-white/5 animate-pulse" style={{ width: 100 + i * 40 }} />
              ))}
            </div>
          </div>
        )}

        {!query.trim() && (
          <div className="absolute inset-0 flex items-center justify-center text-muted-foreground/40 text-sm">
            Type a search query to visualize the knowledge graph
          </div>
        )}

        <svg
          ref={svgRef}
          className="w-full h-full"
          onWheel={handleWheel}
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={handleMouseUp}
        >
          <g transform={`translate(${offset.x},${offset.y}) scale(${zoom})`}>
            {/* Edges */}
            {edges.map((edge, i) => {
              const sourceNode = nodesRef.current.get(edge.source);
              const targetNode = nodesRef.current.get(edge.target);
              if (!sourceNode || !targetNode) return null;
              return (
                <g key={i}>
                  <line
                    x1={sourceNode.x}
                    y1={sourceNode.y}
                    x2={targetNode.x}
                    y2={targetNode.y}
                    stroke="rgba(255,255,255,0.08)"
                    strokeWidth={1}
                  />
                  <text
                    x={(sourceNode.x + targetNode.x) / 2}
                    y={(sourceNode.y + targetNode.y) / 2 - 4}
                    textAnchor="middle"
                    fill="rgba(255,255,255,0.2)"
                    fontSize={8}
                  >
                    {edge.label}
                  </text>
                </g>
              );
            })}

            {/* Nodes */}
            {Array.from(nodesRef.current.values()).map(node => {
              const isSelected = selectedNode === node.id;
              const size = 4 + Math.min(node.score, 10) * 1.5;
              return (
                <g
                  key={node.id}
                  onClick={() => setSelectedNode(isSelected ? null : node.id)}
                  className="cursor-pointer"
                >
                  <circle
                    cx={node.x}
                    cy={node.y}
                    r={isSelected ? size + 2 : size}
                    fill={getColor(node.type)}
                    opacity={isSelected ? 1 : 0.7}
                    stroke={isSelected ? '#fff' : 'none'}
                    strokeWidth={isSelected ? 1.5 : 0}
                  />
                  <text
                    x={node.x}
                    y={node.y + size + 10}
                    textAnchor="middle"
                    fill="rgba(255,255,255,0.5)"
                    fontSize={8}
                    className="pointer-events-none"
                  >
                    {node.label}
                  </text>
                </g>
              );
            })}
          </g>
        </svg>

        {/* Controls */}
        <div className="absolute bottom-3 right-3 flex items-center gap-1">
          <button onClick={() => setZoom(z => Math.min(3, z * 1.3))} className="p-1.5 bg-background/80 rounded hover:bg-background text-muted-foreground hover:text-foreground transition">
            <ZoomIn className="size-3.5" />
          </button>
          <button onClick={() => setZoom(z => Math.max(0.3, z / 1.3))} className="p-1.5 bg-background/80 rounded hover:bg-background text-muted-foreground hover:text-foreground transition">
            <ZoomOut className="size-3.5" />
          </button>
          <button onClick={resetView} className="p-1.5 bg-background/80 rounded hover:bg-background text-muted-foreground hover:text-foreground transition">
            <RotateCcw className="size-3.5" />
          </button>
        </div>

        {/* Legend */}
        <div className="absolute top-3 right-3 bg-background/80 rounded-lg p-2 text-[9px] space-y-1">
          {Object.entries(TYPE_COLORS).slice(0, 8).map(([type, color]) => (
            <div key={type} className="flex items-center gap-1.5">
              <span className="size-2 rounded-full" style={{ backgroundColor: color }} />
              <span className="text-muted-foreground">{type.replace(/_/g, ' ')}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Selected node detail */}
      {selectedEntity && (
        <div className="p-3 border-t border-border/30 bg-muted/20">
          <div className="flex items-center justify-between mb-1">
            <span className="text-xs font-medium">{selectedEntity.name.replace(/_/g, ' ')}</span>
            <span className="text-[9px] font-mono text-muted-foreground">{selectedEntity.type}</span>
          </div>
          <div className="flex items-center gap-3 text-[10px] text-muted-foreground">
            {selectedEntity.confidence && <span>confidence: {Math.round(selectedEntity.confidence * 100)}%</span>}
            {selectedEntity.score && <span>score: {selectedEntity.score}</span>}
          </div>
        </div>
      )}
    </div>
  );
}

/* ── No-Provider Banner ───────────────────────────────────────────────── */
/* Sticky banner shown at the top of the chat thread when no providers are
   configured. Dismissable via localStorage flag. */

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { AlertTriangle, X, Settings } from 'lucide-react';

const DISMISS_KEY = 'august-no-provider-banner-dismissed';

export function NoProviderBanner() {
  const navigate = useNavigate();
  const [dismissed, setDismissed] = useState(() => {
    try {
      return localStorage.getItem(DISMISS_KEY) === 'true';
    } catch {
      return false;
    }
  });

  if (dismissed) return null;

  const handleDismiss = () => {
    setDismissed(true);
    try {
      localStorage.setItem(DISMISS_KEY, 'true');
    } catch { /* noop */ }
  };

  return (
    <div
      className="sticky top-0 z-10 flex items-center gap-3 rounded-lg border border-warning/30 bg-warning/5 px-4 py-2.5 text-sm"
      role="alert"
    >
      <AlertTriangle className="size-4 shrink-0 text-warning" />
      <p className="flex-1 text-foreground/80">
        No AI providers configured.{' '}
        <button
          type="button"
          onClick={() => navigate('/settings/providers')}
          className="inline-flex items-center gap-1 font-medium text-primary hover:underline"
        >
          <Settings className="size-3" />
          Configure a provider
        </button>{' '}
        to start chatting.
      </p>
      <button
        type="button"
        onClick={handleDismiss}
        className="shrink-0 text-muted-foreground hover:text-foreground"
        aria-label="Dismiss"
      >
        <X className="size-4" />
      </button>
    </div>
  );
}

/**
 * SubagentBlock — nested renderer for sub-agent (`august__spawn_subagent` /
 * `august__run_team`) progress. Appears under the parent `toolCall` block
 * in the assistant message, indented inside a left rail so the parent/child
 * relationship is visible at a glance.
 *
 * The block's contents are the sub-agent's own `blocks` array, rendered
 * through the same reducer used for the parent assistant message (thinking,
 * final_output, toolCall, tool_result, command).
 *
 * Structural layout:
 *   ┌─────────────────────────────────────────┐
 *   │ Sub-agent [header]    [Completed] 1.2s │
 *   │   Task: …                                │
 *   │   Tool call 1                            │
 *   │   Tool call 2                            │
 *   │   ┌─────────────────────────────────┐    │
 *   │   │ Final summary text in a box…   │    │
 *   │   └─────────────────────────────────┘    │
 *   └─────────────────────────────────────────┘
 *
 * The outer left rail (`border-l-2`) is owned by ChatThread's wrapper
 * (which already provides the `ml-3` indent that aligns this block with
 * the sibling `PromptDisclosure` chip).
 */

import { useState, useEffect, useMemo, type ReactNode, type ReactElement } from 'react';
import { ChevronDown, ChevronRight, Loader2, CheckCircle2, AlertCircle, StopCircle } from 'lucide-react';
import { cn } from '@/lib/utils';
import type { MessageBlock } from '@/types/chat';
import type { SubagentBlockState } from '@/sections/chat/chat-stream-manager';
import { Markdown } from '@/sections/chat/ChatMarkdown';
import { ToolCallItem } from '@/components/chat/ToolCallItem';
import { ThinkingDisclosure } from '@/components/chat/ThinkingDisclosure';
import { PromptDisclosure } from '@/components/chat/PromptDisclosure';
import { getAgentRoleLabel } from '@/lib/tool-labels';

/** Sub-agent prompt payload stored on ChatThread's `subagentPrompts` map. */
export interface SubagentPromptEntry {
  content: string;
  systemPrompt: string;
  userMessage: string;
  tokens: number;
  subagentId?: string;
  jobId?: string;
}

const SUBAGENT_TOOL_NAMES = new Set([
  'august__spawn_subagent',
  'august_spawn_subagent',
  'workbench_spawn_subagent',
  'invoke_subagent',
  'august__run_team',
  'workbench_run_team',
]);

function isSubagentToolName(name?: string): boolean {
  if (!name) return false;
  const clean = name.replace(/^@/, '');
  return SUBAGENT_TOOL_NAMES.has(clean);
}

interface SubagentBlockProps {
  state: SubagentBlockState;
  /**
   * Maps for nested sub-agent dispatch. When a `toolCall` inside this block
   * is itself a sub-agent spawn, we look up its child container + prompt and
   * render them indented under the tool row (outside the final output box).
   */
  subBlocks?: Map<string, SubagentBlockState>;
  subPrompts?: Map<string, SubagentPromptEntry>;
}

const STATUS_LABEL: Record<SubagentBlockState['status'], string> = {
  running: 'Running',
  completed: 'Completed',
  failed: 'Failed',
  cancelled: 'Cancelled',
};

const STATUS_CLASS: Record<SubagentBlockState['status'], string> = {
  running: 'text-warning bg-warning/10 border-warning/30',
  completed: 'text-success bg-success/10 border-success/30',
  failed: 'text-danger bg-danger/10 border-danger/30',
  cancelled: 'text-muted-foreground bg-muted/40 border-border',
};

function StatusIcon({ status }: { status: SubagentBlockState['status'] }) {
  if (status === 'running') return <Loader2 className="size-3 animate-spin" />;
  if (status === 'completed') return <CheckCircle2 className="size-3" />;
  if (status === 'failed') return <AlertCircle className="size-3" />;
  return <StopCircle className="size-3" />;
}

export function SubagentBlock({ state, subBlocks, subPrompts }: SubagentBlockProps): ReactElement {
  // Persist expand/collapse per job id across re-renders.
  const expandKey = `chat_subagent_expanded_${state.jobId}`;
  const [expanded, setExpanded] = useState<boolean>(() => {
    try {
      const saved = localStorage.getItem(expandKey);
      return saved == null ? true : saved === '1';
    } catch (_) { return true; }
  });
  useEffect(() => {
    try { localStorage.setItem(expandKey, expanded ? '1' : '0'); } catch (_) {}
  }, [expandKey, expanded]);

  // Live elapsed timer while the sub-agent is running.
  const [elapsed, setElapsed] = useState<number>(0);
  useEffect(() => {
    if (state.status !== 'running') {
      setElapsed(state.finishedAt && state.startedAt
        ? Math.max(0, Math.round((state.finishedAt - state.startedAt) / 100) / 10)
        : 0);
      return;
    }
    const startedAt = state.startedAt || Date.now();
    const tick = () => setElapsed(Math.round((Date.now() - startedAt) / 100) / 10);
    tick();
    const id = window.setInterval(tick, 100);
    return () => window.clearInterval(id);
  }, [state.status, state.startedAt, state.finishedAt]);

  const friendlyRole = useMemo(
    () => getAgentRoleLabel(state.agentId),
    [state.agentId],
  );

  // Split `state.blocks` into body (tools, thinking, intermediate text) and
  // the LAST `finalOutput` chunk, which becomes the boxed summary at the
  // bottom. Body blocks render in their original chronological order above
  // the box.
  const { bodyBlocks, finalOutput } = useMemo(() => {
    let lastIdx = -1;
    for (let i = state.blocks.length - 1; i >= 0; i--) {
      if (state.blocks[i].type === 'finalOutput') { lastIdx = i; break; }
    }
    return {
      bodyBlocks: state.blocks.filter((_, i) => i !== lastIdx),
      finalOutput: lastIdx >= 0 ? state.blocks[lastIdx] : null,
    };
  }, [state.blocks]);

  return (
    <div
      className={cn(
        // No `ml-3` here — the parent ChatThread wrapper already indents us
        // by `ml-3`, which keeps us aligned with the sibling PromptDisclosure
        // chip. We only own the rail itself.
        'mt-2 pl-3 border-l-2 border-border/60',
        'transition-colors',
      )}
      data-subagent-id={state.jobId}
      data-subagent-status={state.status}
    >
      <button
        type="button"
        onClick={() => setExpanded((v) => !v)}
        className={cn(
          'group flex w-full items-center gap-2 rounded-md px-2 py-1.5 text-left',
          'hover:bg-muted/40 transition-colors',
        )}
        aria-expanded={expanded}
      >
        {expanded ? (
          <ChevronDown className="size-3 text-muted-foreground shrink-0" />
        ) : (
          <ChevronRight className="size-3 text-muted-foreground shrink-0" />
        )}
        <span className="text-[11px] text-foreground">
          <span className="font-semibold">{friendlyRole}</span>
          <span className="text-muted-foreground/70"> agent</span>
        </span>
        <span className="flex-1" />
        <span
          className={cn(
            'inline-flex items-center gap-1 rounded-full px-1.5 py-0.5',
            'text-[9px] font-medium tracking-wide',
            STATUS_CLASS[state.status],
          )}
        >
          <StatusIcon status={state.status} />
          {STATUS_LABEL[state.status]}
        </span>
        {elapsed > 0 && (
          <span className="tool-row-meta tabular-nums text-muted-foreground/60">
            {elapsed.toFixed(1)}s
          </span>
        )}
      </button>

      {state.task && (
        <div className="mt-1 ml-6 text-[11px] text-muted-foreground line-clamp-2 italic">
          {state.task}
        </div>
      )}

      {expanded && (
        <div className="mt-1 ml-6 space-y-2">
          {state.blocks.length === 0 ? (
            <div className="text-[11px] text-muted-foreground/60 italic py-1">
              {state.status === 'running' ? `${friendlyRole} is starting…` : 'No output recorded.'}
            </div>
          ) : (
            <>
              {bodyBlocks.map((block) => (
                <SubagentInnerBlock
                  key={block.id}
                  block={block}
                  subBlocks={subBlocks}
                  subPrompts={subPrompts}
                />
              ))}
              {finalOutput && (
                <div
                  className="rounded-md border border-border/40 bg-card/50 px-3 py-2 text-[12px] text-foreground/90 chat-message-text"
                  data-slot="subagent-final-output"
                >
                  <Markdown content={finalOutput.content || ''} />
                </div>
              )}
            </>
          )}
          {state.status === 'failed' && state.error && (
            <div className="rounded-md border border-danger/30 bg-danger/5 px-2 py-1.5 text-[11px] text-danger">
              {state.error}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

/** Render a sub-agent inner block — same kinds as the parent message's
 *  blocks array. Kept here so the sub-agent container is self-contained
 *  and doesn't depend on the parent assistant-message reducer. */
function SubagentInnerBlock({
  block,
  subBlocks,
  subPrompts,
}: {
  block: MessageBlock;
  subBlocks?: Map<string, SubagentBlockState>;
  subPrompts?: Map<string, SubagentPromptEntry>;
}): ReactNode {
  if (block.type === 'thinking') {
    return (
      <ThinkingDisclosure pending={false}>
        <div className="pl-3 border-l border-foreground/15 py-1 chat-thought-text text-[11px]">
          <Markdown content={block.content || ''} />
        </div>
      </ThinkingDisclosure>
    );
  }
  if (block.type === 'finalOutput') {
    // Earlier finalOutput chunks (when multiple streamed chunks exist)
    // render as bare Markdown in the body. The LAST chunk is rendered as a
    // box by the caller.
    return (
      <div className="text-[12px] text-foreground/90 chat-message-text">
        <Markdown content={block.content || ''} />
      </div>
    );
  }
  if (block.type === 'toolCall' || block.type === 'command') {
    if (!block.tool) return null;

    const isSubagentCall = isSubagentToolName(block.tool.name);
    // If this tool call itself spawns a sub-agent, look up the matching
    // prompt + child container so we can render them indented under the
    // tool row (outside the final output box).
    const promptEntries = isSubagentCall && block.tool.id && subPrompts
      ? Array.from(subPrompts.entries())
          .filter(([k]) => k === block.tool!.id)
          .map(([, v]) => v)
      : [];
    const subagentContainers = isSubagentCall && block.tool.id && subBlocks
      ? Array.from(subBlocks.values())
          .filter((s) => s.parentToolId === block.tool!.id)
          .sort((a, b) => a.startedAt - b.startedAt)
      : [];

    return (
      <div className="space-y-1.5">
        <ToolCallItem
          tool={{
            id: block.tool.id,
            name: block.tool.name,
            status: block.tool.status,
            context: block.tool.context,
            summary: block.tool.summary,
            error: block.tool.error,
            duration: block.tool.duration,
            startedAt: block.tool.startedAt,
          }}
        />
        {promptEntries.length > 0 && (
          <div className="ml-3 flex flex-col gap-1">
            {promptEntries.map((p, pi) => (
              <PromptDisclosure
                key={`${block.tool!.id}-prompt-${pi}`}
                content={p.content}
                tokens={p.tokens}
                label={p.subagentId
                  ? `SUB-AGENT PROMPT · ${p.subagentId}`
                  : 'SUB-AGENT PROMPT'}
              />
            ))}
          </div>
        )}
        {subagentContainers.length > 0 && (
          <div className="ml-3 pl-3 border-l border-foreground/15 flex flex-col gap-1">
            {subagentContainers.map((s) => (
              <SubagentBlock
                key={s.jobId}
                state={s}
                subBlocks={subBlocks}
                subPrompts={subPrompts}
              />
            ))}
          </div>
        )}
      </div>
    );
  }
  return null;
}

/* ── SubagentPanel ───────────────────────────────────────────────────── */
/* Top-level card showing parallel sub-agent progress. Collapsed shows
   "X/Y agents complete" + Expand button. Expanded lists SubagentRows.
   Auto-dismisses 3 seconds after all agents complete. */

import { useState, useEffect, useRef } from 'react';
import { ChevronDown, ChevronUp, Maximize2, Minimize2 } from 'lucide-react';
import { cn } from '@/lib/utils';
import { useSubagentStream } from '@/hooks/useSubagentStream';
import { useSubagentViewPreference } from '@/hooks/useSubagentViewPreference';
import { SubagentRow } from '@/components/chat/SubagentRow';

interface SubagentPanelProps {
  sessionId: string | null;
}

export function SubagentPanel({ sessionId }: SubagentPanelProps) {
  const { agents, loading, error } = useSubagentStream(sessionId);
  const { view, toggle } = useSubagentViewPreference();
  const [dismissed, setDismissed] = useState(false);
  const dismissTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const totalCount = agents.length;
  const completedCount = agents.filter(
    (a) => a.status === 'completed' || a.status === 'recovered',
  ).length;
  const allDone = totalCount > 0 && completedCount === totalCount;
  const hasActive = agents.some((a) => a.status === 'running');

  // Auto-dismiss after 3s when all complete
  useEffect(() => {
    if (allDone && !hasActive) {
      dismissTimerRef.current = setTimeout(() => {
        setDismissed(true);
      }, 3000);
    }
    return () => {
      if (dismissTimerRef.current) clearTimeout(dismissTimerRef.current);
    };
  }, [allDone, hasActive]);

  if (totalCount === 0 || dismissed || error) return null;

  const isExpanded = view === 'expanded' && !allDone;

  return (
    <div
      className={cn(
        'rounded-xl border border-white/[0.06] bg-card/60 backdrop-blur-sm',
        'transition-all duration-300',
      )}
      data-testid="subagent-panel"
    >
      {/* Header */}
      <div className="flex items-center justify-between px-3 py-2">
        <div className="flex items-center gap-2">
          {loading && (
            <span className="size-2 rounded-full bg-warning animate-pulse" />
          )}
          <span className="text-[11px] font-medium text-foreground/80">
            {allDone
              ? `${completedCount}/${totalCount} agents complete`
              : `${completedCount}/${totalCount} agents`}
          </span>
        </div>

        <div className="flex items-center gap-1">
          {totalCount > 1 && (
            <button
              type="button"
              onClick={toggle}
              className="rounded p-1 text-muted-foreground hover:text-foreground hover:bg-white/[0.06]"
              aria-label={isExpanded ? 'Collapse' : 'Expand'}
            >
              {isExpanded ? (
                <Minimize2 className="size-3" />
              ) : (
                <Maximize2 className="size-3" />
              )}
            </button>
          )}
        </div>
      </div>

      {/* Expanded rows */}
      {isExpanded && (
        <div className="space-y-1.5 px-3 pb-3">
          {agents.map((agent) => (
            <SubagentRow key={agent.taskId} agent={agent} />
          ))}
        </div>
      )}
    </div>
  );
}

/* ── SuggestedActionBubble ─ post-turn follow-up suggestions ──────── */
/* A single pill anchored top-right of the chat scroll area. Appears     */
/* when the previous turn just completed and the user hasn't started     */
/* typing yet. Clicking queues the suggestion as the next user message   */
/* by setting the composer input (the user can edit before sending).     */
/*                                                                       */
/* Default suggestions cover the most common follow-ups for an edit-      */
/* heavy turn; the consumer can override via the `suggestions` prop.     */

import { ArrowRight, X } from 'lucide-react';
import { cn } from '@/lib/utils';

export const DEFAULT_SUGGESTIONS: ReadonlyArray<string> = [
  'Summarize what just changed',
  'Run tests on the diff',
  'Add tests for the changes',
  'Commit the changes',
];

export interface SuggestedActionBubbleProps {
  /** List of suggestion strings (defaults to DEFAULT_SUGGESTIONS). */
  suggestions?: ReadonlyArray<string>;
  /** Called when the user clicks a suggestion. */
  onSelect: (suggestion: string) => void;
  /** Called when the user dismisses the bubble. */
  onDismiss?: () => void;
  /** When false, the bubble is hidden. */
  visible?: boolean;
  className?: string;
}

export function SuggestedActionBubble({
  suggestions = DEFAULT_SUGGESTIONS,
  onSelect,
  onDismiss,
  visible = true,
  className,
}: SuggestedActionBubbleProps) {
  if (!visible) return null;
  // Show only the first suggestion to keep the surface minimal (matches
  // the reference, which renders a single pill).
  const suggestion = suggestions[0];
  if (!suggestion) return null;

  return (
    <div
      className={cn(
        'flex justify-end px-1 pb-1.5 animate-in fade-in slide-in-from-top-2 duration-200',
        className
      )}
      role="region"
      aria-label="Suggested next action"
    >
      <div
        className="group relative inline-flex items-center gap-1.5 max-w-full"
        style={{
          backgroundColor: '#1b2839',
          border: '0.5px solid rgba(59,123,255,0.3)',
          borderRadius: 18,
          padding: '4px 6px 4px 11px',
          fontSize: 11.5,
          color: '#7fa8d0',
          overflow: 'hidden',
          whiteSpace: 'nowrap',
        }}
      >
        <button
          type="button"
          onClick={() => onSelect(suggestion)}
          className="flex items-center gap-1.5 hover:text-foreground/90 transition-colors min-w-0"
          title={`Send: ${suggestion}`}
        >
          <ArrowRight
            size={12}
            style={{ color: '#4a8fff', flexShrink: 0 }}
          />
          <span className="truncate">{suggestion}</span>
        </button>
        {onDismiss && (
          <button
            type="button"
            onClick={onDismiss}
            className="ml-1 p-0.5 rounded hover:bg-white/10 text-muted-foreground/70 hover:text-foreground"
            aria-label="Dismiss suggestion"
          >
            <X size={11} />
          </button>
        )}
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { AlertCircle, Check, CheckCircle2, ChevronDown, ChevronRight, CircleDot, Code2, Loader2, FileSearch } from 'lucide-react';
import { cn, fmtElapsed } from '@/lib/utils';
import { DisclosureRow } from '@/components/chat/DisclosureRow';
import { ToolIcon } from '@/components/ui/ToolIcon';
import { FileIcon } from '@/components/ui/FileIcon';
import { DiffView } from '@/components/chat/DiffView';
import { confirmWorkbenchMutation } from '@/api/workbench';
import { visibleProgress, type ProgressEntry } from '@/lib/tool-progress';
import { getToolLabel } from '@/lib/tool-labels';
import { formatToolContext, formatToolResult, formatToolError, type FormattedContext } from '@/lib/tool-context-format';

/**
 * Extract a filename hint from a tool's JSON context (best-effort).
 * Returns null if the context isn't JSON or no filename-shaped key is present.
 */
function extractFilename(context?: string): string | null {
  if (!context) return null;
  try {
    const parsed = JSON.parse(context);
    if (typeof parsed === 'string') return parsed;
    for (const key of ['filePath', 'file_path', 'path', 'filename', 'file', 'filepath', 'notebook_path', 'target_file']) {
      const v = parsed[key];
      if (typeof v === 'string' && v.length > 0) return v;
    }
  } catch {
    /* not JSON — ignore */
  }
  return null;
}

/**
 * Best-effort extraction of the actual command string for run_command tools.
 * The workbench stores tool input as a JSON-encoded `context` string, so
 * we look for an obvious `command` (or `cmd` / `shell_command`) field.
 */
function extractCommand(context?: string): string | null {
  if (!context) return null;
  try {
    const parsed = JSON.parse(context);
    if (typeof parsed === 'string') return parsed;
    if (parsed && typeof parsed === 'object') {
      for (const key of ['command', 'cmd', 'shell_command', 'shellCommand', 'script']) {
        const v = (parsed as Record<string, unknown>)[key];
        if (typeof v === 'string' && v.length > 0) return v;
      }
    }
  } catch {
    /* not JSON — ignore */
  }
  return null;
}

/**
 * Best-effort extraction of the agentId parameter from a tool's context.
 */
function extractAgentId(context?: string): string | null {
  if (!context) return null;
  try {
    const parsed = JSON.parse(context);
    if (parsed && typeof parsed === 'object') {
      for (const key of ['agentId', 'agent', 'subagentType']) {
        const v = (parsed as Record<string, unknown>)[key];
        if (typeof v === 'string' && v.length > 0) return v;
      }
    }
  } catch {
    /* not JSON — ignore */
  }
  return null;
}

/**
 * Format milliseconds to MM:SS format.
 */
function formatTimer(ms: number): string {
  const totalSeconds = Math.floor(Math.max(0, ms) / 1000);
  const minutes = Math.floor(totalSeconds / 60);
  const seconds = totalSeconds % 60;
  const pad = (num: number) => String(num).padStart(2, '0');
  return `${pad(minutes)}:${pad(seconds)}`;
}

function truncate(s: string, n: number): string {
  if (s.length <= n) return s;
  return `${s.slice(0, n - 1).trimEnd()}…`;
}

// Above this length the per-character shimmer animation becomes visually
// noisy and slow. Used to decide between the animated "thinking-text" path
// and the plain monospace fallback.
const LONG_LABEL_THRESHOLD = 40;
function isLongLabel(label: string): boolean {
  return label.length > LONG_LABEL_THRESHOLD;
}

/**
 * Best-effort extraction of diff inputs from a tool's args / result.
 * Returns a payload compatible with <DiffView> props.
 */
function extractDiffData(tool: { context?: string; result?: unknown; name?: string }): {
  diff?: string;
  oldContent?: string;
  newContent?: string;
} | null {
  const isEditLike = /^(write_file|edit_file|replace_file|apply_patch|create_file|str_replace|@write_file|@edit_file|@replace_file|@apply_patch|@create_file|@str_replace)/i.test(
    (tool.name || '').replace(/^@/, '')
  );
  if (!isEditLike) return null;

  // 1) Pre-formatted diff (most common — workbench already computes it)
  if (tool.context && typeof tool.context === 'string' && /^[+\-@]/.test(tool.context.trim())) {
    // The context itself looks like a diff
    return { diff: tool.context };
  }
  if (typeof (tool as { inlineDiff?: string }).inlineDiff === 'string') {
    return { diff: (tool as { inlineDiff?: string }).inlineDiff };
  }

  // 2) Inspect args and result for old/new pairs
  let args: Record<string, unknown> = {};
  if (tool.context) {
    try { args = JSON.parse(tool.context) as Record<string, unknown>; } catch { /* ignore */ }
  }
  const result = (tool as { result?: unknown }).result;

  // Result: { diff: '...' } or { patch: '...' } or the result itself is a string
  if (typeof result === 'string' && (result.includes('--- ') || result.includes('+++ ') || result.startsWith('@@'))) {
    return { diff: result };
  }
  if (result && typeof result === 'object') {
    const r = result as Record<string, unknown>;
    if (typeof r.diff === 'string') return { diff: r.diff };
    if (typeof r.patch === 'string') return { diff: r.patch };
    if (typeof r.unifiedDiff === 'string') return { diff: r.unifiedDiff };
    if (typeof r.old === 'string' && typeof r.new === 'string') {
      return { oldContent: r.old, newContent: r.new };
    }
    if (typeof r.oldContent === 'string' && typeof r.newContent === 'string') {
      return { oldContent: r.oldContent, newContent: r.newContent };
    }
  }

  // 3) Args: { old_string, new_string } / { find, replace } / { patch } / { content } (no old → all added)
  const pick = (...keys: string[]) => {
    for (const k of keys) {
      const v = args[k];
      if (typeof v === 'string' && v.length > 0) return v;
    }
    return undefined;
  };
  const oldString = pick('old_string', 'find', 'old', 'oldContent');
  const newString = pick('new_string', 'replace', 'new', 'newContent', 'content', 'patch');
  if (oldString !== undefined && newString !== undefined) {
    return { oldContent: oldString, newContent: newString };
  }
  if (newString !== undefined) {
    // write_file with no old → show as all-added
    return { oldContent: '', newContent: newString };
  }

  return null;
}

export interface ToolEntry {
  id: string;
  name: string;
  context?: string;
  preview?: string;
  summary?: string;
  error?: string;
  inlineDiff?: string;
  status: 'running' | 'done' | 'error';
  duration?: number;
  startedAt?: number;
  pendingApproval?: {
    message?: string;
    detail?: string;
    confirmationToken?: string;
  };
  /** For web_search: structured search hits to render as linked list */
  searchHits?: Array<{ title: string; url: string; snippet?: string }>;
}

/**
 * ToolCallItem — renders one tool call like the Thinking disclosure.
 *
 * Uses DisclosureRow + char-glow animation (thinking-text) instead of
 * a bordered card. The tool name animates while running, same as the
 * "Thinking" label in ThinkingDisclosure.
 */
export function ToolCallItem({
  tool,
  progress,
  agentIdOverride,
}: {
  tool: ToolEntry;
  /** Optional live "Reading… / Read" sub-list emitted by the workbench. */
  progress?: ReadonlyArray<ProgressEntry>;
  agentIdOverride?: string;
}) {
  const [userOverride, setUserOverride] = useState<boolean | null>(null);
  const open = userOverride ?? tool.status === 'error';

  const [mountedAt] = useState(() => Date.now());
  const [now, setNow] = useState(() => Date.now());
  useEffect(() => {
    if (tool.status !== 'running') return;
    const id = window.setInterval(() => setNow(() => Date.now()), 500);
    return () => window.clearInterval(id);
  }, [tool.status]);

  let startedAtMs: number | undefined = undefined;
  if (tool.startedAt) {
    if (typeof tool.startedAt === 'number') {
      startedAtMs = tool.startedAt;
    } else if (typeof tool.startedAt === 'string') {
      const parsedNum = Number(tool.startedAt);
      if (!isNaN(parsedNum)) {
        startedAtMs = parsedNum;
      } else {
        const parsedDate = new Date(tool.startedAt).getTime();
        if (!isNaN(parsedDate)) {
          startedAtMs = parsedDate;
        }
      }
    } else if ((tool.startedAt as any) instanceof Date) {
      startedAtMs = (tool.startedAt as Date).getTime();
    }
  }

  if (tool.status === 'running' && (!startedAtMs || isNaN(startedAtMs))) {
    startedAtMs = mountedAt;
  }

  const hasTimestamps = tool.duration !== undefined || (tool.status === 'running' && startedAtMs !== undefined);
  const elapsed = hasTimestamps
    ? tool.duration ?? (startedAtMs ? now - startedAtMs : undefined)
    : undefined;


  const hasBody = !!(
    tool.context || tool.preview || tool.summary || tool.error || tool.inlineDiff || tool.searchHits || tool.pendingApproval
  );
  const [approvalStatus, setApprovalStatus] = useState<'idle' | 'confirming' | 'confirmed'>('idle');

  const isRunning = tool.status === 'running';
  // Safety timeout: if a tool has been running for > 120 seconds without a
  // result event, treat it as stalled — show a warning so the user knows
  // something went wrong rather than seeing an infinite spinner.
  const toolStalled = isRunning && startedAtMs !== undefined && (now - startedAtMs) > 120_000;
  const effectiveStatus = toolStalled ? 'error' : tool.status;
  const isCommand = tool.name.startsWith('@run_command') || tool.name.startsWith('run_command');
  // Strip the @ prefix that the workbench sometimes prepends so the icon
  // mapper matches the canonical tool name (e.g. "read_file" not "@read_file").
  const toolNameForIcon = tool.name.replace(/^@/, '');
  // For run_command tools, surface the actual command string inline so the
  // user can see what's being executed without expanding the disclosure —
  // especially important when the model runs a batch of commands and the
  // user is scanning the list. Truncate long commands with a tooltip that
  // shows the full text.
  const commandText = isCommand ? extractCommand(tool.context) : null;
  const filename = !isCommand ? extractFilename(tool.context) : null;
  const agentId = agentIdOverride || extractAgentId(tool.context);

  const label = getToolLabel(tool.name, {
    agentId: agentId ?? undefined,
    filename: filename ?? undefined,
    command: commandText ?? undefined,
    status: tool.status
  });
  const labelTitle = isCommand && commandText && commandText.length > 120
    ? commandText
    : isLongLabel(label) ? label : undefined;
  const displayLabel = (elapsed !== undefined && elapsed >= 100) ? `${label} · ${formatTimer(elapsed)}` : label;

  // Always-visible friendly context line: prefer the humanized summary from
  // formatToolContext; fall back to a single-line truncation of the raw
  // JSON args when no formatter matches.
  const friendlyCtx = tool.context ? formatToolContext(tool.name, tool.context) : null;
  const inlineContextText =
    friendlyCtx?.summary ??
    (tool.context && tool.context.length > 80
      ? `${tool.context.slice(0, 77).trimEnd()}…`
      : tool.context ?? null);

  return (
    <div className="text-xs text-muted-foreground w-full py-0.5" data-slot="tool-block">
      <DisclosureRow
        onToggle={hasBody ? () => setUserOverride(!open) : undefined}
        open={open && hasBody}
      >
        <span className="flex min-w-0 items-center gap-2">
          {filename ? (
            <FileIcon name={filename} size={14} className="shrink-0" />
          ) : (
            <ToolIcon name={toolNameForIcon} kind={isCommand ? 'command' : 'tool'} size={14} className="shrink-0" />
          )}
          <span
            className={cn(
              'text-xs font-medium leading-5 min-w-0 flex-1',
              isRunning && !isLongLabel(label) && 'text-foreground/85'
            )}
            title={labelTitle}
          >
            {isLongLabel(label) ? (
              // Long labels (typically a multi-flag shell command) bypass the
              // per-character shimmer animation: animating 100+ chars with a
              // 100ms stagger is visually noisy. Render as a plain monospace
              // span with a `title` tooltip for the full text.
              <span className="font-mono text-[11.5px] text-foreground/85 wrap-anywhere break-words">
                {displayLabel}
              </span>
            ) : (
              <span className="thinking-text">
                <span className="thinking-label">
                  {Array.from(displayLabel.replace(/ /g, '\u00A0')).map((ch, i) => (
                    <span
                      key={i}
                      className={cn('thinking-char', i === 0 && 'thinking-cap')}
                      style={{ animationDelay: `${i * 100}ms` }}
                    >
                      {ch}
                    </span>
                  ))}
                </span>
                {isRunning && (
                  <span className="thinking-dots">
                    <span className="dot" style={{ animationDelay: '0ms' }}>.</span>
                    <span className="dot" style={{ animationDelay: '200ms' }}>.</span>
                    <span className="dot" style={{ animationDelay: '400ms' }}>.</span>
                  </span>
                )}
              </span>
            )}
          </span>
          <span className="flex items-center gap-1.5 shrink-0 ml-auto pl-2">
            {toolStalled ? (
              <span className="inline-flex items-center gap-1">
                <AlertCircle className="size-3 text-warning" />
                <span className="tool-row-meta text-warning">stalled</span>
              </span>
            ) : tool.status === 'done' ? (
              <span className="inline-flex items-center gap-1">
                <span className="inline-block size-1.5 rounded-full bg-success" />
                <span className="tool-row-meta text-success">done</span>
              </span>
            ) : tool.status === 'error' ? (
              <span className="inline-flex items-center gap-1">
                <AlertCircle className="size-3 text-danger" />
                <span className="tool-row-meta text-danger">failed</span>
              </span>
            ) : tool.status === 'running' && tool.pendingApproval ? (
              <span className="inline-flex items-center gap-1">
                <CircleDot className="size-3 text-warning animate-pulse" />
                <span className="tool-row-meta text-warning">awaiting</span>
              </span>
            ) : null}
          </span>
        </span>
      </DisclosureRow>

      {inlineContextText && (
        <div
          className="tool-row-meta mt-0.5 text-muted-foreground/85 truncate"
          title={tool.context ?? inlineContextText}
        >
          {inlineContextText}
        </div>
      )}

      {open && hasBody && (
        <div className="mt-0.5 w-full min-w-0 max-w-full overflow-hidden wrap-anywhere pb-1">
          {/* For read-type tools (context_read, memory_search, read_file etc.)
              the raw JSON input is noise — skip it so the user sees what was
              actually read (the result/summary) when they expand the card. */}
          {tool.context && !tool.name.match(/context_read|memory_search|read_file|search/) && (
            <FormattedSection toolName={tool.name} label="context" raw={tool.context} format={formatToolContext} />
          )}

          {(() => {
            const visible = progress ? visibleProgress(progress) : [];
            const total = progress?.length ?? 0;
            const overflow = Math.max(0, total - visible.length);
            if (visible.length === 0) return null;
            return (
              <div className="my-1.5 space-y-0.5" aria-label="Tool progress" data-tool-progress>
                <div className="flex items-center gap-1 text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">
                  <FileSearch size={10} />
                  <span>
                    {tool.status === 'running' ? 'Exploring' : 'Files'}
                  </span>
                </div>
                {visible.map((entry) => (
                  <div
                    key={entry.path}
                    className="flex items-center gap-1.5 text-[11px] truncate"
                    title={entry.path}
                  >
                    <span className="w-2.5 shrink-0 inline-flex justify-center">
                      {entry.status === 'reading' ? (
                        <Loader2 size={10} className="animate-spin text-info" />
                      ) : (
                        <Check size={10} className="text-muted-foreground/50" />
                      )}
                    </span>
                    <span
                      className={cn(
                        'truncate font-mono',
                        entry.status === 'reading' ? 'text-info italic' : 'text-muted-foreground/60 line-through'
                      )}
                    >
                      {entry.status === 'reading' ? 'Reading ' : 'Read '}
                      {entry.path}
                    </span>
                  </div>
                ))}
                {overflow > 0 && (
                  <div className="text-[10px] text-muted-foreground/50 italic pl-4">
                    + {overflow} more
                  </div>
                )}
              </div>
            );
          })()}

          {tool.preview && tool.status === 'running' && (
            <Section label="streaming">
              {tool.preview}
              <span className="inline-block w-1.5 h-3 align-middle bg-foreground/40 ml-0.5 animate-pulse" />
            </Section>
          )}

          {(() => {
            const diffData = extractDiffData(tool);
            return diffData ? (
              <Section label="diff">
                <DiffView
                  diff={diffData.diff}
                  oldContent={diffData.oldContent}
                  newContent={diffData.newContent}
                />
              </Section>
            ) : null;
          })()}

          {tool.searchHits && tool.searchHits.length > 0 && (
            <Section label="results">
              <ol className="m-0 grid list-none gap-3 p-0">
                {tool.searchHits.map((hit, i) => (
                  <li key={i} className="grid min-w-0 gap-1">
                    <div className="flex items-start gap-2">
                      {hit.url && (
                        <img
                          src={`https://www.google.com/s2/favicons?domain=${new URL(hit.url).hostname}&sz=16`}
                          alt=""
                          className="size-4 shrink-0 mt-0.5 rounded"
                          width={16}
                          height={16}
                          loading="lazy"
                        />
                      )}
                      <div className="min-w-0 flex-1">
                        {hit.url ? (
                          <a
                            href={hit.url}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="text-xs font-medium text-primary hover:underline truncate block"
                          >
                            {hit.title || new URL(hit.url).hostname}
                          </a>
                        ) : (
                          <span className="text-xs font-medium text-foreground/90">{hit.title}</span>
                        )}
                        {hit.url && (
                          <p className="text-[10px] text-muted-foreground/60 truncate mt-0.5">
                            {hit.url}
                          </p>
                        )}
                      </div>
                    </div>
                    {hit.snippet && (
                      <p className="text-[10px] text-muted-foreground line-clamp-3 m-0 pl-6">{hit.snippet}</p>
                    )}
                  </li>
                ))}
              </ol>
            </Section>
          )}

          {tool.summary && !tool.searchHits && (
            <FormattedResultSection toolName={tool.name} raw={tool.summary} />
          )}

          {tool.error && (
            <FormattedErrorSection toolName={tool.name} raw={tool.error} />
          )}

          {tool.pendingApproval && (
            <div className="mt-2 flex flex-col gap-2 rounded-md border border-primary/30 bg-primary/10 p-2">
              <div className="text-xs text-foreground/90">
                {tool.pendingApproval.message || 'This change needs approval before it can run.'}
              </div>
              {tool.pendingApproval.detail && (
                <div className="text-[11px] font-mono text-muted-foreground wrap-anywhere">
                  {tool.pendingApproval.detail}
                </div>
              )}
              <button
                type="button"
                disabled={approvalStatus !== 'idle'}
                className="h-7 rounded-md bg-primary px-3 text-xs font-medium text-primary-foreground disabled:opacity-60"
                onClick={() => {
                  const token = tool.pendingApproval?.confirmationToken;
                  if (!token) return;
                  setApprovalStatus('confirming');
                  confirmWorkbenchMutation(token, {
                    onText: ({ content }) => {
                      tool.summary = `${tool.summary || ''}\n${content}`.trim();
                    },
                    onToolUse: ({ id, name, input }) => {
                      tool.summary = `${tool.summary || ''}\nStarted ${name}: ${JSON.stringify(input || {})}`.trim();
                    },
                    onToolResult: ({ content }) => {
                      tool.summary = `${tool.summary || ''}\n${content}`.trim();
                    },
                    onError: ({ message }) => {
                      tool.error = message;
                    },
                    onDone: () => {
                      setApprovalStatus('confirmed');
                    },
                  });
                }}
              >
                {approvalStatus === 'confirming' ? 'Approving…' : 'Approve'}
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function Section({
  label,
  children,
  tone,
}: {
  label: string;
  children: React.ReactNode;
  tone?: 'error';
}) {
  return (
    <div className="flex gap-3 mt-1.5">
      <span
        className={`text-[10px] shrink-0 w-16 pt-0.5 ${
          tone === 'error' ? 'text-destructive' : 'text-muted-foreground/60'
        }`}
      >
        {label}
      </span>
      <div className="flex-1 min-w-0 text-muted-foreground">{children}</div>
    </div>
  );
}

/**
 * Render a section that defaults to a friendly summary line, with a small
 * "Show raw" chevron that reveals the underlying JSON in a `<pre>` block.
 * `format` is one of `formatToolContext` / `formatToolResult`; if it returns
 * null we fall back to rendering the raw text verbatim.
 *
 * The optional `kind` on the formatted result drives a small status icon
 * (`✅` for success, default for neutral) so success/error states are
 * visually obvious at a glance.
 */
function FormattedSection({
  toolName,
  label,
  raw,
  format,
  tone,
}: {
  toolName: string;
  label: string;
  raw: string;
  format: (toolName: string, raw: string) => FormattedContext | null;
  tone?: 'error';
}) {
  const formatted = format(toolName, raw);
  const summary = formatted?.summary ?? raw;
  const showRawToggle = !!formatted && formatted.summary !== formatted.raw;
  const [showRaw, setShowRaw] = useState(false);

  const isSuccess = formatted?.kind === 'success';
  const summaryClass = isSuccess
    ? 'text-success'
    : 'text-foreground/90';

  return (
    <div className="flex gap-3 mt-1.5">
      <span
        className={`text-[10px] shrink-0 w-16 pt-0.5 ${
          tone === 'error' ? 'text-destructive' : 'text-muted-foreground/60'
        }`}
      >
        {label}
      </span>
      <div className="flex-1 min-w-0 text-muted-foreground">
        <span className={cn('inline-flex items-baseline gap-1.5 whitespace-pre-wrap break-words', summaryClass)}>
          {isSuccess && <CheckCircle2 className="inline-block size-3 shrink-0 self-center text-success" />}
          <span>{summary}</span>
        </span>
        {showRawToggle && (
          <button
            type="button"
            onClick={() => setShowRaw(v => !v)}
            className="ml-2 inline-flex items-center gap-0.5 text-[10px] text-muted-foreground/60 hover:text-muted-foreground transition-colors align-baseline"
            title={showRaw ? 'Hide raw JSON' : 'Show raw JSON'}
          >
            <Code2 className="size-2.5" />
            {showRaw ? 'Hide raw' : 'Show raw'}
          </button>
        )}
        {showRaw && showRawToggle && (
          <pre className="mt-1 max-h-60 overflow-auto rounded-md border border-white/[0.06] bg-black/30 px-2 py-1.5 text-[11px] leading-relaxed font-mono whitespace-pre-wrap wrap-break-word text-muted-foreground/85">
            {tryPrettyJson(raw)}
          </pre>
        )}
      </div>
    </div>
  );
}

/**
 * Specialisation of FormattedSection for the `result` line — only reformats
 * when the result is a JSON object in a known shape, otherwise falls back to
 * the existing plain-text rendering.
 */
function FormattedResultSection({ toolName, raw }: { toolName: string; raw: string }) {
  const formatted = formatToolResult(toolName, raw);
  // If the formatter doesn't recognise the shape, render the raw text the
  // way the original code did — preserving whitespace and styling.
  if (!formatted) {
    return (
      <Section label="result">
        <span className="text-foreground/90 whitespace-pre-wrap break-words">{raw}</span>
      </Section>
    );
  }
  return <FormattedSection toolName={toolName} label="result" raw={raw} format={formatToolResult} />;
}

/**
 * Prominent error block — rendered when `tool.error` is present. Uses
 * `formatToolError` to parse structured error payloads (JSON with a
 * `message` field, etc.) into a single clean message + optional detail
 * line, then surfaces the raw text behind a "Show raw" toggle.
 */
function FormattedErrorSection({ toolName, raw }: { toolName: string; raw: string }) {
  const formatted = formatToolError(toolName, raw);
  const message = formatted?.message ?? raw.trim();
  const detail = formatted?.detail;
  const showRawToggle = !!formatted && formatted.raw !== message;
  const [showRaw, setShowRaw] = useState(false);

  return (
    <div className="mt-1.5 flex gap-3">
      <span className="text-[10px] shrink-0 w-16 pt-0.5 text-destructive">error</span>
      <div className="flex-1 min-w-0">
        <div className="rounded-md border border-destructive/30 bg-destructive/10 px-2.5 py-1.5 text-[11.5px] leading-relaxed">
          <div className="flex items-start gap-1.5">
            <AlertCircle className="size-3 shrink-0 mt-0.5 text-destructive" />
            <div className="min-w-0 flex-1">
              <div className="text-destructive whitespace-pre-wrap break-words font-medium">
                {message}
              </div>
              {detail && (
                <div className="mt-0.5 text-destructive/80 text-[11px] font-mono whitespace-pre-wrap break-words">
                  {detail}
                </div>
              )}
            </div>
          </div>
          {showRawToggle && (
            <div className="mt-1.5 flex items-center gap-2">
              <button
                type="button"
                onClick={() => setShowRaw(v => !v)}
                className="inline-flex items-center gap-0.5 text-[10px] text-destructive/70 hover:text-destructive transition-colors"
                title={showRaw ? 'Hide raw error' : 'Show raw error'}
              >
                <Code2 className="size-2.5" />
                {showRaw ? 'Hide raw' : 'Show raw'}
              </button>
              {showRaw && (
                <pre className="flex-1 max-h-40 overflow-auto rounded border border-destructive/20 bg-black/30 px-2 py-1 text-[10.5px] leading-relaxed font-mono whitespace-pre-wrap wrap-break-word text-muted-foreground/85">
                  {tryPrettyJson(raw)}
                </pre>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function tryPrettyJson(raw: string): string {
  try {
    const parsed = JSON.parse(raw);
    return JSON.stringify(parsed, null, 2);
  } catch {
    return raw;
  }
}

import { useEffect, useState } from 'react';
import { Bot, Send, X } from 'lucide-react';
