export function TodoSummary({ todos }: { todos?: WorkbenchTodo[] }) {
  const [expanded, setExpanded] = useState(false);
  if (!todos?.length) return null;

  const total = todos.length;
  const done = todos.filter(t => t.status === 'completed').length;
  const visible = expanded ? todos : todos.slice(0, 3);
  const overflow = total - visible.length;

  return (
    <div className="mx-auto max-w-3xl rounded-lg border border-border bg-card">
      <div className="flex items-center justify-between px-3 py-2">
        <span className="text-xs uppercase tracking-wider text-muted-foreground font-semibold">
          Todos
        </span>
        <span className="font-mono tabular-nums text-xs text-muted-foreground/80">
          {done}/{total}
        </span>
      </div>
      <div className="space-y-0.5 px-3 pb-3">
        {visible.map(todo => (
          <div key={todo.id} className="flex items-center gap-2 text-sm">
            <span className="w-3 inline-flex justify-center shrink-0 text-muted-foreground/80">
              {todo.status === 'completed' ? (
                <Check className="size-3 text-success" />
              ) : todo.status === 'in_progress' ? (
                <ArrowRight className="size-3 text-warning" />
              ) : (
                <Circle className="size-3 text-muted-foreground/40" />
              )}
            </span>
            <span className={cn(
              'flex-1',
              todo.status === 'completed' && 'text-muted-foreground line-through',
              todo.status === 'in_progress' && 'text-foreground',
              todo.status === 'pending' && 'text-muted-foreground/70'
            )}>
              {todo.content}
            </span>
          </div>
        ))}
        {overflow > 0 && (
          <button
            type="button"
            onClick={() => setExpanded(true)}
            className="text-xs text-muted-foreground/60 italic hover:text-foreground pl-5 pt-0.5"
          >
            + {overflow} waiting…
          </button>
        )}
        {expanded && total > 3 && (
          <button
            type="button"
            onClick={() => setExpanded(false)}
            className="text-xs text-muted-foreground/60 italic hover:text-foreground pl-5"
          >
            show less
          </button>
        )}
      </div>
    </div>
  );
}

/* ── DiffView.test.ts ─ unit tests for the diff/parser helpers ─────── */

import { describe, it, expect } from 'vitest';
import { diffLines, parseUnifiedDiff, type DiffLine } from '../DiffView';

describe('diffLines — same content', () => {
  it('returns all context lines for identical text', () => {
    const lines = diffLines('a\nb\nc', 'a\nb\nc');
    expect(lines.every(l => l.kind === 'context')).toBe(true);
    expect(lines).toHaveLength(3);
  });

  it('handles empty strings', () => {
    expect(diffLines('', '')).toEqual([]);
  });
});

describe('diffLines — pure addition (new file / append)', () => {
  it('marks all new lines as added when old is empty', () => {
    const lines = diffLines('', 'a\nb\nc');
    expect(lines).toHaveLength(3);
    expect(lines.every(l => l.kind === 'added')).toBe(true);
    expect(lines.map(l => l.text)).toEqual(['a', 'b', 'c']);
    expect(lines.map(l => l.newLine)).toEqual([1, 2, 3]);
  });
});

describe('diffLines — pure deletion (file removed)', () => {
  it('marks all old lines as removed when new is empty', () => {
    const lines = diffLines('a\nb\nc', '');
    expect(lines).toHaveLength(3);
    expect(lines.every(l => l.kind === 'removed')).toBe(true);
    expect(lines.map(l => l.text)).toEqual(['a', 'b', 'c']);
    expect(lines.map(l => l.oldLine)).toEqual([1, 2, 3]);
  });
});

describe('diffLines — middle edit (the common case)', () => {
  it('preserves common prefix and suffix, marks middle as removed+added', () => {
    const oldText = 'a\nb\nc\nd\ne';
    const newText = 'a\nb\nX\nY\nd\ne';
    const lines = diffLines(oldText, newText);

    const kinds = lines.map(l => l.kind);
    expect(kinds).toEqual(['context', 'context', 'removed', 'added', 'added', 'context', 'context']);
    expect(lines[0]).toMatchObject({ text: 'a', oldLine: 1, newLine: 1 });
    expect(lines[1]).toMatchObject({ text: 'b', oldLine: 2, newLine: 2 });
    expect(lines[2]).toMatchObject({ kind: 'removed', text: 'c', oldLine: 3 });
    expect(lines[3]).toMatchObject({ kind: 'added', text: 'X', newLine: 3 });
    expect(lines[4]).toMatchObject({ kind: 'added', text: 'Y', newLine: 4 });
    expect(lines[5]).toMatchObject({ kind: 'context', text: 'd' });
    expect(lines[6]).toMatchObject({ kind: 'context', text: 'e' });
  });

  it('handles a single-line edit in the middle of a long file', () => {
    const oldText = Array.from({ length: 20 }, (_, i) => `line${i + 1}`).join('\n');
    const newText = oldText.replace('line10', 'line10-CHANGED');
    const lines = diffLines(oldText, newText);

    const removed = lines.filter(l => l.kind === 'removed');
    const added = lines.filter(l => l.kind === 'added');
    expect(removed).toHaveLength(1);
    expect(added).toHaveLength(1);
    expect(removed[0].text).toBe('line10');
    expect(added[0].text).toBe('line10-CHANGED');
    expect(removed[0].oldLine).toBe(10);
    expect(added[0].newLine).toBe(10);
  });

  it('handles a single-line insert', () => {
    const lines = diffLines('a\nb\nc', 'a\nb\nINSERTED\nc');
    expect(lines.map(l => l.kind)).toEqual(['context', 'context', 'added', 'context']);
  });

  it('handles a single-line delete', () => {
    const lines = diffLines('a\nb\nc\nd', 'a\nb\nd');
    expect(lines.map(l => l.kind)).toEqual(['context', 'context', 'removed', 'context']);
  });
});

describe('diffLines — complete rewrite', () => {
  it('marks every line when prefix and suffix are both zero', () => {
    const lines = diffLines('x\ny\nz', '1\n2\n3');
    // No common prefix or suffix → all lines are paired removed/added
    expect(lines.every(l => l.kind === 'removed' || l.kind === 'added')).toBe(true);
    expect(lines.filter(l => l.kind === 'removed').map(l => l.text)).toEqual(['x', 'y', 'z']);
    expect(lines.filter(l => l.kind === 'added').map(l => l.text)).toEqual(['1', '2', '3']);
  });
});

describe('parseUnifiedDiff — basic', () => {
  it('parses a minimal unified diff', () => {
    const diff = [
      '--- a/foo.ts',
      '+++ b/foo.ts',
      '@@ -1,3 +1,3 @@',
      ' a',
      '-b',
      '+B',
      ' c',
    ].join('\n');
    const lines = parseUnifiedDiff(diff);
    expect(lines).toHaveLength(4);
    expect(lines[0]).toMatchObject({ kind: 'context', text: 'a', oldLine: 1, newLine: 1 });
    expect(lines[1]).toMatchObject({ kind: 'removed', text: 'b', oldLine: 2 });
    expect(lines[2]).toMatchObject({ kind: 'added', text: 'B', newLine: 2 });
    expect(lines[3]).toMatchObject({ kind: 'context', text: 'c', oldLine: 3, newLine: 3 });
  });

  it('handles multiple hunks', () => {
    const diff = [
      '--- a/foo.ts',
      '+++ b/foo.ts',
      '@@ -1,2 +1,2 @@',
      ' a',
      '-b',
      '+B',
      '@@ -10,2 +10,2 @@',
      ' x',
      '-y',
      '+Y',
    ].join('\n');
    const lines = parseUnifiedDiff(diff);
    const removed = lines.filter(l => l.kind === 'removed').map(l => l.text);
    const added = lines.filter(l => l.kind === 'added').map(l => l.text);
    expect(removed).toEqual(['b', 'y']);
    expect(added).toEqual(['B', 'Y']);
  });

  it('handles hunk headers with section labels (the optional trailing text)', () => {
    const diff = [
      '--- a/foo.ts',
      '+++ b/foo.ts',
      '@@ -1,3 +1,3 @@ fn main()',
      ' a',
      '-b',
      '+B',
    ].join('\n');
    const lines = parseUnifiedDiff(diff);
    expect(lines).toHaveLength(3);
    expect(lines[1].kind).toBe('removed');
    expect(lines[2].kind).toBe('added');
  });

  it('ignores diff content before the first hunk header', () => {
    const diff = [
      'diff --git a/foo.ts b/foo.ts',
      'index 1234..5678 100644',
      '--- a/foo.ts',
      '+++ b/foo.ts',
      '@@ -1,1 +1,1 @@',
      '-old',
      '+new',
    ].join('\n');
    const lines = parseUnifiedDiff(diff);
    expect(lines).toHaveLength(2);
    expect(lines[0].kind).toBe('removed');
    expect(lines[1].kind).toBe('added');
  });

  it('returns empty for non-diff text', () => {
    expect(parseUnifiedDiff('hello world')).toEqual([]);
  });

  it('treats a line with no prefix as context', () => {
    const diff = [
      '--- a/f',
      '+++ b/f',
      '@@ -1,2 +1,2 @@',
      ' context',
      '-removed',
      '+added',
    ].join('\n');
    const lines = parseUnifiedDiff(diff);
    expect(lines[0]).toMatchObject({ kind: 'context', text: 'context' });
  });
});

/* ── ApprovalBanner ───────────────────────────────────────────────────── */
/* Session-level "awaiting approval" banner driven by /api/workbench/session/:id/status. */
/* Polls the endpoint every 2s; flips to a sticky banner when the server */
/* reports a pending critical mutation. Approve / Deny buttons POST to */
/* /api/workbench/confirm-mutation. */

import { useEffect, useMemo, useState } from 'react';
import { ShieldCheck, ShieldAlert, X } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';

type SessionStatus = {
    sessionId: string;
    status: 'idle' | 'running' | 'awaiting_approval' | 'completed' | 'failed' | 'cancelled';
    pendingTool: string | null;
    pendingToken: string | null;
    pendingArgs: Record<string, unknown> | null;
    pendingCreatedAt: number | null;
    updatedAt: string | null;
    guardMode: 'plan' | 'ask' | 'full';
    approved: boolean;
};

type Props = {
    sessionId: string | null;
    pollIntervalMs?: number;
    onStatusChange?: (status: SessionStatus | null) => void;
};

async function fetchStatus(sessionId: string): Promise<SessionStatus | null> {
    try {
        const r = await fetch(`/api/workbench/session/${encodeURIComponent(sessionId)}/status`, { credentials: 'same-origin' });
        if (!r.ok) return null;
        return r.json() as Promise<SessionStatus>;
    } catch (_) {
        return null;
    }
}

async function postDecision(sessionId: string, token: string, reject: boolean) {
    const r = await fetch('/api/workbench/confirm-mutation', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'same-origin',
        body: JSON.stringify({ sessionId, token, reject })
    });
    if (!r.ok) {
        const text = await r.text().catch(() => '');
        throw new Error(text || `Approval API returned ${r.status}`);
    }
    return r.json();
}

function summarizeTool(toolName: string | null, args: Record<string, unknown> | null): string {
    if (!toolName) return 'The model is waiting for your approval.';
    if (!args) return `Tool: ${toolName}`;
    const keys = Object.keys(args).filter((k) => k !== 'confirmed' && k !== 'reReadFirst');
    const first = keys[0];
    if (first) {
        const value = String(args[first] ?? '').slice(0, 80);
        return `Tool: ${toolName} — ${first}: ${value}`;
    }
    return `Tool: ${toolName}`;
}

export function ApprovalBanner({ sessionId, pollIntervalMs = 2000, onStatusChange }: Props) {
    const [status, setStatus] = useState<SessionStatus | null>(null);
    const [deciding, setDeciding] = useState<'approve' | 'reject' | null>(null);

    useEffect(() => {
        if (!sessionId) {
            setStatus(null);
            onStatusChange?.(null);
            return;
        }
        let cancelled = false;
        const tick = async () => {
            const next = await fetchStatus(sessionId);
            if (cancelled) return;
            setStatus(next);
            onStatusChange?.(next);
        };
        tick();
        const t = setInterval(tick, pollIntervalMs);
        return () => {
            cancelled = true;
            clearInterval(t);
        };
    }, [sessionId, pollIntervalMs, onStatusChange]);

    const isAwaiting = status?.status === 'awaiting_approval' && !!status.pendingToken;
    const summary = useMemo(
        () => summarizeTool(status?.pendingTool ?? null, status?.pendingArgs ?? null),
        [status?.pendingTool, status?.pendingArgs]
    );

    const onApprove = async () => {
        if (!status?.pendingToken) return;
        setDeciding('approve');
        try {
            await postDecision(status.sessionId, status.pendingToken, false);
            toast.success('Approved — resuming the model');
        } catch (e) {
            toast.error(`Approval failed: ${(e as Error).message}`);
        } finally {
            setDeciding(null);
        }
    };

    const onReject = async () => {
        if (!status?.pendingToken) return;
        setDeciding('reject');
        try {
            await postDecision(status.sessionId, status.pendingToken, true);
            toast.message('Denied — the model will be told');
        } catch (e) {
            toast.error(`Denial failed: ${(e as Error).message}`);
        } finally {
            setDeciding(null);
        }
    };

    return (
        <AnimatePresence>
            {isAwaiting && (
                <motion.div
                    key="approval-banner"
                    initial={{ opacity: 0, y: -8 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -8 }}
                    transition={{ duration: 0.18 }}
                    className={cn(
                        'mx-auto my-2 flex w-full max-w-3xl items-start gap-3 rounded-lg border px-4 py-3',
                        'border-warning/30 bg-warning/10 text-foreground'
                    )}
                    data-testid="approval-banner"
                    role="status"
                    aria-live="polite"
                >
                    <ShieldAlert className="mt-0.5 h-5 w-5 flex-none text-warning" />
                    <div className="flex-1 text-sm">
                        <div className="font-medium">Awaiting your approval</div>
                        <div className="text-warning/90">{summary}</div>
                        {status?.pendingArgs && (
                            <details className="mt-1 text-xs text-warning/80">
                                <summary className="cursor-pointer">View arguments</summary>
                                <pre className="mt-1 max-h-32 overflow-auto rounded bg-black/30 p-2 text-[11px]">
                                    {JSON.stringify(status.pendingArgs, null, 2)}
                                </pre>
                            </details>
                        )}
                    </div>
                    <div className="flex gap-2">
                        <Button
                            size="sm"
                            variant="outline"
                            onClick={onReject}
                            disabled={!!deciding}
                            className="border-warning/40 text-warning hover:bg-warning/20"
                        >
                            <X className="mr-1 h-3.5 w-3.5" />
                            Deny
                        </Button>
                        <Button
                            size="sm"
                            onClick={onApprove}
                            disabled={!!deciding}
                            className="bg-warning text-black hover:bg-warning/90"
                        >
                            <ShieldCheck className="mr-1 h-3.5 w-3.5" />
                            {deciding === 'approve' ? 'Approving…' : 'Approve'}
                        </Button>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    );
}

