export function ProxyStatusOverlay() {
  const state = useStore($gateway);
  const qc = useQueryClient();
  if (state.status === 'open') return null;

  if (state.status === 'connecting') {
    return (
      <Backdrop>
        <div className="w-[min(90vw,420px)] rounded-lg border border-border bg-card p-6 text-center">
          <Loader2 className="size-8 mx-auto mb-3 text-muted-foreground animate-spin" />
          <h2 className="text-sm font-semibold">Connecting to proxy…</h2>
          <p className="mt-1 text-xs text-muted-foreground">Waiting for <code className="font-mono">/health</code></p>
        </div>
      </Backdrop>
    );
  }

  const message = state.status === 'error' ? state.message : state.reason ?? 'Connection refused';
  const Icon = state.status === 'error' ? AlertTriangle : WifiOff;
  return (
    <Backdrop>
      <div className="w-[min(90vw,480px)] rounded-lg border border-border bg-card p-6 text-center shadow-2xl">
        <Icon className="size-10 mx-auto mb-3 text-muted-foreground" />
        <h2 className="text-base font-semibold">Proxy is offline</h2>
        <p className="mt-1 text-sm text-muted-foreground max-w-md mx-auto">{message}</p>
        <div className="mt-4 flex justify-center gap-2">
          <Button variant="outline" onClick={() => window.open('http://localhost:8085/', '_blank')}>
            Open in browser
          </Button>
          <Button onClick={() => qc.invalidateQueries()}>Retry</Button>
        </div>
      </div>
    </Backdrop>
  );
}

/* v4.4.3 — BrainIndicator: titlebar Brain icon + pulse dot + draggable +
 * resizable floating popup. ESC and click-outside no longer close — only the
 * × button (per user request). Position and size persist across reloads.
 *
 * IMPORTANT (v4.4.3 bug fix): the popup is rendered via createPortal to
 * document.body. The chat shell wraps content in framer-motion's
 * `<motion.div>` which applies `transform`, and that creates a
 * containing block for `position: fixed` — making the popup get trapped
 * inside the titlebar and render at the wrong offsets (off-screen on the
 * chat route but visible on routes that don't have motion.div ancestors).
 * Portaling to document.body lets fixed be viewport-relative. */
import { useCallback, useEffect, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { Brain, X, Activity, Heart, Sparkles } from 'lucide-react';
import { useQuery } from '@tanstack/react-query';
import { cn } from '@/lib/utils';
import {
  getBrainEvents,
  openBrainEventStream,
  type BrainEvent,
} from '@/api/api-client';
import { LearningTab } from '@/sections/brain/LearningTab';
import { SystemHealthTab } from '@/sections/brain/SystemHealthTab';
import { BrainActivityTab } from '@/sections/brain/BrainActivityTab';

interface BrainIndicatorProps {
  /** Optional initial unseen-event count (for tests + future bootstrap). */
  initialUnseen?: number;
}

type TabKey = 'activity' | 'learning' | 'health';

const STORAGE_KEY = 'august-brain-popup-state';
const DEFAULT_WIDTH = 520;
const DEFAULT_HEIGHT = 520;
const MIN_WIDTH = 380;
const MIN_HEIGHT = 320;
const MARGIN = 16; // padding from viewport edges

interface PopupState {
  width: number;
  height: number;
  x: number; // left in viewport coords
  y: number; // top in viewport coords
}

function loadState(): PopupState {
  if (typeof window === 'undefined') return defaultState();
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) {
      const parsed = JSON.parse(raw) as Partial<PopupState>;
      if (
        typeof parsed.width === 'number' &&
        typeof parsed.height === 'number' &&
        typeof parsed.x === 'number' &&
        typeof parsed.y === 'number'
      ) {
        return clampState(parsed as PopupState);
      }
    }
  } catch {
    /* fall through */
  }
  return defaultState();
}

function defaultState(): PopupState {
  // Default: anchored top-right, just under the title bar (h-12 + 4px)
  return {
    width: DEFAULT_WIDTH,
    height: DEFAULT_HEIGHT,
    x: typeof window !== 'undefined' ? Math.max(MARGIN, window.innerWidth - DEFAULT_WIDTH - MARGIN) : 200,
    y: 64, // title bar (~48px) + 16px gap
  };
}

function clampState(s: PopupState): PopupState {
  const w = Math.max(MIN_WIDTH, Math.min(s.width, (typeof window !== 'undefined' ? window.innerWidth : 1200) - MARGIN * 2));
  const h = Math.max(MIN_HEIGHT, Math.min(s.height, (typeof window !== 'undefined' ? window.innerHeight : 800) - MARGIN * 2));
  const x = Math.max(MARGIN, Math.min(s.x, (typeof window !== 'undefined' ? window.innerWidth : 1200) - w - MARGIN));
  const y = Math.max(MARGIN, Math.min(s.y, (typeof window !== 'undefined' ? window.innerHeight : 800) - h - MARGIN));
  return { width: w, height: h, x, y };
}

export function BrainIndicator({ initialUnseen = 0 }: BrainIndicatorProps) {
  const [open, setOpen] = useState(false);
  const [tab, setTab] = useState<TabKey>('activity');
  const [unseen, setUnseen] = useState(initialUnseen);
  const [geom, setGeom] = useState<PopupState>(() => loadState());
  const geomRef = useRef<PopupState>(geom);
  geomRef.current = geom;

  // Pre-fetch recent events so the popup has content instantly
  useQuery({
    queryKey: ['brain-events'],
    queryFn: () => getBrainEvents(200),
    enabled: open,
  });

  // Always-on SSE so we can bump the unseen counter even when popup is closed
  useEffect(() => {
    const es = openBrainEventStream();
    es.onmessage = (ev: MessageEvent) => {
      try {
        const event: BrainEvent = JSON.parse(ev.data);
        setUnseen((n) => n + 1);
      } catch {
        /* ignore malformed frames */
      }
    };
    return () => es.close();
  }, []);

  // Persist geometry when popup closes
  const persistGeom = useCallback(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(geomRef.current));
    } catch {
      /* swallow quota errors */
    }
  }, []);

  // ---------- Drag (move) — starts from anywhere on the popup except interactive children ----------
  const dragState = useRef<{
    startX: number; startY: number;
    originX: number; originY: number;
  } | null>(null);

  const handleDragPointerDown = (e: React.PointerEvent<HTMLElement>) => {
    console.log('[DRAG] pointerdown', e.clientX, e.clientY, 'button', e.button);
    const button = e.button ?? 0;
    if (button !== 0) return;
    const target = e.target as HTMLElement;
    const blocked = target.closest('button, [role="tab"], input, textarea, select, [data-no-drag], [contenteditable="true"]');
    if (blocked) {
      console.log('[DRAG] blocked by', blocked);
      return;
    }
    const targetEl = e.currentTarget;
    try { targetEl.setPointerCapture?.(e.pointerId); } catch { /* ignore */ }
    const rect = targetEl.getBoundingClientRect();
    const offsetX = e.clientX - rect.left;
    const offsetY = e.clientY - rect.top;
    dragState.current = {
      startX: e.clientX,
      startY: e.clientY,
      originX: geomRef.current.x - offsetX,
      originY: geomRef.current.y - offsetY,
    };
    console.log('[DRAG] state set, attaching listeners', dragState.current);
    // Attach move/up handlers inline (same pattern as resize)
    const onMove = (ev: PointerEvent) => {
      console.log('[DRAG] move', ev.clientX, ev.clientY);
      handleDragPointerMove(ev);
    };
    const onUp = () => {
      console.log('[DRAG] up');
      handleDragPointerUp();
      document.removeEventListener('pointermove', onMove);
      document.removeEventListener('pointerup', onUp);
    };
    document.addEventListener('pointermove', onMove);
    document.addEventListener('pointerup', onUp);
  };

  const handleDragPointerMove = (e: PointerEvent) => {
    const d = dragState.current;
    if (!d) return;
    setGeom((prev) => clampState({
      ...prev,
      x: d.originX + e.clientX,
      y: d.originY + e.clientY,
    }));
  };

  const handleDragPointerUp = () => {
    if (!dragState.current) return;
    dragState.current = null;
    persistGeom();
  };

  // ---------- Resize — image-editor style: 8 handles (4 corners + 4 edges) ----------
  // Each corner resizes both axes; each edge resizes one axis with the
  // opposite edge anchored (e.g. dragging E only changes width; W changes
  // both x and width).
  type ResizeEdge = 'n' | 's' | 'e' | 'w' | 'ne' | 'nw' | 'se' | 'sw';
  const resizeState = useRef<{
    edge: ResizeEdge;
    startX: number; startY: number;
    originX: number; originY: number;
    originW: number; originH: number;
  } | null>(null);

  const handleResizePointerDown = (edge: ResizeEdge) => (e: React.PointerEvent<HTMLDivElement>) => {
    console.log('[RESIZE] pointerdown edge', edge, e.clientX, e.clientY);
    const button = e.button ?? 0;
    if (button !== 0) return;
    e.stopPropagation();
    try { e.currentTarget.setPointerCapture?.(e.pointerId); } catch { /* ignore */ }
    const g = geomRef.current;
    resizeState.current = {
      edge,
      startX: e.clientX,
      startY: e.clientY,
      originX: g.x,
      originY: g.y,
      originW: g.width,
      originH: g.height,
    };
    console.log('[RESIZE] state set, attaching listeners', resizeState.current);
    const onMove = (ev: PointerEvent) => {
      console.log('[RESIZE] move edge', edge, ev.clientX, ev.clientY);
      handleResizePointerMove(ev);
    };
    const onUp = () => {
      console.log('[RESIZE] up edge', edge);
      handleResizePointerUp();
      document.removeEventListener('pointermove', onMove);
      document.removeEventListener('pointerup', onUp);
    };
    document.addEventListener('pointermove', onMove);
    document.addEventListener('pointerup', onUp);
  };

  const handleResizePointerMove = (e: PointerEvent) => {
    const r = resizeState.current;
    if (!r) return;
    const dx = e.clientX - r.startX;
    const dy = e.clientY - r.startY;
    setGeom((prev) => {
      let { x: nx, y: ny, width: nw, height: nh } = prev;
      switch (r.edge) {
        case 'e':
          nw = Math.max(MIN_WIDTH,  nw + dx); break;
        case 'w':  // west edge — drag any grows width (anchor: east); x follows drag
          nx = nx + dx;
          nw = Math.max(MIN_WIDTH, nw + Math.abs(dx));
          break;
        case 's':  // south edge — drag down grows height (anchor: north)
          nh = Math.max(MIN_HEIGHT, nh + dy); break;
        case 'n':  // north edge — drag any grows height (anchor: south); y follows drag
          ny = ny + dy;
          nh = Math.max(MIN_HEIGHT, nh + Math.abs(dy));
          break;
        case 'ne': // top-right corner — drag down-right grows both (anchor: SW)
          nw = Math.max(MIN_WIDTH,  nw + dx);
          ny = ny + dy;
          nh = Math.max(MIN_HEIGHT, nh + dy);
          break;
        case 'nw': // top-left corner — drag any grows both (anchor: SE); x, y follow
          nx = nx + dx;
          nw = Math.max(MIN_WIDTH, nw + Math.abs(dx));
          ny = ny + dy;
          nh = Math.max(MIN_HEIGHT, nh + Math.abs(dy));
          break;
        case 'se': // bottom-right corner — drag any grows both (anchor: NW)
          nw = Math.max(MIN_WIDTH,  nw + dx);
          nh = Math.max(MIN_HEIGHT, nh + dy);
          break;
        case 'sw': // bottom-left corner — drag any grows both (anchor: NE); x follows drag
          nx = nx + dx;
          nw = Math.max(MIN_WIDTH, nw + Math.abs(dx));
          nh = Math.max(MIN_HEIGHT, nh + dy);
          break;
      }
      return clampState({ x: nx, y: ny, width: nw, height: nh });
    });
  };

  const handleResizePointerUp = () => {
    if (!resizeState.current) return;
    resizeState.current = null;
    persistGeom();
  };

  // Attach window-level move/up listeners while drag or resize is active
  // Persist beforeunload (best-effort)
  useEffect(() => {
    const handler = () => persistGeom();
    window.addEventListener('beforeunload', handler);
    return () => window.removeEventListener('beforeunload', handler);
  }, [persistGeom]);

  // Clamp on viewport resize
  useEffect(() => {
    const onResize = () => setGeom((prev) => clampState(prev));
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
  }, []);

  const handleOpen = () => {
    setOpen((v) => !v);
    if (!open) setUnseen(0); // opening the popup resets unseen
  };

  const handleClose = () => {
    persistGeom();
    setOpen(false);
  };

  return (
    <>
      <button
        type="button"
        onClick={handleOpen}
        aria-label="Toggle Brain activity"
        aria-expanded={open}
        data-testid="titlebar-brain-button"
        data-brain-toggle
        className={cn(
          'relative p-1 hover:bg-accent rounded text-muted-foreground hover:text-foreground transition',
          open && 'bg-accent text-foreground',
        )}
        title="Brain activity"
      >
        <Brain className="size-4" />
        {unseen > 0 && (
          <span
            data-testid="brain-pulse-dot"
            className="absolute top-0.5 right-0.5 size-2 rounded-full bg-primary ring-2 ring-background animate-pulse"
            aria-label={`${unseen} unseen brain event(s)`}
          />
        )}
      </button>

      {open && createPortal(<PopupContents
        geom={geom}
        tab={tab}
        setTab={setTab}
        handleClose={handleClose}
        handleDragPointerDown={handleDragPointerDown}
        handleResizePointerDown={handleResizePointerDown}
      />, document.body)}
    </>
  );
}

/* ── PopupContents — rendered via createPortal(document.body) so
 * position: fixed escapes any transformed ancestor (e.g. framer-motion
 * <motion.div> in ChatLayout). */
function PopupContents({
  geom,
  tab,
  setTab,
  handleClose,
  handleDragPointerDown,
  handleResizePointerDown,
}: {
  geom: PopupState;
  tab: TabKey;
  setTab: (k: TabKey) => void;
  handleClose: () => void;
  handleDragPointerDown: (e: React.PointerEvent<HTMLElement>) => void;
  handleResizePointerDown: (edge: 'n' | 's' | 'e' | 'w' | 'ne' | 'nw' | 'se' | 'sw') =>
    (e: React.PointerEvent<HTMLDivElement>) => void;
}) {
  const handleStyle = 'absolute z-10 group hover:bg-primary/20 focus-visible:bg-primary/25 transition';
  const handleFillStyle = 'absolute inset-0';
  const cornerHandles = (
    <>
      {/* NW */}
      <div
        data-testid="brain-resize-nw"
        data-brain-resize-edge="nw"
        data-no-drag
        onPointerDown={handleResizePointerDown('nw')}
        className={cn(handleStyle, 'top-0 left-0 size-3 cursor-nw-resize')}
        aria-label="Resize north-west"
      >
        <div className={handleFillStyle} />
      </div>
      {/* NE */}
      <div
        data-testid="brain-resize-ne"
        data-brain-resize-edge="ne"
        data-no-drag
        onPointerDown={handleResizePointerDown('ne')}
        className={cn(handleStyle, 'top-0 right-0 size-3 cursor-ne-resize')}
        aria-label="Resize north-east"
      >
        <div className={handleFillStyle} />
      </div>
      {/* SW */}
      <div
        data-testid="brain-resize-sw"
        data-brain-resize-edge="sw"
        data-no-drag
        onPointerDown={handleResizePointerDown('sw')}
        className={cn(handleStyle, 'bottom-0 left-0 size-3 cursor-sw-resize')}
        aria-label="Resize south-west"
      >
        <div className={handleFillStyle} />
      </div>
      {/* SE */}
      <div
        data-testid="brain-resize-se"
        data-brain-resize-edge="se"
        data-no-drag
        onPointerDown={handleResizePointerDown('se')}
        className={cn(handleStyle, 'bottom-0 right-0 size-3 cursor-se-resize')}
        aria-label="Resize south-east"
      >
        <div className={handleFillStyle} />
      </div>
    </>
  );

  const edgeHandles = (
    <>
      {/* N */}
      <div
        data-testid="brain-resize-n"
        data-brain-resize-edge="n"
        data-no-drag
        onPointerDown={handleResizePointerDown('n')}
        className={cn(handleStyle, 'top-0 left-3 right-3 h-1.5 cursor-n-resize')}
        aria-label="Resize north"
      />
      {/* S */}
      <div
        data-testid="brain-resize-s"
        data-brain-resize-edge="s"
        data-no-drag
        onPointerDown={handleResizePointerDown('s')}
        className={cn(handleStyle, 'bottom-0 left-3 right-3 h-1.5 cursor-s-resize')}
        aria-label="Resize south"
      />
      {/* E */}
      <div
        data-testid="brain-resize-e"
        data-brain-resize-edge="e"
        data-no-drag
        onPointerDown={handleResizePointerDown('e')}
        className={cn(handleStyle, 'top-3 bottom-3 right-0 w-1.5 cursor-e-resize')}
        aria-label="Resize east"
      />
      {/* W */}
      <div
        data-testid="brain-resize-w"
        data-brain-resize-edge="w"
        data-no-drag
        onPointerDown={handleResizePointerDown('w')}
        className={cn(handleStyle, 'top-3 bottom-3 left-0 w-1.5 cursor-w-resize')}
        aria-label="Resize west"
      />
    </>
  );

  return (
    <div
      data-testid="brain-popup"
      data-brain-popup-root
      role="dialog"
      aria-label="Brain activity"
      onPointerDown={handleDragPointerDown}
      className="fixed bg-popover border border-border rounded-xl shadow-2xl flex flex-col overflow-hidden cursor-grab touch-none select-none"
      style={{ left: geom.x, top: geom.y, width: geom.width, height: geom.height }}
    >
      {/* Header (still has the brain-drag-handle testid for backwards compat) */}
      <div
        data-testid="brain-drag-handle"
        className="flex items-center justify-between px-3 py-2 border-b border-border shrink-0"
      >
        <div className="flex items-center gap-2 pointer-events-none">
          <Brain className="size-4 text-primary" />
          <span className="text-sm font-semibold">Brain</span>
          <span className="text-[10px] text-muted-foreground/70 uppercase tracking-wider">
            realtime flow
          </span>
        </div>
        <button
          type="button"
          onClick={handleClose}
          aria-label="Close"
          className="p-1 rounded hover:bg-muted text-muted-foreground hover:text-foreground pointer-events-auto"
        >
          <X className="size-4" />
        </button>
      </div>

      {/* Tabs (data-no-drag is read by the closest() check inside handleDragPointerDown) */}
      <div
        data-no-drag
        className="flex items-center gap-1 px-2 pt-1.5 border-b border-border shrink-0"
      >
        {(
          [
            { key: 'activity' as const, label: 'Activity', icon: Activity },
            { key: 'learning' as const, label: 'Learning', icon: Sparkles },
            { key: 'health'   as const, label: 'Health',   icon: Heart },
          ]
        ).map(({ key, label, icon: Icon }) => (
          <button
            key={key}
            type="button"
            onClick={() => setTab(key)}
            className={cn(
              'flex items-center gap-1 px-2.5 py-1 text-[11px] rounded-t-md border-b-2 transition',
              tab === key
                ? 'border-primary text-foreground bg-popover'
                : 'border-transparent text-muted-foreground hover:text-foreground hover:bg-muted/50',
            )}
            data-testid={`brain-popup-tab-${key}`}
          >
            <Icon className="size-3" />
            {label}
          </button>
        ))}
      </div>

      {/* Body */}
      <div className="flex-1 overflow-y-auto p-2">
        {tab === 'activity' && <BrainActivityTab />}
        {tab === 'learning' && <LearningTab />}
        {tab === 'health' && <SystemHealthTab />}
      </div>

      {/* Resize handles (image-editor style) */}
      {cornerHandles}
      {edgeHandles}

      {/* Backwards-compatible single resize handle (kept for v4.4.2 tests).
          Re-exported to point at the SE corner so old assertions still match. */}
      <div
        data-testid="brain-resize-handle"
        data-no-drag
        onPointerDown={handleResizePointerDown('se')}
        className="absolute bottom-0 right-0 size-3 cursor-se-resize z-10"
        aria-label="Resize brain popup"
        aria-valuenow={geom.width}
        aria-valuemin={MIN_WIDTH}
        aria-valuemax={1200}
        style={{ pointerEvents: 'auto' }}
      />
    </div>
  );
}

/* ── Chat-first layout ────────────────────────────────────────────── */
/*                                                                          */
/* The right-side Workbench sidebar is rendered as a layout sidebar with    */
/* Preview, Diff, Terminal, Tasks, and Plan sections.                       */

import { useState, useEffect, useRef } from "react";
import { Outlet, useLocation, useNavigate, useParams } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { useStore } from "@nanostores/react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { $sessions, createSession, type Session } from "@/store/sessions";
import { $currentWorkspaceId, $workspaces } from "@/store/workspaces";
import { ChatTitlebar } from "./ChatTitlebar";
import { SessionSidebar } from "./SessionSidebar";
import { RightDrawer } from "./RightDrawer";
import { addRightDrawerSection, closeRightDrawer, setActiveRightDrawerSection, useRightDrawer } from "./RightDrawerState";
import { approveWorkbenchPlan, getWorkbenchSession, rejectWorkbenchPlan, setWorkbenchGuardMode, streamWorkbenchRevision } from "@/api/workbench";
import { toast } from "sonner";
import type { WorkbenchSession } from "@/types/workbench";
import type { RightDrawerSectionId } from "./RightDrawerState";
import { dispatchFocusComposer, dispatchInsertComposerText, onUiAction } from "@/api/ui-events";

const SESSIONS_COLLAPSED_KEY = "august-sessions-collapsed";
const WORKBENCH_SIDEBAR_OPEN_KEY = "august-workbench-sidebar-open";

export function ChatLayout() {
  const navigate = useNavigate();
  const location = useLocation();
  const { sessionId } = useParams<{ sessionId?: string }>();
  const [collapsed, setCollapsed] = useState<boolean>(
    () => localStorage.getItem(SESSIONS_COLLAPSED_KEY) === "1",
  );
  const [showRightSidebar, setShowRightSidebar] = useState<boolean>(
    () => localStorage.getItem(WORKBENCH_SIDEBAR_OPEN_KEY) === "1",
  );
  const sessions = useStore($sessions);
  const rightDrawer = useRightDrawer();
  const queryClient = useQueryClient();
  const currentWorkspaceId = useStore($currentWorkspaceId);
  const workspaces = useStore($workspaces);
  const active =
    sessions.find((s) => s.id === sessionId && !s.isArchived) ?? null;

  // Get current workspace path for auto-assigning to new sessions
  const currentWorkspacePath = currentWorkspaceId
    ? workspaces.find(w => w.id === currentWorkspaceId)?.path ?? null
    : null;

  useEffect(() => {
    localStorage.setItem(
      WORKBENCH_SIDEBAR_OPEN_KEY,
      showRightSidebar ? "1" : "0",
    );
  }, [showRightSidebar]);

  useEffect(() => {
    if (rightDrawer.open && !showRightSidebar) {
      setShowRightSidebar(true);
    }
  }, [rightDrawer.open, showRightSidebar]);

  const openWorkbenchSidebar = (section: RightDrawerSectionId) => {
    addRightDrawerSection(section);
    setShowRightSidebar(true);
  };

  useEffect(() => {
    localStorage.removeItem("august-show-right-sidebar");
  }, []);

  // Listen for the "open right sidebar" event dispatched by the PlanProposalBanner
  // (and any other in-chat call-to-action) so the drawer opens without the
  // caller needing access to the layout's setter.
  useEffect(() => {
    const handler = () => setShowRightSidebar(true);
    window.addEventListener('august:open-right-sidebar', handler);
    return () => window.removeEventListener('august:open-right-sidebar', handler);
  }, []);

  // Task 5: listen for august:ui-action events from the LLM/tool layer.
  // API/state actions only — no DOM clicks/fills (locked decision 3).
  const workbenchSessionId = active?.workbenchSessionId;
  useEffect(() => {
    const handler = (e: { action: string; target: string; payload?: Record<string, unknown> }) => {
      switch (e.action) {
        case 'navigate':
          navigate(e.target);
          break;
        case 'open_drawer': {
          const section = (e.payload?.section || 'preview') as RightDrawerSectionId;
          addRightDrawerSection(section);
          setShowRightSidebar(true);
          break;
        }
        case 'close_drawer':
          closeRightDrawer();
          setShowRightSidebar(false);
          break;
        case 'set_drawer_section': {
          const section = e.target as RightDrawerSectionId;
          if (['preview', 'diff', 'terminal', 'tasks', 'plan'].includes(section)) {
            addRightDrawerSection(section);
            setActiveRightDrawerSection(section);
            setShowRightSidebar(true);
          }
          break;
        }
        case 'set_guard_mode':
          if (workbenchSessionId) {
            const mode = e.target as 'plan' | 'ask' | 'full';
            setWorkbenchGuardMode(workbenchSessionId, mode)
              .catch(err => toast.error(`Failed to update guard mode: ${err?.message || err}`));
          }
          break;
        case 'refresh':
          queryClient.invalidateQueries();
          break;
        case 'focus_composer':
          dispatchFocusComposer();
          break;
        case 'insert_composer_text':
          dispatchInsertComposerText(e.target || '');
          break;
      }
    };
    const unsubscribe = onUiAction(handler);
    return unsubscribe;
  }, [navigate, queryClient, workbenchSessionId]);

  // Fetch the active workbench session to feed the right sidebar. The chat
  // thread also fetches this independently, so this is the layout-level mirror.
  const workbench = useQuery({
    queryKey: ['workbench-session', active?.workbenchSessionId],
    queryFn: () =>
      active?.workbenchSessionId
        ? getWorkbenchSession(active.workbenchSessionId)
        : Promise.resolve(null),
    enabled: !!active?.workbenchSessionId,
    refetchInterval: 2_000,
  });
  const workbenchSession: WorkbenchSession | null = workbench.data || null;

  // Auto-open the Tasks section when todos first appear.
  const hasTodosRef = useRef(false);
  useEffect(() => {
    const hasTodos = (workbenchSession?.todos?.length ?? 0) > 0;
    if (hasTodos && !hasTodosRef.current) {
      hasTodosRef.current = true;
      addRightDrawerSection('tasks');
      setShowRightSidebar(true);
    } else if (!hasTodos) {
      hasTodosRef.current = false;
    }
  }, [workbenchSession?.todos?.length]);

  // Auto redirect from `/` or invalid/archived sessionId to the first non-archived session
  useEffect(() => {
    const activeSessions = sessions.filter((s) => !s.isArchived);
    if (location.pathname === "/" || location.pathname === "") {
      let activeSess = activeSessions[0];
      if (!activeSess) {
        activeSess = createSession(null, 'New Chat', currentWorkspacePath);
      }
      navigate(`/c/${activeSess.id}`, { replace: true });
    } else if (location.pathname.startsWith("/c/")) {
      const match = sessions.find((s) => s.id === sessionId);
      if (!match || match.isArchived) {
        const fallback = activeSessions[0] || createSession(null, 'New Chat', currentWorkspacePath);
        navigate(`/c/${fallback.id}`, { replace: true });
      }
    }
  }, [location.pathname, sessionId, sessions, navigate, currentWorkspacePath]);

  const handleNewSession = (folderId?: string | null) => {
    const newSess = createSession(folderId ?? null, 'New Chat', currentWorkspacePath);
    navigate(`/c/${newSess.id}`);
  };

  const approvePlan = async () => {
    if (!active?.workbenchSessionId) return;
    try {
      const updated = await approveWorkbenchPlan(active.workbenchSessionId);
      queryClient.setQueryData(['workbench-session', active.workbenchSessionId], updated);
      toast.success('Workbench plan approved');
    } catch (e) {
      const message = e instanceof Error ? e.message : String(e);
      toast.error('Could not approve Workbench plan', { description: message });
    }
  };

  const rejectPlan = async () => {
    if (!active?.workbenchSessionId) return;
    try {
      const updated = await rejectWorkbenchPlan(active.workbenchSessionId);
      queryClient.setQueryData(['workbench-session', active.workbenchSessionId], updated);
      toast.success('Workbench plan rejected');
    } catch (e) {
      const message = e instanceof Error ? e.message : String(e);
      toast.error('Could not reject Workbench plan', { description: message });
    }
  };

  const revisePlan = async (feedback: string) => {
    if (!active?.workbenchSessionId) return;
    try {
      await streamWorkbenchRevision(active.workbenchSessionId, feedback, {
        onError: (data) => toast.error('Could not send plan revision', { description: data.message }),
        onSession: () => queryClient.invalidateQueries({ queryKey: ['workbench-session', active.workbenchSessionId] }),
      });
    } catch (e) {
      const message = e instanceof Error ? e.message : String(e);
      toast.error('Could not send plan revision', { description: message });
    }
  };

  const closeWorkbenchSidebar = () => {
    closeRightDrawer();
    setShowRightSidebar(false);
  };

  useEffect(() => {
    localStorage.setItem(SESSIONS_COLLAPSED_KEY, collapsed ? "1" : "0");
  }, [collapsed]);

  // Settings is a FULL-SCREEN page (not a modal). When the path is
  // /settings/*, render the SettingsPage full-width with the chat
  // thread + right drawer hidden. The session sidebar stays visible.
  const isSettings = location.pathname.startsWith("/settings");

  return (
    <div className="h-screen flex flex-col bg-background text-foreground">
      <div className="flex-1 flex min-h-0">
        {!isSettings && (
          <SessionSidebar
            activeId={active?.id}
            collapsed={collapsed}
            onToggleCollapsed={() => setCollapsed((c) => !c)}
            onNew={() => handleNewSession()}
            onNewInFolder={(folderId) => handleNewSession(folderId)}
            onNavigate={(path) => {
              if (path.startsWith("settings") || path.startsWith("/settings")) {
                sessionStorage.setItem("pre-settings-path", location.pathname);
              }
              navigate(path.startsWith("/") ? path : `/${path}`);
            }}
          />
        )}

        <div className="flex-1 flex flex-col min-w-0">
          <ChatTitlebar
            session={active}
            sidebarCollapsed={collapsed}
            rightDrawerOpen={showRightSidebar}
            onToggleSidebar={() => setCollapsed((c) => !c)}
            onSettings={() => {
              sessionStorage.setItem("pre-settings-path", location.pathname);
              navigate("/settings");
            }}
            onSelectRightDrawerSection={openWorkbenchSidebar}
          />
          <div className="flex-1 min-h-0 overflow-hidden relative flex">
            {/* Settings takes the full width (its own internal layout). */}
            {isSettings ? (
              <div className="flex-1 min-w-0 h-full">
                <AnimatePresence mode="wait" initial={false}>
                  <motion.div
                    key={location.pathname}
                    initial={{ opacity: 0, y: 6 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -4 }}
                    transition={{ duration: 0.18, ease: [0.16, 1, 0.3, 1] }}
                    className="h-full min-w-0"
                  >
                    <Outlet />
                  </motion.div>
                </AnimatePresence>
              </div>
            ) : (
              <>
                {/* Full-width chat column — scroll container spans the full
                    chat-area width so the thumb sits at the chat-area edge.
                    Internal content max-width is applied inside ChatThread
                    for message readability. */}
                <div className="flex-1 flex min-w-0 h-full">
                  <AnimatePresence mode="wait" initial={false}>
                    <motion.div
                      key={location.pathname}
                      initial={{ opacity: 0, y: 6 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -4 }}
                      transition={{ duration: 0.18, ease: [0.16, 1, 0.3, 1] }}
                      className="h-full min-w-0 flex-1"
                    >
                      <Outlet />
                    </motion.div>
                  </AnimatePresence>
                </div>

                {!isSettings && active && (
                  <RightDrawer
                    open={showRightSidebar}
                    sessionId={active.id}
                    workspacePath={active.workspacePath || null}
                    workbenchSession={workbenchSession}
                    onApprovePlan={approvePlan}
                    onRejectPlan={rejectPlan}
                    onRevisePlan={revisePlan}
                    onClose={closeWorkbenchSidebar}
                  />
                )}
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import {
  Volume2,
  Minus,
  Square,
  X,
  PanelLeft,
  PanelLeftClose,
  Settings,
  GitBranch,
  Download,
  Minimize2,
} from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import { gitApi } from "@/api/git";
import { cn } from "@/lib/utils";
import { isTauri } from "@/lib/tauri-detect";
import { toast } from "sonner";
import { RightDrawerDropdown } from "./RightDrawerLauncher";
import { BrainIndicator } from "./BrainIndicator";
import type { Session } from "@/store/sessions";
import type { RightDrawerSectionId } from "./RightDrawerState";

interface ChatTitlebarProps {
  session: Session | null;
  sidebarCollapsed: boolean;
  rightDrawerOpen: boolean;
  onToggleSidebar: () => void;
  onSelectRightDrawerSection: (section: RightDrawerSectionId) => void;
  onSettings: () => void;
}

export function ChatTitlebar({
  session,
  sidebarCollapsed,
  rightDrawerOpen,
  onToggleSidebar,
  onSelectRightDrawerSection,
  onSettings,
}: ChatTitlebarProps) {
  const [speaking, setSpeaking] = useState(false);
  const [isMaximized, setIsMaximized] = useState(false);
  const [updateAvailable, setUpdateAvailable] = useState<{
    version: string;
  } | null>(null);
  const [updating, setUpdating] = useState(false);

  const branch = useQuery({
    queryKey: ['git', 'branch', session?.id],
    queryFn: () => gitApi.branch(session?.id),
    refetchInterval: 30_000,
    retry: false,
  });
  const currentBranch = branch.data?.current;

  // ── Window controls (Tauri only) ──
  useEffect(() => {
    if (!isTauri) return;
    (async () => {
      try {
        const { getCurrentWindow } = await import("@tauri-apps/api/window");
        const win = getCurrentWindow();
        setIsMaximized(await win.isMaximized());
      } catch {}
    })();
  }, [isTauri]);

  const handleMinimize = async () => {
    if (!isTauri) return;
    try {
      const { getCurrentWindow } = await import("@tauri-apps/api/window");
      await getCurrentWindow().minimize();
    } catch {}
  };

  const handleToggleMaximize = async () => {
    if (!isTauri) return;
    try {
      const { getCurrentWindow } = await import("@tauri-apps/api/window");
      const win = getCurrentWindow();
      await win.toggleMaximize();
      setIsMaximized(await win.isMaximized());
    } catch {}
  };

  const handleClose = async () => {
    if (!isTauri) return;
    try {
      const { getCurrentWindow } = await import("@tauri-apps/api/window");
      await getCurrentWindow().close();
    } catch {}
  };

  // ── Auto-update check (Tauri only) ──
  useEffect(() => {
    if (!isTauri) return;
    (async () => {
      try {
        const { check } = await import("@tauri-apps/plugin-updater");
        const update = await check();
        if (update) {
          setUpdateAvailable({ version: update.version });
        }
      } catch {
        // Silently ignore — update check is best-effort
      }
    })();
  }, [isTauri]);

  const handleInstallUpdate = async () => {
    if (!isTauri || !updateAvailable) return;
    setUpdating(true);
    try {
      const { check } = await import("@tauri-apps/plugin-updater");
      const update = await check();
      if (update) {
        await update.downloadAndInstall();
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      toast.error(message || "Failed to install update");
      setUpdating(false);
    }
  };

  const speakLatest = () => {
    if (speaking) {
      window.speechSynthesis.cancel();
      setSpeaking(false);
      return;
    }
    const lastMessage = sessionStorage.getItem("august_last_assistant_message");
    if (!lastMessage) {
      toast.info("No message to read");
      return;
    }
    const utterance = new SpeechSynthesisUtterance(lastMessage);
    utterance.rate = 1;
    utterance.pitch = 1;
    utterance.onend = () => setSpeaking(false);
    utterance.onerror = () => setSpeaking(false);
    window.speechSynthesis.speak(utterance);
    setSpeaking(true);
  };

  return (
    <header data-tauri-drag-region className="h-12 bg-background flex items-center justify-between shrink-0 select-none">
      <div className="flex items-center min-w-0">
        <button
          onClick={onToggleSidebar}
          className="size-12 flex items-center justify-center shrink-0 hover:bg-accent text-muted-foreground hover:text-foreground transition"
          title={sidebarCollapsed ? "Show sidebar" : "Hide sidebar"}
        >
          {sidebarCollapsed ? (
            <PanelLeftClose className="size-4" />
          ) : (
            <PanelLeft className="size-4" />
          )}
        </button>

        {/* Update notification button */}
        {updateAvailable && (
          <button
            onClick={handleInstallUpdate}
            disabled={updating}
            className="flex items-center gap-1.5 px-2.5 py-1 mx-1 text-xs font-medium 
              bg-amber-500/15 text-amber-400 hover:bg-amber-500/25 
              rounded-md transition disabled:opacity-50"
            title={`Update to v${updateAvailable.version}`}
          >
            <Download className="size-3" />
            {updating ? "Updating…" : `v${updateAvailable.version} available`}
          </button>
        )}

        <div className="flex items-center gap-2 px-2 min-w-0">
          <h1 className="text-[13px] font-medium text-foreground truncate">
            {session?.title ?? "General Assistance Conversation Started"}
          </h1>
          {currentBranch && (
            <span
              className="inline-flex items-center gap-1 text-[10px] font-mono text-muted-foreground/80 bg-white/[0.04] border border-white/[0.06] px-1.5 py-0.5 rounded-md"
              title={`Current git branch`}
            >
              <GitBranch size={10} />
              {currentBranch}
            </span>
          )}
          <button
            onClick={onSettings}
            className="p-1 hover:bg-accent rounded text-muted-foreground hover:text-foreground transition"
            title="Open settings"
          >
            <Settings className="size-4" />
          </button>
          {/* v4.4.1 — BrainIndicator (self-contained: icon + pulse dot + floating popup) */}
          <BrainIndicator />
        </div>
      </div>

      <div className="flex items-center gap-3">
        <button
          onClick={speakLatest}
          className={cn(
            "p-1 hover:bg-accent rounded transition",
            speaking
              ? "text-primary animate-pulse"
              : "text-muted-foreground hover:text-foreground",
          )}
          title={speaking ? "Stop reading" : "Read latest response"}
        >
          <Volume2 className="size-4" />
        </button>
        <RightDrawerDropdown drawerOpen={rightDrawerOpen} onSelect={onSelectRightDrawerSection} />

        <div className="h-4 w-[1px] bg-border/40" />

        {/* Windows-style title bar buttons */}
        <div className="flex items-stretch ml-1">
          <button
            onClick={handleMinimize}
            className="w-[46px] h-[32px] flex items-center justify-center text-muted-foreground hover:bg-white/10 transition-colors"
            aria-label="Minimize"
          >
            <Minus className="size-4" />
          </button>
          <button
            onClick={handleToggleMaximize}
            className="w-[46px] h-[32px] flex items-center justify-center text-muted-foreground hover:bg-white/10 transition-colors"
            aria-label={isMaximized ? "Restore" : "Maximize"}
          >
            {isMaximized ? <Minimize2 className="size-3.5" /> : <Square className="size-3" />}
          </button>
          <button
            onClick={handleClose}
            className="w-[46px] h-[32px] flex items-center justify-center text-muted-foreground hover:bg-red-500 hover:text-white transition-colors"
            aria-label="Close"
          >
            <X className="size-4" />
          </button>
        </div>
      </div>
    </header>
  );
}

/* ── GitPanel ─ right-sidebar git tools (ZCode reference) ────────── */
/* Workspace-explorer rail: changes summary, branch selector, and commit. */
/* The workbench todo list is intentionally NOT shown here — it lives in   */
/* the chat area as a pill-style expandable component (TodoSummaryPill)   */
/* so the user can track task progress right next to the running turn.    */
/*                                                                          */
/* Polls /api/git/status, /branch, /branches every 30s.                    */

import { useState } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { GitBranch, GitCommit, Plus, Minus, RefreshCw, ChevronDown, Check } from 'lucide-react';
import { gitApi } from '@/api/git';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';

export interface GitPanelProps {
  /** Active session id (used to resolve the workspace cwd). */
  sessionId?: string;
  className?: string;
}

export function GitPanel({ sessionId, className }: GitPanelProps) {
  const qc = useQueryClient();
  const [commitMessage, setCommitMessage] = useState('');
  const [showBranchMenu, setShowBranchMenu] = useState(false);

  const status = useQuery({
    queryKey: ['git', 'status', sessionId],
    queryFn: () => gitApi.status(sessionId),
    refetchInterval: 30_000,
  });
  const branch = useQuery({
    queryKey: ['git', 'branch', sessionId],
    queryFn: () => gitApi.branch(sessionId),
    refetchInterval: 30_000,
  });
  const branches = useQuery({
    queryKey: ['git', 'branches', sessionId],
    queryFn: () => gitApi.branches(sessionId),
    refetchInterval: 30_000,
  });

  const refresh = () => {
    qc.invalidateQueries({ queryKey: ['git'] });
  };

  const handleCommit = async () => {
    const msg = commitMessage.trim();
    if (!msg || !sessionId) return;
    try {
      await gitApi.commit(sessionId, msg);
      setCommitMessage('');
      refresh();
    } catch (err) {
      console.warn('[GitPanel] commit failed:', (err as Error).message);
    }
  };

  const handleCheckout = async (b: string) => {
    if (!sessionId) return;
    setShowBranchMenu(false);
    try {
      await gitApi.checkout(sessionId, b);
      refresh();
    } catch (err) {
      console.warn('[GitPanel] checkout failed:', (err as Error).message);
    }
  };

  const s = status.data;
  const currentBranch = branch.data?.current;
  const branchList = branches.data?.branches || [];
  const isRepo = !status.data?.error || (s?.files && s.files.length > 0);

  return (
    <div className={cn('flex flex-col gap-3 p-3 text-xs', className)}>
      {/* 1. Changes summary */}
      <div className="rounded-xl border border-white/[0.06] bg-card/60 p-3">
        <div className="flex items-center justify-between mb-1.5">
          <span className="text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">Changes</span>
          <button
            type="button"
            onClick={refresh}
            className="p-1 rounded hover:bg-white/10 text-muted-foreground/60"
            aria-label="Refresh git status"
          >
            <RefreshCw size={11} className={status.isFetching ? 'animate-spin' : ''} />
          </button>
        </div>
        {!isRepo ? (
          <div className="text-[11px] text-muted-foreground/60 italic">
            Not a git repository
          </div>
        ) : !s || s.files.length === 0 ? (
          <div className="text-[11px] text-muted-foreground/60 italic">
            Working tree clean
          </div>
        ) : (
          <>
            <div className="flex items-center gap-3 mb-2 font-mono tabular-nums">
              <span className="inline-flex items-center gap-1 text-success">
                <Plus size={11} /> {s.added}
              </span>
              <span className="inline-flex items-center gap-1 text-rose-400">
                <Minus size={11} /> {s.removed}
              </span>
              <span className="text-muted-foreground/60 ml-auto text-[10px]">
                {s.files.length} file{s.files.length === 1 ? '' : 's'}
              </span>
            </div>
            <div className="space-y-0.5 max-h-40 overflow-auto">
              {s.files.slice(0, 12).map((f) => (
                <div key={f.path} className="flex items-center gap-1.5 text-[11px] truncate">
                  <span className="font-mono text-muted-foreground/60 w-6 text-right tabular-nums">
                    {f.added || ''}
                  </span>
                  <span className="font-mono text-muted-foreground/60 w-6 text-right tabular-nums">
                    {f.removed || ''}
                  </span>
                  <span className="truncate text-foreground/85">{f.path}</span>
                </div>
              ))}
              {s.files.length > 12 && (
                <div className="text-[10px] text-muted-foreground/50 italic pt-0.5">
                  + {s.files.length - 12} more
                </div>
              )}
            </div>
          </>
        )}
      </div>

      {/* 2. Branch selector + Commit */}
      <div className="rounded-xl border border-white/[0.06] bg-card/60 p-3">
        <div className="flex items-center justify-between mb-2">
          <span className="text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">Branch &amp; commit</span>
        </div>
        <div className="relative">
          <button
            type="button"
            onClick={() => setShowBranchMenu(o => !o)}
            disabled={!currentBranch}
            className="w-full flex items-center justify-between gap-2 px-2 py-1.5 rounded-md bg-white/[0.04] hover:bg-white/[0.07] text-[12px] disabled:opacity-50"
          >
            <span className="flex items-center gap-1.5 truncate">
              <GitBranch size={12} className="text-muted-foreground/70" />
              <span className="font-mono truncate">{currentBranch || '—'}</span>
            </span>
            <ChevronDown size={11} className="text-muted-foreground/60" />
          </button>
          {showBranchMenu && branchList.length > 0 && (
            <div className="absolute z-20 mt-1 left-0 right-0 max-h-56 overflow-auto rounded-md border border-white/[0.08] bg-[#1c1c1c] shadow-2xl">
              {branchList.map((b) => (
                <button
                  type="button"
                  key={b.name}
                  onClick={() => handleCheckout(b.name)}
                  className={cn(
                    'w-full flex items-center gap-2 px-2 py-1.5 text-left text-[11.5px] hover:bg-white/[0.05]',
                    b.current && 'text-primary'
                  )}
                >
                  <GitBranch size={11} />
                  <span className="truncate font-mono">{b.name}</span>
                  {b.current && <Check size={11} className="ml-auto" />}
                </button>
              ))}
            </div>
          )}
        </div>
        <div className="mt-2 flex items-center gap-1.5">
          <input
            type="text"
            value={commitMessage}
            onChange={(e) => setCommitMessage(e.target.value)}
            placeholder="Commit message…"
            disabled={!sessionId}
            className="flex-1 min-w-0 bg-white/[0.04] rounded-md px-2 py-1 text-[12px] text-foreground placeholder:text-muted-foreground/40 focus:outline-none focus:bg-white/[0.07] disabled:opacity-50"
            onKeyDown={(e) => {
              if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) handleCommit();
            }}
          />
          <Button
            type="button"
            size="sm"
            onClick={handleCommit}
            disabled={!commitMessage.trim() || !sessionId}
            className="h-7 px-2"
          >
            <GitCommit size={12} />
          </Button>
        </div>
      </div>

    </div>
  );
}

/* ── PlanProposalBanner ─ chat-bottom plan proposal actions ───────── */
/*                                                                          */
/* Visual language mirrors the in-composer dropdowns (EffortDropdown,      */
/* WorkbenchModeSelector): rounded-xl panel, bg-card surface, border       */
/* border-border, p-1.5/2 padding, text-xs items with rounded-md hover.    */

import { useEffect, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Check, Send, X, PencilLine } from 'lucide-react';
import { cn } from '@/lib/utils';
import type { WorkbenchSession } from '@/types/workbench';

export interface PlanProposalBannerProps {
  workbenchSession: WorkbenchSession | null;
  /** Display name of the model that proposed the plan (e.g. "Opus 4.7"). */
  modelName?: string;
  /** Open the plan section in the right drawer. */
  onOpenPlan: () => void;
  /**
   * "Accept" — approve the plan and acknowledge it to the model. The model
   * is told the plan is accepted but should NOT proceed with implementation
   * yet; it waits for the next instruction.
   */
  onAccept: () => void | Promise<void>;
  /**
   * "Accept and allow edits" — approve the plan AND instruct the model to
   * proceed with implementation at Full access.
   */
  onAcceptAndImplement: () => void | Promise<void>;
  /** Reject the plan (clears it). */
  onReject: () => void | Promise<void>;
  /** Send a revision request as a chat message so the model revises the plan. */
  onRevise: (feedback: string) => void | Promise<void>;
  /** Optional: whether a chat send is in flight (disables buttons). */
  sending?: boolean;
}

export function PlanProposalBanner({
  workbenchSession,
  modelName,
  onOpenPlan,
  onAccept,
  onAcceptAndImplement,
  onReject,
  onRevise,
  sending,
}: PlanProposalBannerProps) {
  const [revising, setRevising] = useState(false);
  const [feedback, setFeedback] = useState('');
  const textareaRef = useRef<HTMLTextAreaElement | null>(null);
  const plan = workbenchSession?.plan;
  const approved = workbenchSession?.approved || !!workbenchSession?.approvedAt;

  useEffect(() => {
    if (revising) {
      // Focus the textarea after the animation opens.
      const id = setTimeout(() => textareaRef.current?.focus(), 80);
      return () => clearTimeout(id);
    }
  }, [revising]);

  if (!plan || approved) return null;

  const modelLabel = modelName?.trim() || 'The model';

  const submitRevision = () => {
    const text = feedback.trim();
    if (!text || sending) return;
    void onRevise(text);
    setFeedback('');
    setRevising(false);
  };

  return (
    <div className="mx-auto w-full max-w-3xl px-2">
      <div className="rounded-xl border border-border bg-card p-3 shadow-2xl">
        {/* Top row: title + open plan link — matches dropdown header style */}
        <div className="flex items-center justify-between gap-3 px-2 py-1.5">
          <div className="flex min-w-0 items-center gap-1.5 text-sm font-medium text-foreground/90">
            <span className="truncate">
              <span className="font-semibold">{modelLabel}</span> proposed a plan
            </span>
          </div>
          <button
            type="button"
            onClick={onOpenPlan}
            className="text-sm font-semibold text-primary hover:underline shrink-0"
          >
            Open plan
          </button>
        </div>

        {/* Revise textarea — collapsible with the same animation language as the
            dropdowns in ChatComposer. */}
        <AnimatePresence initial={false}>
          {revising && (
            <motion.div
              key="revise"
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
              transition={{ duration: 0.18, ease: [0.16, 1, 0.3, 1] }}
              className="overflow-hidden"
            >
              <textarea
                ref={textareaRef}
                value={feedback}
                onChange={(e) => setFeedback(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    void submitRevision();
                  } else if (e.key === 'Escape') {
                    setRevising(false);
                    setFeedback('');
                  }
                }}
                placeholder="What would you like to change? (Enter to send, Shift+Enter for newline, Esc to cancel)"
                rows={3}
                className={cn(
                  'w-full resize-none rounded-md border border-border bg-muted',
                  'px-2.5 py-2 mt-1 text-sm text-foreground placeholder:text-muted-foreground/60',
                  'outline-none focus:border-primary/60 transition',
                )}
              />
            </motion.div>
          )}
        </AnimatePresence>

        {/* Action row — same `rounded-md text-xs` button styling as the
            dropdown menu items so the banner feels like part of the same
            control family. */}
        <div className="mt-2 flex items-center gap-1">
          <BannerButton onClick={onReject} disabled={sending}>
            <X className="size-3" />
            Reject
          </BannerButton>

          <BannerButton
            active={revising}
            onClick={() => {
              if (revising) {
                setRevising(false);
                setFeedback('');
              } else {
                setRevising(true);
              }
            }}
          >
            {revising ? <Check className="size-3" /> : <PencilLine className="size-3" />}
            {revising ? 'Cancel' : 'Revise…'}
          </BannerButton>

          {revising ? (
            <BannerButton
              primary
              onClick={submitRevision}
              disabled={sending || !feedback.trim()}
              className="ml-auto"
            >
              <Send className="size-3" />
              Send
              <kbd className="ml-1 rounded bg-primary-foreground/10 px-1 text-[10px] font-mono">↵</kbd>
            </BannerButton>
          ) : (
            <>
              <BannerButton onClick={onAccept} disabled={sending}>
                Accept
              </BannerButton>
              <BannerButton primary onClick={onAcceptAndImplement} disabled={sending} className="ml-auto">
                Accept and allow edits
                <kbd className="ml-1 rounded bg-primary-foreground/10 px-1 text-[10px] font-mono">Ctrl ↵</kbd>
              </BannerButton>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

/* ── BannerButton ─ dropdown-styled action button ─────────────────── */

function BannerButton({
  children,
  onClick,
  disabled,
  active,
  primary,
  className,
}: {
  children: React.ReactNode;
  onClick?: () => void;
  disabled?: boolean;
  active?: boolean;
  primary?: boolean;
  className?: string;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      disabled={disabled}
      className={cn(
        'inline-flex items-center justify-center gap-1.5 rounded-md text-sm font-medium',
        'px-2 py-1.5 transition-colors',
        primary
          ? 'bg-primary text-primary-foreground hover:bg-primary/90 disabled:opacity-50'
          : active
            ? 'bg-accent text-foreground'
            : 'text-muted-foreground hover:bg-muted hover:text-foreground',
        'disabled:opacity-50 disabled:cursor-not-allowed',
        className,
      )}
    >
      {children}
    </button>
  );
}

/* ── RightDrawerDiffSection ─ full diff view ──────────────────────── */

import { useQuery, useQueryClient } from '@tanstack/react-query';
import { FileText, RefreshCw, ArrowRight } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { cn } from '@/lib/utils';
import { gitApi } from '@/api/git';
import { DiffView } from '@/components/chat/DiffView';
import { FileIcon } from '@/components/ui/FileIcon';
import { useRightDrawer } from './RightDrawerState';

export function RightDrawerDiffSection({ sessionId }: { sessionId: string | null }) {
  const qc = useQueryClient();
  const drawer = useRightDrawer();
  const storedDiff = drawer.diff;

  const query = useQuery({
    queryKey: ['git', 'diff', sessionId],
    queryFn: () => (sessionId ? gitApi.diff(sessionId) : Promise.resolve(null)),
    enabled: !!sessionId,
    retry: false,
  });

  const diff = query.data || storedDiff || undefined;
  const files = diff?.files?.filter((file) => file.added > 0 || file.removed > 0 || file.status || file.diff?.trim()) ?? [];
  const added = diff?.added ?? files.reduce((sum, file) => sum + file.added, 0);
  const removed = diff?.removed ?? files.reduce((sum, file) => sum + file.removed, 0);

  return (
    <div className="h-full space-y-3 drawer-section-text">
      <div className="flex items-start justify-between gap-3">
        <div>
          <div className="text-xs text-muted-foreground">
            {diff ? `${files.length} changed file${files.length === 1 ? '' : 's'}` : 'No diff loaded yet'}
          </div>
          <div className="mt-0.5 flex items-center gap-2 font-mono text-xs tabular-nums">
            {added > 0 && <span className="text-success">+{added}</span>}
            {removed > 0 && <span className="text-danger">-{removed}</span>}
            {!added && !removed && <span className="text-muted-foreground/60">0</span>}
          </div>
        </div>
        <Button
          variant="outline"
          size="sm"
          disabled={!sessionId || query.isFetching}
          onClick={() => qc.invalidateQueries({ queryKey: ['git', 'diff', sessionId] })}
        >
          <RefreshCw className={cn('size-3', query.isFetching && 'animate-spin')} />
          Refresh
        </Button>
      </div>

      {!diff && query.isLoading && (
        <div className="rounded-lg border border-border/50 bg-card/60 p-4 text-center text-muted-foreground">
          Loading diff…
        </div>
      )}

      {!diff && query.error && (
        <div className="rounded-lg border border-destructive/30 bg-destructive/10 p-3 text-destructive">
          {(query.error as Error).message}
        </div>
      )}

      {files.length === 0 && diff && (
        <div className="rounded-lg border border-border/50 bg-card/60 p-4 text-center text-muted-foreground">
          Working tree is clean.
        </div>
      )}

      <div className="space-y-3">
        {files.map((file) => {
          const selected = drawer.selectedDiffPath === file.path;
          return (
            <div
              key={file.path}
              className={cn(
                'overflow-hidden rounded-lg border bg-black/20',
                selected ? 'border-primary/50' : 'border-white/[0.06]'
              )}
            >
              <div
                className={cn(
                  'flex items-center justify-between gap-2 border-b px-2.5 py-2',
                  selected ? 'border-primary/30 bg-primary/10' : 'border-white/[0.05] bg-white/[0.025]'
                )}
              >
                <div className="flex min-w-0 items-center gap-2">
                  <FileIcon name={file.path} size={13} className="shrink-0" />
                  <span className="truncate font-mono text-xs text-foreground/85" title={file.path}>
                    {file.path}
                  </span>
                </div>
                <div className="flex items-center gap-1.5 shrink-0">
                  {file.status && <Badge variant="secondary" className="text-[10px]">{file.status}</Badge>}
                  <span className="font-mono text-xs text-success">+{file.added}</span>
                  <span className="font-mono text-xs text-danger">-{file.removed}</span>
                  <ArrowRight className="size-3 text-muted-foreground/50" />
                  <FileText className="size-3 text-muted-foreground/50" />
                </div>
              </div>

              {file.diff?.trim() ? (
                <DiffView diff={file.diff} maxLines={240} />
              ) : (
                <div className="p-3 text-center text-muted-foreground/60">No diff content available.</div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ── RightDrawerPreviewSection ─ browser preview workflow ────────── */

import { useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Activity, Check, Globe, Loader2, Play, ShieldAlert, Square, X } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { cn } from '@/lib/utils';
import {
  approvePreviewRequest,
  getPreviewSession,
  getPreviewSessions,
  getRequests,
  startPreviewSession,
  stopPreviewSession,
  type PreviewApproval,
} from '@/api/api-client';
import type { RequestEntry } from '@/api/api-client';

export function RightDrawerPreviewSection({
  sessionId,
  workspacePath,
}: {
  sessionId: string | null;
  workspacePath: string | null;
}) {
  const qc = useQueryClient();
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [command, setCommand] = useState('npm run dev');
  const [previewUrl, setPreviewUrl] = useState('');

  const { data, isLoading } = useQuery({
    queryKey: ['preview-sessions', sessionId],
    queryFn: getPreviewSessions,
    refetchInterval: 2_500,
  });

  const sessions = data?.sessions ?? [];
  const approvals = data?.approvals ?? [];
  const active = sessions.find((session) => session.id === selectedId) ?? sessions[0] ?? null;

  const { data: activePreview } = useQuery({
    queryKey: ['preview-session', active?.id],
    queryFn: () => (active?.id ? getPreviewSession(active.id) : Promise.resolve(null)),
    enabled: !!active?.id,
    refetchInterval: 1_500,
  });

  const { data: requests } = useQuery({
    queryKey: ['preview-requests', sessionId],
    queryFn: () => getRequests('today'),
    enabled: !!sessionId,
    refetchInterval: 5_000,
  });

  const start = useMutation({
    mutationFn: () => startPreviewSession({ command, cwd: workspacePath || undefined, approved: false }),
    onSuccess: (result: any) => {
      if (result?.status === 'approval_required') {
        qc.invalidateQueries({ queryKey: ['preview-sessions', sessionId] });
        return;
      }
      setCommand('');
      qc.invalidateQueries({ queryKey: ['preview-sessions', sessionId] });
    },
  });

  const stop = useMutation({
    mutationFn: (id: string) => stopPreviewSession(id),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['preview-sessions', sessionId] }),
  });

  const approve = useMutation({
    mutationFn: (requestId: string) => approvePreviewRequest(requestId, true),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['preview-sessions', sessionId] }),
  });
  const reject = useMutation({
    mutationFn: (requestId: string) => approvePreviewRequest(requestId, false),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['preview-sessions', sessionId] }),
  });

  const url = activePreview?.url || active?.url || previewUrl;
  const canEmbed = url ? isLocalPreviewUrl(url) : false;
  const recentRequests = (requests?.completed || []).slice(0, 8);

  return (
    <div className="h-full space-y-3 drawer-section-text">
      <div className="flex items-center justify-between gap-2">
        <div className="text-xs text-muted-foreground">
          Run a local dev server and inspect the browser preview
        </div>
        <Badge variant="secondary" className="text-[10px]">
          <Globe className="size-3" />
          local preview
        </Badge>
      </div>

      {approvals.length > 0 && (
        <PreviewApprovalList approvals={approvals} approve={approve} reject={reject} />
      )}

      <form
        className="flex items-center gap-2"
        onSubmit={(event) => {
          event.preventDefault();
          if (command.trim()) start.mutate();
        }}
      >
        <Input
          value={command}
          onChange={(event) => setCommand(event.target.value)}
          placeholder="npm run dev"
          className="font-mono text-xs"
          disabled={start.isPending}
        />
        <Button type="submit" size="sm" disabled={!command.trim() || start.isPending}>
          {start.isPending ? <Loader2 className="size-3 animate-spin" /> : <Play className="size-3" />}
          Start
        </Button>
      </form>

      <div className="grid grid-cols-[150px_minmax(0,1fr)] gap-3 min-h-[320px]">
        <div className="space-y-1 overflow-auto rounded-lg border border-border/50 bg-card/40 p-1.5">
          {sessions.length === 0 && !isLoading && (
            <div className="py-6 text-center text-muted-foreground/60">No previews</div>
          )}
          {sessions.map((session) => (
            <button
              key={session.id}
              type="button"
              onClick={() => setSelectedId(session.id)}
              className={cn(
                'w-full rounded-md px-2 py-1.5 text-left transition',
                active?.id === session.id ? 'bg-primary text-primary-foreground' : 'hover:bg-accent'
              )}
            >
              <div className="flex items-center gap-1.5">
                <Globe className="size-3 shrink-0" />
                <span className="truncate font-mono text-xs">{session.title || session.id}</span>
              </div>
              <div className={cn(
                'mt-0.5 truncate text-[10px]',
                active?.id === session.id ? 'text-primary-foreground/70' : 'text-muted-foreground/55'
              )}>
                {session.status}
              </div>
            </button>
          ))}
        </div>

        <div className="min-w-0 space-y-3">
          {active ? (
            <>
              <div className="flex items-start justify-between gap-2">
                <div className="min-w-0">
                  <div className="flex items-center gap-1.5 font-mono text-xs text-muted-foreground">
                    <Badge variant="secondary" className="text-[10px]">{active.id}</Badge>
                    <span>{active.status}</span>
                  </div>
                  <div className="mt-1 truncate text-xs text-muted-foreground/70">{active.cwd}</div>
                </div>
                <Button
                  variant="ghost"
                  size="icon-sm"
                  onClick={() => stop.mutate(active.id)}
                  disabled={stop.isPending || active.status === 'exited'}
                  aria-label="Stop preview"
                >
                  <Square className="size-3" />
                </Button>
              </div>

              {url && (
                <div className="flex items-center gap-2 rounded-lg border border-border/60 bg-background px-2.5 py-2">
                  <Globe className="size-3 text-muted-foreground" />
                  <input
                    value={url}
                    onChange={(event) => setPreviewUrl(event.target.value)}
                    className="min-w-0 flex-1 bg-transparent text-xs font-mono outline-none"
                  />
                </div>
              )}

              {canEmbed ? (
                <div className="h-[180px] overflow-hidden rounded-lg border border-border bg-background">
                  <iframe
                    key={url}
                    src={url}
                    className="h-full w-full border-0"
                    title="Local preview"
                    sandbox="allow-scripts allow-same-origin allow-forms"
                  />
                </div>
              ) : (
                <div className="flex h-[180px] flex-col items-center justify-center rounded-lg border border-border/50 bg-card/40 text-center text-muted-foreground">
                  <Activity className="size-6 text-muted-foreground/40" />
                  <div className="mt-2 text-[11px]">
                    {active.status === 'running' ? 'Waiting for a local preview URL…' : 'Start a preview to see the browser target.'}
                  </div>
                </div>
              )}
            </>
          ) : (
            <div className="flex h-full min-h-[260px] flex-col items-center justify-center rounded-lg border border-border/50 bg-card/40 text-center text-muted-foreground">
              <Play className="size-6 text-muted-foreground/40" />
              <div className="mt-2 text-[11px]">{isLoading ? 'Loading previews…' : 'Start a local dev server preview.'}</div>
            </div>
          )}

          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <div className="text-[10px] uppercase tracking-wider text-muted-foreground font-semibold">Logs</div>
              {activePreview?.logLength ? <span className="font-mono text-[10px] text-muted-foreground">{activePreview.logLength}</span> : null}
            </div>
            <div className="max-h-[120px] overflow-auto rounded-lg bg-black/80 p-3 font-mono text-[10px] leading-relaxed text-success/90">
              <pre className="whitespace-pre-wrap break-all">
                {activePreview?.log || active?.status === 'running' ? 'Waiting for preview logs…' : 'No preview logs yet.'}
              </pre>
            </div>
          </div>

          <NetworkList requests={recentRequests} />
        </div>
      </div>
    </div>
  );
}

function PreviewApprovalList({
  approvals,
  approve,
  reject,
}: {
  approvals: PreviewApproval[];
  approve: { mutate: (requestId: string) => void; isPending: boolean };
  reject: { mutate: (requestId: string) => void; isPending: boolean };
}) {
  return (
    <div className="rounded-lg border border-warning/30 bg-warning/5 p-3 space-y-2">
      <div className="flex items-center gap-1.5 text-[10px] uppercase tracking-wider text-warning font-semibold">
        <ShieldAlert className="size-3" />
        {approvals.length} approval{approvals.length > 1 ? 's' : ''} required
      </div>
      {approvals.map((approval) => (
        <div key={approval.requestId} className="flex items-start justify-between gap-2 rounded-md border border-warning/20 bg-card/70 p-2">
          <div className="min-w-0">
            <pre className="whitespace-pre-wrap break-all text-[10.5px] font-mono text-foreground/85">
              {approval.command || '(no command)'}
            </pre>
            <div className="mt-0.5 text-[10px] text-muted-foreground">{approval.reason || approval.cwd}</div>
          </div>
          <div className="flex items-center gap-1 shrink-0">
            <Button size="sm" onClick={() => approve.mutate(approval.requestId)} disabled={approve.isPending}>
              <Check className="size-3" />
            </Button>
            <Button variant="outline" size="sm" onClick={() => reject.mutate(approval.requestId)} disabled={reject.isPending}>
              <X className="size-3" />
            </Button>
          </div>
        </div>
      ))}
    </div>
  );
}

function NetworkList({ requests }: { requests: RequestEntry[] }) {
  return (
    <div className="space-y-2">
      <div className="flex items-center justify-between">
        <div className="text-[10px] uppercase tracking-wider text-muted-foreground font-semibold">Network</div>
        <Activity className="size-3 text-muted-foreground/60" />
      </div>
      {requests.length === 0 && (
        <div className="rounded-lg border border-border/50 bg-card/40 p-3 text-center text-muted-foreground/70">
          No recent requests yet.
        </div>
      )}
      <div className="space-y-1">
        {requests.map((request) => (
          <div key={request.reqId} className="rounded-md border border-border/50 bg-card/40 px-2.5 py-2">
            <div className="flex items-center justify-between gap-2">
              <span className="truncate font-mono text-[10.5px]">{request.endpoint}</span>
              <span className={cn(
                'font-mono text-[10px]',
                request.status === 'success' || request.status === 'completed' ? 'text-success' : 'text-danger'
              )}>
                {Math.round(request.durationMs)}ms
              </span>
            </div>
            <div className="mt-0.5 text-[10px] text-muted-foreground/65 truncate">
              {request.model || request.clientType}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function isLocalPreviewUrl(value: string) {
  try {
    const url = new URL(value);
    return ['localhost', '127.0.0.1', '0.0.0.0'].includes(url.hostname);
  } catch {
    return false;
  }
}

/* ── RightDrawerTerminalSection ─ real xterm.js PTY panel ────────── */

import { useEffect, useRef, useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Check, Loader2, Plus, ShieldAlert, X, Inbox } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import { Terminal as XTerm } from 'xterm';
import { FitAddon } from 'xterm-addon-fit';
import 'xterm/css/xterm.css';
import {
  approveTerminalRequest,
  createTerminalSession,
  deleteTerminalSession,
  getTerminalSessions,
  resizeTerminalSession,
  type TerminalApproval,
} from '@/api/api-client';

export function RightDrawerTerminalSection() {
  const qc = useQueryClient();
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [socketReady, setSocketReady] = useState(false);
  const terminalRef = useRef<XTerm | null>(null);
  const fitRef = useRef<FitAddon | null>(null);
  const socketRef = useRef<WebSocket | null>(null);
  const containerRef = useRef<HTMLDivElement | null>(null);
  const connectedRef = useRef(false);
  const autoSpawnRef = useRef(false);

  const { data, isLoading } = useQuery({
    queryKey: ['terminal-sessions'],
    queryFn: getTerminalSessions,
    refetchInterval: 3_000,
  });

  const sessions = data?.sessions ?? [];
  const approvals = data?.approvals ?? [];
  const activeId = selectedId ?? sessions[0]?.id ?? null;
  const active = sessions.find((session) => session.id === activeId) ?? null;

  const resize = useMutation({
    mutationFn: ({ sessionId, cols, rows }: { sessionId: string; cols: number; rows: number }) =>
      resizeTerminalSession(sessionId, cols, rows),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['terminal-sessions'] }),
  });

  const createSession = useMutation({
    mutationFn: () => createTerminalSession(),
    onSuccess: (session) => {
      setSelectedId(session.id);
      qc.invalidateQueries({ queryKey: ['terminal-sessions'] });
    },
  });

  const approve = useMutation({
    mutationFn: (requestId: string) => approveTerminalRequest(requestId, true),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['terminal-sessions'] }),
  });
  const reject = useMutation({
    mutationFn: (requestId: string) => approveTerminalRequest(requestId, false),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['terminal-sessions'] }),
  });
  const close = useMutation({
    mutationFn: deleteTerminalSession,
    onSuccess: () => {
      if (selectedId) setSelectedId(null);
      qc.invalidateQueries({ queryKey: ['terminal-sessions'] });
    },
  });

  // Auto-spawn a real terminal session if there are none yet.
  useEffect(() => {
    if (
      !autoSpawnRef.current &&
      !isLoading &&
      sessions.length === 0 &&
      !activeId &&
      !createSession.isPending
    ) {
      autoSpawnRef.current = true;
      createSession.mutate();
    }
  }, [isLoading, sessions.length, activeId, createSession]);

  useEffect(() => {
    if (!activeId) {
      socketRef.current?.close();
      socketRef.current = null;
      connectedRef.current = false;
      setSocketReady(false);
      terminalRef.current?.dispose();
      terminalRef.current = null;
      fitRef.current = null;
      return;
    }

    const terminal = new XTerm({
      convertEol: true,
      cursorBlink: true,
      fontFamily: 'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", monospace',
      fontSize: 14,
      theme: {
        background: '#020617',
        foreground: '#e5e7eb',
      },
    });
    const fit = new FitAddon();
    terminal.loadAddon(fit);
    terminalRef.current = terminal;
    fitRef.current = fit;

    const container = containerRef.current;
    if (container) {
      terminal.open(container);
      // Defer initial fit until after layout settles.
      requestAnimationFrame(() => fit.fit());
    }

    const syncSize = () => {
      const bounds = containerRef.current?.getBoundingClientRect();
      const terminalInstance = terminalRef.current;
      const fitAddon = fitRef.current;
      if (!bounds || !terminalInstance || !fitAddon) return;
      fitAddon.fit();
      const cols = Math.max(20, Math.floor(bounds.width / 7.5));
      const rows = Math.max(5, Math.floor(bounds.height / 16));
      terminalInstance.resize(cols, rows);
      resize.mutate({ sessionId: activeId, cols, rows });
    };

    const observer = new ResizeObserver(syncSize);
    if (containerRef.current) observer.observe(containerRef.current);
    window.addEventListener('resize', syncSize);

    const protocol = window.location.protocol === 'https:' ? 'wss' : 'ws';
    const socket = new WebSocket(`${protocol}://${window.location.host}/api/terminal/connect?id=${encodeURIComponent(activeId)}`);
    socketRef.current = socket;

    const onData = (data: string) => {
      if (socket.readyState === WebSocket.OPEN) socket.send(data);
    };
    const onDataDisposable = terminal.onData(onData);

    socket.addEventListener('open', () => {
      connectedRef.current = true;
      setSocketReady(true);
      syncSize();
      terminal.focus();
    });
    socket.addEventListener('message', (event) => {
      if (typeof event.data === 'string') {
        terminal.write(event.data);
      } else if (event.data instanceof ArrayBuffer) {
        terminal.write(new Uint8Array(event.data));
      } else if (event.data instanceof Blob) {
        event.data.arrayBuffer().then((buffer) => terminal.write(new Uint8Array(buffer)));
      }
    });
    socket.addEventListener('close', () => {
      connectedRef.current = false;
      setSocketReady(false);
    });
    socket.addEventListener('error', () => {
      connectedRef.current = false;
      setSocketReady(false);
    });

    return () => {
      onDataDisposable.dispose();
      observer.disconnect();
      window.removeEventListener('resize', syncSize);
      if (socket.readyState <= WebSocket.OPEN) socket.close();
      terminal.dispose();
      terminalRef.current = null;
      fitRef.current = null;
      socketRef.current = null;
      connectedRef.current = false;
      setSocketReady(false);
    };
  }, [activeId, resize]);

  const showConnectingOverlay =
    !socketReady && !connectedRef.current && (isLoading || createSession.isPending || !!active);

  return (
    <div className="relative h-full min-h-0 w-full">
      {/* Floating toolbar in the top-right corner; doesn't eat terminal width. */}
      <div className="absolute right-1 top-1 z-10 flex items-center gap-1 rounded-md bg-black/40 px-1 py-0.5 backdrop-blur-sm">
        <Button
          variant="ghost"
          size="icon-sm"
          onClick={() => terminalRef.current?.clear()}
          disabled={!active}
          aria-label="Clear terminal"
          title="Clear"
        >
          <Check className="size-3" />
        </Button>
        <Button
          variant="ghost"
          size="icon-sm"
          onClick={() => createSession.mutate()}
          disabled={createSession.isPending}
          aria-label="New terminal session"
          title="New"
        >
          {createSession.isPending ? <Loader2 className="size-3 animate-spin" /> : <Plus className="size-3" />}
        </Button>
        {active && (
          <Button
            variant="ghost"
            size="icon-sm"
            onClick={() => close.mutate(active.id)}
            disabled={close.isPending}
            aria-label="Close terminal session"
            title="Close"
          >
            <X className="size-3" />
          </Button>
        )}
      </div>

      {approvals.length > 0 && (
        <div className="absolute left-1 right-12 top-9 z-10">
          <ApprovalList approvals={approvals} approve={approve} reject={reject} />
        </div>
      )}

      {/* The xterm pane fills the entire section. */}
      <div
        ref={containerRef}
        className={cn(
          'absolute inset-0 overflow-hidden rounded-lg border border-black/20 bg-[#020617]',
          !socketReady && !connectedRef.current && 'opacity-95'
        )}
      />

      {showConnectingOverlay && (
        <div className="pointer-events-none absolute inset-0 flex items-center justify-center text-[11px] text-muted-foreground">
          {isLoading || createSession.isPending ? 'Starting real terminal…' : 'Connecting to shell…'}
        </div>
      )}

      {!active && !isLoading && !createSession.isPending && (
        <div className="pointer-events-none absolute inset-0 flex flex-col items-center justify-center text-center text-muted-foreground">
          <Inbox className="size-6 text-muted-foreground/40" />
          <div className="mt-2 text-[11px]">Click + to start a terminal session.</div>
        </div>
      )}
    </div>
  );
}

function ApprovalList({
  approvals,
  approve,
  reject,
}: {
  approvals: TerminalApproval[];
  approve: { mutate: (requestId: string) => void; isPending: boolean };
  reject: { mutate: (requestId: string) => void; isPending: boolean };
}) {
  return (
    <div className="rounded-md border border-warning/30 bg-warning/5 p-2 space-y-1.5 shadow">
      <div className="flex items-center gap-1.5 text-[10px] uppercase tracking-wider text-warning font-semibold">
        <ShieldAlert className="size-3" />
        {approvals.length} approval{approvals.length > 1 ? 's' : ''} required
      </div>
      {approvals.map((approval) => (
        <div key={approval.requestId} className="flex items-start justify-between gap-2 rounded-md border border-warning/20 bg-card/70 p-1.5">
          <div className="min-w-0">
            <pre className="whitespace-pre-wrap break-all text-[10.5px] font-mono text-foreground/85">
              {approval.command || approval.inputPreview || '(no command)'}
