import { useEffect, useState, type CSSProperties } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { SessionList } from "@/components/sidebar/SessionList";
import { useStore } from "@nanostores/react";
import { $sessions, $folders, $sessionStates } from "@/store/sessions";

interface SessionSidebarProps {
  activeId?: string;
  collapsed: boolean;
  onToggleCollapsed: () => void;
  onNew: () => void;
  onNewInFolder: (folderId: string) => void;
  onNavigate: (path: string) => void;
}

const SIDEBAR_WIDTH_KEY = "august-session-sidebar-width";
const DEFAULT_WIDTH = 256;
const MIN_WIDTH = 150;
const MAX_VIEWPORT_FRACTION = 0.4;

function loadStoredWidth(): number {
  if (typeof window === "undefined") return DEFAULT_WIDTH;
  const raw = window.localStorage.getItem(SIDEBAR_WIDTH_KEY);
  const parsed = raw ? Number.parseInt(raw, 10) : NaN;
  if (!Number.isFinite(parsed)) return DEFAULT_WIDTH;
  return clampWidth(parsed);
}

function clampWidth(value: number): number {
  const max = Math.max(MIN_WIDTH, Math.floor(window.innerWidth * MAX_VIEWPORT_FRACTION));
  return Math.min(max, Math.max(MIN_WIDTH, value));
}

export function SessionSidebar({
  activeId,
  collapsed,
  onToggleCollapsed,
  onNew,
  onNewInFolder,
  onNavigate,
}: SessionSidebarProps) {
  const sessions = useStore($sessions);
  const folders = useStore($folders);
  const sessionStates = useStore($sessionStates);
  const [width, setWidth] = useState<number>(loadStoredWidth);
  const [isDragging, setIsDragging] = useState(false);

  useEffect(() => {
    if (typeof window === "undefined") return;
    window.localStorage.setItem(SIDEBAR_WIDTH_KEY, String(width));
  }, [width]);

  // Stop dragging if the component unmounts mid-drag.
  useEffect(() => {
    if (!isDragging) return;
    const stop = () => setIsDragging(false);
    window.addEventListener("mouseup", stop);
    window.addEventListener("touchend", stop);
    return () => {
      window.removeEventListener("mouseup", stop);
      window.removeEventListener("touchend", stop);
    };
  }, [isDragging]);

  const startResize = (clientX: number) => {
    const startX = clientX;
    const startW = width;
    setIsDragging(true);

    const onMove = (ev: MouseEvent | TouchEvent) => {
      const next = "touches" in ev && ev.touches.length
        ? ev.touches[0].clientX
        : (ev as MouseEvent).clientX;
      const delta = next - startX;
      setWidth(clampWidth(startW + delta));
    };
    const onUp = () => {
      window.removeEventListener("mousemove", onMove as (e: MouseEvent) => void);
      window.removeEventListener("mouseup", onUp);
      window.removeEventListener("touchmove", onMove as (e: TouchEvent) => void);
      window.removeEventListener("touchend", onUp);
      setIsDragging(false);
    };

    window.addEventListener("mousemove", onMove as (e: MouseEvent) => void);
    window.addEventListener("mouseup", onUp);
    window.addEventListener("touchmove", onMove as (e: TouchEvent) => void, { passive: true });
    window.addEventListener("touchend", onUp);
  };

  const asideStyle: CSSProperties = { width };

  return (
    <>
      <AnimatePresence initial={false}>
        {!collapsed && (
          <motion.aside
            key="sidebar"
            initial={{ width: 0, opacity: 0 }}
            animate={{ width, opacity: 1 }}
            exit={{ width: 0, opacity: 0 }}
            transition={{ duration: isDragging ? 0 : 0.2, ease: [0.16, 1, 0.3, 1] }}
            className="relative shrink-0 bg-sidebar text-sidebar-foreground flex flex-col overflow-hidden"
            style={asideStyle}
          >
            <div className="w-full flex-1 overflow-hidden">
              <SessionList
                activeId={activeId}
                collapsed={collapsed}
                onToggleCollapsed={onToggleCollapsed}
                onSelect={(s) => onNavigate(`/c/${s.id}`)}
                onNew={onNew}
                onNewInFolder={onNewInFolder}
                onNavigate={onNavigate}
              />
            </div>

            <div
              role="separator"
              aria-orientation="vertical"
              aria-label="Resize session sidebar"
              onMouseDown={(e) => {
                e.preventDefault();
                startResize(e.clientX);
              }}
              onTouchStart={(e) => {
                if (e.touches.length) startResize(e.touches[0].clientX);
              }}
              className={`absolute top-0 right-0 h-full w-1 cursor-col-resize select-none touch-none transition-colors hover:bg-primary/40 ${isDragging ? "bg-primary/50" : "bg-transparent"}`}
            />
          </motion.aside>
        )}
      </AnimatePresence>
    </>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { useStore } from '@nanostores/react';
import { useParams } from 'react-router-dom';
import { StatusDot, type StatusTone } from '@/components/StatusDot';
import { $gateway } from '@/store/gateway';
import { $sessions } from '@/store/sessions';
import { api } from '@/api/client';
import { getActiveSessionIds, subscribeActiveSessions } from '@/sections/chat/chat-runtime';

interface LearningStatus {
  status: 'idle' | 'learning' | 'evolved' | 'skipped' | 'failed';
  lastStartedAt?: string | null;
  lastEndedAt?: string | null;
  lastDurationMs?: number;
  lastClientId?: string | null;
  lastTopic?: string | null;
  lastSummary?: string | null;
  lastReason?: string | null;
  lastError?: string | null;
  history?: Array<{
    status: LearningStatus['status'];
    startedAt: string;
    endedAt: string;
    durationMs: number;
    topic?: string | null;
    summary?: string | null;
    reason?: string | null;
    warning?: string | null;
    error?: string | null;
  }>;
}

export function Statusbar() {
  const g = useStore($gateway);
  const sessions = useStore($sessions);
  const { sessionId } = useParams<{ sessionId?: string }>();
  const [now, setNow] = useState(Date.now());
  const [activeSessionIds, setActiveSessionIds] = useState<string[]>([]);

  useEffect(() => {
    return subscribeActiveSessions(setActiveSessionIds);
  }, []);

  useEffect(() => {
    const id = setInterval(() => setNow(Date.now()), 1000);
    return () => clearInterval(id);
  }, []);

  const activeSession = useMemo(() => {
    return sessions.find((s) => s.id === sessionId && !s.isArchived) ?? sessions.find((s) => !s.isArchived) ?? null;
  }, [sessions, sessionId]);

  const activeSessionLabels = useMemo(() => {
    return activeSessionIds
      .map((id) => sessions.find((s) => s.id === id && !s.isArchived)?.title || id.slice(0, 12))
      .filter((label, index, labels) => label && labels.indexOf(label) === index);
  }, [activeSessionIds, sessions]);

  const { data: learning, error } = useQuery<LearningStatus>({
    queryKey: ['memory-learning-status'],
    queryFn: () => api.get<LearningStatus>('/api/brain/learning'),
    refetchInterval: 15_000,
    refetchOnWindowFocus: false,
    retry: 1,
  });

  const gatewayTone: StatusTone = g.status === 'open' ? 'good' : g.status === 'connecting' ? 'muted' : 'bad';
  const gatewayLabel = g.status === 'open' ? `gateway :${g.port || '?'}` : g.status;
  const learningView = getLearningView(learning);
  const elapsedSeconds = Math.max(0, Math.floor((now - Date.parse(activeSession?.startedAt || new Date().toISOString())) / 1000));

  return (
    <div className="flex items-center justify-end mt-1 px-1">
      <div className="flex items-center gap-3 text-[12px] text-muted-foreground font-mono">
        <span className="inline-flex items-center gap-1.5">
          <StatusDot tone={gatewayTone} className="size-1.5" />
          {gatewayLabel}
        </span>
        <span className="text-muted-foreground/30">·</span>
        <span className="inline-flex items-center gap-1.5">
          <StatusDot
            tone={learningView.tone}
            className={cnPulse(learningView.tone === 'warn' && learning?.status === 'learning', 'size-1.5')}
          />
          {learningView.label}
        </span>
        {activeSessionLabels.length > 0 && (
          <>
            <span className="text-muted-foreground/30">·</span>
            <span className="inline-flex items-center gap-1.5">
              <StatusDot tone="warn" className="size-1.5 animate-pulse" />
              {activeSessionLabels.length === 1
                ? `${activeSessionLabels[0]} working`
                : `${activeSessionLabels.length} chats working`}
            </span>
          </>
        )}
        <span className="text-muted-foreground/30">·</span>
        <span className="tabular-nums">{formatClock(elapsedSeconds)}</span>
      </div>
    </div>
  );
}

function getLearningView(learning?: LearningStatus | null) {
  const status = learning?.status || 'idle';
  if (status === 'learning') return { tone: 'warn' as StatusTone, label: 'Learning...' };
  if (status === 'evolved') return { tone: 'good' as StatusTone, label: 'Evolved' };
  if (status === 'failed') return { tone: 'bad' as StatusTone, label: 'Learning failed' };
  if (status === 'skipped') return { tone: 'muted' as StatusTone, label: 'Memory idle' };
  return { tone: 'muted' as StatusTone, label: 'Memory idle' };
}

function formatClock(totalSeconds: number) {
  const h = Math.floor(totalSeconds / 3600);
  const m = Math.floor((totalSeconds % 3600) / 60);
  const s = totalSeconds % 60;
  return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}

function cnPulse(pulse: boolean, extra = '') {
  return `${pulse ? 'animate-pulse shadow-amber-500/40' : ''} ${extra}`.trim();
}

