/* ── StatusPill — small status badge used across Observability ────────── */
/* Variants:
 *   ok       — green dot  (audit 'ok', connected)
 *   warn     — amber dot  (ask, disconnected, available)
 *   danger   — red dot    (denied, failed, error)
 *   muted    — slate dot  (unknown, blocked, idle)
 *
 * Used in:
 *   - Overview stat cards (host-agent health, allowlist counts)
 *   - Audit timeline badges (result, critical, blocked)
 *   - Rollback rows (status)
 *   - Observation gallery (focused app presence)
 */

import { cn } from '@/lib/utils';

export type StatusPillVariant = 'ok' | 'warn' | 'danger' | 'muted';

const VARIANT_CLS: Record<StatusPillVariant, string> = {
    ok: 'bg-success/15 text-success ring-success/30',
    warn: 'bg-warning/15 text-warning ring-warning/30',
    danger: 'bg-danger/15 text-danger ring-danger/30',
    muted: 'bg-white/[0.06] text-muted-foreground ring-white/10'
};

const DOT_CLS: Record<StatusPillVariant, string> = {
    ok: 'bg-success',
    warn: 'bg-warning',
    danger: 'bg-danger',
    muted: 'bg-muted-foreground/60'
};

export function StatusPill({
    variant = 'muted',
    label,
    className,
    dot = true
}: {
    variant?: StatusPillVariant;
    label: string;
    className?: string;
    dot?: boolean;
}) {
    return (
        <span
            className={cn(
                'inline-flex items-center gap-1.5 rounded-full px-2 py-0.5 text-[10px] font-medium ring-1 ring-inset',
                VARIANT_CLS[variant],
                className
            )}
        >
            {dot && <span className={cn('inline-block size-1.5 rounded-full', DOT_CLS[variant])} />}
            {label}
        </span>
    );
}

export function variantForResult(result: string | null | undefined): StatusPillVariant {
    switch (String(result || '')) {
        case 'ok':
            return 'ok';
        case 'blocked':
            return 'warn';
        case 'error':
            return 'danger';
        default:
            return 'muted';
    }
}

export function variantForRollbackStatus(status: string | null | undefined): StatusPillVariant {
    switch (String(status || '')) {
        case 'available':
            return 'warn';
        case 'undone':
            return 'ok';
        case 'failed':
            return 'danger';
        default:
            return 'muted';
    }
}

export function variantForAppPolicy(policy: string | null | undefined): StatusPillVariant {
    switch (String(policy || '')) {
        case 'allow':
            return 'ok';
        case 'ask':
            return 'warn';
        case 'deny':
            return 'danger';
        default:
            return 'muted';
    }
}

export function variantForHostStatus(status: string | null | undefined): StatusPillVariant {
    switch (String(status || '')) {
        case 'connected':
            return 'ok';
        case 'error':
            return 'danger';
        case 'disconnected':
        default:
            return 'muted';
    }
}

/* ── WorkspaceDonut — SVG donut chart for the Model-usage view ──────── */
/* Pure SVG. Slices are computed from cumulative offsets so the chart
 * scales gracefully for any number of segments. Palette lifted from the
 * legacy Usage.tsx for visual parity with the screenshot. */

import { cn } from '@/lib/utils';

export interface DonutSlice {
  label: string;
  value: number;
  percent: number;
  color?: string;
}

export const DEFAULT_COLORS = [
  '#3b7eff',
  '#4ade80',
  '#f59e0b',
  '#f87171',
  '#a78bfa',
  '#06b6d4',
  '#ec4899',
  '#84cc16',
];

const COLOR_CACHE = new Map<string, string>();
/**
 * Stable model → color mapping. Same model always renders in the same
 * color across the donut and the Tokens-per-day chart, so the legend
 * matches the bar segments. Tolerates undefined / null / non-string
 * inputs by falling back to a default color.
 */
export function modelColor(model: unknown): string {
  const key = typeof model === 'string' ? model : '';
  if (COLOR_CACHE.has(key)) return COLOR_CACHE.get(key)!;
  let hash = 5381;
  for (let i = 0; i < key.length; i++) {
    hash = ((hash << 5) + hash + key.charCodeAt(i)) | 0;
  }
  const color = DEFAULT_COLORS[Math.abs(hash) % DEFAULT_COLORS.length];
  COLOR_CACHE.set(key, color);
  return color;
}

interface Props {
  slices: DonutSlice[];
  /** Center label for the donut. */
  centerLabel?: string;
  centerSub?: string;
  /** Max slices to show in the legend. Default 6. */
  legendLimit?: number;
  className?: string;
  /** Format function for the right-hand number column. */
  formatValue?: (v: number) => string;
}

export function WorkspaceDonut({
  slices,
  centerLabel,
  centerSub = 'tokens',
  legendLimit = 6,
  className,
  formatValue,
}: Props) {
  const R = 36;
  const STROKE = 14;
  const C = 2 * Math.PI * R;
  const total = slices.reduce((s, x) => s + x.value, 0) || 1;

  let offset = 0;
  const visible = slices.slice(0, legendLimit);

  return (
    <div className={cn('flex items-center gap-6', className)}>
      <svg viewBox="0 0 96 96" className="size-32 shrink-0">
        <g transform="rotate(-90 48 48)">
          {visible.map((s, i) => {
            const len = (s.value / total) * C;
            const dash = `${len} ${C - len}`;
            const off = -offset;
            offset += len;
            const color = s.color ?? modelColor(s.label);
            return (
              <circle
                key={s.label + i}
                cx="48"
                cy="48"
                r={R}
                fill="none"
                stroke={color}
                strokeWidth={STROKE}
                strokeDasharray={dash}
                strokeDashoffset={off}
              />
            );
          })}
        </g>
        <text
          x="48"
          y="48"
          textAnchor="middle"
          dominantBaseline="central"
          className="fill-white"
          style={{ fontSize: 13, fontWeight: 600 }}
        >
          {centerLabel ?? total.toLocaleString()}
        </text>
        <text
          x="48"
          y="62"
          textAnchor="middle"
          dominantBaseline="central"
          className="fill-white/70"
          style={{ fontSize: 7 }}
        >
          {centerSub}
        </text>
      </svg>

      <div className="flex-1 min-w-0 space-y-1.5">
        {visible.map((s, i) => {
          const color = s.color ?? modelColor(s.label);
          return (
            <div key={s.label + i} className="flex items-center gap-2 text-xs">
              <span
                className="size-2 rounded-full shrink-0"
                style={{ backgroundColor: color }}
              />
              <span className="flex-1 truncate text-foreground">{s.label}</span>
              <span className="text-muted-foreground tabular-nums shrink-0">
                {formatValue ? formatValue(s.value) : s.value.toLocaleString()}
              </span>
              <span className="text-muted-foreground tabular-nums shrink-0 w-12 text-right">
                {s.percent.toFixed(1)}%
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ── WorkspaceHeatmap — GitHub-style activity heatmap ────────────────── */
/* Pure CSS. 5-row layout so the calendar reads like a week column. Lifted
 * from the legacy Usage.tsx so visual parity is preserved. */

import { useMemo } from 'react';
import { cn } from '@/lib/utils';

export interface HeatmapCell {
  date: string; // YYYY-MM-DD
  count: number;
}

interface Props {
  cells: HeatmapCell[];
  className?: string;
  /** Show the Less → More intensity legend. Defaults to true. */
  legend?: boolean;
}

const LEVELS = [
  'bg-white/[0.025]',
  'bg-success/40',
  'bg-success/60',
  'bg-success/80',
  'bg-success',
];

function intensity(count: number, max: number): number {
  if (count <= 0 || max <= 0) return 0;
  const r = count / max;
  if (r < 0.25) return 1;
  if (r < 0.5) return 2;
  if (r < 0.75) return 3;
  return 4;
}

export function WorkspaceHeatmap({ cells, className, legend = true }: Props) {
  const max = useMemo(() => Math.max(0, ...cells.map((c) => c.count)), [cells]);

  // Reshape into a 5-row grid; columns flow top-to-bottom then left-to-right.
  const cols = Math.ceil(cells.length / 5);
  const grid: HeatmapCell[][] = Array.from({ length: 5 }, () => []);
  cells.forEach((cell, i) => grid[Math.floor(i / 5)].push(cell));

  return (
    <div className={cn('space-y-2', className)}>
      <div className="flex gap-[2px] overflow-x-auto pb-1">
        {grid.map((row, r) => (
          <div key={r} className="flex flex-col gap-[2px] shrink-0">
            {row.map((cell) => {
              const level = intensity(cell.count, max);
              return (
                <div
                  key={cell.date}
                  title={`${cell.date}: ${cell.count.toLocaleString()}`}
                  className={cn('size-[9px] rounded-[2px]', LEVELS[level])}
                />
              );
            })}
          </div>
        ))}
      </div>
      {legend && (
        <div className="flex items-center justify-end gap-2 text-[10px] text-muted-foreground">
          <span>Less</span>
          <div className="flex gap-[2px]">
            {LEVELS.map((cls, i) => (
              <div key={i} className={cn('size-[9px] rounded-[2px]', cls)} />
            ))}
          </div>
          <span>More</span>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { FolderOpen, ChevronDown, Check, Plus, X } from 'lucide-react';
import { useStore } from '@nanostores/react';
import { cn } from '@/lib/utils';
import {
  $workspaces,
  $currentWorkspaceId,
  addWorkspace,
  removeWorkspace,
  setCurrentWorkspace,
  type Workspace,
} from '@/store/workspaces';
import { isTauri } from '@/lib/tauri-detect';

interface WorkspaceSelectorProps {
  sessionId: string | null;
  onWorkspaceChange?: (workspace: Workspace | null) => void;
}

export function WorkspaceSelector({ sessionId, onWorkspaceChange }: WorkspaceSelectorProps) {
  const [open, setOpen] = useState(false);
  const workspaces = useStore($workspaces);
  const currentWorkspaceId = useStore($currentWorkspaceId);
  const rootRef = useRef<HTMLDivElement>(null);
  const dirInputRef = useRef<HTMLInputElement>(null);

  const currentWorkspace = workspaces.find(w => w.id === currentWorkspaceId) ?? null;

  // Close on click outside
  useEffect(() => {
    if (!open) return;
    const handler = (e: MouseEvent) => {
      if (rootRef.current && !rootRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [open]);

  // Close on Escape
  useEffect(() => {
    if (!open) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setOpen(false);
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [open]);

  const handleSelectWorkspace = (ws: Workspace) => {
    setCurrentWorkspace(ws.id);
    setOpen(false);
    onWorkspaceChange?.(ws);
  };

  const handleOpenFolder = async () => {
    let path: string | null = null;

    if (isTauri) {
      try {
        const { invoke } = await import('@tauri-apps/api/core');
        path = await invoke<string | null>('select_directory');
      } catch (err) {
        console.error('[WorkspaceSelector] Tauri directory picker failed:', err);
      }
    } else {
      // Use the hidden directory input to open the native OS folder picker.
      // showDirectoryPicker() only returns the folder name, not the absolute
      // path, so we use <input type="file" webkitdirectory> instead — Chrome's
      // File.path exposes the full filesystem path the backend needs.
      dirInputRef.current?.click();
      return; // path will be set by the input's change handler
    }

    if (path) {
      const ws = addWorkspace(path);
      setOpen(false);
      onWorkspaceChange?.(ws);
    }
  };

  const handleDirPicked = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    // Chrome exposes the full path on File.path; fall back to extracting from webkitRelativePath
    const fullPath = file.path
      || file.webkitRelativePath.slice(0, file.webkitRelativePath.indexOf('/'));
    if (fullPath) {
      const ws = addWorkspace(fullPath);
      setOpen(false);
      onWorkspaceChange?.(ws);
    }
    // Reset so the same directory can be re-selected
    e.target.value = '';
  };

  const handleRemoveWorkspace = (e: React.MouseEvent, ws: Workspace) => {
    e.stopPropagation();
    removeWorkspace(ws.id);
    onWorkspaceChange?.(null);
  };

  return (
    <div ref={rootRef} className="relative">
      <input
        ref={dirInputRef}
        type="file"
        webkitdirectory=""
        directory=""
        className="hidden"
        onChange={handleDirPicked}
      />
      <button
        onClick={() => setOpen(v => !v)}
        className={cn(
          'flex items-center gap-1.5 px-2 py-1 rounded-md text-xs transition',
          'hover:bg-muted text-muted-foreground hover:text-foreground',
          'border border-transparent hover:border-border/60',
          currentWorkspace
            ? 'text-foreground/80'
            : 'text-muted-foreground'
        )}
        title={currentWorkspace ? `${currentWorkspace.name}\n${currentWorkspace.path}` : 'Select workspace'}
      >
        <FolderOpen className="size-3.5 shrink-0" />
        <span className="truncate max-w-[120px]">
          {currentWorkspace?.name ?? 'Open folder'}
        </span>
        <ChevronDown className={cn(
          'size-3 transition-transform',
          open && 'rotate-180'
        )} />
      </button>

      {open && (
        <div className="absolute left-0 bottom-full mb-2 w-72 max-h-80 overflow-y-auto bg-card border border-border rounded-xl shadow-2xl p-1.5 z-50 animate-in fade-in slide-in-from-bottom-2 duration-150">
          <div className="px-2 py-1.5 text-[10px] text-muted-foreground uppercase font-semibold">
            Workspaces
          </div>

          {workspaces.length === 0 && (
            <div className="px-2.5 py-3 text-[11px] text-muted-foreground text-center">
              No workspaces yet. Open a folder to get started.
            </div>
          )}

          {workspaces.map(ws => (
            <button
              key={ws.id}
              onClick={() => handleSelectWorkspace(ws)}
              className={cn(
                'w-full text-left px-2.5 py-1.5 rounded-md text-xs hover:bg-muted transition flex items-center gap-2 group',
                ws.id === currentWorkspaceId && 'bg-primary/10 text-primary'
              )}
            >
              <FolderOpen className="size-3.5 shrink-0 text-muted-foreground" />
              <div className="flex-1 min-w-0">
                <div className="font-medium truncate">{ws.name}</div>
                <div className="text-[10px] text-muted-foreground truncate">{ws.path}</div>
              </div>
              {ws.id === currentWorkspaceId && (
                <Check className="size-3.5 shrink-0 text-primary" />
              )}
              <button
                onClick={(e) => handleRemoveWorkspace(e, ws)}
                className="p-0.5 rounded opacity-0 group-hover:opacity-100 hover:bg-destructive/20 hover:text-destructive transition"
                title="Remove workspace"
              >
                <X className="size-3" />
              </button>
            </button>
          ))}

          <div className="border-t border-border/70 mt-1 pt-1">
            <button
              onClick={handleOpenFolder}
              className="w-full text-left px-2.5 py-1.5 rounded-md text-xs hover:bg-muted transition flex items-center gap-2 text-primary"
            >
              <Plus className="size-3.5" />
              <span>Open folder</span>
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

/* ── WorkspaceShell — settings-panel shell (chat-side) ───────────────── */
/* Mounted by SettingsPage inside ChatLayout. Renders the dark left rail */
/* + scrollable content area. Section nav clicks use `/settings/:id` — */
/* the Settings overlay route. The previous `/workspace/*` routes were     */
/* retired when Settings absorbed the panel.                                   */

import { type ReactNode, useMemo, useState } from 'react';
import {
  ArrowLeft,
  Activity,
  Boxes,
  ChevronDown,
  ChevronRight,
  Globe,
  LineChart,
  ShieldCheck,
  Wrench,
  type LucideIcon,
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { WorkspaceNavLink } from './WorkspaceNavLink';
import { SettingsSearch } from '@/components/settings/SettingsSearch';
import { useSettingsAdvancedPreference } from '@/hooks/useSettingsAdvancedPreference';
import { cn } from '@/lib/utils';
import {
  SETTINGS_SECTIONS,
  SETTINGS_CATEGORIES,
  type SettingsSection,
} from '@/settings/settings-registry';

export interface WorkspaceSectionMeta {
  id: string;
  label: string;
  icon: LucideIcon;
  /** Optional category label shown above the item. */
  category?: string;
}

/** Map of category id → lucide icon for the rail group header. */
const CATEGORY_ICONS: Record<string, LucideIcon> = {
  general: Activity,
  intelligence: Boxes,
  tools: Wrench,
  activity: LineChart,
  security: ShieldCheck,
};

interface WorkspaceShellProps {
  sections: WorkspaceSectionMeta[];
  active: string;
  children: ReactNode;
  className?: string;
}

export function WorkspaceShell({
  sections,
  active,
  children,
  className,
}: WorkspaceShellProps) {
  const navigate = useNavigate();
  const [query, setQuery] = useState('');
  const { showAdvanced, toggle: toggleAdvanced } = useSettingsAdvancedPreference();

  // Resolve each section's category label, icon, tier, description, and
  // keywords. Falls back to the raw `category` string if a section isn't
  // in the settings registry (e.g., legacy workspace-registry panels
  // still calling this).
  const decorated = useMemo(() => {
    return sections.map((s) => {
      const fromRegistry: SettingsSection | undefined =
        SETTINGS_SECTIONS.find((r) => r.id === s.id);
      const categoryLabel =
        SETTINGS_CATEGORIES.find((c) => c.id === s.category)?.label ??
        s.category ??
        '';
      const categoryIcon = CATEGORY_ICONS[s.category ?? ''] ?? Globe;
      return {
        ...s,
        categoryLabel,
        categoryIcon,
        tier: fromRegistry?.tier ?? 'basic',
        // Pull description/keywords from the registry when available —
        // gives the search something useful to match.
        description: fromRegistry?.description ?? '',
        keywords: fromRegistry?.keywords ?? [],
      };
    });
  }, [sections]);

  // Apply tier filter: when "Show advanced" is off, hide advanced items
  // UNLESS the user has deep-linked to one (we keep the active section
  // visible so legacy URLs continue to work).
  const tiered = useMemo(() => {
    if (showAdvanced) return decorated;
    return decorated.filter((s) => s.tier === 'basic' || s.id === active);
  }, [decorated, showAdvanced, active]);

  // Filter by free-text query (matches label, description, keywords).
  // Search bypasses the tier filter so users can still find advanced
  // sections by keyword even when advanced is hidden.
  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    const source = q ? decorated : tiered;
    const m = new Map<string, typeof decorated>();
    for (const [cat, items] of groupAllByCategory(source).entries()) {
      const kept = items.filter((s) => {
        if (s.label.toLowerCase().includes(q)) return true;
        if (s.description.toLowerCase().includes(q)) return true;
        if (s.keywords.some((k) => k.toLowerCase().includes(q)) ) return true;
        return false;
      });
      if (kept.length > 0) m.set(cat, kept);
    }
    return m;
  }, [decorated, tiered, query]);

  const isFiltering = query.trim().length > 0;
  const totalShown = useMemo(
    () => Array.from(filtered.values()).reduce((n, items) => n + items.length, 0),
    [filtered],
  );

  return (
    <div className={cn('flex h-full min-h-0', className)}>
      {/* Left rail */}
      <aside className="w-64 shrink-0 border-r border-white/[0.06] bg-[#0f0f12] flex flex-col">
        <button
          onClick={() => navigate('/')}
          className="flex items-center gap-2 px-4 py-3 text-sm text-muted-foreground hover:text-foreground transition text-left"
        >
          <ArrowLeft className="size-4" />
          Back to workspace
        </button>
        <div className="px-3 pb-2">
          <SettingsSearch value={query} onChange={setQuery} />
          {isFiltering && (
            <p className="mt-1.5 px-1 text-[10px] text-muted-foreground/70">
              {totalShown} of {decorated.length} sections
            </p>
          )}
        </div>
        <nav className="flex-1 overflow-y-auto py-1">
          {totalShown === 0 ? (
            <div className="px-4 py-6 text-center text-xs text-muted-foreground">
              No sections match{' '}
              <span className="font-mono">&ldquo;{query}&rdquo;</span>.
            </div>
          ) : (
            Array.from(filtered.entries()).map(([category, items]) => {
              const Icon = items[0]?.categoryIcon ?? Globe;
              const categoryLabel = items[0]?.categoryLabel ?? category;
              return (
                <div key={category || 'default'} className="mb-1">
                  <div className="flex items-center gap-1.5 px-4 pt-2 pb-1 text-[10px] uppercase tracking-widest text-muted-foreground/50 font-semibold">
                    <Icon className="size-3" aria-hidden="true" />
                    <span>{categoryLabel}</span>
                  </div>
                  {items.map((s) => (
                    <WorkspaceNavLink
                      key={s.id}
                      icon={s.icon}
                      label={s.label}
                      active={active === s.id}
                      onSelect={() => {
                        setQuery('');
                        navigate(`/settings/${s.id}`);
                      }}
                    />
                  ))}
                </div>
              );
            })
          )}
        </nav>

        {/* Bottom: Show advanced toggle. Quiet and always visible so
         * power users can reveal advanced sections without using search. */}
        <div className="shrink-0 border-t border-white/[0.06] px-3 py-2">
          <button
            type="button"
            onClick={toggleAdvanced}
            aria-pressed={showAdvanced}
            className="flex w-full items-center justify-between rounded-md px-2 py-1.5 text-xs text-muted-foreground hover:bg-white/[0.04] hover:text-foreground transition"
          >
            <span>{showAdvanced ? 'Hide advanced' : 'Show advanced'}</span>
            {showAdvanced
              ? <ChevronDown className="size-3.5" aria-hidden="true" />
              : <ChevronRight className="size-3.5" aria-hidden="true" />}
          </button>
        </div>
      </aside>

      {/* Main content — each section renders its own h1 inside */}
      <div className="flex-1 min-w-0 overflow-auto">{children}</div>
    </div>
  );
}

/** Re-group a flat section list by category (used by search to bypass
 *  the tier filter). Generic so callers can pass either the full
 *  decorated list or the tier-filtered one. */
function groupAllByCategory<T extends { category?: string }>(items: ReadonlyArray<T>) {
  const m = new Map<string, T[]>();
  for (const s of items) {
    const k = s.category ?? '';
    if (!m.has(k)) m.set(k, []);
    m.get(k)!.push(s);
  }
  return m;
}

/* ── useBackendStatus — backend supervisor status for Settings ───────── */
/* Polls `proxy_status`, reads the last spawn error, and exposes a
 * `syncBackendDeps` trigger so the UI can show backend up/down/setting-up
 * and kick off a dependency re-sync. Tauri-only; in the browser it
 * reports "unsupported" (no native supervisor).
 */

import { useCallback, useEffect, useState } from 'react';
import { invoke } from '@tauri-apps/api/core';
import { isTauri } from '@/lib/tauri-detect';

export type BackendSync = 'unknown' | 'up-to-date' | 'syncing' | 'needs_setup' | 'error';

export interface BackendStatus {
    proxy: 'up' | 'down' | 'unknown';
    port: number | null;
    lastError: string | null;
    sync: BackendSync;
    syncError: string | null;
    loading: boolean;
}

const INITIAL: BackendStatus = {
    proxy: 'unknown',
    port: null,
    lastError: null,
    sync: 'unknown',
    syncError: null,
    loading: false,
};

export function useBackendStatus() {
    const [status, setStatus] = useState<BackendStatus>(INITIAL);
    const tauri = isTauri;

    const refresh = useCallback(async () => {
        if (!tauri) return;
        setStatus((s) => ({ ...s, loading: true }));
        try {
            const proxy = (await invoke<string>('proxy_status')) as string;
            let proxyState: BackendStatus['proxy'] = 'unknown';
            let port: number | null = null;
            if (proxy.startsWith('ok:')) {
                proxyState = 'up';
                port = Number(proxy.split(':')[1]) || null;
            } else {
                proxyState = 'down';
            }
            let lastError: string | null = null;
            try {
                lastError = (await invoke<string | null>('backend_last_error')) || null;
            } catch {
                lastError = null;
            }
            setStatus((s) => ({ ...s, proxy: proxyState, port, lastError }));
        } catch {
            setStatus((s) => ({ ...s, proxy: 'unknown' }));
        } finally {
            setStatus((s) => ({ ...s, loading: false }));
        }
    }, [tauri]);

    const sync = useCallback(async () => {
        if (!tauri) return;
        setStatus((s) => ({ ...s, sync: 'syncing', syncError: null }));
        try {
            const res = (await invoke<string>('sync_backend_deps')) as string;
            if (res.startsWith('error')) {
                setStatus((s) => ({ ...s, sync: 'error', syncError: res.slice(6) }));
            } else if (res === 'needs_setup') {
                setStatus((s) => ({ ...s, sync: 'needs_setup' }));
            } else if (res === 'syncing') {
                setStatus((s) => ({ ...s, sync: 'syncing' }));
                // The sync is detached; re-check shortly after.
                setTimeout(() => refresh(), 4000);
            } else {
                setStatus((s) => ({ ...s, sync: 'up-to-date' }));
            }
        } catch (e) {
            setStatus((s) => ({
                ...s,
                sync: 'error',
                syncError: e instanceof Error ? e.message : String(e),
            }));
        }
    }, [tauri, refresh]);

    useEffect(() => {
        if (!tauri) return;
        refresh();
    }, [tauri, refresh]);

    return { status, refresh, sync, isTauri: tauri };
}

/* ── useLogStream — WebSocket subscriber for Settings → Backend Monitor */
/* Connects to /ui/logs/stream, backfills from /api/logs/recent, appends
 * live frames, dedupes by event id, and exposes pause/resume/clear.
 * Reconnects with exponential backoff (1s → 30s). Capped at MAX_EVENTS. */

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { atom, onMount } from 'nanostores';
import { useStore } from '@nanostores/react';
import { getRecentLogs, type LogEvent } from '@/api/api-client';
import { whenReady } from '@/api/client';

const MAX_EVENTS = 10_000;
const BACKFILL_LIMIT = 500;

export type StreamStatus = 'connecting' | 'live' | 'disconnected' | 'paused';

interface WSFrame {
    type: 'snapshot' | 'event';
    event?: LogEvent;
    events?: LogEvent[];
}

interface StreamState {
    events: LogEvent[];
    status: StreamStatus;
    lastError: string | null;
    retryInMs: number | null;
}

const streamAtom = atom<StreamState>({
    events: [],
    status: 'connecting',
    lastError: null,
    retryInMs: null,
});

const pausedAtom = atom<boolean>(false);

let _socket: WebSocket | null = null;
let _retryTimer: ReturnType<typeof setTimeout> | null = null;
let _retryDelay = 1000;
let _mountedSubscribers = 0;

function pushEvents(newEvents: LogEvent[]) {
    const prev = streamAtom.get().events;
    const seen = new Set(prev.map((e) => e.id));
    const merged: LogEvent[] = [];
    for (let i = newEvents.length - 1; i >= 0; i--) {
        const e = newEvents[i];
        if (!seen.has(e.id)) {
            seen.add(e.id);
            merged.push(e);
        }
    }
    if (merged.length === 0) return;
    const next = [...merged.reverse(), ...prev].slice(0, MAX_EVENTS);
    streamAtom.set({ ...streamAtom.get(), events: next });
}

function pushEvent(event: LogEvent) {
    const prev = streamAtom.get().events;
    if (prev.some((e) => e.id === event.id)) return;
    streamAtom.set({ ...streamAtom.get(), events: [event, ...prev].slice(0, MAX_EVENTS) });
}

function scheduleRetry() {
    if (_retryTimer) return;
    const delay = _retryDelay;
    streamAtom.set({ ...streamAtom.get(), status: 'disconnected', retryInMs: delay });
    _retryTimer = setTimeout(() => {
        _retryTimer = null;
        _retryDelay = Math.min(_retryDelay * 2, 30_000);
        connect();
    }, delay);
}

async function connect() {
    if (_socket && (_socket.readyState === WebSocket.OPEN || _socket.readyState === WebSocket.CONNECTING)) return;
    // Tauri desktop: connect directly to the backend (loopback HTTP → ws).
    // Browser dev: same-origin; Vite proxy handles the WS upgrade.
    let wsUrl: string;
    const baseUrl = await whenReady();
    if (baseUrl) {
        const host = baseUrl.replace(/^https?:\/\//, '');
        wsUrl = `ws://${host}/api/logs/stream`;
    } else {
        const proto = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
        wsUrl = `${proto}//${window.location.host}/api/logs/stream`;
    }
    let ws: WebSocket;
    try {
        ws = new WebSocket(wsUrl);
    } catch (err) {
        streamAtom.set({ ...streamAtom.get(), lastError: String(err), status: 'disconnected' });
        scheduleRetry();
        return;
    }
    _socket = ws;
    streamAtom.set({ ...streamAtom.get(), status: 'connecting', lastError: null });

    ws.onopen = async () => {
        _retryDelay = 1000;
        streamAtom.set({ ...streamAtom.get(), status: 'live', retryInMs: null });
        try {
            const backfill = await getRecentLogs(BACKFILL_LIMIT);
            pushEvents(backfill.events || []);
        } catch (e) {
            // Backfill is best-effort; live stream still works
        }
    };
    ws.onmessage = (msg) => {
        if (pausedAtom.get()) return;
        let frame: WSFrame;
        try { frame = JSON.parse(msg.data); } catch { return; }
        if (frame.type === 'snapshot' && Array.isArray(frame.events)) {
            pushEvents(frame.events);
        } else if (frame.type === 'event' && frame.event) {
            pushEvent(frame.event);
        }
    };
    ws.onerror = () => {
        streamAtom.set({ ...streamAtom.get(), lastError: 'WebSocket error' });
    };
    ws.onclose = () => {
        _socket = null;
        if (_mountedSubscribers > 0) scheduleRetry();
        else streamAtom.set({ ...streamAtom.get(), status: 'disconnected', retryInMs: null });
    };
}

function disconnect() {
    if (_retryTimer) { clearTimeout(_retryTimer); _retryTimer = null; }
    if (_socket) {
        const s = _socket;
        _socket = null;
        try { s.close(); } catch { /* ignore */ }
    }
}

export function useLogStream() {
    const state = useStore(streamAtom);
    const paused = useStore(pausedAtom);
    const isMounted = useRef(false);

    useEffect(() => {
        if (isMounted.current) return;
        isMounted.current = true;
        _mountedSubscribers += 1;
        if (!_socket) connect();
        return () => {
            _mountedSubscribers -= 1;
            if (_mountedSubscribers <= 0) {
                _mountedSubscribers = 0;
                disconnect();
            }
        };
    }, []);

    const pause = useCallback(() => pausedAtom.set(true), []);
    const resume = useCallback(() => pausedAtom.set(false), []);
    const clear = useCallback(() => {
        streamAtom.set({ ...streamAtom.get(), events: [] });
    }, []);

    const status: StreamStatus = paused ? 'paused' : state.status;

    return useMemo(
        () => ({ events: state.events, status, lastError: state.lastError, retryInMs: state.retryInMs, pause, resume, clear }),
        [state.events, status, state.lastError, state.retryInMs, pause, resume, clear],
    );
}

// Mount-once: ensure the atom is hot so first consumer gets a fast render.
// Not required but useful for tests.
onMount(streamAtom, () => () => { /* nothing to clean on unmount */ });

/* ── Provider availability (React Query) ──────────────────────────── */
/* Replaces the one-shot useEffect in ChatThread so newly-added providers */
/* appear in the model dropdown without remounting the chat. */

import { useQuery } from '@tanstack/react-query';

export interface ProviderAvailability {
  id: string;
  name: string;
  apiMode: string;
  isAvailable: boolean;
}

export interface ProviderAvailabilityResponse {
  activeProvider: string | null;
  providers: ProviderAvailability[];
}

export function useProviderAvailability() {
  const q = useQuery<ProviderAvailabilityResponse>({
    queryKey: ['provider-availability'],
    queryFn: async () => {
      const res = await fetch('/api/config/activeProvider');
      if (!res.ok) throw new Error('Failed to fetch provider availability');
      return res.json();
    },
    refetchInterval: 30_000,
    staleTime: 15_000,
  });
  return {
    providers: q.data?.providers ?? ([] as ProviderAvailability[]),
    activeProvider: q.data?.activeProvider ?? null,
    isLoading: q.isLoading,
    error: q.error,
    refetch: q.refetch,
  };
}

/* ── Provider Onboarding State ────────────────────────────────────────── */
/* Determines whether the first-launch onboarding modal should show.
   The modal is shown when the providers list is empty AND the user has not
   previously dismissed or skipped onboarding. */

import { useState } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { providersApi, type Provider } from '@/api/providers';

const SKIP_KEY = 'august-onboarding-skipped';

export function useProviderOnboardingState() {
  const qc = useQueryClient();
  const [tick, setTick] = useState(0);

  const providersQ = useQuery<Provider[]>({
    queryKey: ['providers'],
    queryFn: () => providersApi.list(),
    staleTime: 30_000,
  });

  const providers = providersQ.data ?? [];
  const dismissed = localStorage.getItem(SKIP_KEY) === 'true';
  const shouldShow = !dismissed && providers.length === 0 && !providersQ.isLoading;

  const skip = () => {
    localStorage.setItem(SKIP_KEY, 'true');
    qc.invalidateQueries({ queryKey: ['providers'] });
    setTick((t) => t + 1);
  };

  const resetDismissed = () => {
    localStorage.removeItem(SKIP_KEY);
  };

  return {
    shouldShow,
    providers,
    dismissed,
    isLoading: providersQ.isLoading,
    skip,
    resetDismissed,
  };
}

/* ── Settings Advanced Preference ────────────────────────────────────────── */
/* Persists the rail's "Show advanced" toggle to localStorage. Defaults to
 * hidden (false) so first-time users see the short, beginner-friendly list.
 *
 * Mirrors the localStorage pattern in `useSubagentViewPreference.ts`. */

import { useState, useCallback } from 'react';

const STORAGE_KEY = 'august-settings-advanced';

type AdvancedPreference = boolean;

function loadPreference(): AdvancedPreference {
  try {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved === 'true') return true;
    if (saved === 'false') return false;
  } catch { /* noop */ }
  return false; // default: beginner-friendly, advanced hidden
}

function savePreference(value: AdvancedPreference) {
  try {
    localStorage.setItem(STORAGE_KEY, value ? 'true' : 'false');
  } catch { /* noop */ }
}

export function useSettingsAdvancedPreference() {
  const [showAdvanced, setShowAdvancedState] = useState<AdvancedPreference>(loadPreference);

  const setShowAdvanced = useCallback(
    (next: AdvancedPreference | ((prev: AdvancedPreference) => AdvancedPreference)) => {
      setShowAdvancedState((prev) => {
        const value =
          typeof next === 'function'
            ? (next as (prev: AdvancedPreference) => AdvancedPreference)(prev)
            : next;
        savePreference(value);
        return value;
      });
    },
    [],
  );

  const toggle = useCallback(() => {
    setShowAdvanced((prev) => !prev);
  }, [setShowAdvanced]);

  return { showAdvanced, setShowAdvanced, toggle };
}

/* ── Subagent Stream Hook ────────────────────────────────────────────── */
/* React hook wrapping subscribeToSubagentEvents. Manages a list of active
   sub-agents and their events for a session. */

import { useState, useEffect, useCallback, useRef } from 'react';
import {
  subscribeToSubagentEvents,
  listActive,
  type SubagentInfo,
  type SubagentEvent,
} from '@/api/subagents';

interface UseSubagentStreamResult {
  agents: SubagentInfo[];
  events: SubagentEvent[];
  loading: boolean;
  error: string | null;
  refresh: () => void;
}

export function useSubagentStream(sessionId: string | null): UseSubagentStreamResult {
  const [agents, setAgents] = useState<SubagentInfo[]>([]);
  const [events, setEvents] = useState<SubagentEvent[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const unsubRef = useRef<(() => void) | null>(null);

  const refresh = useCallback(async () => {
    if (!sessionId) return;
    setLoading(true);
    try {
      const active = await listActive(sessionId);
      setAgents(active);
      setError(null);
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : 'Failed to fetch agents');
    } finally {
      setLoading(false);
    }
  }, [sessionId]);

  useEffect(() => {
    if (!sessionId) return;

    // Initial fetch
    refresh();

    // Subscribe to SSE events
    const unsub = subscribeToSubagentEvents(sessionId, (event: SubagentEvent) => {
      setEvents((prev) => [...prev.slice(-100), event]); // keep last 100

      // Update agent status from events
      if (event.taskId && (event.type === 'subagentCompleted' || event.type === 'subagentDone')) {
        setAgents((prev) =>
          prev.map((a) =>
            a.taskId === event.taskId
              ? { ...a, status: 'completed', finishedAt: Date.now() }
              : a,
          ),
        );
      } else if (event.type === 'subagentStarted' && event.agentId && event.goal) {
        // Capture into locals so TS narrowing on `event.agentId` / `event.goal`
        // survives the closure below (the inline conditional narrowing does
        // not propagate into callback bodies).
        const taskId = event.taskId ?? `task_${Date.now()}`;
        const agentId: string = event.agentId;
        const goal: string = event.goal;
        setAgents((prev) => {
          const next: SubagentInfo[] = [
            ...prev,
            {
              taskId,
              agentId,
              goal,
              status: 'running',
              startedAt: Date.now(),
              elapsed: 0,
            },
          ];
          return next;
        });
      }
    });

    unsubRef.current = unsub;

    return () => {
      unsub();
      unsubRef.current = null;
    };
  }, [sessionId, refresh]);

  return { agents, events, loading, error, refresh };
}

/* ── Subagent View Preference ────────────────────────────────────────── */
/* Persists the subagent panel view mode (collapsed/expanded) to localStorage. */

import { useState, useCallback } from 'react';

const STORAGE_KEY = 'august-subagent-view';

type SubagentView = 'collapsed' | 'expanded';

function loadPreference(): SubagentView {
  try {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved === 'collapsed' || saved === 'expanded') return saved;
  } catch { /* noop */ }
  return 'expanded'; // default
}

function savePreference(view: SubagentView) {
  try {
    localStorage.setItem(STORAGE_KEY, view);
  } catch { /* noop */ }
}

export function useSubagentViewPreference() {
  const [view, setViewState] = useState<SubagentView>(loadPreference);

  // Accept either a direct value (legacy callers) or an updater function
  // (matches React's `Dispatch<SetStateAction<T>>` shape so call sites can
  // use `(prev) => ...` safely).
  const setView = useCallback(
    (newView: SubagentView | ((prev: SubagentView) => SubagentView)) => {
      setViewState((prev) => {
        const next =
          typeof newView === 'function'
            ? (newView as (prev: SubagentView) => SubagentView)(prev)
            : newView;
        savePreference(next);
        return next;
      });
    },
    [],
  );

  const toggle = useCallback(() => {
    setView((prev) => (prev === 'expanded' ? 'collapsed' : 'expanded'));
  }, [setView]);

  return { view, setView, toggle };
}

/* ── File-icon utility ─ brand-aware language/file icons ──────────── */
/* Single source of truth for language-coloured file icons used by       */
/* DisclosureRow, ToolCallItem, DiffView, and anywhere else that        */
/* renders a filename.                                                  */
/*                                                                       */
/* Coverage: 60+ kinds grouped by category. Brand logos come from        */
/* react-icons/si (Simple Icons, official CC0 SVGs). No-brand formats    */
/* fall back to themed lucide-react File* variants.                      */

import type { ComponentType, SVGProps } from 'react';
import {
  // Web / JS ecosystem
  SiReact, SiTypescript, SiJavascript, SiVuedotjs, SiSvelte,
  // Backend languages
  SiPython, SiRuby, SiGo, SiRust, SiOpenjdk, SiKotlin, SiSwift,
  SiC, SiCplusplus, SiSharp, SiPhp, SiScala, SiElixir, SiDart,
  // Shell / scripting
  SiGnubash, SiZsh, SiPowers, SiLua, SiPerl, SiHaskell, SiClojure,
  // Web markup / styles
  SiHtml5, SiCss3, SiSass, SiLess, SiPostcss,
  // Data / config
  SiYaml, SiMarkdown, SiDotenv,
  // Query / schema
  SiSqlite, SiPostgresql, SiMysql, SiGraphql,
  // Build / tooling
  SiDocker, SiApachemaven, SiGradle,
  // VCS / meta
  SiGitignoredotio,
} from 'react-icons/si';
import {
  FileText, FileCode, FileCog, FileJson, FileImage, FileVideo, FileMusic,
  FileType, FileArchive, FileSpreadsheet, FileLock, File as FileGeneric,
  Settings, BookOpen, ScrollText, Hash, BookText, Globe, Network,
} from 'lucide-react';

type IconComp = ComponentType<{ size?: number; color?: string } & SVGProps<SVGSVGElement>>;

export type FileKind =
  // Web / JS
  | 'react' | 'typescript' | 'javascript' | 'vue' | 'svelte'
  // Backend
  | 'python' | 'ruby' | 'go' | 'rust' | 'java' | 'kotlin' | 'swift'
  | 'c' | 'cpp' | 'csharp' | 'php' | 'scala' | 'elixir' | 'dart'
  // Shell / scripting
  | 'shell' | 'powershell' | 'lua' | 'perl' | 'haskell' | 'clojure'
  // Web markup / styles
  | 'html' | 'css' | 'scss' | 'less' | 'stylus' | 'postcss'
  // Data / config
  | 'json' | 'yaml' | 'toml' | 'ini' | 'xml' | 'csv' | 'env' | 'lock'
  // Docs
  | 'markdown' | 'rst' | 'asciidoc' | 'latex'
  // Query / schema
  | 'sql' | 'graphql' | 'protobuf'
  // Build / tooling
  | 'docker' | 'makefile' | 'cmake' | 'gradle' | 'maven' | 'gnumakefile'
  // VCS / meta
  | 'gitignore' | 'editorconfig' | 'license' | 'changelog' | 'readme' | 'log'
  // Media / assets
  | 'image' | 'video' | 'audio' | 'font' | 'binary'
  | 'archive' | 'pdf' | 'ebook' | 'spreadsheet'
  // Fallback
  | 'config' | 'plaintext' | 'unknown';

export interface FileIcon {
  Icon: IconComp;
  color: string;
  kind: FileKind;
}

const ICONS: Record<FileKind, { Icon: IconComp; color: string }> = {
  // ── Web / JS ecosystem ──
