export function Archive() {
  const navigate = useNavigate();
  const sessions = useStore($sessions);
  const folders = useStore($folders);

  const [filter, setFilter] = useState('');
  const [sortBy, setSortBy] = useState<'newest' | 'oldest' | 'alpha'>('newest');

  // Filter archived sessions
  const archived = sessions.filter(s => s.isArchived && (!filter || s.title.toLowerCase().includes(filter.toLowerCase())));

  // Sort archived sessions
  const sortedArchived = [...archived].sort((a, b) => {
    if (sortBy === 'alpha') {
      return a.title.localeCompare(b.title);
    }
    const timeA = new Date(a.startedAt).getTime();
    const timeB = new Date(b.startedAt).getTime();
    return sortBy === 'newest' ? timeB - timeA : timeA - timeB;
  });

  const handleClearAll = () => {
    if (confirm('Are you sure you want to delete sessions? This will wipe your conversation history and cannot be undone.')) {
      const deleteArchived = confirm('Do you want to delete archived sessions as well? Click OK to delete BOTH active and archived sessions, or Cancel to delete ONLY active sessions.');
      const newSess = clearAllSessions(deleteArchived);
      navigate(`/c/${newSess.id}`);
      // Close settings by pressing Escape or navigating back
      const preSettingsPath = sessionStorage.getItem('pre-settings-path') || '/';
      navigate(preSettingsPath);
    }
  };

  const handleRestore = (id: string) => {
    restoreSession(id);
  };

  const handleDeletePermanently = (id: string) => {
    if (confirm('Are you sure you want to permanently delete this session and its history? This action is irreversible.')) {
      deleteSession(id);
    }
  };

  return (
    <div className="p-6 space-y-6">
      {/* Top action row */}
      <div className="flex flex-col sm:flex-row gap-3 items-stretch sm:items-center justify-between pb-4 border-b border-border/40">
        <div className="flex flex-1 max-w-md gap-2">
          <div className="relative flex-1">
            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 size-3.5 text-muted-foreground" />
            <input
              value={filter}
              onChange={(e) => setFilter(e.target.value)}
              placeholder="Search archived sessions..."
              className="w-full pl-8 pr-2 py-1.5 text-xs bg-popover border border-border/40 rounded-md outline-none text-foreground placeholder:text-muted-foreground focus:border-primary/50"
            />
          </div>
          <select
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value as any)}
            className="px-2 py-1.5 text-xs bg-popover border border-border/40 rounded-md text-foreground outline-none cursor-pointer focus:border-primary/50"
          >
            <option value="newest">Newest First</option>
            <option value="oldest">Oldest First</option>
            <option value="alpha">Alphabetical</option>
          </select>
        </div>
        
        <Button variant="destructive" size="sm" onClick={handleClearAll} className="h-8">
          <Trash2 className="size-3" />
          Clear All Sessions
        </Button>
      </div>

      {/* Grouped sessions list */}
      <div className="space-y-6">
        {archived.length === 0 ? (
          <div className="text-center py-12 border border-dashed border-border/40 rounded-lg text-muted-foreground/60 text-xs">
            {filter ? 'No archived sessions match your search' : 'No archived sessions'}
          </div>
        ) : (
          <div className="space-y-5">
            {/* Folders */}
            {folders.map(folder => {
              const folderSessions = sortedArchived.filter(s => s.folderId === folder.id);
              if (folderSessions.length === 0) return null;
              
              return (
                <div key={folder.id} className="space-y-2">
                  <div className="flex items-center gap-1.5 text-foreground/80 px-1 font-semibold text-xs border-b border-border/10 pb-1">
                    <FolderIcon className="size-3.5 text-muted-foreground/75" />
                    <span>📁 {folder.name}</span>
                    <span className="text-[10px] text-muted-foreground/50 font-normal">({folderSessions.length})</span>
                  </div>
                  <div className="grid grid-cols-1 gap-1.5">
                    {folderSessions.map(s => (
                      <ArchiveRow
                        key={s.id}
                        session={s}
                        onRestore={() => handleRestore(s.id)}
                        onDelete={() => handleDeletePermanently(s.id)}
                      />
                    ))}
                  </div>
                </div>
              );
            })}

            {/* Uncategorized (Other Chats) */}
            {(() => {
              const uncategorizedSessions = sortedArchived.filter(s => !s.folderId);
              if (uncategorizedSessions.length === 0) return null;
              
              return (
                <div className="space-y-2">
                  <div className="flex items-center gap-1.5 text-foreground/80 px-1 font-semibold text-xs border-b border-border/10 pb-1">
                    <MessageSquare className="size-3.5 text-muted-foreground/75" />
                    <span>Other Chats</span>
                    <span className="text-[10px] text-muted-foreground/50 font-normal">({uncategorizedSessions.length})</span>
                  </div>
                  <div className="grid grid-cols-1 gap-1.5">
                    {uncategorizedSessions.map(s => (
                      <ArchiveRow
                        key={s.id}
                        session={s}
                        onRestore={() => handleRestore(s.id)}
                        onDelete={() => handleDeletePermanently(s.id)}
                      />
                    ))}
                  </div>
                </div>
              );
            })()}
          </div>
        )}
      </div>
    </div>
  );
}

function ArchiveRow({ 
  session, onRestore, onDelete 
}: {
  session: Session;
  onRestore: () => void;
  onDelete: () => void;
}) {
  return (
    <div className="flex items-center justify-between p-3 rounded-md bg-[#111113]/40 border border-border/20 hover:border-border/40 hover:bg-[#111113]/80 transition group">
      <div className="min-w-0 flex-1 pr-4">
        <h4 className="text-xs font-semibold text-foreground/90 truncate">{session.title}</h4>
        <div className="flex items-center gap-2 mt-1 text-[10px] text-muted-foreground font-mono">
          <span>Started {formatTimeAgo(session.startedAt)}</span>
          <span>·</span>
          <span>{session.messageCount} messages</span>
          <span>·</span>
          <span className="truncate">{session.model}</span>
        </div>
      </div>
      <div className="flex items-center gap-1">
        <Button 
          variant="outline" 
          size="icon-sm" 
          onClick={onRestore}
          className="size-7 text-muted-foreground hover:text-foreground"
          title="Restore session to sidebar"
        >
          <RotateCcw className="size-3" />
        </Button>
        <Button 
          variant="outline" 
          size="icon-sm" 
          onClick={onDelete}
          className="size-7 text-destructive hover:bg-destructive hover:text-destructive-foreground"
          title="Permanently delete session"
        >
          <Trash2 className="size-3" />
        </Button>
      </div>
    </div>
  );
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { SectionHeader } from '@/components/SectionHeader';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { StatusPill } from '@/components/StatusPill';
import { Play, Trash2, ShieldAlert, Clock, Inbox, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { getAutomations, runAutomation, deleteAutomation, type AutomationJob } from '@/api/api-client';

export function Automations() {
  const qc = useQueryClient();
  const { data, isLoading } = useQuery({
    queryKey: ['automations'],
    queryFn: () => getAutomations(),
    refetchInterval: 8_000,
  });

  const jobs = data?.jobs ?? [];

  const run = useMutation({
    mutationFn: (job: AutomationJob) => runAutomation(job.id, job.approvalRequired === false),
    onSuccess: (res: any) => {
      qc.invalidateQueries({ queryKey: ['automations'] });
      if (res?.status === 'approval_required') {
        toast.info('Automation requires approval', { description: 'Approve it to run the next time.' });
      } else {
        toast.success('Automation triggered');
      }
    },
    onError: (e: unknown) => toast.error('Could not run automation', { description: String((e as Error).message) }),
  });

  const remove = useMutation({
    mutationFn: (id: string) => deleteAutomation(id),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['automations'] });
      toast.success('Automation deleted');
    },
  });

  function handleDelete(job: AutomationJob) {
    if (!confirm(`Delete automation "${job.name || job.id}"? This cannot be undone.`)) return;
    remove.mutate(job.id);
  }

  return (
    <div className="p-6 space-y-6">
      <SectionHeader
        title="Automations"
        subtitle={
          isLoading
            ? 'Loading jobs…'
            : `${jobs.length} job${jobs.length === 1 ? '' : 's'} · ${jobs.filter((j) => j.enabled).length} enabled`
        }
      />

      {isLoading ? (
        <div className="grid place-items-center py-10">
          <Loader2 className="size-5 animate-spin text-muted-foreground" />
        </div>
      ) : jobs.length === 0 ? (
        <Card className="border-dashed">
          <CardContent className="p-10 grid place-items-center text-center text-muted-foreground">
            <Inbox className="size-8 text-muted-foreground/40 mb-2" />
            <p className="text-sm">No automation jobs configured.</p>
            <p className="text-xs text-muted-foreground mt-1 max-w-sm">
              Jobs are defined in backend automation config. They appear here once created.
            </p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {jobs.map((job) => (
            <AutomationCard
              key={job.id}
              job={job}
              onRun={() => run.mutate(job)}
              onDelete={() => handleDelete(job)}
              busy={run.isPending || remove.isPending}
            />
          ))}
        </div>
      )}
    </div>
  );
}

function AutomationCard({
  job,
  onRun,
  onDelete,
  busy,
}: {
  job: AutomationJob;
  onRun: () => void;
  onDelete: () => void;
  busy: boolean;
}) {
  return (
    <Card className={job.enabled ? '' : 'opacity-70'}>
      <CardContent className="p-3">
        <div className="flex items-start justify-between gap-3">
          <div className="min-w-0 flex-1">
            <div className="flex items-center gap-2 flex-wrap">
              <span className="text-sm font-semibold">{job.name || job.id}</span>
              <Badge variant="secondary" className="text-[9px]">{job.type || 'automation'}</Badge>
              {job.approvalRequired !== false && (
                <Badge variant="outline" className="text-[9px] border-warning/50 text-warning">
                  <ShieldAlert className="size-2.5 mr-0.5" /> approval
                </Badge>
              )}
            </div>

            <div className="flex items-center gap-3 mt-1.5 text-[11px] text-muted-foreground font-mono flex-wrap">
              <StatusPill tone={job.enabled ? 'good' : 'muted'} label={job.enabled ? 'enabled' : 'disabled'} />
              {job.schedule && (
                <span className="inline-flex items-center gap-1">
                  <Clock className="size-2.5" /> {job.schedule}
                </span>
              )}
              {job.agent && <span>agent: {job.agent}</span>}
              {job.lastRunAt && <span>last run: {shortDate(job.lastRunAt)}</span>}
              {job.nextRunAt && <span className="text-warning">next: {shortDate(job.nextRunAt)}</span>}
            </div>

            {(job.task || job.command) && (
              <pre className="text-[11px] font-mono whitespace-pre-wrap break-all text-muted-foreground/70 mt-1.5 bg-muted/40 rounded px-2 py-1">
                {job.task || job.command}
              </pre>
            )}
          </div>

          <div className="flex items-center gap-1 shrink-0">
            <Button size="sm" variant="outline" onClick={onRun} disabled={busy} title="Run now">
              <Play className="size-3" /> Run
            </Button>
            <Button size="icon-sm" variant="outline" onClick={onDelete} disabled={busy} title="Delete">
              <Trash2 className="size-3 text-destructive" />
            </Button>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

function shortDate(iso: string): string {
  try {
    const d = new Date(iso);
    const now = Date.now();
    const diff = d.getTime() - now;
    const abs = Math.abs(diff);
    const mins = Math.round(abs / 60000);
    if (mins < 60) return diff >= 0 ? `in ${mins}m` : `${mins}m ago`;
    const hrs = Math.round(mins / 60);
    if (hrs < 24) return diff >= 0 ? `in ${hrs}h` : `${hrs}h ago`;
    return d.toLocaleDateString();
  } catch {
    return iso;
  }
}

/* v4.3 — Brain Activity tab: live feed of brain events with chip filters + pause. */
import { useEffect, useMemo, useRef, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Loader2, Pause, Play, Sparkles } from 'lucide-react';
import { getBrainEvents, openBrainEventStream, type BrainEvent } from '@/api/api-client';

const CATEGORIES: Array<{ key: BrainEvent['category'] | 'all'; label: string; color: string }> = [
  { key: 'all',          label: 'All',           color: 'text-foreground' },
  { key: 'consolidation', label: 'Consolidation', color: 'text-info' },
  { key: 'heuristic',     label: 'Heuristics',    color: 'text-success' },
  { key: 'delta_engine',  label: 'Delta Engine',  color: 'text-warning' },
  { key: 'review',        label: 'Review',        color: 'text-primary' },
  { key: 'skill_genesis', label: 'Skill Genesis', color: 'text-accent' },
];

const CATEGORY_COLOR: Record<string, string> = Object.fromEntries(
  CATEGORIES.map((c) => [c.key, c.color]),
);

export function BrainActivityTab() {
  const [activeChip, setActiveChip] = useState<BrainEvent['category'] | 'all'>('all');
  const [paused, setPaused] = useState(false);
  const [liveEvents, setLiveEvents] = useState<BrainEvent[]>([]);

  const eventsQ = useQuery({
    queryKey: ['brain-events', activeChip],
    queryFn: () => getBrainEvents(200),
  });

  // SSE: when not paused, push events into liveEvents (capped).
  // We don't filter live events by chip — UI does it client-side.
  const streamRef = useRef<EventSource | null>(null);
  useEffect(() => {
    const es = openBrainEventStream();
    streamRef.current = es;
    es.onmessage = (ev: MessageEvent) => {
      if (paused) return;
      try {
        const event = JSON.parse(ev.data) as BrainEvent;
        setLiveEvents((prev) => [event, ...prev].slice(0, 200));
      } catch {
        // Ignore malformed frames
      }
    };
    return () => {
      es.close();
      streamRef.current = null;
    };
  }, [paused]);

  // Merge recent + live. Live takes precedence on dedupe by id.
  const merged = useMemo(() => {
    const seen = new Set<string>();
    const combined: BrainEvent[] = [];
    for (const e of liveEvents) {
      if (!seen.has(e.id)) {
        seen.add(e.id);
        combined.push(e);
      }
    }
    for (const e of eventsQ.data ?? []) {
      if (!seen.has(e.id)) {
        seen.add(e.id);
        combined.push(e);
      }
    }
    return combined;
  }, [eventsQ.data, liveEvents]);

  const filtered = useMemo(() => {
    if (activeChip === 'all') return merged;
    return merged.filter((e) => e.category === activeChip);
  }, [merged, activeChip]);

  if (eventsQ.isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="size-6 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Toolbar: status indicator + pause + filter chips */}
      <div className="flex items-center gap-3 flex-wrap">
        <div className="flex items-center gap-1.5 text-xs">
          <span
            className={`size-2 rounded-full ${paused ? 'bg-muted-foreground' : 'bg-success animate-pulse'}`}
            aria-hidden
          />
          <span className="text-muted-foreground">{paused ? 'Paused' : 'Live'}</span>
        </div>
        <button
          type="button"
          onClick={() => setPaused((p) => !p)}
          aria-label={paused ? 'Resume' : 'Pause'}
          data-testid="brain-activity-pause"
          className="px-2 py-1 text-xs rounded border border-white/[0.06] hover:bg-white/[0.06] flex items-center gap-1"
        >
          {paused ? <Play className="size-3" /> : <Pause className="size-3" />}
          <span>{paused ? 'Resume' : 'Pause'}</span>
        </button>

        <div className="flex flex-wrap gap-1.5 ml-2" role="group" aria-label="Filter by category">
          {CATEGORIES.map((c) => (
            <button
              key={c.key}
              type="button"
              onClick={() => setActiveChip(c.key)}
              data-testid={`brain-chip-${c.key}`}
              className={`px-2 py-1 text-xs rounded-full border transition ${
                activeChip === c.key
                  ? 'bg-primary/20 border-primary text-foreground'
                  : 'border-white/[0.06] text-muted-foreground hover:bg-white/[0.03]'
              }`}
            >
              {c.label}
            </button>
          ))}
        </div>
      </div>

      {/* Event feed */}
      {filtered.length === 0 ? (
        <div className="text-xs text-muted-foreground text-center py-12 border border-dashed border-white/[0.06] rounded-lg">
          <Sparkles className="size-4 inline-block mr-2 opacity-40" />
          No brain activity yet — start chatting to see the brain learn.
        </div>
      ) : (
        <ul
          className="space-y-1 max-h-[60vh] overflow-y-auto"
          data-testid="brain-activity-feed"
        >
          {filtered.map((e) => (
            <li
              key={e.id}
              data-testid="brain-event"
              data-category={e.category}
              className="bg-card/60 border border-white/[0.06] rounded-md p-2 text-xs flex gap-3"
            >
              <span className="text-muted-foreground/70 font-mono shrink-0 w-20">
                {new Date(e.at).toLocaleTimeString()}
              </span>
              <span
                className={`shrink-0 w-24 truncate text-[10px] uppercase tracking-wide ${CATEGORY_COLOR[e.category] ?? 'text-muted-foreground'}`}
              >
                {e.category.replace('_', ' ')}
              </span>
              <span className="flex-1">{e.summary}</span>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

/* v3 — Learning tab: heuristics, auto-memories, facts, sleep cycle, delta engine, skill genesis */
import { useEffect, useState } from 'react';
import { Sparkles, Brain, Clock, Zap, ListChecks } from 'lucide-react';
import { Card } from '@/components/ui/card';

interface Heuristic {
  id: number;
  rule: string;
  source: string;
  category: string;
  createdAt: string;
}

interface AutoMemory {
  id: number;
  key: string;
  content: string;
  importance: number;
  createdAt?: string;
}

interface PendingSkill {
  id: number;
  name: string;
  description: string;
  triggerText?: string;
}

interface LearningData {
  heuristics: Heuristic[];
  heuristicCount: number;
  coreFacts: unknown;
  userProfile: unknown;
  autoMemories: AutoMemory[];
  sleepCycle: { lastRunAt: string | null; lastMerged: number; lastPromoted: number; lastDeleted: number };
  deltaEngine: { consentGranted: boolean; queueSize: number; lastFlushAt: string | null };
  pendingSkills: PendingSkill[];
}

const API_BASE = '/api/brain';

export function LearningTab() {
  const [data, setData] = useState<LearningData | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    const fetchData = async () => {
      try {
        const resp = await fetch(`${API_BASE}/learning`);
        if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
        const json = await resp.json();
        // Wire format is camelCase (`heuristics`, `heuristicCount`,
        // `sleepCycle`, `deltaEngine`, `pendingSkills`, …) per the v3
        // brain API contract.
        const normalized: LearningData = {
          heuristics: json.heuristics ?? [],
          heuristicCount: json.heuristicCount ?? 0,
          coreFacts: json.coreFacts ?? null,
          userProfile: json.userProfile ?? null,
          autoMemories: json.autoMemories ?? [],
          sleepCycle: {
            lastRunAt: json.sleepCycle?.lastRunAt ?? null,
            lastMerged: json.sleepCycle?.lastMerged ?? 0,
            lastPromoted: json.sleepCycle?.lastPromoted ?? 0,
            lastDeleted: json.sleepCycle?.lastDeleted ?? 0,
          },
          deltaEngine: {
            consentGranted: json.deltaEngine?.consentGranted ?? false,
            queueSize: json.deltaEngine?.queueSize ?? 0,
            lastFlushAt: json.deltaEngine?.lastFlushAt ?? null,
          },
          pendingSkills: json.pendingSkills ?? [],
        };
        if (!cancelled) setData(normalized);
      } catch (e) {
        if (!cancelled) setError((e as Error).message);
      }
    };
    fetchData();
    const id = setInterval(fetchData, 5000);
    return () => {
      cancelled = true;
      clearInterval(id);
    };
  }, []);

  if (error) {
    return <div className="p-4 text-danger">Error loading brain data: {error}</div>;
  }
  if (!data) {
    return (
      <div className="p-8 text-center text-muted-foreground flex items-center justify-center gap-2">
        <Clock className="size-4 animate-spin" /> Loading…
      </div>
    );
  }

  return (
    <div className="grid gap-4 md:grid-cols-2">
      {/* Learned heuristics */}
      <Card className="p-4 space-y-3 md:col-span-2">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Brain className="size-4 text-primary" />
            <h3 className="font-medium text-sm">Learned heuristics</h3>
          </div>
          <span className="text-xs text-muted-foreground bg-muted px-2 py-0.5 rounded-full">
            {data.heuristicCount}
          </span>
        </div>
        {data.heuristics.length === 0 ? (
          <p className="text-xs text-muted-foreground">
            No learned heuristics yet — the brain starts learning once you use it.
          </p>
        ) : (
          <ul className="space-y-2 max-h-72 overflow-y-auto">
            {data.heuristics.map((h) => (
              <li
                key={h.id}
                className="text-xs flex items-start gap-2 p-2 rounded hover:bg-muted/30"
              >
                <span
                  className={`mt-1 size-1.5 rounded-full shrink-0 ${
                    h.source === 'manual'
                      ? 'bg-primary'
                      : h.source === 'local-diff'
                      ? 'bg-success'
                      : 'bg-muted-foreground'
                  }`}
                />
                <div className="flex-1 min-w-0">
                  <p>{h.rule}</p>
                  <span className="text-[10px] text-muted-foreground">
                    <span>{h.source}</span>
                    {' · '}
                    <span>{h.category}</span>
                  </span>
                </div>
              </li>
            ))}
          </ul>
        )}
      </Card>

      {/* Auto-memories */}
      <Card className="p-4 space-y-3">
        <div className="flex items-center gap-2">
          <ListChecks className="size-4 text-primary" />
          <h3 className="font-medium text-sm">Recent auto-memories</h3>
        </div>
        {data.autoMemories.length === 0 ? (
          <p className="text-xs text-muted-foreground">
            No auto-memories captured yet. The model saves them as you chat.
          </p>
        ) : (
          <ul className="space-y-2 max-h-60 overflow-y-auto">
            {data.autoMemories.map((m) => (
              <li key={m.id} className="text-xs p-2 rounded hover:bg-muted/30">
                <p>{m.content}</p>
                <span className="text-[10px] text-muted-foreground">
                  importance: {m.importance.toFixed(2)}
                </span>
              </li>
            ))}
          </ul>
        )}
      </Card>

      {/* Core facts */}
      <Card className="p-4 space-y-3">
        <div className="flex items-center gap-2">
          <Sparkles className="size-4 text-warning" />
          <h3 className="font-medium text-sm">Core facts</h3>
        </div>
        {data.coreFacts ? (
          <pre className="text-xs text-muted-foreground whitespace-pre-wrap max-h-60 overflow-y-auto">
            {JSON.stringify(data.coreFacts, null, 2).slice(0, 800)}
          </pre>
        ) : (
          <p className="text-xs text-muted-foreground">No core facts yet.</p>
        )}
      </Card>

      {/* Sleep cycle */}
      <Card className="p-4 space-y-3">
        <div className="flex items-center gap-2">
          <Clock className="size-4 text-primary" />
          <h3 className="font-medium text-sm">Sleep cycle</h3>
        </div>
        {data.sleepCycle.lastRunAt ? (
          <p className="text-xs text-muted-foreground">
            Last run: {new Date(data.sleepCycle.lastRunAt).toLocaleString()}
            <br />
            {data.sleepCycle.lastMerged} merges, {data.sleepCycle.lastPromoted} promotions,{' '}
            {data.sleepCycle.lastDeleted} deletions
          </p>
        ) : (
          <p className="text-xs text-muted-foreground">No consolidation runs yet.</p>
        )}
      </Card>

      {/* Delta engine */}
      <Card className="p-4 space-y-3">
        <div className="flex items-center gap-2">
