const LONG_MSG_THRESHOLD = 1000;

/**
 * InitAugCard — preview UI for the `/init` AUG.md flow.
 *
 * Shows the LLM-generated (or refined) AUG.md draft and lets the user
 * confirm (save), regenerate, or cancel. When refining an existing file,
 * a side-by-side diff is shown so the user can see what will change.
 */
import { useState } from 'react';
import { Markdown } from './ChatMarkdown';
import { api } from '@/api/client';
import { voiceCommandEvents } from '@/api/voice/registry-events';
import { Check, RefreshCw, X } from 'lucide-react';

interface InitAugCardProps {
  draft: string;
  existing: boolean;
  workspacePath: string;
  sessionId?: string;
}

function simpleDiff(existing: string, next: string): { type: 'same' | 'add' | 'del'; text: string }[] {
  const a = existing.split('\n');
  const b = next.split('\n');
  const out: { type: 'same' | 'add' | 'del'; text: string }[] = [];
  const max = Math.max(a.length, b.length);
  for (let i = 0; i < max; i++) {
    const left = a[i];
    const right = b[i];
    if (left === right) out.push({ type: 'same', text: right ?? '' });
    else {
      if (left !== undefined) out.push({ type: 'del', text: left });
      if (right !== undefined) out.push({ type: 'add', text: right });
    }
  }
  return out;
}

export function InitAugCard({ draft, existing, workspacePath, sessionId }: InitAugCardProps) {
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [currentDraft, setCurrentDraft] = useState(draft);
  const [currentExisting, setCurrentExisting] = useState(existing);
  const [savedPath, setSavedPath] = useState<string | null>(null);

  async function regenerate() {
    setBusy(true);
    setError(null);
    try {
      const res = await api.post<{ draft: string; existing: boolean }>('/api/aug/init', {
        mode: currentExisting ? 'refine' : 'create',
        workspacePath: workspacePath || undefined,
      });
      setCurrentDraft(res.draft);
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Failed to regenerate');
    } finally {
      setBusy(false);
    }
  }

  async function save() {
    setBusy(true);
    setError(null);
    try {
      const res = await api.put<{ path: string }>('/api/aug/content', {
        content: currentDraft,
        workspacePath: workspacePath || undefined,
        sessionId: sessionId || undefined,
      });
      setSavedPath(res.path);
      voiceCommandEvents.emit({ type: 'aug-saved', path: res.path });
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Failed to save AUG.md');
    } finally {
      setBusy(false);
    }
  }

  function close() {
    voiceCommandEvents.emit({ type: 'reset-session' } as never);
  }

  if (savedPath) {
    return (
      <div className="rounded-lg border border-emerald-500/40 bg-emerald-500/5 p-4 text-sm">
        <p className="font-medium text-emerald-300">AUG.md saved to:</p>
        <code className="block mt-1 break-all text-xs text-emerald-200/80">{savedPath}</code>
        <p className="mt-2 text-emerald-200/70">
          It will be loaded into the system prompt on your next message.
        </p>
      </div>
    );
  }

  return (
    <div className="rounded-lg border border-zinc-700 bg-zinc-900/60 p-4">
      <div className="mb-3 flex items-center justify-between">
        <div>
          <h3 className="text-sm font-semibold text-zinc-100">
            {currentExisting ? 'Refine AUG.md' : 'Initialize AUG.md'}
          </h3>
          <p className="text-xs text-zinc-400">
            {workspacePath ? workspacePath : 'project root'}
          </p>
        </div>
        <button
          onClick={close}
          className="rounded p-1 text-zinc-400 hover:bg-zinc-800 hover:text-zinc-200"
          aria-label="Dismiss"
        >
          <X size={16} />
        </button>
      </div>

      {currentExisting ? (
        <div className="mb-3 max-h-72 overflow-auto rounded border border-zinc-800 bg-black/30 p-2 text-xs">
          {simpleDiff(draft, currentDraft).map((line, i) => (
            <div
              key={i}
              className={
                line.type === 'add'
                  ? 'text-emerald-300'
                  : line.type === 'del'
                    ? 'text-rose-300 line-through'
                    : 'text-zinc-500'
              }
            >
              <span className="select-none opacity-60">
                {line.type === 'add' ? '+ ' : line.type === 'del' ? '- ' : '  '}
              </span>
              {line.text}
            </div>
          ))}
        </div>
      ) : (
        <div className="mb-3 max-h-72 overflow-auto rounded border border-zinc-800 bg-black/30 p-3">
          <Markdown content={currentDraft} />
        </div>
      )}

      {error && <p className="mb-2 text-xs text-rose-400">{error}</p>}

      <div className="flex gap-2">
        <button
          onClick={save}
          disabled={busy}
          className="flex items-center gap-1 rounded bg-emerald-600 px-3 py-1.5 text-xs font-medium text-white hover:bg-emerald-500 disabled:opacity-50"
        >
          <Check size={14} /> {currentExisting ? 'Refine & Save' : 'Save AUG.md'}
        </button>
        <button
          onClick={regenerate}
          disabled={busy}
          className="flex items-center gap-1 rounded bg-zinc-700 px-3 py-1.5 text-xs font-medium text-zinc-100 hover:bg-zinc-600 disabled:opacity-50"
        >
          <RefreshCw size={14} /> Regenerate
        </button>
        <button
          onClick={close}
          disabled={busy}
          className="ml-auto rounded px-3 py-1.5 text-xs text-zinc-400 hover:text-zinc-200"
        >
          Cancel
        </button>
      </div>
    </div>
  );
}

/**
 * ModelPickerCard — Inline model picker for voice commands
 *
 * Spec: docs/superpowers/specs/2026-06-30-voice-subagent-provider-overhaul-design.md
 *
 * Grouped-by-provider list of available models fetched via useModels().
 * Implements VoiceCommandCardProps so it plugs into the registry.
 */

import { useState, useEffect, useRef, useMemo } from 'react';
import { Search, X, Zap, Settings } from 'lucide-react';
import { cn } from '@/lib/utils';
import { useModels } from '@/hooks/useModels';
import type { VoiceCommandCardProps } from '@/api/voice/registry';
import { useNavigate } from 'react-router-dom';

export function ModelPickerCard({ onDismiss }: VoiceCommandCardProps) {
  const { models, isLoading, error } = useModels();
  const navigate = useNavigate();
  const [searchQuery, setSearchQuery] = useState('');
  const [focusedIndex, setFocusedIndex] = useState(0);
  const searchRef = useRef<HTMLInputElement>(null);
  const listRef = useRef<HTMLDivElement>(null);

  // Auto-focus search on mount.
  useEffect(() => {
    searchRef.current?.focus();
  }, []);

  // Group by provider.
  const grouped = useMemo(() => {
    const map = new Map<string, typeof models>();
    for (const m of models) {
      const key = m.provider || 'Unknown';
      if (!map.has(key)) map.set(key, []);
      map.get(key)!.push(m);
    }
    return Array.from(map.entries()).map(([provider, items]) => ({
      provider,
      items: items.filter(
        m =>
          (m.name ?? '').toLowerCase().includes(searchQuery.toLowerCase()) ||
          m.provider.toLowerCase().includes(searchQuery.toLowerCase()),
      ),
    }));
  }, [models, searchQuery]);

  // Flatten the grouped items so focusedIndex maps to a linear list.
  const flatItems = useMemo(
    () => grouped.flatMap(g => g.items),
    [grouped],
  );

  // Keyboard navigation.
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        onDismiss();
      } else if (e.key === 'ArrowDown') {
        e.preventDefault();
        setFocusedIndex(i => Math.min(i + 1, flatItems.length - 1));
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        setFocusedIndex(i => Math.max(i - 1, 0));
      } else if (e.key === 'Enter' && flatItems[focusedIndex]) {
        e.preventDefault();
        const model = flatItems[focusedIndex];
        // Select model via a custom event or direct store mutation.
        // For now, emit a toast and dismiss the card.
        handleSelect(model.id, model.provider);
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [focusedIndex, flatItems, onDismiss]);

  useEffect(() => {
    setFocusedIndex(0);
  }, [searchQuery]);

  useEffect(() => {
    if (listRef.current) {
      const items = listRef.current.querySelectorAll('[data-model-item]');
      const focused = items[focusedIndex] as HTMLElement;
      if (focused) {
        focused.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
      }
    }
  }, [focusedIndex]);

  const handleSelect = (modelId: string, provider: string) => {
    // v4.5: Wire to session model-update store mutation.
    // For now, emit a custom event so ChatThread can catch it.
    window.dispatchEvent(
      new CustomEvent('august:model-selected', {
        detail: { modelId, provider },
      }),
    );
    onDismiss();
  };

  // ── Empty / Error states ──────────────────────────────────────────────

  if (isLoading) {
    return (
      <div className="my-3 mx-auto max-w-2xl bg-card border border-border rounded-lg shadow-lg p-8 text-center text-sm text-muted-foreground">
        Loading models…
      </div>
    );
  }

  if (error) {
    return (
      <div className="my-3 mx-auto max-w-2xl bg-card border border-border rounded-lg shadow-lg p-8 text-center text-sm text-red-500">
        Failed to load models.
      </div>
    );
  }

  if (models.length === 0) {
    return (
      <div className="my-3 mx-auto max-w-2xl bg-card border border-border rounded-lg shadow-lg overflow-hidden">
        <div className="px-4 py-8 text-center space-y-3">
          <Zap className="size-6 text-muted-foreground mx-auto" />
          <div className="text-sm text-foreground font-medium">
            No models available
          </div>
          <div className="text-xs text-muted-foreground">
            Add a provider in Settings to get started.
          </div>
          <button
            type="button"
            onClick={() => {
              navigate('/settings/providers');
              onDismiss();
            }}
            className="inline-flex items-center gap-1.5 text-xs px-3 py-1.5 rounded-md bg-primary text-primary-foreground hover:opacity-90 transition-opacity"
          >
            <Settings className="size-3" />
            Go to Settings
          </button>
        </div>
      </div>
    );
  }

  // ── Normal render ─────────────────────────────────────────────────────

  return (
    <div className="my-3 mx-auto max-w-2xl bg-card border border-border rounded-lg shadow-lg overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-3 border-b border-border bg-muted/30">
        <div className="flex items-center gap-2">
          <Zap className="size-4 text-primary" />
          <span className="text-sm font-medium">Switch Model</span>
        </div>
        <button
          onClick={onDismiss}
          className="text-muted-foreground hover:text-foreground transition-colors p-1 rounded hover:bg-muted"
          aria-label="Close"
        >
          <X className="size-4" />
        </button>
      </div>

      {/* Search */}
      <div className="px-4 py-3 border-b border-border">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-muted-foreground pointer-events-none" />
          <input
            ref={searchRef}
            type="text"
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            placeholder="Search models…"
            className="w-full pl-9 pr-3 py-2 text-sm bg-background border border-border rounded-md focus:outline-none focus:ring-2 focus:ring-primary/50"
          />
        </div>
      </div>

      {/* Grouped model list */}
      <div ref={listRef} className="max-h-80 overflow-y-auto">
        {grouped.map(group => {
          if (group.items.length === 0) return null;
          const groupStart = flatItems.indexOf(group.items[0]);
          return (
            <div key={group.provider}>
              <div className="px-4 py-1.5 text-[11px] uppercase tracking-wide text-muted-foreground font-semibold bg-muted/10">
                {group.provider}
              </div>
              {group.items.map((model, idx) => {
                const globalIdx = groupStart + idx;
                const isFocused = globalIdx === focusedIndex;
                return (
                  <button
                    key={model.id}
                    data-model-item
                    onClick={() => handleSelect(model.id, model.provider)}
                    className={cn(
                      'w-full px-4 py-3 flex items-start gap-3 text-left transition-colors',
                      isFocused && 'bg-muted',
                      !isFocused && 'hover:bg-muted/50',
                    )}
                  >
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="text-sm font-medium">{model.name}</span>
                        {(model as any).isFree && (
                          <span className="text-xs px-1.5 py-0.5 rounded bg-green-500/10 text-green-600 dark:text-green-400">
                            Free
                          </span>
                        )}
                        {(model as any).supportsReasoning && (
                          <span className="text-xs px-1.5 py-0.5 rounded bg-purple-500/10 text-purple-600 dark:text-purple-400">
                            Reasoning
                          </span>
                        )}
                      </div>
                      <div className="text-xs text-muted-foreground mt-1">
                        {model.contextWindow
                          ? `${(model.contextWindow / 1000).toFixed(0)}K context`
                          : '—'}
                      </div>
                    </div>
                  </button>
                );
              })}
            </div>
          );
        })}
        {flatItems.length === 0 && (
          <div className="px-4 py-8 text-center text-sm text-muted-foreground">
            No models matching &ldquo;{searchQuery}&rdquo;
          </div>
        )}
      </div>

      {/* Footer hint */}
      <div className="px-4 py-2 bg-muted/30 border-t border-border text-xs text-muted-foreground">
        <kbd className="px-1.5 py-0.5 bg-background border border-border rounded">↑↓</kbd> navigate ·{' '}
        <kbd className="px-1.5 py-0.5 bg-background border border-border rounded ml-1">Enter</kbd> select ·{' '}
        <kbd className="px-1.5 py-0.5 bg-background border border-border rounded ml-1">Esc</kbd> close
      </div>
    </div>
  );
}

/* ── SubagentApprovalCard ────────────────────────────────────────────── */
/* Approval card for proposed-mode sub-agent breakdown. Shows work items
   and allows Approve/Cancel. */

import { useState } from 'react';
import { Loader2, Check, X } from 'lucide-react';
import { proposeBreakdown } from '@/api/subagents';

interface WorkBreakdownItem {
  goal: string;
  agentId?: string;
}

interface SubagentApprovalCardProps {
  proposalId: string;
  workBreakdown: WorkBreakdownItem[];
  onApproved: () => void;
  onRejected: () => void;
}

export function SubagentApprovalCard({
  proposalId,
  workBreakdown,
  onApproved,
  onRejected,
}: SubagentApprovalCardProps) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleApprove = async () => {
    setLoading(true);
    setError(null);
    try {
      await proposeBreakdown(proposalId, true);
      onApproved();
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : 'Approval failed');
    } finally {
      setLoading(false);
    }
  };

  const handleReject = async () => {
    setLoading(true);
    setError(null);
    try {
      await proposeBreakdown(proposalId, false);
      onRejected();
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : 'Rejection failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="rounded-xl border border-primary/30 bg-primary/5 p-4 space-y-3">
      <div className="flex items-center gap-2">
        <div className="size-2 rounded-full bg-primary animate-pulse" />
        <p className="text-sm font-semibold">Sub-agent plan proposed</p>
      </div>

      <div className="space-y-1.5">
        <p className="text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">
          Work breakdown
        </p>
        {workBreakdown.map((item, i) => (
          <div
            key={i}
            className="rounded-lg border border-white/[0.06] bg-card/40 px-3 py-2 text-xs"
          >
            <p className="font-medium text-foreground/90">{item.goal}</p>
            {item.agentId && (
              <p className="text-[10px] text-muted-foreground font-mono">
                Agent: {item.agentId}
              </p>
            )}
          </div>
        ))}
      </div>

      {error && (
        <p className="text-xs text-destructive">{error}</p>
      )}

      <div className="flex items-center gap-2 pt-1">
        <button
          type="button"
          onClick={handleApprove}
          disabled={loading}
          className="flex-1 inline-flex items-center justify-center gap-1.5 rounded-lg bg-primary px-3 py-2 text-xs font-medium text-primary-foreground hover:opacity-90 disabled:opacity-50"
        >
          {loading ? (
            <Loader2 className="size-3 animate-spin" />
          ) : (
            <Check className="size-3" />
          )}
          Approve
        </button>
        <button
          type="button"
          onClick={handleReject}
          disabled={loading}
          className="flex-1 inline-flex items-center justify-center gap-1.5 rounded-lg border border-white/[0.06] px-3 py-2 text-xs font-medium hover:bg-white/[0.06] disabled:opacity-50"
        >
          <X className="size-3" />
          Cancel
        </button>
      </div>
    </div>
  );
}

import { useState, useEffect, useMemo, useRef } from 'react';
import { useStore } from '@nanostores/react';
import { $sessions, updateSessionWorkspace } from '@/store/sessions';
import { FolderGit2, ChevronRight, ChevronDown, Folder, FolderOpen, FileText, AlertCircle, Trash2, FolderSearch, Link2, Plus } from 'lucide-react';
import { cn } from '@/lib/utils';
import { isTauri } from '@/lib/tauri-detect';
import { toast } from 'sonner';

interface FlatFileNode {
  name: string;
  path: string;
  isDir: boolean;
  depth: number;
  isExpanded: boolean;
  sizeBytes?: number;
}

export function WorkspacePanel({ sessionId }: { sessionId: string | null }) {
  const sessions = useStore($sessions);
  const activeSession = useMemo(() => sessions.find(s => s.id === sessionId), [sessions, sessionId]);
  const workspacePath = activeSession?.workspacePath || null;

  const [flatTree, setFlatTree] = useState<FlatFileNode[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Sync state with active session's workspace path
  useEffect(() => {
    if (workspacePath) {
      loadRootFiles(workspacePath);
    } else {
      setFlatTree([]);
      setError(null);
    }
  }, [workspacePath, sessionId]);

  const loadRootFiles = async (dirPath: string) => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch(`/api/workspace/files?path=${encodeURIComponent(dirPath)}`);
      if (!res.ok) {
        const errData = await res.json().catch(() => ({}));
        throw new Error(errData.error || 'Failed to list directory contents');
      }
      const data = await res.json();
      setFlatTree(
        data.files.map((f: any) => ({
          name: f.name,
          path: f.path,
          isDir: f.isDir,
          depth: 0,
          isExpanded: false,
          sizeBytes: f.sizeBytes,
        }))
      );
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      setError(message);
      setFlatTree([]);
    } finally {
      setLoading(false);
    }
  };

  const handleClear = () => {
    if (!sessionId) return;
    updateSessionWorkspace(sessionId, null);
    setFlatTree([]);
    setError(null);
    toast.info('Workspace cleared for this session');
  };

  const toggleFolder = async (node: FlatFileNode, idx: number) => {
    if (node.isExpanded) {
      // Collapse
      const prefix = node.path + '/';
      setFlatTree(prev => {
        const next = prev.filter(n => !n.path.startsWith(prefix));
        next[idx] = { ...node, isExpanded: false };
        return next;
      });
    } else {
      // Expand
      try {
        const res = await fetch(`/api/workspace/files?path=${encodeURIComponent(node.path)}`);
        if (!res.ok) throw new Error('Failed to load subfolder');
        const data = await res.json();
        const subnodes = data.files.map((f: any) => ({
          name: f.name,
          path: f.path,
          isDir: f.isDir,
          depth: node.depth + 1,
          isExpanded: false,
          sizeBytes: f.sizeBytes,
        }));

        setFlatTree(prev => {
          const next = [...prev];
          next[idx] = { ...node, isExpanded: true };
          next.splice(idx + 1, 0, ...subnodes);
          return next;
        });
      } catch (err) {
        const message = err instanceof Error ? err.message : String(err);
        toast.error(`Could not read folder: ${node.name}: ${message}`);
      }
    }
  };

  const handleSetWorkspace = (folderPath: string) => {
    if (!sessionId) return;
    updateSessionWorkspace(sessionId, folderPath);
    toast.success('Workspace updated to subfolder');
  };

  const handleReferenceFile = (filePath: string) => {
    const event = new CustomEvent('august-insert-composer-text', {
      detail: ` @read_file ${filePath} `,
    });
    window.dispatchEvent(event);
    toast.info(`Referenced: ${filePath.split('/').pop()}`);
  };

  // Hidden file input for native folder picker (browser fallback)
  const dirInputRef = useRef<HTMLInputElement>(null);

  const handleSelectFolder = async () => {
    let selectedPath: string | null = null;

    if (isTauri) {
      try {
        const { invoke } = await import('@tauri-apps/api/core');
        selectedPath = await invoke<string | null>('select_directory');
      } catch (err) {
        console.error('Failed to open Tauri directory dialog:', err);
      }
    } else {
      dirInputRef.current?.click();
      return;
    }

    if (!selectedPath) return;
    selectedPath = selectedPath.trim();
    if (!selectedPath) return;

    const normalizedPath = selectedPath.replace(/\\/g, '/');
    const folderName = normalizedPath.split('/').pop() || 'workspace';

    const toastId = toast.loading(`Connecting to workspace: ${folderName}...`);

    try {
      const res = await fetch(`/api/workspace/files?path=${encodeURIComponent(normalizedPath)}`);
      if (!res.ok) {
        const errData = await res.json().catch(() => ({}));
        throw new Error(errData.error || 'Directory does not exist or is not readable');
      }

      toast.success(`Connected to workspace: ${folderName}`, { id: toastId });

      if (sessionId) {
        updateSessionWorkspace(sessionId, normalizedPath);
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      toast.error(`Access failed: ${message}`, { id: toastId });
    }
  };

  const handleDirPicked = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const fullPath = file.path
      || file.webkitRelativePath.slice(0, file.webkitRelativePath.indexOf('/'));
    if (!fullPath) return;
    const normalizedPath = fullPath.replace(/\\/g, '/');
    const folderName = normalizedPath.split('/').pop() || 'workspace';
    const toastId = toast.loading(`Connecting to workspace: ${folderName}...`);
    (async () => {
      try {
        const res = await fetch(`/api/workspace/files?path=${encodeURIComponent(normalizedPath)}`);
        if (!res.ok) throw new Error((await res.json().catch(() => ({}))).error || 'Directory not accessible');
        toast.success(`Connected to workspace: ${folderName}`, { id: toastId });
        if (sessionId) updateSessionWorkspace(sessionId, normalizedPath);
      } catch (err) {
        const message = err instanceof Error ? err.message : String(err);
        toast.error(`Access failed: ${message}`, { id: toastId });
      }
    })();
    e.target.value = '';
  };

  const formatBytes = (bytes?: number) => {
    if (bytes === undefined || bytes === null) return '';
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
  };

  return (
    <div className="flex flex-col h-full bg-sidebar text-sm">
      <input
        ref={dirInputRef}
        type="file"
        webkitdirectory=""
        directory=""
        className="hidden"
        onChange={handleDirPicked}
      />
      {/* Header */}
      <div className="p-3 border-b border-border/40 flex items-center justify-between shrink-0 bg-background">
        <div className="flex items-center gap-2">
          <FolderGit2 className="size-4 text-warning/80" />
          <div className="flex flex-col">
            <span className="font-semibold text-foreground/80 text-[13px]">Workspace Explorer</span>
            {workspacePath && (
              <span className="text-[9px] text-muted-foreground/50 font-mono truncate max-w-[180px]" title={workspacePath}>
                {workspacePath.split(/[/\\]/).pop()}
              </span>
            )}
          </div>
        </div>
        {workspacePath && (
          <button
            onClick={handleClear}
            title="Disconnect Workspace"
            className="p-1 hover:bg-white/5 rounded text-muted-foreground hover:text-destructive transition"
          >
            <Trash2 className="size-3.5" />
          </button>
        )}
      </div>

      {/* Path Display / Connect Fallback */}
      <div className="p-3 border-b border-border/10 bg-sidebar shrink-0">
        {workspacePath ? (
          <div className="flex flex-col gap-0.5 min-w-0">
            <span className="text-[10px] text-muted-foreground/50 font-mono truncate" title={workspacePath}>
              {workspacePath}
            </span>
          </div>
        ) : (
          <div className="py-4 px-2 text-center text-muted-foreground/60 space-y-3">
            <p className="text-[12.5px]">No folder connected to this session.</p>
            <input
              type="text"
              placeholder="Paste path & press Enter (e.g. C:/my-project)..."
              className="w-full h-8 px-2.5 rounded border border-border/40 bg-muted/20 text-xs text-foreground placeholder:text-muted-foreground/45 outline-none focus:ring-1 focus:ring-primary/40 focus:border-primary transition"
              onKeyDown={async (e) => {
                if (e.key === 'Enter') {
                  const val = (e.target as HTMLInputElement).value.trim();
                  if (val) {
                    const normalized = val.replace(/\\/g, '/');
                    const folderName = normalized.split('/').pop() || 'workspace';
                    const toastId = toast.loading(`Connecting to workspace: ${folderName}...`);
                    try {
                      const res = await fetch(`/api/workspace/files?path=${encodeURIComponent(normalized)}`);
                      if (!res.ok) throw new Error('Directory does not exist or is not readable');
                      toast.success(`Connected to workspace: ${folderName}`, { id: toastId });
                      if (sessionId) {
                        updateSessionWorkspace(sessionId, normalized);
                        (e.target as HTMLInputElement).value = '';
                      }
                    } catch (err) {
                      const message = err instanceof Error ? err.message : String(err);
                      toast.error(`Access failed: ${message}`, { id: toastId });
                    }
                  }
                }
              }}
            />
            <div className="relative flex items-center justify-center my-1">
              <span className="w-full h-[1px] bg-border/20 absolute" />
              <span className="text-[9px] uppercase px-2 bg-sidebar text-muted-foreground/60 relative font-bold">or</span>
            </div>
            <button
              onClick={handleSelectFolder}
              className="w-full py-1.5 px-3 rounded-lg bg-primary text-primary-foreground font-semibold text-[10.5px] hover:opacity-95 active:scale-95 transition flex items-center justify-center gap-1.5 cursor-pointer"
            >
              <FolderGit2 className="size-3.5" />
              <span>Select Folder</span>
            </button>
          </div>
        )}
      </div>

      {/* Error Message */}
      {error && (
        <div className="flex items-start gap-2 text-destructive text-xs bg-destructive/10 border border-destructive/20 rounded-lg m-3 p-2.5">
          <AlertCircle className="size-4 shrink-0 mt-0.5" />
          <span>{error}</span>
        </div>
      )}

      {/* File Tree */}
      <div className="flex-1 overflow-y-auto p-1.5 scrollbar-thin">
        {workspacePath && !error && (
          <>
            {flatTree.length === 0 && !loading && (
              <div className="py-12 text-center text-muted-foreground/40 text-[11px] italic">
                No files found in this directory
              </div>
            )}
            {flatTree.map((node, i) => (
              <div
                key={node.path}
                className="group flex items-center justify-between rounded px-1.5 py-1 hover:bg-white/5 transition cursor-pointer text-foreground/80 hover:text-foreground"
                style={{ paddingLeft: `${node.depth * 10 + 6}px` }}
                onClick={() => node.isDir && toggleFolder(node, i)}
              >
                <div className="flex items-center gap-2 min-w-0">
                  {node.isDir ? (
                    <>
                      {node.isExpanded ? (
                        <ChevronDown className="size-3 text-muted-foreground/60 shrink-0" />
                      ) : (
                        <ChevronRight className="size-3 text-muted-foreground/60 shrink-0" />
                      )}
                      {node.isExpanded ? (
                        <FolderOpen className="size-3.5 text-warning/80 shrink-0" />
                      ) : (
                        <Folder className="size-3.5 text-warning/80 shrink-0" />
                      )}
                    </>
                  ) : (
                    <>
                      <span className="w-3" />
                      <FileText className="size-3.5 text-muted-foreground/60 shrink-0" />
                    </>
                  )}
                  <span className="truncate text-[13px] font-mono">{node.name}</span>
                </div>

                <div className="flex items-center gap-2 shrink-0">
                  {!node.isDir && node.sizeBytes !== undefined && (
                    <span className="text-[9px] text-muted-foreground/45 font-mono">
                      {formatBytes(node.sizeBytes)}
                    </span>
                  )}

                  <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                    {node.isDir ? (
                      <button
                        onClick={e => {
                          e.stopPropagation();
                          handleSetWorkspace(node.path);
                        }}
                        title="Set as active workspace path"
                        className="p-0.5 hover:bg-white/10 rounded text-primary hover:text-primary-foreground transition"
                      >
                        <FolderSearch className="size-3" />
                      </button>
                    ) : (
                      <button
                        onClick={e => {
                          e.stopPropagation();
                          handleReferenceFile(node.path);
                        }}
                        title="Reference in chat"
                        className="p-0.5 hover:bg-white/10 rounded text-muted-foreground hover:text-foreground transition"
                      >
                        <Link2 className="size-3" />
                      </button>
                    )}
                  </div>
                </div>
              </div>
            ))}
            {loading && (
              <div className="py-4 text-center text-muted-foreground/50 text-[12px] animate-pulse">
                Loading files...
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

/* ── ContextRing regression tests for black-screen bug ───────────────── */
/* These tests assert that the portaled ContextRing tooltip is positioned
 * safely inside the viewport and does not carry the compositing hint
 * (`will-change`) that, combined with `position: fixed` and negative
 * coordinates, produces a full-viewport black rectangle.
 */

import { describe, it, expect, vi } from 'vitest';
import { render, screen, fireEvent } from '@testing-library/react';
import { ContextRing, estimateContextBreakdown } from '../ChatComposer';

const mockBreakdown = estimateContextBreakdown({
  messages: [{ role: 'user', content: 'hello world' }],
  input: 'test',
  toolCount: 1,
});

describe('ContextRing tooltip regression', () => {
  it('renders a portaled tooltip on hover without will-change transform/opacity', () => {
    render(
      <ContextRing
        pct={42}
        estTokens={1000}
        maxContext={4000}
        modelName="test-model"
        breakdown={mockBreakdown}
      />
    );

    const trigger = screen.getByRole('button', { name: /context used/i });
    fireEvent.mouseEnter(trigger);

    const tooltip = document.querySelector('[data-composer-popover]');
    expect(tooltip).toBeInTheDocument();

    const style = (tooltip as HTMLElement | null)?.style;
    expect(style?.willChange).not.toMatch(/transform/);
    expect(style?.willChange).not.toMatch(/opacity/);
  });

  it('positions the tooltip inside the viewport with finite width', () => {
    render(
      <ContextRing
        pct={42}
        estTokens={1000}
        maxContext={4000}
        modelName="test-model"
        breakdown={mockBreakdown}
      />
    );

    const trigger = screen.getByRole('button', { name: /context used/i });
    fireEvent.mouseEnter(trigger);

    const tooltip = document.querySelector('[data-composer-popover]') as HTMLElement | null;
    expect(tooltip).toBeInTheDocument();

    // jsdom does not run a CSS layout engine, so getBoundingClientRect() returns
    // zeros for portaled elements. Derive a rect from the inline position the
    // component actually set (style.top/style.left, produced by the clamping
    // logic under test) plus the fixed w-72 width (288px) so the bounds
    // assertions exercise the real positioning rather than jsdom's no-op layout.
    const top = parseFloat(tooltip!.style.top) || 0;
    const left = parseFloat(tooltip!.style.left) || 0;
    const width = 288; // w-72
    const height = 180;
    vi.spyOn(tooltip!, 'getBoundingClientRect').mockReturnValue({
      top, left, width, height, bottom: top + height, right: left + width, x: left, y: top,
      toJSON: () => ({ top, left, width, height }),
    });

    const rect = tooltip!.getBoundingClientRect();
    expect(rect.left).toBeGreaterThanOrEqual(0);
    expect(rect.top).toBeGreaterThanOrEqual(0);
    expect(Number.isFinite(rect.width)).toBe(true);
    expect(Number.isFinite(rect.height)).toBe(true);
    expect(rect.width).toBeGreaterThan(0);
    expect(rect.width).toBeLessThanOrEqual(288);
  });
});

describe('ContextRing gauge percentage from server ground truth', () => {
  it('derives pct from estTokens/maxContext (server contextTokens)', () => {
    // Simulates: backend reported contextTokens = 48000 for a 200k window.
    // The ring should show 24% — NOT an inflated value from the old flat-3000
    // + 15% thinking + all-tools heuristic.
    const maxContext = 200000;
    const contextTokens = 48000;
    const pct = Math.min(100, Math.round((contextTokens / maxContext) * 100));
    expect(pct).toBe(24);

    const breakdown = estimateContextBreakdown({
      messages: [{ role: 'user', content: 'a'.repeat(4000) }],
      input: '',
      toolCount: 10,
      scaleToTotal: contextTokens,
    });

    render(
      <ContextRing
        pct={pct}
        estTokens={contextTokens}
        maxContext={maxContext}
        modelName="claude-sonnet"
        breakdown={breakdown}
      />
    );

    const trigger = screen.getByRole('button', { name: /context used/i });
    fireEvent.mouseEnter(trigger);

    const tooltip = document.querySelector('[data-composer-popover]');
    expect(tooltip).toBeInTheDocument();
    // Header reads the real server total, not an inflated heuristic.
    expect(tooltip?.textContent).toContain('48.0K');
    expect(tooltip?.textContent).toContain('200.0K');
    expect(tooltip?.textContent).toContain('24%');
  });

  it('breakdown rows sum to the displayed estTokens total', () => {
    const maxContext = 128000;
    const contextTokens = 25600; // 20%
    const pct = Math.min(100, Math.round((contextTokens / maxContext) * 100));
    const breakdown = estimateContextBreakdown({
      messages: [{ role: 'user', content: 'a'.repeat(2000) }],
      input: 'a'.repeat(500),
      toolCount: 8,
      scaleToTotal: contextTokens,
    });
    const sum =
      breakdown.messages +
      breakdown.thinking +
      breakdown.systemTools +
      breakdown.systemPrompt +
      breakdown.skills +
      breakdown.meta;
    expect(sum).toBe(contextTokens);

    render(
      <ContextRing
        pct={pct}
        estTokens={contextTokens}
        maxContext={maxContext}
        breakdown={breakdown}
      />
    );

    const trigger = screen.getByRole('button', { name: /context used/i });
    fireEvent.mouseEnter(trigger);
    const tooltip = document.querySelector('[data-composer-popover]');
    expect(tooltip).toBeInTheDocument();
    expect(tooltip?.textContent).toContain('20%');
  });
});

import { describe, expect, it } from 'vitest';
import { createChatRuntime } from './chat-runtime';

describe('chat runtime session isolation', () => {
  it('allows different sessions to stream concurrently', () => {
    const runtime = createChatRuntime();
    const a = runtime.startTurn({ sessionId: 'a', assistantMsgId: 'a1' });
    const b = runtime.startTurn({ sessionId: 'b', assistantMsgId: 'b1' });

    expect(runtime.isSessionStreaming('a')).toBe(true);
    expect(runtime.isSessionStreaming('b')).toBe(true);
    expect(runtime.canStartTurn('a')).toBe(false);
    expect(runtime.canStartTurn('b')).toBe(false);

    runtime.finishTurn(a.turnId, 'done');

    expect(runtime.isSessionStreaming('a')).toBe(false);
    expect(runtime.isSessionStreaming('b')).toBe(true);
  });

  it('blocks duplicate turns within the same session', () => {
    const runtime = createChatRuntime();
    const first = runtime.startTurn({ sessionId: 'a', assistantMsgId: 'a1' });
    const second = runtime.startTurn({ sessionId: 'a', assistantMsgId: 'a2' });

    expect(second.turnId).toBe(first.turnId);
    expect(runtime.getActiveTurn('a')?.assistantMsgId).toBe('a1');
    expect(runtime.canStartTurn('a')).toBe(false);
  });

  it('only aborts the requested session turn', () => {
    const runtime = createChatRuntime();
    const a = runtime.startTurn({ sessionId: 'a', assistantMsgId: 'a1' });
    const b = runtime.startTurn({ sessionId: 'b', assistantMsgId: 'b1' });

    runtime.abortTurn(a.turnId);

    expect(a.controller.signal.aborted).toBe(true);
    expect(b.controller.signal.aborted).toBe(false);
    expect(runtime.isSessionStreaming('a')).toBe(false);
    expect(runtime.isSessionStreaming('b')).toBe(true);
  });
});

export type ChatTransport = 'ws' | 'http' | 'none';
export type ChatTurnStatus = 'pending' | 'streaming' | 'done' | 'error' | 'aborted';

export interface ChatTurnRecord {
  turnId: string;
  sessionId: string | null;
  assistantMsgId: string;
  requestId?: string;
  controller: AbortController;
  transport: ChatTransport;
  status: ChatTurnStatus;
  startedAt: number;
  updatedAt: number;
}

export interface StartTurnInput {
  sessionId: string | null;
  assistantMsgId: string;
  transport?: ChatTransport;
}

export interface ChatRuntimeSnapshot {
  activeTurns: ChatTurnRecord[];
  activeTurnIdsBySession: Record<string, string[]>;
}

type RuntimeSubscriber = () => void;

export interface ChatRuntime {
  canStartTurn(sessionId: string | null): boolean;
  startTurn(input: StartTurnInput): ChatTurnRecord;
  getTurn(turnId: string): ChatTurnRecord | null;
  setRequestId(turnId: string, requestId: string): void;
  setTransport(turnId: string, transport: ChatTransport): void;
  finishTurn(turnId: string, status?: ChatTurnStatus): void;
  abortTurn(turnId: string): void;
  abortSession(sessionId: string | null): void;
  isSessionStreaming(sessionId: string | null): boolean;
  getActiveTurn(sessionId: string | null): ChatTurnRecord | null;
  getLatestActiveTurnId(sessionId: string | null): string | null;
  subscribe(callback: RuntimeSubscriber): () => void;
  snapshot(): ChatRuntimeSnapshot;
}

const GLOBAL_SESSION_KEY = '__global__';

function sessionKey(sessionId: string | null) {
  return sessionId ?? GLOBAL_SESSION_KEY;
}

export function getActiveSessionIds(snapshot: ChatRuntimeSnapshot = chatRuntime.snapshot()) {
  return Array.from(new Set(snapshot.activeTurns.map((turn) => turn.sessionId).filter(Boolean) as string[]));
}

export function subscribeActiveSessions(callback: (sessionIds: string[]) => void) {
  const sync = () => callback(getActiveSessionIds(chatRuntime.snapshot()));
  sync();
  return chatRuntime.subscribe(sync);
}

export function createChatRuntime(): ChatRuntime {
  const turns = new Map<string, ChatTurnRecord>();
  const turnIdsBySession = new Map<string, string[]>();
  const subscribers = new Set<RuntimeSubscriber>();

  const notify = () => {
    Array.from(subscribers).forEach((subscriber) => subscriber());
  };

  const reindexSession = (sessionId: string | null) => {
    turnIdsBySession.set(
      sessionKey(sessionId),
      Array.from(turns.values())
        .filter((turn) => turn.sessionId === sessionId && turn.status === 'streaming')
        .map((turn) => turn.turnId)
    );
  };

  const runtime: ChatRuntime = {
    canStartTurn(sessionId) {
      const activeIds = turnIdsBySession.get(sessionKey(sessionId)) ?? [];
      return !activeIds.some((id) => turns.get(id)?.status === 'streaming');
    },

    startTurn(input) {
      const existing = this.getActiveTurn(input.sessionId);
      if (existing) return existing;

      const controller = new AbortController();
      const now = Date.now();
      const turnId = `${input.sessionId ?? 'global'}:${input.assistantMsgId}:${now}:${Math.random().toString(36).slice(2)}`;
      const turn: ChatTurnRecord = {
        turnId,
        sessionId: input.sessionId,
        assistantMsgId: input.assistantMsgId,
        controller,
        transport: input.transport ?? 'none',
        status: 'streaming',
        startedAt: now,
        updatedAt: now,
      };

      turns.set(turnId, turn);
      const sessionTurns = turnIdsBySession.get(sessionKey(input.sessionId)) ?? [];
      sessionTurns.push(turnId);
      turnIdsBySession.set(sessionKey(input.sessionId), sessionTurns);
      notify();
      return turn;
    },

    getTurn(turnId) {
      return turns.get(turnId) ?? null;
    },

    setRequestId(turnId, requestId) {
      const turn = turns.get(turnId);
      if (!turn) return;
      turn.requestId = requestId;
      turn.updatedAt = Date.now();
      notify();
    },

    setTransport(turnId, transport) {
      const turn = turns.get(turnId);
      if (!turn) return;
      turn.transport = transport;
      turn.updatedAt = Date.now();
      notify();
    },

    finishTurn(turnId, status = 'done') {
      const turn = turns.get(turnId);
      if (!turn) return;
      turn.status = status;
      turn.updatedAt = Date.now();
      reindexSession(turn.sessionId);
      notify();
    },

    abortTurn(turnId) {
      const turn = turns.get(turnId);
      if (!turn) return;
      turn.controller.abort();
      turn.status = 'aborted';
      turn.updatedAt = Date.now();
      reindexSession(turn.sessionId);
      notify();
    },

    abortSession(sessionId) {
      for (const turn of Array.from(turns.values())) {
        if (turn.sessionId === sessionId && turn.status === 'streaming') {
          turn.controller.abort();
          turn.status = 'aborted';
          turn.updatedAt = Date.now();
        }
      }
      reindexSession(sessionId);
      notify();
    },

    isSessionStreaming(sessionId) {
      const activeIds = turnIdsBySession.get(sessionKey(sessionId)) ?? [];
      return activeIds.some((id) => turns.get(id)?.status === 'streaming');
    },

    getActiveTurn(sessionId) {
      const activeIds = turnIdsBySession.get(sessionKey(sessionId)) ?? [];
      return activeIds.map((id) => turns.get(id)).find((turn): turn is ChatTurnRecord => !!turn && turn.status === 'streaming') ?? null;
    },

    getLatestActiveTurnId(sessionId) {
      const activeIds = turnIdsBySession.get(sessionKey(sessionId)) ?? [];
      return activeIds.length > 0 ? activeIds[activeIds.length - 1] : null;
    },

    subscribe(callback) {
      subscribers.add(callback);
      return () => subscribers.delete(callback);
    },

    snapshot() {
      return {
        activeTurns: Array.from(turns.values()).filter((turn) => turn.status === 'streaming'),
        activeTurnIdsBySession: Object.fromEntries(Array.from(turnIdsBySession.entries()) as [string, string[]][]),
      };
    },
  };

  return runtime;
}

export const chatRuntime = createChatRuntime();

import { atom } from 'nanostores';
import type { ChatMessage, MessageBlock } from '@/types/chat';
import type { WorkbenchMode, EffortLevel } from '@/types/chat';
import type { WorkbenchSession } from '@/types/workbench';
import { streamWorkbenchChat, streamWorkbenchReconnect, stopWorkbenchChat } from '@/api/workbench';
import { setSessionStatus, clearSessionStatus, $sessions } from '@/store/sessions';
import { makeStreamHandlers } from './makeStreamHandlers';
import { gitApi } from '@/api/git';
import { chatRuntime } from './chat-runtime';
import { pushBrowserAction } from '@/lib/browser-store';
import { upsertQueuedMessage, removeQueuedMessage, setQueuedMessages } from './queue-store';

export interface SessionStreamState {
  messages: ChatMessage[];
  subagentPrompts: Map<string, {
    content: string;
    systemPrompt: string;
    userMessage: string;
    tokens: number;
    subagentId?: string;
    jobId?: string;
  }>;
  /** Live sub-agent containers keyed by the agent job id. Each container
   *  holds its own `blocks` array so thinking/text/toolCall/toolResult
   *  events for the sub-agent are rendered nested under the parent
   *  `august__spawn_subagent` / `august__run_team` tool call. */
  subagentBlocks: Map<string, SubagentBlockState>;
  toolProgress: Map<string, ReadonlyArray<ToolProgressEntry>>;
  workbenchBtw: WorkbenchBtwState | null;
  workbenchSession: WorkbenchSession | null;
}

export type {
  ChatMessage,
  MessageBlock,
  SubagentBlockState,
  ToolProgressEntry,
  WorkbenchBtwState,
} from '@/types/chat';
import type { SubagentBlockState, ToolProgressEntry, WorkbenchBtwState, AppendBlockEvent } from '@/types/chat';

/** Apply a React-style SetStateAction updater to a previous value. Mirrors
 *  the semantics of `React.Dispatch<React.SetStateAction<T>>` so the chat
 *  store layer can use the same calling convention. */
function applyUpdater<T>(updater: T | ((prev: T) => T), prev: T): T {
  return typeof updater === 'function' ? (updater as (prev: T) => T)(prev) : updater;
}

// Global store for the stream states of all sessions
export const $sessionStreamStates = atom<Record<string, SessionStreamState>>({});

// Keep track of active fetch AbortControllers on the client
export const activeStreamControllers = new Map<string, AbortController>();

/**
 * Per-session SSE subscriber that holds the live GET /api/workbench/chat/stream
 * connection. Independent of the per-turn AbortController above — detaching
 * this subscriber (e.g. when the user switches sessions) does NOT stop the
 * backend generation; the connection is just closed client-side. Other
 * subscribers (e.g. another tab) can re-attach via `sinceSeq` and replay
 * the missed events from the persistent chat-event-log.
 */
const sessionSubscribers = new Map<string, {
  controller: AbortController;
  lastSeq: number;
}>();

const LAST_SEQ_PREFIX = 'chat_last_seq_';
const SUB_LAST_SEQ = (sessionId: string) => `${LAST_SEQ_PREFIX}${sessionId}`;

function readLastSeq(sessionId: string): number {
  try {
    const raw = localStorage.getItem(SUB_LAST_SEQ(sessionId));
    const n = Number(raw);
    return Number.isFinite(n) && n > 0 ? n : 0;
  } catch (_) { return 0; }
}

function writeLastSeq(sessionId: string, seq: number) {
  if (!Number.isFinite(seq) || seq <= 0) return;
  try { localStorage.setItem(SUB_LAST_SEQ(sessionId), String(seq)); } catch (_) {}
}

const MESSAGES_STORAGE_PREFIX = 'chat_messages_';

const messagesStorageKey = (sessionId: string | null) => sessionId ? `${MESSAGES_STORAGE_PREFIX}${sessionId}` : null;

export function loadMessagesForSession(sessionId: string | null): ChatMessage[] {
  const key = messagesStorageKey(sessionId);
  if (!key) return [];

  try {
    const saved = localStorage.getItem(key);
    if (saved) return JSON.parse(saved);
  } catch {}

  return [];
}

export function getOrInitSessionStreamState(sessionId: string | null): SessionStreamState {
  if (!sessionId) {
    return {
      messages: [],
      subagentPrompts: new Map(),
      subagentBlocks: new Map(),
      toolProgress: new Map(),
      workbenchBtw: null,
      workbenchSession: null,
    };
  }

  const current = $sessionStreamStates.get()[sessionId];
  if (current) return current;

  // Initialize from localStorage or defaults
  const initialMessages = loadMessagesForSession(sessionId);

  let workbenchSession: WorkbenchSession | null = null;
  const sessions = $sessions.get();
  const activeSession = sessions.find(s => s.id === sessionId);
  if (activeSession?.workbenchSessionId) {
    workbenchSession = {
      id: activeSession.workbenchSessionId,
      provider: (activeSession.workbenchProvider || 'claude'),
      agentId: activeSession.workbenchAgentId || 'build',
      agentRole: activeSession.workbenchAgentId || 'build',
      agentMode: 'assistant',
      approved: false,
      approvedAt: null,
      plan: null,
      goal: null,
      lastGoal: null,
      messageCount: 0,
      mutationCount: 0,
      lastMutationAt: null,
      updatedAt: new Date().toISOString(),
      todos: [],
      guardMode: 'full',
    };
  }

  const state: SessionStreamState = {
    messages: initialMessages,
    subagentPrompts: new Map(),
    subagentBlocks: new Map(),
    toolProgress: new Map(),
    workbenchBtw: null,
    workbenchSession,
  };

  $sessionStreamStates.set({
    ...$sessionStreamStates.get(),
    [sessionId]: state,
  });

  return state;
}

export function updateSessionStreamState(
  sessionId: string,
  updater: (prev: SessionStreamState) => Partial<SessionStreamState>
) {
  const current = getOrInitSessionStreamState(sessionId);
  const next = { ...current, ...updater(current) };
  $sessionStreamStates.set({
    ...$sessionStreamStates.get(),
    [sessionId]: next,
  });
}

function persistMessages(sessionId: string, messages: ChatMessage[]) {
  try {
    localStorage.setItem(`chat_messages_${sessionId}`, JSON.stringify(messages));
  } catch {}
}

// Check if we are currently streaming a session
export function isSessionStreaming(sessionId: string | null): boolean {
  if (!sessionId) return false;
  return activeStreamControllers.has(sessionId);
}

// Start a new chat generation
export async function startChatStream(
  sessionId: string,
  params: {
    message: string;
    chatHistory: ChatMessage[];
    workbenchMode: WorkbenchMode;
    effort: EffortLevel;
    model: string | undefined;
    modelProvider: string | undefined;
    getWorkbenchProvider: () => 'claude' | 'codex';
    ensureWorkbenchSession: () => Promise<WorkbenchSession | null>;
  }
) {
  if (activeStreamControllers.has(sessionId)) {
    if (chatRuntime.isSessionStreaming(sessionId)) {
      return;
    }
    activeStreamControllers.delete(sessionId);
  }

  setSessionStatus(sessionId, 'working');

  const assistantMsgId = `a${Date.now()}`;
  const abortController = new AbortController();
  activeStreamControllers.set(sessionId, abortController);

  const turn = chatRuntime.startTurn({
    sessionId,
    assistantMsgId,
    transport: 'none',
  });

  const { handlers, finalize } = makeStreamHandlers({
    sessionId,
    assistantMsgId,
    initialMessages: params.chatHistory,
    setMessages: (updater) => {
      updateSessionStreamState(sessionId, prev => {
        const nextMsgs = applyUpdater(updater, prev.messages);
        persistMessages(sessionId, nextMsgs);
        return { messages: nextMsgs };
      });
    },
    persistMessages,
    setSessionStatus,
    setWorkbenchSession: (session) => {
      updateSessionStreamState(sessionId, () => ({ workbenchSession: session }));
    },
    setSubagentPrompts: (updater) => {
      updateSessionStreamState(sessionId, prev => {
        const nextPrompts = applyUpdater(updater, prev.subagentPrompts);
        return { subagentPrompts: nextPrompts };
      });
    },
    setToolProgress: (updater) => {
      updateSessionStreamState(sessionId, prev => {
        const nextProgress = applyUpdater(updater, prev.toolProgress);
        return { toolProgress: nextProgress };
      });
    },
    setWorkbenchBtw: (btw) => {
      updateSessionStreamState(sessionId, () => ({ workbenchBtw: btw }));
    },
    isTurnVisible: () => true,
    finishTurn: (t, status) => {
      chatRuntime.finishTurn(t.turnId, status);
      activeStreamControllers.delete(sessionId);
    },
    turn,
    gitApi,
    streamUpdateIntervalMs: 24,
    appendBlockEvent,
  });

  try {
    const session = await params.ensureWorkbenchSession();
    if (!session) {
      updateSessionStreamState(sessionId, prev => ({
        messages: prev.messages.map(msg =>
          msg.id === assistantMsgId ? { ...msg, content: '⚠️ Could not initialize Workbench session.' } : msg
        )
      }));
      finalize('error');
      activeStreamControllers.delete(sessionId);
      return;
    }

    chatRuntime.setTransport(turn.turnId, 'http');

    const startResult = await streamWorkbenchChat({
      sessionId: session.id,
      message: params.message,
      provider: params.getWorkbenchProvider(),
      effort: params.effort,
      model: params.model,
      modelProvider: params.modelProvider,
    }, handlers, abortController.signal);

    // The POST handler returns { sinceSeq } JSON immediately and runs the
    // generation in the background. Live events are delivered via the
    // separate /api/workbench/chat/stream SSE channel — attach it now using
    // the same per-turn handlers so streamed text / thinking / toolUse /
    // toolResult events reach the chat UI. Without this, events accumulate
    // in the chat-event-log unread and the assistant bubble stays empty.
    //
    // Always attach the SSE subscriber when the POST didn't already consume
    // the event stream (legacy SSE POST body path sets consumedViaPost=true).
    // The backend handles missing/undefined sinceSeq by starting from the
    // current event log position.
    if (startResult?.consumedViaPost) {
      // Events were already delivered through the POST response body
      // (older backend / proxy without the JSON sinceSeq contract).
    } else {
      const reconnectSinceSeq = Number.isFinite(startResult?.sinceSeq)
        ? startResult!.sinceSeq
        : undefined;
      if (reconnectSinceSeq === undefined) {
        console.warn('[startChatStream] POST succeeded without a valid sinceSeq — reconnecting from current position as fallback');
      }
      await streamWorkbenchReconnect(
        session.id,
        handlers,
        abortController.signal,
        reconnectSinceSeq
      );
    }

    finalize(abortController.signal.aborted ? 'aborted' : 'done');
  } catch (e) {
    if (e instanceof Error && e.name === 'AbortError') {
      clearSessionStatus(sessionId);
      finalize('aborted');
      return;
    }
    console.error('[startChatStream] error:', e);
    const errorMsg = e instanceof Error
      ? e.message
      : typeof e === 'string'
        ? e
        : 'Unknown error';
    updateSessionStreamState(sessionId, prev => ({
      messages: prev.messages.map(msg =>
        msg.id === assistantMsgId
          ? { ...msg, content: (msg.content || '') + `\n\n⚠️ Could not generate a response: ${errorMsg}` }
          : msg
      )
    }));
    // Also emit an error event through the handler so the onError path
    // in makeStreamHandlers can write the ⚠️ block into streamBlocks.
    try { handlers.onError?.({ message: errorMsg }); } catch {}
    finalize('error');
  } finally {
    activeStreamControllers.delete(sessionId);
  }
}

// Stop/abort generation for a session
export async function stopChatStream(sessionId: string) {
  const controller = activeStreamControllers.get(sessionId);
  if (controller) {
    controller.abort();
    activeStreamControllers.delete(sessionId);
  }

  const activeTurnId = chatRuntime.getLatestActiveTurnId(sessionId);
  const turn = activeTurnId ? chatRuntime.getTurn(activeTurnId) : null;
  if (turn) {
    chatRuntime.abortTurn(turn.turnId);
  }

  clearSessionStatus(sessionId);

  // Tell the backend to stop
  try {
    const state = getOrInitSessionStreamState(sessionId);
    const wbSessionId = state.workbenchSession?.id || sessionId;
    await stopWorkbenchChat(wbSessionId);
  } catch (err) {
    console.warn('Failed to notify backend of stop:', err);
  }
}

// Reconnect/sync stream with the backend
export async function reconnectChatStream(
  sessionId: string,
  ensureWorkbenchSession: () => Promise<WorkbenchSession | null>
) {
  if (activeStreamControllers.has(sessionId)) {
    // Already active
    return;
  }

  const state = getOrInitSessionStreamState(sessionId);
  const messages = state.messages;
  const lastUserIdx = messages.map(m => m.role).lastIndexOf('user');
  const initialMessages = lastUserIdx !== -1 ? messages.slice(0, lastUserIdx + 1) : messages;

  let assistantMsgId = '';
  if (lastUserIdx !== -1 && lastUserIdx + 1 < messages.length) {
    assistantMsgId = messages[lastUserIdx + 1].id;
  } else {
    assistantMsgId = `a${Date.now()}`;
  }

  const turn = chatRuntime.startTurn({
    sessionId,
    assistantMsgId,
    transport: 'none',
  });

  // Use the turn's controller so aborting the turn also cancels fetches.
  const abortController = turn.controller;
  activeStreamControllers.set(sessionId, abortController);

  const { handlers, finalize } = makeStreamHandlers({
    sessionId,
    assistantMsgId,
    initialMessages,
    setMessages: (updater) => {
      updateSessionStreamState(sessionId, prev => {
        const nextMsgs = applyUpdater(updater, prev.messages);
        persistMessages(sessionId, nextMsgs);
        return { messages: nextMsgs };
      });
    },
    persistMessages,
    setSessionStatus,
    setWorkbenchSession: (session) => {
      updateSessionStreamState(sessionId, () => ({ workbenchSession: session }));
    },
    setSubagentPrompts: (updater) => {
      updateSessionStreamState(sessionId, prev => {
        const nextPrompts = applyUpdater(updater, prev.subagentPrompts);
        return { subagentPrompts: nextPrompts };
      });
    },
    setToolProgress: (updater) => {
      updateSessionStreamState(sessionId, prev => {
        const nextProgress = applyUpdater(updater, prev.toolProgress);
        return { toolProgress: nextProgress };
      });
    },
    setWorkbenchBtw: (btw) => {
      updateSessionStreamState(sessionId, () => ({ workbenchBtw: btw }));
    },
    isTurnVisible: () => true,
    finishTurn: (t, status) => {
      chatRuntime.finishTurn(t.turnId, status);
      activeStreamControllers.delete(sessionId);
    },
    turn,
    gitApi,
    streamUpdateIntervalMs: 24,
    appendBlockEvent,
  });

  try {
    chatRuntime.setTransport(turn.turnId, 'http');

    const lastSeq = getSessionSubscriberLastSeq(sessionId);
    await streamWorkbenchReconnect(sessionId, handlers, abortController.signal, lastSeq || undefined);
    finalize(abortController.signal.aborted ? 'aborted' : 'done');
  } catch (e) {
    if (e instanceof Error && e.name === 'AbortError') {
      clearSessionStatus(sessionId);
      finalize('aborted');
      return;
    }
    console.warn('Reconnect error:', e);
    finalize('done');
  } finally {
    activeStreamControllers.delete(sessionId);
  }
}

// Sync all active streams with the backend
export async function syncActiveStreams(ensureWorkbenchSession: () => Promise<WorkbenchSession | null>) {
  try {
    const res = await fetch('/api/workbench/chat/active');
    if (!res.ok) return;
    const active: Record<string, string> = await res.json();
    for (const sessionId of Object.keys(active)) {
      if (active[sessionId] === 'streaming') {
        // Re-attach the per-session SSE subscriber if we don't have one.
        // The subscriber is independent of any per-turn AbortController —
        // it stays attached across tab/session switches and only detaches
        // when the backend reports the turn finished or the SSE closes.
        ensureSessionSubscriber(sessionId);
      }
    }
  } catch (err) {
    console.warn('Failed to sync active streams:', err);
  }
}

/**
 * Attach (or re-attach) the per-session SSE subscriber that pulls events
 * from GET /api/workbench/chat/stream. The subscriber is idempotent: if
 * one is already attached for `sessionId` it is left alone. The reducer
 * updates `subagentBlocks` (so background sub-agents appear in the chat
 * thread even when no per-turn handler is active) and bumps the stored
 * `lastSeq` so subsequent reconnects don't replay events.
 */
export function ensureSessionSubscriber(sessionId: string): void {
  if (!sessionId) return;
  if (sessionSubscribers.has(sessionId)) return;

  // Ensure there is an active turn in chatRuntime so the AUG streaming
  // indicator (WorkingIndicator) shows while the backend is generating.
  // Without this, a previous turn may have been finalized when the original
  // SSE connection dropped (tab switch, throttling), leaving isSessionStreaming
  // false even though the backend is still actively streaming and reconnecting
  // via this subscriber.
  let dummyTurnId: string | null = null;
  if (!chatRuntime.isSessionStreaming(sessionId)) {
    const assistantMsgId = `subscriber-${sessionId}-${Date.now()}`;
    const turn = chatRuntime.startTurn({
      sessionId,
      assistantMsgId,
      transport: 'none',
    });
    dummyTurnId = turn.turnId;
  }

  const controller = new AbortController();
  const sinceSeq = readLastSeq(sessionId);
  const entry = { controller, lastSeq: sinceSeq };
  sessionSubscribers.set(sessionId, entry);

  const handlers: import('@/types/workbench').WorkbenchEventHandlers = {
    onSeq: (seq) => {
      if (seq > entry.lastSeq) {
        entry.lastSeq = seq;
        writeLastSeq(sessionId, seq);
      }
    },
    onSubagentStart: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentStart',
        jobId: data.jobId,
        agentId: data.agentId,
        parentToolUseId: data.parentToolUseId,
        scope: data.scope,
        task: data.task,
        depth: data.depth,
      });
    },
    onSubagentDone: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentDone',
        jobId: data.jobId,
        status: data.status,
        message: data.message,
        result: data.result,
      });
    },
    onSubagentText: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentText',
        jobId: data.jobId,
        content: data.content || '',
      });
    },
    onSubagentToolCall: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentToolCall',
        jobId: data.jobId,
        id: data.id,
        name: data.name,
        input: data.input,
        status: data.status || 'running',
      });
    },
    onSubagentToolResult: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentToolResult',
        jobId: data.jobId,
        id: data.id,
        content: data.content,
        isError: data.isError,
      status: data.status || (data.isError ? 'error' : 'done'),
        });
      },
      onCompaction: (_data) => {
        // Compaction events are handled by the per-turn handler
        // (makeStreamHandlers); the background subscriber acknowledges
        // them so the SSE stream stays healthy.
      },
      onWarning: (data) => {
        console.warn('[chat-stream-manager] warning:', data?.message || data);
      },
      onInfo: (data) => {
        console.info('[chat-stream-manager] info:', data?.message || data);
      },
      onBrowserAction: (data) => {
        pushBrowserAction({
          id: data.id,
          name: data.name,
          input: data.input,
          url: data.url,
          title: data.title,
          target: data.target ?? null,
          screenshot: data.screenshot ?? null,
          typed: data.typed,
          selected: data.selected,
          scrolled: data.scrolled,
          status: data.status,
          ts: Date.now(),
        });
      },
      onUserMessageQueued: (data) => {
        // A follow-up was queued (possibly from another tab or via the
        // optimistic local API call). Add it to the per-session queue
        // store so the UI pills update in real time.
        if (!data?.messageId || !data?.sessionId) return;
        upsertQueuedMessage(data.sessionId, {
          id: data.messageId,
          text: data.text ?? '',
          queuedAt: data.queuedAt ?? new Date().toISOString(),
        });
      },
      onUserMessageDequeued: (data) => {
        if (!data?.messageId || !data?.sessionId) return;
        removeQueuedMessage(data.sessionId, data.messageId);
      },
      onUserMessageInjected: (data) => {
        // The backend drained this message and appended it to the model's
        // in-flight conversation. Clear it from the local queue (it now
        // lives as an inline user bubble in the chat thread) and append
        // a synthetic user message to the session's message log so the
        // thread renders it in the right place.
        if (!data?.messageId || !data?.sessionId) return;
        removeQueuedMessage(data.sessionId, data.messageId);
        const entry = {
          id: `qm-${data.messageId}`,
          role: 'user' as const,
          content: data.text ?? '',
          timestamp: data.queuedAt ?? new Date().toISOString(),
          queued: true,
        };
        updateSessionStreamState(data.sessionId, (prev) => ({
          ...prev,
          messages: [...(prev.messages ?? []), entry],
        }));
      },
    };

  streamWorkbenchReconnect(sessionId, handlers, controller.signal, sinceSeq, {
    // Durable subscriber: effectively-unbounded retry with capped backoff.
    // The backend always emits a terminal event (done/error/aborted) when
    // the turn ends, so retries converge; a dead backend fails fast at the
    // POST /chat that started the turn. This keeps the stream bound to the
    // session across transient drops / tab switches (issue #2).
    maxRetries: Infinity,
  })
    .catch((err) => {
      if (err?.name !== 'AbortError') {
        console.warn('[chat-stream-manager] subscriber error:', err?.message || err);
      }
    })
    .finally(() => {
      // If the controller is still ours (not aborted), drop the entry so
      // a later sync can re-attach. Aborted means we intentionally stopped.
      if (!controller.signal.aborted) {
        sessionSubscribers.delete(sessionId);
      }
      // Finalize the turn we created above so isSessionStreaming reflects
      // the true state. The original stream's turn was already finalized
      // when it disconnected; this cleans up the subscriber-created turn.
      if (dummyTurnId) {
        chatRuntime.finishTurn(dummyTurnId, 'done');
      }
    });
}

export function detachSessionSubscriber(sessionId: string): void {
  const entry = sessionSubscribers.get(sessionId);
  if (!entry) return;
  entry.controller.abort();
  sessionSubscribers.delete(sessionId);
}

export function getSessionSubscriberLastSeq(sessionId: string): number {
  return sessionSubscribers.get(sessionId)?.lastSeq ?? readLastSeq(sessionId);
}

export function appendBlockEvent(
  prevBlocks: MessageBlock[],
  event: AppendBlockEvent
): MessageBlock[] {
  const blocks = [...prevBlocks];
  const lastBlock = blocks[blocks.length - 1];

  if (event.type === 'thinking') {
    const text = event.content || '';
    if (lastBlock && lastBlock.type === 'thinking') {
      lastBlock.content = (lastBlock.content || '') + text;
    } else {
      blocks.push({
        id: `b_think_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        type: 'thinking',
        content: text
      });
    }
    } else if (event.type === 'text' || event.type === 'content' || event.type === 'finalOutput') {
    const text = event.content || '';
    if (lastBlock && lastBlock.type === 'finalOutput') {
      lastBlock.content = (lastBlock.content || '') + text;
    } else {
      blocks.push({
        id: `b_out_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        type: 'finalOutput',
        content: text
      });
    }
  } else if (event.type === 'toolCall' || event.type === 'command') {
    const isCommand = event.type === 'command' || event.name?.startsWith('@run_command') || event.name?.startsWith('run_command');
    const existingIdx = blocks.findIndex(b => b.tool && b.tool.id === event.id);
    if (existingIdx !== -1) {
      const target = { ...blocks[existingIdx] };
      if (target.tool) {
        target.tool = {
          ...target.tool,
          context: event.context || target.tool.context || '',
          status: event.status || target.tool.status || 'running',
        };
      }
      blocks[existingIdx] = target;
    } else {
      blocks.push({
        id: `b_tool_${event.id || Date.now()}`,
        type: isCommand ? 'command' : 'toolCall',
        tool: {
          id: event.id || `tc_${Date.now()}`,
          name: event.name || 'tool',
          context: event.context || '',
          status: event.status || 'running',
          startedAt: Date.now()
        },
        ...(event.isRevisedPlan ? { isRevisedPlan: true } : {}),
      });
    }
  } else if (event.type === 'tool_progress') {
    const targetIdx = blocks.findIndex(b => b.tool && b.tool.id === event.id);
    if (targetIdx !== -1) {
      const target = { ...blocks[targetIdx] };
      if (target.tool) {
        target.tool = {
          ...target.tool,
          preview: (target.tool.preview || '') + (event.preview || '')
        };
      }
      blocks[targetIdx] = target;
    }
  } else if (event.type === 'toolResult') {
    const targetIdx = blocks.findIndex(b => b.tool && b.tool.id === event.id);
    if (targetIdx !== -1) {
      const target = { ...blocks[targetIdx] };
      if (target.tool) {
        target.tool = {
          ...target.tool,
          status: event.status || 'done',
          summary: event.summary || '',
          error: event.error || '',
          duration: event.duration,
          searchHits: event.searchHits ?? target.tool.searchHits,
        };
      }
      blocks[targetIdx] = target;
    }
  }

  return blocks;
}

/**
 * Apply a backend SSE event to the per-session `subagentBlocks` map. Used
 * by the per-session SSE subscriber (and by the per-turn reducer when it
 * wants to surface sub-agent events). Events that don't target a sub-agent
 * (no `jobId`) are no-ops.
 *
 * Returns `true` when the event mutated state, so callers can decide
 * whether to trigger a re-render.
 */
export function applySubagentEvent(
  sessionId: string,
  event:
    | { type: 'subagentStart'; jobId: string; agentId: string; parentToolUseId?: string; scope?: string; task?: string; depth?: number }
    | { type: 'subagent_thinking'; jobId: string; content?: string }
    | { type: 'subagentText'; jobId: string; content?: string }
    | { type: 'subagentToolCall'; jobId: string; id: string; name: string; input?: Record<string, unknown>; context?: string; status?: 'running' | 'done' | 'error' }
    | { type: 'subagentToolResult'; jobId: string; id: string; content?: unknown; isError?: boolean; status?: 'done' | 'error' | 'running'; summary?: string; error?: string; duration?: number }
    | { type: 'subagentDone'; jobId: string; status?: 'completed' | 'failed' | 'cancelled'; message?: string; result?: string }
): boolean {
  if (!sessionId || !event?.jobId) return false;
  const jobId = event.jobId;
  let mutated = false;

  if (event.type === 'subagentStart') {
    updateSessionStreamState(sessionId, (prev) => {
      const blocks = new Map(prev.subagentBlocks);
      if (blocks.has(jobId)) return {};
      blocks.set(jobId, {
        id: `sb_${jobId}`,
        jobId,
        parentToolId: event.parentToolUseId || `subagent-${jobId}`,
        agentId: event.agentId,
        scope: event.scope,
        task: event.task,
        depth: event.depth,
        status: 'running',
        startedAt: Date.now(),
        blocks: [],
      });
      mutated = true;
      return { subagentBlocks: blocks };
    });
    return mutated;
  }

  if (event.type === 'subagentDone') {
    updateSessionStreamState(sessionId, (prev) => {
      const blocks = new Map(prev.subagentBlocks);
      const current = blocks.get(jobId);
      if (!current) return {};
      const status = event.status === 'failed' ? 'failed'
        : event.status === 'cancelled' ? 'cancelled'
        : 'completed';
      blocks.set(jobId, {
        ...current,
        status,
        finishedAt: Date.now(),
        error: event.message,
      });
      mutated = true;
      return { subagentBlocks: blocks };
    });
    return mutated;
  }

  // For thinking/text/toolCall/toolResult events, mutate the inner
  // blocks array via appendBlockEvent (same reducer as the parent).
  updateSessionStreamState(sessionId, (prev) => {
    const blocks = new Map(prev.subagentBlocks);
    const current = blocks.get(jobId);
    if (!current) return {};
    if (event.type === 'subagent_thinking') {
      const inner = appendBlockEvent(current.blocks, { type: 'thinking', content: event.content || '' });
      blocks.set(jobId, { ...current, blocks: inner });
      mutated = true;
    } else if (event.type === 'subagentText') {
      const inner = appendBlockEvent(current.blocks, { type: 'text', content: event.content || '' });
      blocks.set(jobId, { ...current, blocks: inner });
      mutated = true;
    } else if (event.type === 'subagentToolCall') {
      const context = event.context
        || (event.input && Object.keys(event.input).length > 0
          ? JSON.stringify(event.input, null, 2)
          : '');
      const inner = appendBlockEvent(current.blocks, {
        type: 'toolCall',
        id: event.id,
        name: event.name,
        context,
        status: event.status || 'running',
      });
      blocks.set(jobId, { ...current, blocks: inner });
      mutated = true;
    } else if (event.type === 'subagentToolResult') {
      const resultStr = typeof event.content === 'string'
        ? event.content
        : event.content != null ? JSON.stringify(event.content) : '';
      const inner = appendBlockEvent(current.blocks, {
        type: 'toolResult',
        id: event.id,
        status: (event.status || (event.isError ? 'error' : 'done')) as 'done' | 'error',
        summary: event.summary || resultStr.slice(0, 240),
        error: event.error || (event.isError ? resultStr.slice(0, 240) : ''),
        duration: event.duration,
      });
      blocks.set(jobId, { ...current, blocks: inner });
      mutated = true;
    }
    return { subagentBlocks: blocks };
  });
  return mutated;
}

// ── Resilience: re-attach SSE subscribers on tab refocus / network recovery ──
//
// A dropped per-turn stream (tab switch, throttling, brief network blip) used
// to finalize the turn as errored even though the backend kept generating.
// The durable per-session subscriber (ensureSessionSubscriber, unbounded
// retries) keeps the stream bound to the session, but it only gets re-attached
// if something calls syncActiveStreams. We trigger that here on:
//   * visibilitychange (document refocus / tab switch back)
//   * online (network recovered after going offline)
// in addition to the existing poller. This is the frontend half of issue #2:
// long tool→think cycles stay live across interruptions.

let _registeredEnsureSession: ((sessionId: string) => Promise<WorkbenchSession | null>) | null = null;
let _resyncListenersAttached = false;

/** Register the ensureWorkbenchSession callback used by the auto-resync
 *  listeners, and attach the window listeners (idempotently). Called once
 *  at app init with the real session-ensure function. */
export function registerStreamResync(
  ensureWorkbenchSession: (sessionId: string) => Promise<WorkbenchSession | null>,
): void {
  _registeredEnsureSession = ensureWorkbenchSession;
  if (_resyncListenersAttached || typeof window === 'undefined') return;
  _resyncListenersAttached = true;

  const resync = () => {
    if (typeof document !== 'undefined' && document.visibilityState === 'hidden') return;
    // syncActiveStreams accepts a no-arg ensureWorkbenchSession; wrap ours.
    syncActiveStreams(() => _registeredEnsureSession
      ? _registeredEnsureSession('')
      : Promise.resolve(null));
  };

  window.addEventListener('visibilitychange', resync);
  window.addEventListener('online', resync);
}

/**
 * makeStreamHandlers — factory for the per-turn Workbench SSE handler
 * bundle used by both the composer (`ChatThread.handleSend` →
 * `generateAIResponse`) and the plan banner click handlers
 * (`onAccept` / `onAcceptAndImplement` / `onReject` / `onRevise`).
 *
 * Why a factory (not a hook): each turn is a self-contained stream
 * whose closure state (streamBlocks, toolResults, thinkingContent, …)
 * is created fresh per call and discarded when `finalize()` resolves.
 * A React hook would force this state into refs + useState, adding
 * ceremony and rules-of-hooks pitfalls. A plain factory keeps the
 * closure in scope exactly as the composer originally had it.
 *
 * The factory returns:
 *   - `handlers`: the full `WorkbenchEventHandlers` bundle the SSE
 *     reader passes events to. Every event is rendered into the
 *     chat thread via the same reducer (`appendBlockEvent`) the
 *     composer uses.
 *   - `finalize(status)`: called once when the stream ends (or
 *     errors). Writes the final accumulated state into the
 *     assistant message and updates the session status.
 *   - `getState()`: exposes the live per-turn state for callers
 *     that need it.
 *
 * The factory does NOT start the stream itself. The caller drives
 * the stream and then calls `finalize` exactly once.
 */

import type { ChatMessage, MessageBlock, WorkbenchBtwState, AppendBlockEvent } from '@/types/chat';
import type { ChatTurnRecord } from './chat-runtime';
import type { WorkbenchEventHandlers, WorkbenchSession } from '@/types/workbench';
import type { GitDiffResult } from '@/api/git';
import type { ToolProgressEvent, ToolProgressMap } from '@/lib/tool-progress';
import { applyToolProgress } from '@/lib/tool-progress';
import { pushBrowserAction } from '@/lib/browser-store';
import { applySubagentEvent } from './chat-stream-manager';

export interface MakeStreamHandlersOptions {
  sessionId: string;
  assistantMsgId: string;
  /** Current messages at turn start. The factory pushes a placeholder
   *  assistant message and returns the new array via `getNextMessages()`. */
  initialMessages: ChatMessage[];
  setMessages: React.Dispatch<React.SetStateAction<ChatMessage[]>>;
  /** Persist a messages array to durable storage. The factory calls
   *  this on placeholder push and on queue-drain so refresh restores
   *  the right state. */
  persistMessages: (sessionId: string, messages: ChatMessage[]) => void;

  setSessionStatus: (sessionId: string, status: 'idle' | 'working' | 'awaiting' | 'error' | 'done') => void;

  setWorkbenchSession: (session: WorkbenchSession | null) => void;
  setSubagentPrompts: React.Dispatch<React.SetStateAction<Map<string, {
    content: string;
    systemPrompt: string;
    userMessage: string;
    tokens: number;
    subagentId?: string;
    jobId?: string;
  }>>>;
  setToolProgress: React.Dispatch<React.SetStateAction<ToolProgressMap>>;
  setWorkbenchBtw: (result: WorkbenchBtwState | null) => void;

  isTurnVisible: (sessionId: string) => boolean;
  finishTurn: (turn: ChatTurnRecord, status: 'done' | 'error' | 'aborted') => void;
  turn: ChatTurnRecord;



  gitApi: { diff: (sessionId: string) => Promise<GitDiffResult> };
  streamUpdateIntervalMs: number;
  initialMutationCount?: number;

  /** Pure reducer that merges a new SSE event into the streamBlocks
   *  array. Lives in ChatThread.tsx so the composer and the factory
   *  share the exact same merging behavior. */
  appendBlockEvent: (prev: MessageBlock[], event: AppendBlockEvent) => MessageBlock[];
}

export interface StreamHandlers {
  handlers: WorkbenchEventHandlers;
  finalize: (status: 'done' | 'error' | 'aborted') => void;
  getState: () => {
    streamBlocks: MessageBlock[];
    assistantContent: string;
    thinkingContent: string;
    toolResults: NonNullable<ChatMessage['tools']>;
    changedFiles: GitDiffResult | null;
  };
}

export function makeStreamHandlers(opts: MakeStreamHandlersOptions): StreamHandlers {
  const {
    sessionId,
    assistantMsgId,
    initialMessages,
    setMessages,
    persistMessages,
    setSessionStatus,
    setWorkbenchSession,
    setSubagentPrompts,
    setToolProgress,
    setWorkbenchBtw,
    isTurnVisible,
    finishTurn,
    turn,

    gitApi,
    streamUpdateIntervalMs,
    initialMutationCount,
    appendBlockEvent,
  } = opts;

  // Per-turn closure state.
  let assistantContent = '';
  let thinkingContent = '';
  let toolResults: NonNullable<ChatMessage['tools']> = [];
  const pendingConfirmations = new Map<string, { message?: string; detail?: string; confirmationToken?: string }>();
  let streamBlocks: MessageBlock[] = [];
  let changedFiles: GitDiffResult | null = null;
  let beforeMutationCount = initialMutationCount ?? 0;
  let latestMutationCount = 0;
  let latestWorkbenchTodos: NonNullable<ChatMessage['todos']> = [];
  const thinkingStart = Date.now();
  let thinkingEnd: number | null = null;
  let finished = false;

  // Push the assistant placeholder into message state so the bubble
  // exists from frame 0. Persist to storage so refresh restores it.
  const placeholder: ChatMessage = {
    id: assistantMsgId,
    role: 'assistant',
    content: '',
    timestamp: new Date().toISOString(),
  };
  const nextMessages = [...initialMessages, placeholder];
  setMessages(nextMessages);
  persistMessages(sessionId, nextMessages);
  setSubagentPrompts(new Map());

  // ---- update / scheduleUpdate (throttled flush to React state) ----
  let updateTimeout: number | null = null;
  let lastFlushAt = 0;
  const update = () => {
    setMessages(prev => prev.map(msg =>
      msg.id === assistantMsgId ? {
        ...msg,
        content: assistantContent,
        thinking: thinkingContent || undefined,
        tools: toolResults && toolResults.length > 0 ? toolResults : undefined,
        blocks: streamBlocks,
        todos: latestWorkbenchTodos.length > 0 ? latestWorkbenchTodos : undefined,
        changedFiles: changedFiles || undefined,
      } : msg
    ));
  };
  const flushUpdate = () => {
    updateTimeout = null;
    lastFlushAt = (typeof performance !== 'undefined' ? performance.now() : Date.now());
    update();
  };
  const scheduleUpdate = () => {
    if (updateTimeout !== null) return;
    const now = (typeof performance !== 'undefined' ? performance.now() : Date.now());
    const delay = Math.max(0, streamUpdateIntervalMs - (now - lastFlushAt));
    updateTimeout = window.setTimeout(flushUpdate, delay);
  };
  const cancelPendingUpdate = () => {
    if (updateTimeout !== null) {
      window.clearTimeout(updateTimeout);
      updateTimeout = null;
    }
  };

  const finalize = (status: 'done' | 'error' | 'aborted') => {
    if (finished) return;
    finished = true;
    cancelPendingUpdate();
    setMessages(prev => prev.map(msg =>
      msg.id === assistantMsgId ? {
        ...msg,
        content: assistantContent || msg.content,
        thinking: thinkingContent || undefined,
        thinkingDuration: thinkingEnd
          ? Math.round((thinkingEnd - thinkingStart) / 100) / 10
          : thinkingContent.trim()
            ? Math.round((Date.now() - thinkingStart) / 100) / 10
            : undefined,
        tools: toolResults && toolResults.length > 0 ? toolResults : undefined,
        blocks: streamBlocks,
        todos: latestWorkbenchTodos.length > 0 ? latestWorkbenchTodos : undefined,
        changedFiles: changedFiles || undefined,
      } : msg
    ));
    if (status === 'done' || status === 'error') {
      if (isTurnVisible(sessionId)) setSessionStatus(sessionId, status === 'done' ? 'done' : 'error');
    }
    finishTurn(turn, status);

  };

  const handlers: WorkbenchEventHandlers = {
    onPrompt: ({ content, systemPrompt, userMessage, tokens, toolUseId, subagentId, jobId }) => {
      const key = toolUseId || (jobId ? `subagent-${jobId}` : `prompt-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);
      setSubagentPrompts(prev => {
        const next = new Map(prev);
        next.set(key, {
          content,
          systemPrompt: systemPrompt ?? '',
          userMessage: userMessage ?? '',
          tokens: tokens ?? 0,
          subagentId: subagentId || undefined,
          jobId: jobId || undefined,
        });
        return next;
      });
      // Also seed the live sub-agent container so the parent tool call
      // can render the nested block immediately, even if a separate
      // `subagentStart` event arrives later (or was missed during a
      // reconnect).
      if (jobId) {
        applySubagentEvent(sessionId, {
          type: 'subagentStart',
          jobId,
          agentId: subagentId || 'subagent',
          parentToolUseId: toolUseId,
        });
      }
    },
    onSubagentStart: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentStart',
        jobId: data.jobId,
        agentId: data.agentId,
        parentToolUseId: data.parentToolUseId,
        scope: data.scope,
        task: data.task,
        depth: data.depth,
      });
    },
    onSubagentDone: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentDone',
        jobId: data.jobId,
        status: data.status,
        message: data.message,
        result: data.result,
      });
    },
    onSubagentText: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentText',
        jobId: data.jobId,
        content: data.content || '',
      });
    },
    onSubagentToolCall: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentToolCall',
        jobId: data.jobId,
        id: data.id,
        name: data.name,
        input: data.input,
        status: data.status || 'running',
      });
    },
    onSubagentToolResult: (data) => {
      if (!data?.jobId) return;
      applySubagentEvent(sessionId, {
        type: 'subagentToolResult',
        jobId: data.jobId,
        id: data.id,
        content: data.content,
        isError: data.isError,
        status: data.status || (data.isError ? 'error' : 'done'),
      });
    },
    onStarted: ({ sinceSeq }) => {
      // The backend reports the seq of the 'started' event so callers
      // can attach an SSE subscriber that doesn't replay already-seen
      // events. We don't need to act on it here (the subscriber is
      // independent), but we expose it for debugging via a console hint.
      if (Number.isFinite(sinceSeq)) {
        // eslint-disable-next-line no-console
        console.debug('[makeStreamHandlers] chat turn started at seq', sinceSeq);
      }
    },
    onThinking: ({ content }) => {
      // Skip empty thinking deltas — they create a visible thinking block
      // with no text content and no way to dismiss it.
      if (!content) return;
      if (!thinkingEnd && content.trim()) {
        thinkingEnd = Date.now();
      }
      thinkingContent += content;
      streamBlocks = appendBlockEvent(streamBlocks, { type: 'thinking', content });
      scheduleUpdate();
    },
    onText: ({ content }) => {
      if (!thinkingEnd && thinkingContent.trim()) {
        thinkingEnd = Date.now();
      }
      assistantContent += content;
      streamBlocks = appendBlockEvent(streamBlocks, { type: 'finalOutput', content });
      scheduleUpdate();
    },
    onToolUse: ({ id, name, input }) => {
      const existingIdx = toolResults.findIndex(t => t.id === id);
      const toolEntry = {
        name,
        context: JSON.stringify(input || {}, null, 2),
        id,
        status: 'running' as const,
        summary: Object.keys(input || {}).join(', '),
        error: '',
        startedAt: existingIdx !== -1 ? toolResults[existingIdx].startedAt : Date.now(),
      };
      if (existingIdx !== -1) {
        toolResults = toolResults.map((t, idx) => idx === existingIdx ? toolEntry : t);
      } else {
        toolResults = [...toolResults, toolEntry];
      }

      streamBlocks = appendBlockEvent(streamBlocks, {
        type: name.startsWith('@run_command') || name.startsWith('run_command') ? 'command' : 'toolCall',
        name,
        id,
        context: JSON.stringify(input || {}, null, 2),
        status: 'running',
      } as any);
      scheduleUpdate();
    },
    onToolResult: ({ id, content, isError }) => {
      let parsedResult: any;
      try {
        parsedResult = typeof content === 'string' ? JSON.parse(content) : content;
      } catch {
        parsedResult = null;
      }

      if (parsedResult?.type === 'mutation_pending_confirmation') {
        pendingConfirmations.set(id, {
          message: parsedResult.message,
          detail: parsedResult.detail,
          confirmationToken: parsedResult.confirmationToken,
        });
      } else {
        pendingConfirmations.delete(id);
      }

      const resultText = typeof content === 'string' ? content : content != null ? JSON.stringify(content) : '';

      // Extract search hits from structured web_search JSON result
      let searchHits: Array<{ title: string; url: string; snippet?: string }> | undefined;
      const toolEntry = toolResults.find(t => t.id === id);
      if (toolEntry && (toolEntry.name === 'web_search' || toolEntry.name === 'WebSearch')) {
        if (parsedResult && Array.isArray(parsedResult.results)) {
          searchHits = parsedResult.results.map((r: any) => ({
            title: r.title || r.snippet || '',
            url: r.url || '',
            snippet: r.snippet || '',
          }));
        }
      }

      toolResults = toolResults.map(t => t.id === id ? {
        ...t,
        pendingApproval: parsedResult?.type === 'mutation_pending_confirmation' ? {
          message: parsedResult.message,
          detail: parsedResult.detail,
          confirmationToken: parsedResult.confirmationToken,
        } : undefined,
        status: isError && !parsedResult?.type ? 'error' : 'done',
        result: resultText,
        error: isError && !parsedResult?.type ? resultText : '',
        duration: t.startedAt ? Date.now() - t.startedAt : undefined,
        searchHits: searchHits ?? t.searchHits,
      } : t);
      streamBlocks = appendBlockEvent(streamBlocks, {
        type: 'toolResult',
        id,
        status: isError && !parsedResult?.type ? 'error' : 'done',
        summary: resultText.slice(0, 240),
        error: isError && !parsedResult?.type ? resultText.slice(0, 240) : '',
        duration: toolResults.find(t => t.id === id)?.duration,
        searchHits,
      });
      scheduleUpdate();
    },
    onSession: (sessionState) => {
      latestWorkbenchTodos = sessionState.todos ?? [];
      latestMutationCount = sessionState.mutationCount;
      setWorkbenchSession(sessionState);
      scheduleUpdate();
    },
    onBrowserAction: (data) => {
      pushBrowserAction({
        id: data.id,
        name: data.name,
        input: data.input,
        url: data.url,
        title: data.title,
        target: data.target ?? null,
        screenshot: data.screenshot ?? null,
        typed: data.typed,
        selected: data.selected,
        scrolled: data.scrolled,
        status: data.status,
        ts: Date.now(),
      });
    },
    onToolProgress: (event) => {
      const e: ToolProgressEvent = {
        id: event.id,
        phase: event.phase,
        paths: event.paths,
        path: event.path,
      };
      setToolProgress(prev => applyToolProgress(prev, e));
    },
    onBtw: (result) => {
      setWorkbenchBtw(result);
    },
    onCompaction: (info) => {
      // When the summarizing compressor collapses the middle of the
      // conversation, surface a small inline notice so the user can see
      // it happened. The notice is part of the assistant turn so it
      // disappears if the turn is rolled back.
      const notice = `\n\n📦 Context compacted — kept the first ${info.headCount} and last ${info.tailCount} messages; summarized ${info.compressedCount} middle messages (~${info.originalTokens} → ~${info.compressedTokens} tokens).`;
      assistantContent += notice;
      streamBlocks = appendBlockEvent(streamBlocks, { type: 'finalOutput', content: notice });
      scheduleUpdate();
    },
    onWarning: ({ message }) => {
      const warning = `\n\n⚠️ ${message || 'Warning'}`;
      assistantContent += warning;
      streamBlocks = appendBlockEvent(streamBlocks, { type: 'finalOutput', content: warning });
      scheduleUpdate();
    },
    onInfo: ({ message }) => {
      const info = `\n\nℹ️ ${message || ''}`;
      assistantContent += info;
      streamBlocks = appendBlockEvent(streamBlocks, { type: 'finalOutput', content: info });
      scheduleUpdate();
    },
    onDone: async () => {
      if (latestMutationCount > beforeMutationCount && sessionId) {
        try {
          const diff = await gitApi.diff(sessionId);
          if (diff.files.length > 0) changedFiles = diff;
        } catch (e) {
          console.warn('[makeStreamHandlers] Failed to load changed files:', e);
        }
      }
      finalize('done');
    },
    onError: ({ message }) => {
      assistantContent += `\n\n⚠️ Workbench error: ${message}`;
      streamBlocks = appendBlockEvent(streamBlocks, { type: 'finalOutput', content: `\n\n⚠️ Workbench error: ${message}` });
      scheduleUpdate();
      finalize('error');
    },
  };

  return {
    handlers,
    finalize,
    getState: () => ({ streamBlocks, assistantContent, thinkingContent, toolResults, changedFiles }),
  };
}

import { useQuery } from '@tanstack/react-query';
import { useSearchParams } from 'react-router-dom';
import { SectionHeader } from '@/components/SectionHeader';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { StatusPill } from '@/components/StatusPill';
import { Button } from '@/components/ui/button';
import { Server, Plug, ArrowRight, RefreshCw, Wifi, WifiOff } from 'lucide-react';
import { getHostAgentStatus } from '@/api/api-client';
import { api } from '@/api/client';

/* ── Service connection read shape (mirrors Services.tsx, narrowed) ── */
interface ServiceConnection {
  name: string;
  connected: boolean;
  account?: string;
  scopes?: string[];
  status?: string;
}

interface ServiceConnectionsResponse {
  connections: Partial<Record<string, ServiceConnection>>;
}

const SERVICE_LABELS: Record<string, string> = {
  google: 'Google Workspace',
  github: 'GitHub',
  slack: 'Slack',
};

export function Connections() {
  const [params, setParams] = useSearchParams();

  const { data: hostData } = useQuery({
    queryKey: ['host-agent-status'],
    queryFn: () => getHostAgentStatus(),
    refetchInterval: 5_000,
  });
  const { data: svcData } = useQuery({
    queryKey: ['service-connections-summary'],
    queryFn: () => api.get<ServiceConnectionsResponse>('/api/service-connections'),
    refetchInterval: 8_000,
  });

  const connections = Object.values(svcData?.connections || {}) as ServiceConnection[];
  const connectedCount = connections.filter((c) => c.connected).length;
  const hostStatus = hostData?.status || 'unknown';
  const hostConnected = hostStatus === 'connected' || hostStatus === 'open';

  return (
    <div className="p-6 space-y-6">
      <SectionHeader
        title="Connections"
        subtitle={`${connectedCount}/${connections.length} services connected · host agent ${hostStatus}`}
        actions={
          <Button variant="outline" size="sm" onClick={() => setParams({ tab: 'mcp' })}>
            <Plug className="size-3" /> Manage in MCP
          </Button>
        }
      />

      {/* Host agent */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-sm">
            <Server className="size-4" /> Host agent
          </CardTitle>
        </CardHeader>
        <CardContent className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            {hostConnected ? (
              <Wifi className="size-5 text-success" />
            ) : (
              <WifiOff className="size-5 text-muted-foreground" />
            )}
            <div>
              <StatusPill
                tone={hostConnected ? 'good' : 'muted'}
                label={hostStatus}
              />
              <p className="text-xs text-muted-foreground mt-1">
                {hostConnected
                  ? 'Host agent is reachable and accepting commands.'
                  : 'Host agent is not running. Start it to enable file and terminal operations.'}
              </p>
            </div>
          </div>
          <RefreshCw className="size-3.5 text-muted-foreground/50" />
        </CardContent>
      </Card>

      {/* Service connections summary */}
      <div>
        <div className="flex items-center justify-between mb-2">
          <h3 className="text-sm font-semibold">Service connections</h3>
          <button
            onClick={() => setParams({ tab: 'mcp' })}
            className="text-[11px] text-muted-foreground hover:text-foreground inline-flex items-center gap-1 transition"
          >
            Open Services <ArrowRight className="size-3" />
          </button>
        </div>
        {connections.length === 0 ? (
          <Card className="border-dashed">
            <CardContent className="p-6 text-center text-sm text-muted-foreground">
              No service connections configured. Use the Services tab to connect Google, GitHub, or Slack.
            </CardContent>
          </Card>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            {connections.map((c) => (
              <Card key={c.name} className={c.connected ? '' : 'opacity-70'}>
                <CardContent className="p-3 flex items-center justify-between">
                  <div className="min-w-0">
                    <div className="flex items-center gap-2">
                      <span className="text-sm font-medium">{SERVICE_LABELS[c.name] || c.name}</span>
                      <Badge variant={c.connected ? 'outline' : 'secondary'} className="text-[9px]">
                        {c.connected ? 'connected' : 'disconnected'}
                      </Badge>
                    </div>
                    {c.connected && c.account && (
                      <p className="text-[11px] text-muted-foreground font-mono truncate mt-0.5">{c.account}</p>
                    )}
                    {c.connected && c.scopes && c.scopes.length > 0 && (
                      <p className="text-[10px] text-muted-foreground/60 font-mono truncate mt-0.5">
                        {c.scopes.length} scopes
                      </p>
                    )}
                  </div>
                  {!c.connected && (
                    <Button size="sm" variant="outline" onClick={() => setParams({ tab: 'mcp' })}>
                      Connect
                    </Button>
                  )}
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>
      <p className="text-[9px] text-muted-foreground font-mono">
        🔒 Account credentials and tokens are never displayed. Manage OAuth/tokens in the Services tab.
      </p>
    </div>
  );
}

import { useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { SectionHeader } from '@/components/SectionHeader';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Search, MessageSquare, Inbox } from 'lucide-react';
import { formatTimeAgo, cn } from '@/lib/utils';
import { getConversations, type ConversationsResponse, type RequestEntry } from '@/api/api-client';

interface ConversationItem {
  reqId: string;
  clientType: string;
  model: string;
  status: string;
  date?: string;
  messages: Array<{ role: string; content: string }>;
  response?: unknown;
  finishReason?: string | null;
  error?: string | null;
}

function normalize(grouped: ConversationsResponse | undefined): ConversationItem[] {
  const items: ConversationItem[] = [];
  for (const [clientType, entries] of Object.entries(grouped || {})) {
    for (const e of entries as Array<RequestEntry & { details: { messages: unknown; response: unknown; finishReason?: string | null; error?: string | null } | null }>) {
      const rawMessages = e.details?.messages;
      const messages = toMessages(rawMessages);
      items.push({
        reqId: e.reqId,
        clientType,
        model: e.model || 'unknown',
        status: e.status || 'unknown',
        date: e.date,
        messages,
        response: e.details?.response,
        finishReason: e.details?.finishReason,
        error: e.details?.error,
      });
    }
  }
  return items.sort((a, b) => (b.date || '').localeCompare(a.date || ''));
}

function toMessages(raw: unknown): Array<{ role: string; content: string }> {
  if (!Array.isArray(raw)) return [];
  return raw
    .map((m: any) => {
      const role = m?.role || 'unknown';
      let content = '';
      if (typeof m?.content === 'string') content = m.content;
      else if (Array.isArray(m?.content)) {
        content = m.content
          .map((b: any) => (typeof b === 'string' ? b : b?.text || b?.content || b?.type || ''))
          .filter(Boolean)
          .join('\n');
      } else if (m?.content && typeof m.content === 'object') {
        content = String(m.content.text || m.content.content || '');
      }
      return { role, content };
    })
    .filter((m) => m.content);
}

export function Conversations() {
  const { data, isLoading } = useQuery({
    queryKey: ['conversations', 'today'],
    queryFn: () => getConversations('today'),
    refetchInterval: 5_000,
  });

  const items = useMemo(() => normalize(data), [data]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [filter, setFilter] = useState('');

  const visible = items.filter((it) => {
    if (!filter) return true;
    const hay = `${it.clientType} ${it.model} ${it.messages.map((m) => m.content).join(' ')}`.toLowerCase();
    return hay.includes(filter.toLowerCase());
  });

  const selected = items.find((i) => i.reqId === selectedId) ?? null;

  return (
    <div className="flex h-full">
      <div className="w-80 shrink-0 border-r border-border flex flex-col">
        <div className="p-4 border-b border-border">
          <SectionHeader title="Conversations" />
          <div className="relative">
            <Search className="absolute left-2 top-1/2 -translate-y-1/2 size-3.5 text-muted-foreground" />
            <input
              value={filter}
              onChange={(e) => setFilter(e.target.value)}
              placeholder="Filter by client, model, or text…"
              className="w-full pl-7 pr-2 py-1.5 text-xs bg-secondary rounded-md border border-transparent focus:border-border focus:bg-background outline-none transition"
            />
          </div>
        </div>
        <div className="flex-1 overflow-y-auto p-2 space-y-1">
          {isLoading && (
            <p className="text-center text-xs text-muted-foreground py-6">Loading…</p>
          )}
          {!isLoading && visible.length === 0 && (
            <p className="text-center text-xs text-muted-foreground py-6">
              {filter ? `No conversations match "${filter}"` : 'No conversations captured yet'}
            </p>
          )}
          {visible.map((it) => (
            <button
              key={it.reqId}
              onClick={() => setSelectedId(it.reqId)}
              className={cn(
                'w-full text-left rounded-md px-2.5 py-2 transition',
                selectedId === it.reqId ? 'bg-accent' : 'hover:bg-accent/50',
              )}
            >
              <div className="flex items-center justify-between gap-2">
                <p className="text-sm font-medium truncate flex-1">{it.clientType}</p>
                <Badge variant={it.status === 'error' ? 'destructive' : 'secondary'} className="text-[9px]">
                  {it.status.slice(0, 8)}
                </Badge>
              </div>
              <p className="text-[11px] text-muted-foreground truncate mt-0.5">
                {it.messages[it.messages.length - 1]?.content || it.model}
              </p>
              <div className="flex items-center gap-2 mt-1 text-[10px] text-muted-foreground font-mono">
                <span>{it.date ? formatTimeAgo(it.date) : '—'}</span>
                <span>·</span>
                <span><MessageSquare className="inline size-2.5" /> {it.messages.length}</span>
                <span>·</span>
                <span className="truncate">{it.model}</span>
              </div>
            </button>
          ))}
        </div>
      </div>
      <div className="flex-1 overflow-auto p-6">
        {selected ? (
          <ConversationDetail item={selected} />
        ) : (
          <div className="h-full grid place-items-center text-sm text-muted-foreground">
            <div className="text-center">
              <Inbox className="size-8 text-muted-foreground/40 mx-auto mb-2" />
              Select a conversation to view its transcript
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

function ConversationDetail({ item }: { item: ConversationItem }) {
  return (
    <div className="space-y-4">
      <SectionHeader
        title={item.clientType}
        subtitle={`${item.model} · ${item.status} · ${item.date ? formatTimeAgo(item.date) : ''}`}
        actions={
          <div className="flex items-center gap-2 text-[10px] font-mono text-muted-foreground">
            <span>{item.messages.length} messages</span>
            <span>·</span>
            <span className="font-mono">{item.reqId}</span>
          </div>
        }
      />

      {item.error && (
        <Card>
          <CardContent className="p-4">
            <p className="text-[10px] uppercase tracking-wider text-destructive mb-1">Error</p>
            <pre className="text-xs font-mono whitespace-pre-wrap break-all text-destructive">{item.error}</pre>
          </CardContent>
        </Card>
      )}

      {item.messages.length === 0 ? (
        <Card>
          <CardContent className="p-5 text-sm text-muted-foreground italic">
            No message bodies were captured for this request.
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {item.messages.map((m, i) => (
            <div key={i} className={cn('flex', m.role === 'user' ? 'justify-end' : 'justify-start')}>
              <Card className={cn('max-w-[85%]', m.role === 'user' ? 'bg-secondary' : 'bg-card')}>
                <CardContent className="py-2.5 px-3">
                  <div className="flex items-center gap-1.5 text-[10px] text-muted-foreground mb-1 font-mono">
                    <span className="font-semibold">{m.role}</span>
                  </div>
                  <p className="text-sm whitespace-pre-wrap break-words">{m.content}</p>
                </CardContent>
              </Card>
            </div>
          ))}
        </div>
      )}

      {item.finishReason && (
        <p className="text-[10px] text-muted-foreground font-mono px-1">
          finish_reason: {item.finishReason}
        </p>
      )}
    </div>
  );
}

import { useState, useCallback } from 'react';
import { X, HelpCircle, CheckCircle2, XCircle, ChevronRight, Lightbulb, Plus } from 'lucide-react';

interface Question {
  id: number;
  stem: string;
  options: string[];
}

interface AnswerResult {
  correct?: boolean;
  isCorrect?: boolean;
  correctIndex: number;
  rationale: string;
}

interface ExamBannerProps {
  examId: number;
  question: Question;
  onAnswer: (questionId: number, selectedIndex: number) => Promise<AnswerResult>;
  onNext: () => void;
  onAddQuestion: (request: string) => Promise<void>;
  onDismiss: () => void;
}

export function ExamBanner({ examId, question, onAnswer, onNext, onAddQuestion, onDismiss }: ExamBannerProps) {
  const [selected, setSelected] = useState<number | null>(null);
  const [answerResult, setAnswerResult] = useState<AnswerResult | null>(null);
  const [helpText, setHelpText] = useState('');
  const [showExplanation, setShowExplanation] = useState(false);
  const [explanation, setExplanation] = useState('');
  const [addRequest, setAddRequest] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const isCorrect = answerResult
    ? (answerResult.isCorrect ?? answerResult.correct ?? false)
    : false;

  const handleSelect = useCallback(async (index: number) => {
    if (answerResult) return; // already answered
    setSelected(index);
    setIsSubmitting(true);
    try {
      const result = await onAnswer(question.id, index);
      setAnswerResult(result);
    } catch {
      setAnswerResult({ isCorrect: false, correctIndex: 0, rationale: 'Error checking answer.' });
    }
    setIsSubmitting(false);
  }, [question.id, answerResult, onAnswer]);

  const handleHelp = useCallback(async () => {
    if (!helpText.trim()) return;
    setIsSubmitting(true);
    try {
      const res = await fetch(`/api/exam/${examId}/help`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ questionId: question.id, ask: helpText }),
      });
      if (res.ok) {
        const data = await res.json();
        setExplanation(data.explanation || 'No explanation available.');
      } else {
        setExplanation('Unable to get help right now.');
      }
      setShowExplanation(true);
    } catch {
      setExplanation('Unable to get help right now.');
      setShowExplanation(true);
    }
    setIsSubmitting(false);
  }, [examId, question.id, helpText]);

  const handleAddQuestion = useCallback(async () => {
    if (!addRequest.trim()) return;
    setIsSubmitting(true);
    try {
      await onAddQuestion(addRequest);
      setAddRequest('');
    } catch {}
    setIsSubmitting(false);
  }, [addRequest, onAddQuestion]);

  return (
    <>
      {/* Banner */}
      <div className="fixed bottom-0 left-0 right-0 z-50 border-t border-border bg-card shadow-2xl animate-slide-up">
        <div className="mx-auto max-w-3xl p-4 space-y-4">
          {/* Header */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Lightbulb className="size-4 text-warning" />
              <span className="text-sm font-medium">Exam Mode</span>
            </div>
            <button onClick={onDismiss} className="text-muted-foreground hover:text-foreground transition">
              <X className="size-4" />
            </button>
          </div>

          {/* Question stem */}
          <p className="text-sm leading-relaxed">{question.stem}</p>

          {/* Options */}
          <div className="space-y-2">
            {question.options.map((opt, i) => {
              let className = 'w-full text-left px-3 py-2 rounded-lg border text-sm transition-colors ';
              if (answerResult === null) {
                className += 'border-border hover:border-primary hover:bg-accent/30 cursor-pointer';
              } else if (i === answerResult.correctIndex) {
                className += 'border-success bg-success/10 text-success';
              } else if (i === selected && !isCorrect) {
                className += 'border-danger bg-danger/10 text-danger';
              } else {
                className += 'border-border opacity-50';
              }
              return (
                <button key={i} onClick={() => handleSelect(i)} className={className} disabled={answerResult !== null || isSubmitting}>
                  <span className="flex items-center gap-2">
                    {answerResult !== null && i === answerResult.correctIndex && <CheckCircle2 className="size-3.5 shrink-0" />}
                    {answerResult !== null && i === selected && !isCorrect && <XCircle className="size-3.5 shrink-0" />}
                    <span className="text-xs font-medium text-muted-foreground w-5">{String.fromCharCode(65 + i)}.</span>
                    {opt}
                  </span>
                </button>
              );
            })}
          </div>

          {/* Result + Next */}
          {answerResult && (
            <div className="flex items-center justify-between">
              <p className={`text-xs ${isCorrect ? 'text-success' : 'text-danger'}`}>
                {isCorrect ? 'Correct!' : 'Incorrect'}
              </p>
              <button onClick={onNext} className="flex items-center gap-1 text-xs font-medium text-primary hover:underline">
                <span>Next</span>
                <ChevronRight className="size-3" />
              </button>
            </div>
          )}

          {/* Help input */}
          <div className="flex items-center gap-2">
            <input
              type="text"
              value={helpText}
              onChange={(e) => setHelpText(e.target.value)}
              placeholder="Ask the model for help…"
              className="flex-1 bg-muted border border-border rounded-lg px-3 py-1.5 text-xs outline-none focus:border-ring transition"
              onKeyDown={(e) => e.key === 'Enter' && handleHelp()}
            />
            <button onClick={handleHelp} disabled={isSubmitting || !helpText.trim()} className="text-primary hover:underline text-xs font-medium shrink-0">
              <HelpCircle className="size-4" />
            </button>
          </div>

          {/* Add question input */}
          <div className="flex items-center gap-2 border-t border-border pt-2">
            <input
              type="text"
              value={addRequest}
              onChange={(e) => setAddRequest(e.target.value)}
              placeholder="Add a question about…"
              className="flex-1 bg-transparent text-xs text-muted-foreground outline-none placeholder:text-muted-foreground/50"
              onKeyDown={(e) => e.key === 'Enter' && handleAddQuestion()}
            />
            <button onClick={handleAddQuestion} disabled={isSubmitting || !addRequest.trim()} className="text-primary hover:underline text-xs font-medium shrink-0">
              <Plus className="size-3.5" />
            </button>
          </div>
        </div>
      </div>

      {/* Explanation modal (overlay, non-blocking) */}
      {showExplanation && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/30" onClick={() => setShowExplanation(false)}>
          <div className="bg-card border border-border rounded-xl shadow-2xl max-w-lg w-full mx-4 p-5 space-y-3 animate-in fade-in zoom-in-95" onClick={(e) => e.stopPropagation()}>
            <div className="flex items-center justify-between">
              <h3 className="text-sm font-medium">Explanation</h3>
              <button onClick={() => setShowExplanation(false)} className="text-muted-foreground hover:text-foreground">
                <X className="size-4" />
              </button>
            </div>
            <div className="text-xs text-muted-foreground leading-relaxed whitespace-pre-wrap">{explanation}</div>
            {answerResult && (
              <p className={`text-xs font-medium ${isCorrect ? 'text-success' : 'text-danger'}`}>
                {isCorrect ? '✓ You got it right' : '✗ Keep studying'}
              </p>
            )}
            <button onClick={() => setShowExplanation(false)} className="w-full mt-2 py-2 text-xs font-medium bg-primary text-primary-foreground rounded-lg hover:opacity-90 transition">
              Got it
            </button>
          </div>
        </div>
      )}
    </>
  );
}

/* v3 — ExamHost: manages exam lifecycle (generate → fetch → answer → next).
   Wraps the controlled ExamBanner with state for examId, current question,
   total questions, and progression. Used by ChatThread when the user types
   `/Exam` (with optional topic or file paths). */
import { useEffect, useState, useCallback } from 'react';
import { ExamBanner } from './ExamBanner';

interface Question {
  id: number;
  examId?: number;
  position?: number;
  stem: string;
  options: string[];
}

interface AnswerResult {
  correct?: boolean;
  isCorrect?: boolean;
  correctIndex: number;
  rationale: string;
}

interface ExamHostProps {
  topic?: string;
  files?: string[];
  count?: number;
  difficulty?: string;
  model?: string;
  provider?: string;
  onDismiss: () => void;
}

const API_BASE = '/api/exam';

export function ExamHost(props: ExamHostProps) {
  const {
    onDismiss,
  } = props;
  // Stable defaults — default param values like `files = []` would allocate
  // a fresh array on every render and re-fire the bootstrap useEffect,
  // overwriting the user's current question after every answer/next click.
  const [topic] = useState<string>(() => props.topic ?? 'general knowledge');
  const [files] = useState<string[]>(() => props.files ?? []);
  const [count] = useState<number>(() => props.count ?? 5);
  const [difficulty] = useState<string>(() => props.difficulty ?? 'medium');
  const [sessionModel] = useState<string>(() => props.model ?? '');
  const [sessionProvider] = useState<string>(() => props.provider ?? '');

  const [examId, setExamId] = useState<number | null>(null);
  const [question, setQuestion] = useState<Question | null>(null);
  const [position, setPosition] = useState<number>(1);
  const [totalQuestions, setTotal] = useState<number>(0);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState<boolean>(true);

  // Bootstrap: generate the exam. Run exactly once on mount.
  // topic/files/count/difficulty are now state (stable references), so
  // the deps array never changes after first render.
  useEffect(() => {
    let cancelled = false;
    const bootstrap = async () => {
      try {
        const body: Record<string, unknown> = { count, difficulty };
        if (sessionModel) body.model = sessionModel;
        if (sessionProvider) body.provider = sessionProvider;
        if (files.length > 0) body.files = files;
        else body.topic = topic;

        const resp = await fetch(`${API_BASE}/generate`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(body),
        });
        if (!resp.ok) {
          const err = await resp.json().catch(() => ({}));
          throw new Error(err.detail || `HTTP ${resp.status}`);
        }
        const data = await resp.json();
        if (cancelled) return;
        // Wire format: camelCase (`examId`, `totalQuestions`, …).
        const examIdNum: number | null = data.examId ?? null;
        const total: number = data.totalQuestions ?? 0;
        const rawQ = data.question ?? data;
        const question: Question = {
          id: rawQ.id,
          examId: rawQ.examId ?? examIdNum ?? 0,
          position: rawQ.position ?? 1,
          stem: rawQ.stem,
          options: rawQ.options ?? [],
        };
        setExamId(examIdNum);
        setQuestion(question);
        setTotal(total);
        setPosition(1);
      } catch (e) {
        if (!cancelled) setError((e as Error).message);
      } finally {
        if (!cancelled) setLoading(false);
      }
    };
    bootstrap();
    return () => {
      cancelled = true;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleAnswer = useCallback(
    async (questionId: number, selectedIndex: number): Promise<AnswerResult> => {
      if (!examId) throw new Error('No exam');
      const resp = await fetch(`${API_BASE}/${examId}/answer`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ questionId: questionId, selectedIndex: selectedIndex }),
      });
      if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
      const data = await resp.json();
      // Wire format: camelCase (`isCorrect`, `correctIndex`, `rationale`).
      return {
        isCorrect: data.isCorrect ?? data.correct ?? false,
        correctIndex: data.correctIndex ?? -1,
        rationale: data.rationale ?? '',
      };
    },
    [examId],
  );

  const handleNext = useCallback(async () => {
    if (!examId) return;
    const nextPos = position + 1;
    if (totalQuestions > 0 && nextPos > totalQuestions) {
      // Exam complete — dismiss
      onDismiss();
      return;
    }
    setPosition(nextPos);
    try {
      const resp = await fetch(`${API_BASE}/${examId}/question/${nextPos}`);
      if (!resp.ok) {
        if (resp.status === 404) {
          onDismiss();
          return;
        }
        throw new Error(`HTTP ${resp.status}`);
      }
      const q = await resp.json();
      // Wire format: camelCase (`examId`, `position`, `stem`, `options`).
      const nextQuestion: Question = {
        id: q.id,
        examId: q.examId ?? examId,
        position: q.position ?? nextPos,
        stem: q.stem,
        options: q.options ?? [],
      };
      setQuestion(nextQuestion);
    } catch (e) {
      setError((e as Error).message);
    }
  }, [examId, position, totalQuestions, onDismiss]);

  const handleAddQuestion = useCallback(
    async (request: string) => {
      if (!examId) return;
      const body: Record<string, unknown> = { request };
      if (sessionModel) body.model = sessionModel;
      if (sessionProvider) body.provider = sessionProvider;
      const resp = await fetch(`${API_BASE}/${examId}/questions`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
      const data = await resp.json();
      if (data?.question) {
        setQuestion(data.question);
        setPosition(data.position);
        setTotal((t) => (t > 0 ? t + 1 : t));
      }
    },
    [examId, sessionModel, sessionProvider],
  );

  if (loading) {
    return (
      <div className="fixed bottom-0 left-0 right-0 z-50 border-t border-border bg-card shadow-2xl p-4">
        <div className="mx-auto max-w-3xl text-sm text-muted-foreground">Generating exam…</div>
      </div>
    );
  }
  if (error) {
    return (
      <div className="fixed bottom-0 left-0 right-0 z-50 border-t border-border bg-card shadow-2xl p-4">
        <div className="mx-auto max-w-3xl text-sm text-danger">
          Failed to load exam: {error}
          <button onClick={onDismiss} className="ml-3 underline text-xs">
            dismiss
          </button>
        </div>
      </div>
    );
  }
  if (!question || !examId) return null;

  return (
    <ExamBanner
      key={question.id}
      examId={examId}
      question={question}
      onAnswer={handleAnswer}
      onNext={handleNext}
      onAddQuestion={handleAddQuestion}
      onDismiss={onDismiss}
    />
  );
}

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { api } from '@/api/client';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { StatusPill } from '@/components/StatusPill';
import { SectionHeader } from '@/components/SectionHeader';
import { useStore } from '@nanostores/react';
import { $gateway } from '@/store/gateway';
import { PageLoader } from '@/components/PageLoader';
import { Copy, Check, Link2, Terminal, Brain } from 'lucide-react';

interface HealthData {
  claude?: { status: string };
  codex?: { status: string };
  uptime?: number;
  memory?: { used: number; total: number };
  origin?: string;
  port?: number;
  endpoints?: {
    anthropic: { url: string; label: string; client: string };
    openai: { url: string; label: string; client: string };
    models: { url: string; label: string; client: string };
  };
  activeUpstream?: { provider: string; baseUrl: string } | null;
}

export function Health() {
  const g = useStore($gateway);
  const { data, isLoading, error } = useQuery({
    queryKey: ['health', 'detailed'],
    queryFn: () => api.get<HealthData>('/api/health/detailed'),
    refetchInterval: 5_000,
  });

  if (isLoading) return <PageLoader label="Checking health…" />;
  if (error) {
    return (
      <div className="p-6">
        <SectionHeader title="Health" />
        <p className="text-sm text-destructive">Failed: {String(error)}</p>
      </div>
    );
  }
  if (!data) return null;

  const port = data.port || (g.status === 'open' ? g.port : 0) || 8085;
  const endpoints = data.endpoints;

  return (
    <div className="p-6 space-y-6">
      <SectionHeader title="Health" subtitle="Live runtime status, provider health, and connection URLs." />

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card>
          <CardHeader>
            <CardTitle>Gateway</CardTitle>
          </CardHeader>
          <CardContent className="flex items-center gap-2">
            <StatusPill
              tone={g.status === 'open' ? 'good' : 'bad'}
              label={g.status === 'open' ? 'Open' : g.status}
            />
            <span className="text-xs text-muted-foreground">port {port}</span>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Claude</CardTitle>
          </CardHeader>
          <CardContent>
            <StatusPill
              tone={data.claude?.status === 'ok' ? 'good' : 'muted'}
              label={data.claude?.status ?? 'unknown'}
            />
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Codex</CardTitle>
          </CardHeader>
          <CardContent>
            <StatusPill
              tone={data.codex?.status === 'ok' ? 'good' : 'muted'}
              label={data.codex?.status ?? 'unknown'}
            />
          </CardContent>
        </Card>
      </div>

      {/* Connect an app — copy these base URLs into Claude Code, Cursor, etc. */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-base">
            <Link2 className="size-4" /> Connect an app
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <p className="text-sm text-muted-foreground">
            Point any OpenAI- or Anthropic-compatible app at this proxy. Models from every configured provider are available on all paths — the proxy translates formats and routes per model.
          </p>

          {endpoints ? (
            <div className="space-y-3">
              <EndpointRow
                endpoint={endpoints.anthropic}
                hint="ANTHROPIC_BASE_URL — Claude Code, Anthropic SDKs. Sends /v1/messages."
                icon={<Brain className="size-3.5" />}
              />
              <EndpointRow
                endpoint={endpoints.openai}
                hint="OPENAI_API_BASE — OpenAI SDKs, Cursor, codex CLI. Sends /v1/chat/completions."
                icon={<Terminal className="size-3.5" />}
              />
              <EndpointRow
                endpoint={endpoints.models}
                hint="Fetch the model list. Any OpenAI-compatible client."
                icon={<Link2 className="size-3.5" />}
              />
            </div>
          ) : (
            <div className="space-y-2">
              <CopyableUrl url={`http://localhost:${port}/v1/messages`} label="Anthropic (Claude Code)" />
              <CopyableUrl url={`http://localhost:${port}/v1/chat/completions`} label="OpenAI Chat Completions" />
              <CopyableUrl url={`http://localhost:${port}/v1/models`} label="Model list" />
            </div>
          )}

          {data.activeUpstream?.baseUrl && (
            <div className="pt-2 border-t border-border/40 text-[11px] text-muted-foreground font-mono">
              active upstream: {data.activeUpstream.provider} → {data.activeUpstream.baseUrl}
            </div>
          )}
          <p className="text-[9px] text-muted-foreground font-mono">
            🔒 The base URL works over the network this app is served from. Use a real API key from Settings for the upstream provider.
          </p>
        </CardContent>
      </Card>

      {data.memory && (
        <Card>
          <CardHeader>
            <CardTitle>Memory</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-sm font-mono">
              {data.memory.used} MB / {data.memory.total} MB
            </p>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

function EndpointRow({
  endpoint,
  hint,
  icon,
}: {
  endpoint: { url: string; label: string; client: string };
  hint: string;
  icon: React.ReactNode;
}) {
  const [copied, setCopied] = useState(false);
  function copy() {
    navigator.clipboard?.writeText(endpoint.url);
    setCopied(true);
    setTimeout(() => setCopied(false), 1200);
  }
  return (
    <div className="rounded-md border border-border bg-card/60 px-3 py-2.5">
      <div className="flex items-center justify-between gap-3">
        <div className="flex items-center gap-2 min-w-0">
          <span className="text-muted-foreground shrink-0">{icon}</span>
          <span className="text-sm font-medium">{endpoint.label}</span>
        </div>
        <button
          onClick={copy}
          className="inline-flex items-center gap-1 rounded-md border border-border bg-background px-2 py-1 text-[10px] font-mono hover:bg-accent transition shrink-0"
          title="Copy URL"
        >
          {copied ? <Check className="size-3 text-success" /> : <Copy className="size-3" />}
          {copied ? 'copied' : 'copy'}
        </button>
      </div>
      <code className="block mt-1.5 text-[11px] font-mono text-foreground break-all">{endpoint.url}</code>
      <p className="text-[10px] text-muted-foreground mt-1">{hint}</p>
    </div>
  );
}

function CopyableUrl({ url, label }: { url: string; label: string }) {
  const [copied, setCopied] = useState(false);
  function copy() {
    navigator.clipboard?.writeText(url);
    setCopied(true);
    setTimeout(() => setCopied(false), 1200);
  }
  return (
    <div className="flex items-center gap-2">
      <span className="text-xs text-muted-foreground w-44 shrink-0">{label}</span>
      <code className="flex-1 text-[11px] font-mono text-foreground truncate">{url}</code>
      <button
        onClick={copy}
        className="p-1 rounded hover:bg-accent text-muted-foreground hover:text-foreground transition shrink-0"
        title="Copy URL"
      >
        {copied ? <Check className="size-3 text-success" /> : <Copy className="size-3" />}
      </button>
    </div>
  );
}

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { SectionHeader } from '@/components/SectionHeader';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { StatusPill } from '@/components/StatusPill';
import { RightRail } from '@/components/shell/RightRail';
import { PageLoader } from '@/components/PageLoader';
import { formatTimeAgo } from '@/lib/utils';
import {
  getRequestDetails,
  getRequestDetail,
  type RequestDetailEntry,
  type Period,
} from '@/api/api-client';

const PERIODS: { key: Period; label: string }[] = [
  { key: 'today', label: 'Today' },
  { key: 'yesterday', label: 'Yesterday' },
  { key: 'week', label: '7d' },
  { key: 'all', label: 'All' },
];

export function Inspector() {
  const [period, setPeriod] = useState<Period>('today');
  const [selectedId, setSelectedId] = useState<string | null>(null);

  const { data: details, isLoading } = useQuery({
    queryKey: ['request-details', period],
    queryFn: () => getRequestDetails(period),
    refetchInterval: 3_000,
  });

  const { data: selectedDetail } = useQuery({
    queryKey: ['request-detail', selectedId],
    queryFn: () => (selectedId ? getRequestDetail(selectedId) : Promise.resolve(null)),
    enabled: !!selectedId,
  });

  const rows = details ?? [];
  const selected = selectedDetail ?? rows.find((d) => d.reqId === selectedId) ?? null;

  if (isLoading) return <PageLoader label="Loading inspector…" />;

  return (
    <div className="flex h-full">
      <div className="flex-1 flex flex-col min-w-0">
        <div className="p-6 pb-3">
          <SectionHeader
            title="Inspector"
            subtitle={`${rows.length} captured requests · click a row for sanitized bodies`}
            actions={
              <div className="flex items-center gap-1 text-[10px]">
                {PERIODS.map((p) => (
                  <button
                    key={p.key}
                    onClick={() => setPeriod(p.key)}
                    className={`rounded-md px-2 py-1 font-mono transition ${
                      period === p.key ? 'bg-primary text-primary-foreground' : 'text-muted-foreground hover:bg-accent'
                    }`}
                  >
                    {p.label}
                  </button>
                ))}
              </div>
            }
          />
        </div>
        <div className="flex-1 overflow-auto px-6 pb-3 space-y-1.5">
          {rows.length === 0 ? (
            <div className="h-full grid place-items-center text-xs text-muted-foreground">
              No captured requests in this period. Send a chat message to populate the inspector.
            </div>
          ) : (
            rows.slice(0, 120).map((d) => (
              <button
                key={d.reqId}
                onClick={() => setSelectedId(d.reqId)}
                className={`w-full text-left rounded-md border border-border bg-card hover:bg-accent/30 transition px-3 py-2 ${
                  selected?.reqId === d.reqId ? 'ring-1 ring-primary' : ''
                }`}
              >
                <div className="flex items-center gap-3 text-xs font-mono">
                  <DetailStatus status={d.status} error={d.error} />
                  <span className="text-muted-foreground">{d.requestType || 'request'}</span>
                  <span className="font-semibold flex-1 truncate">{d.reqId}</span>
                  {d.date && (
                    <span className="text-muted-foreground text-[10px]">{formatTimeAgo(d.date)}</span>
                  )}
                </div>
              </button>
            ))
          )}
        </div>
      </div>

      {selected && (
        <RightRail title="Request detail" subtitle={selected.reqId}>
          <RequestDetail d={selected} />
        </RightRail>
      )}
    </div>
  );
}

function DetailStatus({ status, error }: { status?: string; error?: string | null }) {
  const isError = status === 'error' || !!error;
  return (
    <StatusPill
      tone={isError ? 'bad' : status === 'completed' ? 'good' : 'muted'}
      label={(status || 'unknown').slice(0, 10)}
    />
  );
}

function RequestDetail({ d }: { d: RequestDetailEntry }) {
  const reqBody = safeStringify(d.requestBody);
  const resBody = safeStringify(d.responseBody);

  return (
    <div className="space-y-3 text-xs">
      <div className="grid grid-cols-2 gap-2">
        <Field label="Status" value={<DetailStatus status={d.status} error={d.error} />} />
        <Field label="Type" value={<span className="font-mono">{d.requestType || '—'}</span>} />
        {d.date && <Field label="Time" value={<span className="font-mono">{new Date(d.date).toLocaleString()}</span>} />}
        {d.finishReason && <Field label="Finish" value={<span className="font-mono">{d.finishReason}</span>} />}
        <Field label="Input tok" value={<span className="font-mono tabular-nums">{(d.inputTokens || 0).toLocaleString()}</span>} />
        <Field label="Output tok" value={<span className="font-mono tabular-nums">{(d.outputTokens || 0).toLocaleString()}</span>} />
      </div>

      {d.error && (
        <Card>
          <CardContent className="p-3">
            <p className="text-[10px] uppercase tracking-wider text-destructive mb-1">Error</p>
            <pre className="text-[10px] font-mono whitespace-pre-wrap break-all bg-destructive/5 text-destructive p-2 rounded">
              {d.error}
            </pre>
          </CardContent>
        </Card>
      )}

      <Card>
        <CardContent className="p-3">
          <p className="text-[10px] uppercase tracking-wider text-muted-foreground mb-2">Request body</p>
          {reqBody ? (
            <pre className="text-[10px] font-mono whitespace-pre-wrap break-all bg-muted p-2 rounded">
              {reqBody}
            </pre>
          ) : (
            <p className="text-[10px] text-muted-foreground italic">Not captured</p>
          )}
        </CardContent>
      </Card>

      <Card>
        <CardContent className="p-3">
          <p className="text-[10px] uppercase tracking-wider text-muted-foreground mb-2">Response body</p>
          {resBody ? (
            <pre className="text-[10px] font-mono whitespace-pre-wrap break-all bg-muted p-2 rounded">
              {resBody}
            </pre>
          ) : (
            <p className="text-[10px] text-muted-foreground italic">Pending or not captured</p>
          )}
        </CardContent>
      </Card>

      {d.thinking != null && (
        <Card>
          <CardContent className="p-3">
            <p className="text-[10px] uppercase tracking-wider text-muted-foreground mb-2">Thinking</p>
            <pre className="text-[10px] font-mono whitespace-pre-wrap break-all bg-muted p-2 rounded">
              {safeStringify(d.thinking)}
            </pre>
          </CardContent>
        </Card>
      )}

      {d.toolCalls != null && (
        <Card>
          <CardContent className="p-3">
            <p className="text-[10px] uppercase tracking-wider text-muted-foreground mb-2">Tool calls</p>
            <pre className="text-[10px] font-mono whitespace-pre-wrap break-all bg-muted p-2 rounded">
              {safeStringify(d.toolCalls)}
            </pre>
          </CardContent>
        </Card>
      )}

      <p className="text-[9px] text-muted-foreground font-mono px-1">
        🔒 Secrets are redacted server-side before display.
      </p>
    </div>
  );
}

function Field({ label, value }: { label: string; value: React.ReactNode }) {
  return (
    <div>
      <p className="text-[10px] uppercase tracking-wider text-muted-foreground">{label}</p>
      <div className="mt-0.5">{value}</div>
    </div>
  );
}

/** Stringify a possibly-object/already-string value, never throwing. */
function safeStringify(v: unknown): string {
  if (v == null || v === '') return '';
  if (typeof v === 'string') {
    // Already-stringified (e.g. sanitizeForDisplay output); pretty-print if JSON.
    try {
      const parsed = JSON.parse(v);
      return JSON.stringify(parsed, null, 2);
    } catch {
      return v;
    }
  }
  try {
    return JSON.stringify(v, null, 2);
  } catch {
    return String(v);
  }
}

import { useState, useEffect, useRef } from 'react';
import { X, Mic } from 'lucide-react';
import { useLiveSession } from './useLiveSession';
import { LiveOrb } from './LiveOrb';
import { LiveCaptions } from './LiveCaptions';
import { LiveToolRail } from './LiveToolRail';
import { LiveApprovalCard } from './LiveApprovalCard';
import { LiveControls } from './LiveControls';
import { liveClient } from '@/api/liveClient';
import { liveSTTFactory } from '@/api/speech/liveSTT';
import { liveTTSFactory } from '@/api/speech/liveTTS';
import type { LiveSTT } from '@/api/speech/liveSTT';
import type { LiveTTS } from '@/api/speech/liveTTS';
import type { PendingMutation } from './useLiveSession';

interface LiveSurfaceProps {
  onSwitchToChat: () => void;
  pendingMutations?: PendingMutation[];
}

export function LiveSurface({ onSwitchToChat, pendingMutations = [] }: LiveSurfaceProps) {
  const session = useLiveSession();
  const [reducedMotion, setReducedMotion] = useState(false);
  const sessionIdRef = useRef<string>('');
  const sttRef = useRef<LiveSTT | null>(null);
  const ttsRef = useRef<LiveTTS | null>(null);

  // Reduced-motion preference (feature-detect for jsdom)
  useEffect(() => {
    if (typeof window.matchMedia !== 'function') return;
    const mq = window.matchMedia('(prefers-reduced-motion: reduce)');
    setReducedMotion(mq.matches);
    const handler = (e: MediaQueryListEvent) => setReducedMotion(e.matches);
    mq.addEventListener('change', handler);
    return () => mq.removeEventListener('change', handler);
  }, []);

  // Push prop-supplied pending mutations into the session queue
  useEffect(() => {
    pendingMutations.forEach((m) => session.addPendingMutation(m));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pendingMutations]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      sttRef.current?.stop();
      ttsRef.current?.cancel();
    };
  }, []);

  const startListening = async () => {
    if (session.state !== 'idle') return;
    sessionIdRef.current = sessionIdRef.current || (await liveClient.startSession());
    const stt = liveSTTFactory();
    const tts = liveTTSFactory();
    sttRef.current = stt;
    ttsRef.current = tts;

    stt.onPartial((text) => {
      // Barge-in: if the user starts talking while TTS is speaking, cancel TTS.
      if (session.state === 'speaking') {
        tts.cancel();
      }
      session.onPartial(text);
    });
    stt.onFinal(async (text) => {
      session.onFinal(text);
      const turnId = `t-${Date.now()}`;
      session.addToolEvent({
        id: turnId,
        name: 'turn',
        args: { transcript: text },
        status: 'running',
      });
      const response = await liveClient.sendTurn(sessionIdRef.current, text);
      if (response) {
        await tts.speak(response);
        session.updateToolEvent(turnId, { status: 'done', result: response });
      } else {
        session.updateToolEvent(turnId, { status: 'error' });
      }
    });
    stt.onError((err) => {
      session.addToolEvent({
        id: `e-${Date.now()}`,
        name: 'stt_error',
        args: { message: err.message },
        status: 'error',
      });
      session.stop();
    });

    session.start();
    await stt.start();
  };

  return (
    <div
      className="h-full w-full flex flex-col bg-background"
      data-testid="live-surface"
    >
      {/* Top bar */}
      <div className="flex items-center justify-between px-4 py-3 border-b border-border">
        <div className="text-sm font-medium">August Live</div>
        <button
          type="button"
          aria-label="Close"
          onClick={onSwitchToChat}
          className="p-1 rounded hover:bg-muted"
        >
          <X className="size-4" />
        </button>
      </div>

      {/* Body: tool rail | main */}
      <div className="flex-1 flex min-h-0">
        <aside className="w-56 border-r border-border overflow-y-auto">
          <LiveToolRail events={session.toolEvents} />
        </aside>

        <main className="flex-1 flex flex-col items-center justify-center gap-6 p-6 min-h-0">
          <LiveOrb state={session.state} reducedMotion={reducedMotion} />
          <LiveCaptions partial={session.partialTranscript} transcript={session.transcript} />

          {session.state === 'idle' && (
            <button
              type="button"
              data-testid="start-listening"
              onClick={startListening}
              className="px-4 py-2 rounded-full bg-primary text-primary-foreground text-sm hover:opacity-90"
            >
              <Mic className="size-4 inline mr-2" />
              Start listening
            </button>
          )}

          {session.pendingMutations[0] && (
            <LiveApprovalCard
              mutation={session.pendingMutations[0]}
              onApprove={session.approve}
              onDeny={session.deny}
              onVoiceConfirm={session.approve}
            />
          )}
        </main>
      </div>

      {/* Bottom controls */}
      <div className="flex items-center justify-center p-4 border-t border-border">
        <LiveControls
          isMuted={session.isMuted}
          continuousMode={false}
          onToggleMute={() => {
            // Toggle the underlying audio capture directly; the hook's
            // isMuted state updates through toggleMute() but we don't
            // read it back here to avoid a stale-closure on `session`.
            if (sttRef.current) {
              if (session.isMuted) sttRef.current.start();
              else sttRef.current.stop();
            }
            session.toggleMute();
          }}
          onEnd={() => {
            session.stop();
            sttRef.current?.stop();
            ttsRef.current?.cancel();
            if (sessionIdRef.current) liveClient.stopSession(sessionIdRef.current);
            onSwitchToChat();
          }}
          onToggleContinuous={() => {}}
          onSwitchToChat={onSwitchToChat}
        />
      </div>
    </div>
  );
