              <Card>
                <CardContent className="p-3 text-center">
                  <p className="text-2xl font-bold">{graphCounts.relations}</p>
                  <p className="text-[10px] text-muted-foreground">Relations</p>
                </CardContent>
              </Card>
              <Card>
                <CardContent className="p-3 text-center">
                  <p className="text-2xl font-bold">{graphCounts.observations}</p>
                  <p className="text-[10px] text-muted-foreground">Observations</p>
                </CardContent>
              </Card>
            </div>
          )}

          {/* Interactive Graph */}
          <Card className="overflow-hidden">
            <div className="h-[500px]">
              <KnowledgeGraph />
            </div>
          </Card>
        </div>
      )}

      {/* Search Tab */}
      {tab === 'search' && (
        <div className="space-y-4">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-muted-foreground" />
            <input
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              placeholder="Search memory..."
              className="w-full pl-10 pr-4 py-2.5 text-sm bg-background border border-border rounded-lg outline-none focus:ring-2 focus:ring-primary/40 transition"
              autoFocus
            />
          </div>

          {searchQuery.trim() && searchResults.data && (
            <div className="space-y-2">
              {(searchResults.data.results || []).length === 0 && (
                <p className="text-sm text-muted-foreground text-center py-8">No results found</p>
              )}
              {(searchResults.data.results || []).map((r, i) => (
                <Card key={i}>
                  <CardContent className="p-3">
                    <div className="flex items-start justify-between gap-2">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <Badge variant="outline" className="text-[9px] shrink-0">{r.provider}</Badge>
                          <span className="text-xs font-medium text-foreground truncate">{r.title}</span>
                        </div>
                        <p className="text-xs text-muted-foreground mt-1 line-clamp-2">{r.text}</p>
                      </div>
                      <Badge variant="outline" className="shrink-0 text-[9px]">{r.score}</Badge>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}

          {!searchQuery.trim() && (
            <p className="text-sm text-muted-foreground text-center py-8">Type to search your memory</p>
          )}
        </div>
      )}

      {/* Prompt Tab */}
      {tab === 'prompt' && (
        <Card>
          <CardContent className="p-4">
            {!prompt ? (
              <p className="text-sm text-muted-foreground text-center py-4">Loading system prompt...</p>
            ) : (
              <>
                <div className="flex items-center justify-between mb-2">
                  <span className="text-xs text-muted-foreground font-mono">{promptData.data?.length ?? prompt.length} chars</span>
                  <Badge variant={brain?.compacted ? 'destructive' : 'secondary'}>
                    {brain?.compacted ? 'compacted' : 'full'}
                  </Badge>
                </div>
                <pre className="text-xs font-mono whitespace-pre-wrap text-foreground/80 leading-relaxed max-h-[60vh] overflow-y-auto bg-muted/20 rounded p-3">
                  {prompt}
                </pre>
              </>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useMemo, useState } from 'react';
import { useQuery, useMutation } from '@tanstack/react-query';
import { SectionHeader } from '@/components/SectionHeader';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Search, Boxes, ArrowRightLeft, Calculator, Inbox, Gauge, Tag, Plus, Trash2, Save, RefreshCw, Power } from 'lucide-react';
import { quotaApi, type ModelQuota } from '@/api/quota';
import {
  getModelCatalog,
  getModelCapabilities,
  getModelAliases,
  estimateModelCost,
  getAggregatedModels,
  getUserModelAliases,
  updateUserModelAliases,
  restartBackend,
  isFreeModelId,
  type CatalogModel,
  type ModelAlias,
  type ModelCostEstimate,
  type AggregatedModel,
  type UserModelAlias,
} from '@/api/api-client';

type Tab = 'catalog' | 'capabilities' | 'aliases' | 'user-aliases' | 'cost' | 'quotas';

const TABS: { key: Tab; label: string; Icon: typeof Boxes }[] = [
  { key: 'catalog', label: 'Catalog', Icon: Boxes },
  { key: 'capabilities', label: 'Capabilities', Icon: Search },
  { key: 'aliases', label: 'Aliases', Icon: ArrowRightLeft },
  { key: 'user-aliases', label: 'User Aliases', Icon: Tag },
  { key: 'cost', label: 'Cost estimator', Icon: Calculator },
  { key: 'quotas', label: 'Per-model quota', Icon: Gauge },
];

export function Models() {
  const [tab, setTab] = useState<Tab>('catalog');

  return (
    <div className="p-6 space-y-4 flex flex-col h-full">
      <SectionHeader
        title="Models"
        subtitle="All models from every configured provider. Models are listed under the provider that serves them — e.g. deepseek/kimi models appear under opencode-zen when served through it."
        actions={
          <div className="flex items-center gap-1 text-[10px]">
            {TABS.map((t) => (
              <button
                key={t.key}
                onClick={() => setTab(t.key)}
                className={`rounded-md px-2 py-1 font-mono transition inline-flex items-center gap-1 ${
                  tab === t.key ? 'bg-primary text-primary-foreground' : 'text-muted-foreground hover:bg-accent'
                }`}
              >
                <t.Icon className="size-3" /> {t.label}
              </button>
            ))}
          </div>
        }
      />
      <div className="flex-1 min-h-0">
        {tab === 'catalog' && <CatalogTab />}
        {tab === 'capabilities' && <CapabilitiesTab />}
        {tab === 'aliases' && <AliasesTab />}
        {tab === 'user-aliases' && <UserAliasesTab />}
        {tab === 'cost' && <CostTab />}
        {tab === 'quotas' && <QuotasTab />}
      </div>
    </div>
  );
}

function CatalogTab() {
  const [q, setQ] = useState('');
  const [page, setPage] = useState(0);
  const PAGE_SIZE = 50;
  const { data: skeletonData } = useQuery({
    queryKey: ['aggregated-models-skeleton'],
    queryFn: () => getAggregatedModels({ skeleton: true }),
    staleTime: 30_000,
  });
  const { data, isLoading, isFetching } = useQuery({
    queryKey: ['aggregated-models', page],
    queryFn: () => getAggregatedModels({ limit: PAGE_SIZE, offset: page * PAGE_SIZE }),
  });
  const showSkeleton = isLoading || (isFetching && (data?.models?.length ?? 0) === 0);

  // Free models first, then alphabetical — mirrors the server sort but
  // applied client-side so the search filter stays stable.
  const grouped = useMemo(() => {
    const all = (data?.models ?? []).map((m) => ({ ...m, isFree: m.isFree ?? isFreeModelId(m.id) }));
    const filtered = q
      ? all.filter((m) => `${m.id} ${m.provider}`.toLowerCase().includes(q.toLowerCase()))
      : all;
    filtered.sort((a, b) => {
      if (a.isFree !== b.isFree) return a.isFree ? -1 : 1;
      return (a.id || '').localeCompare(b.id || '');
    });
    const byProvider = new Map<string, AggregatedModel[]>();
    for (const m of filtered) {
      if (!byProvider.has(m.provider)) byProvider.set(m.provider, []);
      byProvider.get(m.provider)!.push(m);
    }
    // Sort providers so free-heavy ones float up.
    return Array.from(byProvider.entries()).sort(([, a], [, b]) => {
      const fa = a.filter((m) => m.isFree).length;
      const fb = b.filter((m) => m.isFree).length;
      if (fa !== fb) return fb - fa;
      return (a[0]?.provider || '').localeCompare(b[0]?.provider || '');
    });
  }, [data, q]);

  const total = grouped.reduce((sum, [, list]) => sum + list.length, 0);
  const freeCount = grouped.reduce((sum, [, list]) => sum + list.filter((m) => m.isFree).length, 0);

  if (isLoading || showSkeleton) return (
    <div className="space-y-2 p-3" data-testid="models-skeleton">
      <div className="text-[10px] uppercase tracking-wider text-muted-foreground/60">
        Warming model cache…
      </div>
      {[0, 1, 2, 3, 4, 5].map((i) => (
        <div key={i} className="h-10 rounded-md bg-muted/30 animate-pulse" />
      ))}
    </div>
  );

  return (
    <div className="space-y-3 h-full flex flex-col">
      <div className="flex items-center gap-3">
        <div className="relative flex-1 max-w-md">
          <Search className="absolute left-2 top-1/2 -translate-y-1/2 size-3.5 text-muted-foreground" />
          <Input
            value={q}
            onChange={(e) => setQ(e.target.value)}
            placeholder="Search models across all providers…"
            className="pl-7"
          />
        </div>
        <span className="text-[10px] text-muted-foreground font-mono shrink-0">
          {total} models · {freeCount} free
        </span>
      </div>
      {total === 0 ? (
        <EmptyState label="No models available — configure a provider API key to populate the list" />
      ) : (
        <Card className="flex-1 overflow-auto">
          <div className="divide-y divide-border/40">
            {grouped.map(([provider, list]) => (
              <div key={provider}>
                <div className="sticky top-0 z-10 bg-popover/95 backdrop-blur px-3 py-1.5 text-[10px] uppercase tracking-widest text-muted-foreground font-semibold border-b border-border/40">
                  {provider}
                  <span className="ml-2 text-[9px] lowercase font-mono text-muted-foreground/60">
                    {list.filter((m) => m.isFree).length}/{list.length} free
                  </span>
                </div>
                {list.map((m) => (
                  <CatalogRow key={`${provider}-${m.id}`} m={m} />
                ))}
              </div>
            ))}
          </div>
        </Card>
      )}
      {data?.hasMore && (
        <div className="flex justify-center pt-2">
          <Button
            size="sm"
            variant="outline"
            onClick={() => setPage((p) => p + 1)}
            disabled={isFetching}
          >
            {isFetching ? 'Loading…' : 'Load more'}
          </Button>
        </div>
      )}
    </div>
  );
}

function CatalogRow({ m }: { m: AggregatedModel }) {
  return (
    <div className="px-3 py-2.5 flex items-start gap-3 hover:bg-accent/20">
      <div className="min-w-0 flex-1">
        <div className="flex items-center gap-2 flex-wrap">
          <span className="text-sm font-medium font-mono">{m.id}</span>
          {m.isFree && (
            <Badge variant="outline" className="text-[9px] border-success/50 text-success">free</Badge>
          )}
          {m.supportsReasoning && (
            <Badge variant="outline" className="text-[9px]">reasoning</Badge>
          )}
          {m.supportsThinking && (
            <Badge variant="outline" className="text-[9px]">thinking</Badge>
          )}
        </div>
        {m.contextWindow ? (
          <p className="text-[11px] text-muted-foreground font-mono mt-0.5">
            {(m.contextWindow / 1000).toFixed(0)}k context
          </p>
        ) : null}
      </div>
    </div>
  );
}

function CapabilitiesTab() {
  const { data, isLoading } = useQuery({
    queryKey: ['model-capabilities'],
    queryFn: () => getModelCapabilities(),
  });
  const caps = data?.capabilities ?? [];
  if (isLoading) return <div className="text-sm text-muted-foreground p-6">Loading…</div>;
  if (caps.length === 0) return <EmptyState label="No capabilities registered" />;
  return (
    <Card className="p-4">
      <CardHeader className="p-0 mb-3">
        <CardTitle className="text-sm">Available capabilities</CardTitle>
      </CardHeader>
      <CardContent className="p-0 flex flex-wrap gap-2">
        {caps.map((c) => (
          <Badge key={c} variant="outline">{c}</Badge>
        ))}
      </CardContent>
    </Card>
  );
}

function AliasesTab() {
  const { data, isLoading } = useQuery({
    queryKey: ['model-aliases'],
    queryFn: () => getModelAliases(),
  });
  const aliases = data?.aliases ?? [];
  if (isLoading) return <div className="text-sm text-muted-foreground p-6">Loading…</div>;
  if (aliases.length === 0) return <EmptyState label="No model aliases defined" />;
  return (
    <Card className="overflow-auto">
      <div className="grid grid-cols-[1fr_24px_1fr_120px] gap-2 px-3 py-2 text-[10px] uppercase tracking-wider text-muted-foreground border-b border-border font-mono">
        <span>Alias</span><span /><span>Resolves to</span><span>Provider</span>
      </div>
      <div className="divide-y divide-border/40">
        {aliases.map((a: ModelAlias) => (
          <div key={a.alias} className="grid grid-cols-[1fr_24px_1fr_120px] gap-2 px-3 py-2 text-xs items-center font-mono">
            <span className="truncate">{a.alias}</span>
            <ArrowRightLeft className="size-3 text-muted-foreground/50" />
            <span className="truncate text-foreground">{a.resolvesTo}</span>
            <span className="text-muted-foreground truncate">{a.provider}</span>
          </div>
        ))}
      </div>
    </Card>
  );
}

function UserAliasesTab() {
  const { data: aliasData, isLoading: aliasesLoading } = useQuery({
    queryKey: ['user-model-aliases'],
    queryFn: () => getUserModelAliases(),
  });
  const { data: modelsData, refetch: refetchModels } = useQuery({
    queryKey: ['aggregated-models'],
    queryFn: () => getAggregatedModels(),
  });

  const [aliases, setAliases] = useState<UserModelAlias[]>([]);
  const [dirty, setDirty] = useState(false);
  const [saving, setSaving] = useState(false);
  const [restarting, setRestarting] = useState(false);

  // Initialise from server data once loaded.
  if (!dirty && aliasData && aliases.length === 0 && aliasData.aliases.length > 0) {
    setAliases(aliasData.aliases);
  }

  const availableModels = useMemo(() => {
    const all = modelsData?.models ?? [];
    // Deduplicate by id so the dropdown is clean.
    const seen = new Set<string>();
    return all.filter((m) => { if (seen.has(m.id)) return false; seen.add(m.id); return true; });
  }, [modelsData]);

  function addAlias() {
    setAliases((prev) => [...prev, { alias: '', targetModel: '', targetProvider: '' }]);
    setDirty(true);
  }

  function updateAlias(index: number, field: keyof UserModelAlias, value: string) {
    setAliases((prev) => {
      const next = [...prev];
      next[index] = { ...next[index], [field]: value };
      // Auto-fill provider when target model changes.
      if (field === 'targetModel') {
        const model = availableModels.find((m) => m.id === value);
        if (model) next[index].targetProvider = model.provider;
      }
      return next;
    });
    setDirty(true);
  }

  function removeAlias(index: number) {
    setAliases((prev) => prev.filter((_, i) => i !== index));
    setDirty(true);
  }

  async function save() {
    setSaving(true);
    try {
      const valid = aliases.filter((a) => a.alias.trim() && a.targetModel.trim());
      await updateUserModelAliases(valid);
      setDirty(false);
    } catch (e) {
      console.error('Failed to save aliases:', e);
    } finally {
      setSaving(false);
    }
  }

  async function handleRestart() {
    if (!window.confirm('Restart the backend? This will briefly interrupt active requests.')) return;
    setRestarting(true);
    try {
      await restartBackend();
    } catch {
      // Backend will disconnect — that's expected.
    } finally {
      setRestarting(false);
    }
  }

  if (aliasesLoading) return <div className="text-sm text-muted-foreground p-6">Loading…</div>;

  return (
    <div className="space-y-3 h-full flex flex-col">
      <div className="flex items-center justify-between">
        <p className="text-xs text-muted-foreground">
          Define custom model IDs that route to your chosen backend models. These will appear in the model list and can be selected in the chat dropdown.
        </p>
        <div className="flex items-center gap-2 shrink-0">
          <Button size="sm" variant="outline" onClick={() => refetchModels()} title="Refresh model list">
            <RefreshCw className="size-3" /> Refresh
          </Button>
          <Button size="sm" variant="outline" onClick={addAlias}>
            <Plus className="size-3" /> Add alias
          </Button>
          <Button size="sm" onClick={save} disabled={!dirty || saving}>
            <Save className="size-3" /> {saving ? 'Saving…' : 'Save'}
          </Button>
          <Button size="sm" variant="destructive" onClick={handleRestart} disabled={restarting} title="Restart backend to pick up all changes">
            <Power className="size-3" /> {restarting ? 'Restarting…' : 'Restart'}
          </Button>
        </div>
      </div>

      {aliases.length === 0 ? (
        <EmptyState label="No user-defined aliases yet — click 'Add alias' to create one." />
      ) : (
        <Card className="overflow-auto flex-1">
          <div className="grid grid-cols-[1fr_2fr_100px_36px] gap-2 px-3 py-2 text-[10px] uppercase tracking-wider text-muted-foreground border-b border-border font-mono">
            <span>Alias name</span>
            <span>Target model</span>
            <span>Provider</span>
            <span />
          </div>
          <div className="divide-y divide-border/40">
            {aliases.map((a, i) => (
              <div key={i} className="grid grid-cols-[1fr_2fr_100px_36px] gap-2 px-3 py-2 text-xs items-center font-mono">
                <Input
                  value={a.alias}
                  onChange={(e) => updateAlias(i, 'alias', e.target.value)}
                  placeholder="my-fake-model"
                  className="h-7 text-xs font-mono"
                />
                <select
                  value={a.targetModel}
                  onChange={(e) => updateAlias(i, 'targetModel', e.target.value)}
                  className="h-7 w-full rounded-md border border-border bg-background px-2 text-xs font-mono focus:outline-none focus:ring-1 focus:ring-primary"
                >
                  <option value="" disabled>Select a model…</option>
                  {availableModels.map((m) => (
                    <option key={m.id} value={m.id}>
                      {m.id}{m.isFree ? ' (free)' : ''}
                    </option>
                  ))}
                </select>
                <span className="text-muted-foreground truncate text-[10px]">{a.targetProvider || '—'}</span>
                <Button
                  variant="ghost"
                  size="icon-sm"
                  onClick={() => removeAlias(i)}
                  className="text-destructive/60 hover:text-destructive"
                >
                  <Trash2 className="size-3" />
                </Button>
              </div>
            ))}
          </div>
        </Card>
      )}
    </div>
  );
}

function CostTab() {
  const [modelId, setModelId] = useState('');
  const [inputTokens, setInputTokens] = useState('1000');
  const [outputTokens, setOutputTokens] = useState('500');

  const estimate = useMutation<ModelCostEstimate>({
    mutationFn: () =>
      estimateModelCost(modelId, Number(inputTokens) || 0, Number(outputTokens) || 0),
  });

  return (
    <div className="space-y-4 max-w-xl">
      <Card>
        <CardContent className="p-4 space-y-3">
          <div>
            <label className="text-[10px] uppercase tracking-wider text-muted-foreground">Model ID</label>
            <Input
              value={modelId}
              onChange={(e) => setModelId(e.target.value)}
              placeholder="e.g. claude-sonnet-4-5"
              className="mt-1 font-mono text-sm"
            />
          </div>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="text-[10px] uppercase tracking-wider text-muted-foreground">Input tokens</label>
              <Input
                value={inputTokens}
                onChange={(e) => setInputTokens(e.target.value)}
                type="number"
                className="mt-1 font-mono text-sm"
              />
            </div>
            <div>
              <label className="text-[10px] uppercase tracking-wider text-muted-foreground">Output tokens</label>
              <Input
                value={outputTokens}
                onChange={(e) => setOutputTokens(e.target.value)}
                type="number"
                className="mt-1 font-mono text-sm"
              />
            </div>
          </div>
          <Button
            size="sm"
            disabled={!modelId.trim() || estimate.isPending}
            onClick={() => estimate.mutate()}
          >
            <Calculator className="size-3" /> Estimate cost
          </Button>
        </CardContent>
      </Card>

      {estimate.data && (
        <Card>
          <CardContent className="p-4 space-y-2">
            {estimate.data.error ? (
              <p className="text-sm text-destructive">{estimate.data.error}</p>
            ) : (
              <>
                <Row label="Model" value={estimate.data.model} />
                <div className="border-t border-border pt-2">
                  <Row label="Total" value={`$${(estimate.data.cost || 0).toFixed(6)}`} strong />
                </div>
              </>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

function Row({ label, value, strong }: { label: string; value: string; strong?: boolean }) {
  return (
    <div className="flex items-center justify-between text-sm">
      <span className="text-muted-foreground">{label}</span>
      <span className={`font-mono tabular-nums ${strong ? 'font-semibold' : ''}`}>{value}</span>
    </div>
  );
}

function EmptyState({ label }: { label: string }) {
  return (
    <Card className="border-dashed">
      <CardContent className="p-10 grid place-items-center text-center text-muted-foreground">
        <Inbox className="size-8 text-muted-foreground/40 mb-2" />
        <p className="text-sm">{label}</p>
      </CardContent>
    </Card>
  );
}

function formatQuotaNumber(n: number): string {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(2)}M`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
  return n.toLocaleString();
}

/** Per-provider / per-model daily quota cards. */
function QuotasTab() {
  const all = useQuery({
    queryKey: ['quota', 'all'],
    queryFn: () => quotaApi.all(),
    refetchInterval: 30_000,
  });

  if (all.isLoading) return <div className="text-sm text-muted-foreground">Loading quota…</div>;
  const data = all.data?.results || [];

  if (data.length === 0) {
    return (
      <EmptyState label="No quota data yet. Once adapters record usage, your daily model quotas will appear here." />
    );
  }

  return (
    <div className="space-y-4 overflow-auto">
      {data.map(({ provider, quotas }) => (
        <Card key={provider}>
          <CardHeader className="pb-2">
            <div className="flex items-center justify-between">
              <CardTitle className="text-sm">{provider}</CardTitle>
              <span className="text-[10px] text-muted-foreground font-mono">
                {quotas.length} model{quotas.length === 1 ? '' : 's'} · resets at {new Date(quotas[0]?.resetsAt || Date.now()).toUTCString().slice(17, 22)} UTC
              </span>
            </div>
          </CardHeader>
          <CardContent className="space-y-2">
            {quotas.map((q) => (
              <QuotaRow key={q.model} q={q} />
            ))}
          </CardContent>
        </Card>
      ))}
    </div>
  );
}

function QuotaRow({ q }: { q: ModelQuota }) {
  const hasLimit = q.limit != null && q.limit > 0;
  return (
    <div className="space-y-1">
      <div className="flex items-center justify-between text-xs">
        <div className="flex items-center gap-2 min-w-0">
          <span className="font-mono text-foreground truncate">{q.model || 'unknown'}</span>
          <Badge variant="outline" className="text-[9px] py-0 h-4">
            {q.source}
          </Badge>
        </div>
        <div className="font-mono tabular-nums text-muted-foreground shrink-0 text-[11px]">
          {hasLimit
            ? <><span className="text-foreground">{formatQuotaNumber(q.used)}</span> / {formatQuotaNumber(q.limit!)} ({q.percent.toFixed(1)}%)</>
            : <span className="text-foreground">{formatQuotaNumber(q.used)}</span>}
        </div>
      </div>
      {hasLimit && (
        <div className="h-1.5 rounded-full bg-white/[0.06] overflow-hidden">
          <div
            className="h-full rounded-full transition-all duration-300"
            style={{
              width: `${Math.max(1, Math.min(100, q.percent))}%`,
              backgroundColor: q.percent > 90 ? '#f87171' : q.percent > 70 ? '#f59e0b' : '#4ade80',
            }}
          />
        </div>
      )}
    </div>
  );
}

/* ── BrainSettings ────────────────────────────────────────────────────── */
/* User-tunable Brain Orchestrator knobs.                                  */
/*                                                                          */
/* On first mount, the form is pre-populated with the brain policy of the    */
/* user's most recent chat session (banner: "Defaults pulled from your last */
/* chat session"). Subsequent edits persist to cfg.brainOrchestrator.        */

import { useEffect, useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { SectionHeader } from '@/components/SectionHeader';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Brain, RotateCcw, Save, Sparkles, Check, X } from 'lucide-react';
import {
  getBrainConfig,
  saveBrainConfig,
  resetBrainConfig,
  getBrainConfigFromSession,
  type BrainConfig,
  type BrainConfigResponse,
  type BrainConfigSource,
} from '@/api/workbench';
import { toast } from 'sonner';

const BOOLEAN_KEYS: { key: keyof BrainConfig; label: string; description: string }[] = [
  { key: 'enabled',                    label: 'Master switch',                 description: 'Turns the brain orchestrator on or off. When off, the model runs without per-turn policy injection.' },
  { key: 'adaptivePolicy',             label: 'Adaptive policy',              description: 'When on, the orchestrator picks a per-turn policy (debug / research / code edit / …) based on the user message.' },
  { key: 'failureLearning',            label: 'Failure learning',              description: 'Surface past tool-failure hints in the system prompt so the model avoids the same mistake.' },
  { key: 'graphMemory',                label: 'Graph memory',                  description: 'Pull graph-memory observations (entities + relations) into context.' },
  { key: 'agentJobs',                  label: 'Agent jobs persistence',        description: 'Persist every sub-agent invocation to disk so they show up in the Agents tab and audit log.' },
  { key: 'hierarchicalAgents',         label: 'Hierarchical agents',           description: 'Allow sub-agents to spawn their own children (project_manager → team).' },
  { key: 'adapterParallelTools',       label: 'Adapter parallel tools',        description: 'Run tool calls in parallel when the provider supports it.' },
  { key: 'parallelReadTools',          label: 'Parallel read-only tools',      description: 'Allow the model to fire multiple read-only tool calls in a single turn.' },
  { key: 'reviewLearnedGuidelines',    label: 'Review learned guidelines',     description: 'Surface pending learned guidelines in the system prompt for the user to accept or reject.' },
];

export function BrainSettings() {
  const queryClient = useQueryClient();
  const [draft, setDraft] = useState<BrainConfig | null>(null);
  const [sourceInfo, setSourceInfo] = useState<BrainConfigResponse | null>(null);

  const { data, isLoading, isError, error, refetch } = useQuery({
    queryKey: ['brain-config'],
    queryFn: () => getBrainConfig(),
    refetchOnMount: 'always',
  });

  useEffect(() => {
    if (data) {
      setDraft(data.config);
      setSourceInfo(data);
    }
  }, [data]);

  const save = useMutation({
    mutationFn: (updates: Partial<BrainConfig>) => saveBrainConfig(updates),
    onSuccess: (res) => {
      setDraft(res.config);
      queryClient.invalidateQueries({ queryKey: ['brain-config'] });
      queryClient.invalidateQueries({ queryKey: ['brain-policy'] });
      toast.success('Brain config saved — next turn will use the new policy.');
    },
    onError: (e: Error) => toast.error(e.message || 'Save failed'),
  });

  const reset = useMutation({
    mutationFn: () => resetBrainConfig(),
    onSuccess: (res) => {
      setDraft(res.config);
      queryClient.invalidateQueries({ queryKey: ['brain-config'] });
      toast.message('Reset to factory defaults');
    },
    onError: (e: Error) => toast.error(e.message || 'Reset failed'),
  });

  const pullFromSession = useMutation({
    mutationFn: () => (data?.sessionId ? getBrainConfigFromSession(data.sessionId) : Promise.reject(new Error('No session'))),
    onSuccess: (res) => {
      setDraft(res.config);
      setSourceInfo(res);
      toast.message('Pulled defaults from the most recent chat session');
    },
    onError: (e: Error) => toast.error(e.message || 'Pull failed'),
  });

  if (isError) {
    return (
      <div
        className="p-6 text-sm text-destructive flex items-center gap-3"
        data-testid="brain-settings-error"
      >
        <span>Could not load brain config: {(error as Error)?.message || 'unknown error'}</span>
        <Button size="sm" variant="outline" onClick={() => refetch()}>
          <RotateCcw className="mr-1 h-3.5 w-3.5" />
          Retry
        </Button>
      </div>
    );
  }

  if (isLoading || !draft) {
    return <div className="p-6 text-sm text-muted-foreground">Loading brain config…</div>;
  }

  const update = <K extends keyof BrainConfig>(key: K, value: BrainConfig[K]) => {
    setDraft((d) => (d ? { ...d, [key]: value } : d));
  };

  const dirty = JSON.stringify(draft) !== JSON.stringify(data?.config);

  return (
    <div className="p-6 space-y-4 h-full overflow-auto" data-testid="brain-settings-page">
      <SectionHeader
        title="Brain Orchestrator"
        subtitle="Tune the policy the model uses on every turn. Defaults are pulled from your most recent chat session when available."
        actions={
          <div className="flex items-center gap-2">
            <SourceBadge source={sourceInfo?.source} sessionId={sourceInfo?.sessionId} />
            <Button
              size="sm"
              variant="outline"
              onClick={() => pullFromSession.mutate()}
              disabled={!sourceInfo?.sessionId || pullFromSession.isPending}
            >
              <Sparkles className="mr-1 h-3.5 w-3.5" />
              Use chat defaults
            </Button>
            <Button
              size="sm"
              variant="outline"
              onClick={() => reset.mutate()}
              disabled={reset.isPending}
            >
              <RotateCcw className="mr-1 h-3.5 w-3.5" />
              Reset
            </Button>
            <Button
              size="sm"
              onClick={() => save.mutate(draft)}
              disabled={!dirty || save.isPending}
            >
              <Save className="mr-1 h-3.5 w-3.5" />
              {save.isPending ? 'Saving…' : 'Save'}
            </Button>
          </div>
        }
      />

      {sourceInfo?.source === 'session' && (
        <Card className="border-warning/30 bg-warning/5">
          <CardContent className="text-xs text-warning/90 p-3 flex items-center gap-2">
            <Brain className="h-4 w-4" />
            Defaults pulled from your last chat session
            {sourceInfo.sessionId ? ` (id: ${sourceInfo.sessionId.slice(0, 12)}…)` : ''}.
            Edit any value and click Save to apply.
          </CardContent>
        </Card>
      )}

      <Card>
        <CardHeader>
          <CardTitle className="text-sm">Toggles</CardTitle>
        </CardHeader>
        <CardContent className="space-y-2">
          {BOOLEAN_KEYS.map((b) => (
            <div key={b.key} className="flex items-start gap-3 py-1.5 border-b border-border/30 last:border-0">
              <label className="flex items-center gap-2 cursor-pointer min-w-[200px]">
                <input
                  type="checkbox"
                  className="h-4 w-4 accent-primary"
                  checked={!!draft[b.key]}
                  onChange={(e) => update(b.key, e.target.checked as never)}
                />
                <span className="text-sm font-medium">{b.label}</span>
              </label>
              <span className="text-xs text-muted-foreground flex-1">{b.description}</span>
            </div>
          ))}
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="text-sm">Limits</CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          <div className="flex items-center gap-3">
            <label className="text-sm font-medium min-w-[200px]">Max agent depth</label>
            <Input
              type="number"
              min={1}
              max={5}
              value={draft.maxAgentDepth}
              onChange={(e) => update('maxAgentDepth', Math.max(1, Math.min(5, Number(e.target.value) || 1)))}
              className="w-24"
            />
            <span className="text-xs text-muted-foreground">
              Maximum nested sub-agent depth. Default 4.
            </span>
          </div>
          <div className="flex items-center gap-3">
            <label className="text-sm font-medium min-w-[200px]">Max tool loops</label>
            <Input
              type="number"
              min={1}
              max={500}
              value={draft.maxWorkbenchToolLoops}
              onChange={(e) => update('maxWorkbenchToolLoops', Math.max(1, Math.min(500, Number(e.target.value) || 1)))}
              className="w-24"
            />
            <span className="text-xs text-muted-foreground">
              How many tool calls one turn may emit before the workbench stops. Default 100. Safety nets stop sooner if the token budget is exhausted or the same tool call repeats.
            </span>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

function SourceBadge({ source, sessionId }: { source?: BrainConfigSource; sessionId?: string | null }) {
  if (!source) return null;
  if (source === 'persisted') {
    return <Badge variant="secondary" className="text-[10px]">Persisted</Badge>;
  }
  if (source === 'session') {
    return <Badge variant="outline" className="text-[10px] border-warning/40 text-warning">From session {sessionId?.slice(0, 8) ?? ''}</Badge>;
  }
  return <Badge variant="outline" className="text-[10px]">Factory default</Badge>;
}

export default BrainSettings;

import { useState } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { api } from '@/api/client';
import { useProviderHealth } from '@/api/provider-health';
import { providersApi, type ProviderTemplate } from '@/api/providers';
import { useProviderTemplates } from '@/hooks/useProviderTemplates';
import { SectionHeader } from '@/components/SectionHeader';
import { PageLoader } from '@/components/PageLoader';
import { Eye, EyeOff, ChevronDown, ChevronRight, Save, Check, Key, ArrowUpRight, PlugZap, ShieldCheck, Globe, Loader2, Plus } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';

interface Provider {
  id: string;
  name: string;
  apiMode: string;
  isAvailable: boolean;
  redactedKey: string | null;
  authType?: string;
  signupUrl?: string;
}

interface ProviderDetails {
  id: string;
  name: string;
  description?: string;
  baseUrl?: string;
  apiMode: string;
  authType: string;
  envVars?: string[];
  envStatus?: Record<string, boolean>;
  isAvailable: boolean;
  defaultModel?: string;
  signupUrl?: string;
  supportsHealthCheck?: boolean;
  isActive: boolean;
  configOverrides?: Record<string, string>;
  modelProfiles?: string[];
}

interface ActiveProviderData {
  activeProvider: string;
  providers: Provider[];
}

function authLabel(authType?: string) {
  switch (authType) {
    case 'api_key': return 'API key';
    case 'oauth': return 'Login';
    case 'aws_sdk': return 'AWS SDK';
    case 'none': return 'No auth';
    default: return authType || 'Unknown';
  }
}

export function Providers() {
  const { data, isLoading, error, refetch } = useQuery({
    queryKey: ['providers'],
    queryFn: () => api.get<ActiveProviderData>('/api/config/activeProvider'),
  });
  const { byProvider: healthByProvider, loaded: healthLoaded, refresh: refreshHealth } = useProviderHealth(60_000);
  const { templates } = useProviderTemplates();
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [showAddForm, setShowAddForm] = useState(false);
  const [selectedTemplate, setSelectedTemplate] = useState<string>('');
  const [newProviderName, setNewProviderName] = useState('');
  const [newProviderKey, setNewProviderKey] = useState('');
  const [adding, setAdding] = useState(false);
  const [apiKeys, setApiKeys] = useState<Record<string, string>>({});
  const [baseUrls, setBaseUrls] = useState<Record<string, string>>({});
  const [showKeyFor, setShowKeyFor] = useState<Record<string, boolean>>({});
  const [showKeyFieldFor, setShowKeyFieldFor] = useState<Record<string, boolean>>({});
  const [showEndpointFor, setShowEndpointFor] = useState<Record<string, boolean>>({});
  const [saving, setSaving] = useState<string | null>(null);
  const [saveMsg, setSaveMsg] = useState<{ id: string; type: 'ok' | 'err'; text: string } | null>(null);
  const queryClient = useQueryClient();

  const { data: details } = useQuery({
    queryKey: ['provider-details', expandedId],
    enabled: Boolean(expandedId),
    queryFn: async () => {
      const res = await api.get<ProviderDetails>(`/api/config/provider-details?provider=${encodeURIComponent(expandedId || '')}`);
      return res;
    },
  });

  if (isLoading) return <PageLoader label="Loading providers…" />;
  if (error) {
    return (
      <div className="p-6">
        <SectionHeader title="Providers" />
        <p className="text-sm text-destructive">Failed: {String(error)}</p>
      </div>
    );
  }
  if (!data) return null;

  const sorted = [...data.providers].sort((a, b) => {
    if (a.id === data.activeProvider) return -1;
    if (b.id === data.activeProvider) return 1;
    if (a.isAvailable && !b.isAvailable) return -1;
    if (!a.isAvailable && b.isAvailable) return 1;
    return a.name.localeCompare(b.name);
  });

  const toggleExpand = (id: string) => {
    setExpandedId(expandedId === id ? null : id);
    setSaveMsg(null);
  };

  const handleSetActive = async (providerId: string) => {
    setSaving(providerId);
    setSaveMsg(null);
    try {
      await api.put('/api/config/activeProvider', { provider: providerId });
      queryClient.invalidateQueries({ queryKey: ['providers'] });
    } catch (e) {
      const message = e instanceof Error ? e.message : String(e);
      setSaveMsg({ id: providerId, type: 'err', text: message || 'Failed to activate' });
    } finally {
      setSaving(null);
    }
  };

  const handleSave = async (providerId: string) => {
    setSaving(providerId);
    setSaveMsg(null);
    try {
      const config: Record<string, string> = {};
      if (apiKeys[providerId]) config.apiKey = apiKeys[providerId];
      if (baseUrls[providerId]) config.baseUrl = baseUrls[providerId];
      await api.post('/api/config/provider-details', { provider: providerId, config });
      setSaveMsg({ id: providerId, type: 'ok', text: 'Saved' });
      queryClient.invalidateQueries({ queryKey: ['providers'] });
      queryClient.invalidateQueries({ queryKey: ['model-options'] });
    } catch (e) {
      const message = e instanceof Error ? e.message : String(e);
      setSaveMsg({ id: providerId, type: 'err', text: message || 'Save failed' });
    } finally {
      setSaving(null);
    }
  };

  const handleAddProvider = async () => {
    if (!newProviderName.trim()) return;
    setAdding(true);
    try {
      await providersApi.create({
        name: newProviderName,
        // `selectedTemplate` is UI-only scaffolding for future preset
        // support; ProviderCreate does not yet accept it, so drop it
        // when undefined.
        ...(selectedTemplate ? { template: selectedTemplate } : {}),
        apiKey: newProviderKey,
        apiFormat: 'openai-chat',
        baseUrl: '',
        enabled: true,
      });
      setShowAddForm(false);
      setSelectedTemplate('');
      setNewProviderName('');
      setNewProviderKey('');
      queryClient.invalidateQueries({ queryKey: ['providers'] });
      queryClient.invalidateQueries({ queryKey: ['aggregated-models'] });
    } catch (e) {
      const message = e instanceof Error ? e.message : String(e);
      setSaveMsg({ id: 'add', type: 'err', text: message || 'Failed to add provider' });
    } finally {
      setAdding(false);
    }
  };

  const handleTemplateSelect = (templateId: string) => {
    setSelectedTemplate(templateId);
    const tmpl = templates.find((t) => t.id === templateId);
    if (tmpl) {
      setNewProviderName(tmpl.name);
    }
  };

  return (
    <div className="p-6 space-y-6">
      <SectionHeader
        title="Providers"
        actions={
          <div className="flex items-center gap-2">
            <Button type="button" variant="outline" size="sm" onClick={() => setShowAddForm(!showAddForm)}>
              <Plus className="size-3 mr-1" />
              Add Provider
            </Button>
            <Button type="button" variant="outline" size="sm" onClick={() => refetch()}>
              Refresh
            </Button>
          </div>
        }
      />

      {showAddForm && (
        <div className="rounded-2xl border border-white/[0.06] bg-card/80 p-4 space-y-3">
          <p className="text-sm font-semibold">Add a Provider</p>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            <div>
              <label className="block text-[10px] text-muted-foreground mb-1 font-medium">Template</label>
              <select
                value={selectedTemplate}
                onChange={(e) => handleTemplateSelect(e.target.value)}
                className="w-full rounded-lg border border-white/[0.06] bg-black/20 px-3 py-2 text-sm text-foreground focus:border-primary outline-none"
              >
                <option value="">Custom (manual setup)</option>
                {templates.map((t: ProviderTemplate) => (
                  <option key={t.id} value={t.id}>
                    {t.name}
                  </option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-[10px] text-muted-foreground mb-1 font-medium">Provider Name</label>
              <input
                type="text"
                value={newProviderName}
                onChange={(e) => setNewProviderName(e.target.value)}
                placeholder="My Provider"
                className="w-full rounded-lg border border-white/[0.06] bg-black/20 px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground/40 focus:border-primary outline-none"
              />
            </div>
            <div>
              <label className="block text-[10px] text-muted-foreground mb-1 font-medium">API Key</label>
              <input
                type="password"
                value={newProviderKey}
                onChange={(e) => setNewProviderKey(e.target.value)}
                placeholder="sk-..."
                className="w-full rounded-lg border border-white/[0.06] bg-black/20 px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground/40 focus:border-primary outline-none"
              />
            </div>
          </div>
          {selectedTemplate && (
            <div className="rounded-lg border border-white/[0.06] bg-black/10 p-2.5 text-xs text-muted-foreground">
              Using <span className="font-medium text-foreground">{templates.find(t => t.id === selectedTemplate)?.name}</span> template.
              Base URL and API format will be pre-filled from the template.
            </div>
          )}
          {saveMsg && saveMsg.id === 'add' && (
            <p className="text-xs text-destructive">{saveMsg.text}</p>
          )}
          <div className="flex items-center justify-end gap-2 pt-1">
            <Button type="button" variant="outline" size="sm" onClick={() => { setShowAddForm(false); setSaveMsg(null); }}>
              Cancel
            </Button>
            <Button type="button" size="sm" onClick={handleAddProvider} disabled={!newProviderName.trim() || adding}>
              {adding ? 'Adding…' : 'Add Provider'}
            </Button>
          </div>
        </div>
      )}

      <div className="space-y-3">
        <p className="text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold px-1">Available providers</p>
          {sorted.map((p) => {
            const isExpanded = expandedId === p.id;
            const providerDetails = details?.id === p.id ? details : null;
            const authType = providerDetails?.authType || p.authType || 'api_key';
            const hasKey = p.isAvailable || Boolean(providerDetails?.configOverrides?.apiKey);
            const showKeyField = showKeyFieldFor[p.id] || !hasKey || authType === 'api_key' && !hasKey;
            const hasEndpointOverride = Boolean(providerDetails?.configOverrides?.baseUrl || providerDetails?.configOverrides?.targetUrl);
            const showEndpointField = showEndpointFor[p.id] || hasEndpointOverride || p.id === 'custom';

            return (
              <div
                key={p.id}
                className={cn(
                  'group overflow-hidden rounded-2xl border bg-card/80 transition-all hover:border-primary/30 hover:bg-card',
                  isExpanded && 'border-primary/40 shadow-lg shadow-primary/5'
                )}
              >
                <button
                  onClick={() => toggleExpand(p.id)}
                  className="w-full flex items-center justify-between gap-3 px-4 py-3 text-left"
                >
                  <div className="flex items-center gap-3 min-w-0">
                    <span className={cn(
                      'inline-block size-2.5 rounded-full shrink-0',
                      hasKey ? 'bg-success shadow-[0_0_16px_rgba(16,185,129,.45)]' : 'bg-muted-foreground/30'
                    )} />
                    <div className="min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="truncate text-sm font-semibold">{p.name}</span>
                        {p.id === data.activeProvider && (
                          <span className="inline-flex items-center gap-1 text-[9px] font-medium text-primary bg-primary/10 px-1.5 py-0.5 rounded-full">
                            <Check className="size-2.5" /> active
                          </span>
                        )}
                        {hasKey && healthLoaded && (
                          <span
                            className={cn(
                              'inline-block size-1.5 rounded-full shrink-0',
                              healthByProvider.get(p.id)?.online
                                ? 'bg-success shadow-[0_0_8px_rgba(16,185,129,.5)]'
                                : 'bg-muted-foreground/40'
                            )}
                            title={healthByProvider.get(p.id)?.online ? 'Live · reachable' : 'Offline or unreachable'}
                            aria-label={healthByProvider.get(p.id)?.online ? 'Provider online' : 'Provider offline'}
                          />
                        )}
                      </div>
                      <div className="mt-0.5 flex items-center gap-2 text-[10px] text-muted-foreground">
                        <span className="font-mono">{p.apiMode}</span>
                        <span className="size-1 rounded-full bg-muted-foreground/30" />
                        <span>{authLabel(authType)}</span>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-2 shrink-0">
                    {hasKey && (p.redactedKey || providerDetails?.configOverrides?.apiKey) ? (
                      <span className="inline-flex items-center gap-1 rounded-full border bg-muted/40 px-2 py-0.5 text-[10px] font-mono text-muted-foreground">
                        <Key className="size-2.5" />
                        configured
                      </span>
                    ) : (
                      <span className="inline-flex items-center gap-1 rounded-full border border-warning/20 bg-warning/10 px-2 py-0.5 text-[10px] font-medium text-warning">
                        <ShieldCheck className="size-2.5" />
                        needs auth
                      </span>
                    )}
                    {isExpanded
                      ? <ChevronDown className="size-3 text-muted-foreground" />
                      : <ChevronRight className="size-3 text-muted-foreground" />}
                  </div>
                </button>

                {isExpanded && (
                  <div className="border-t bg-muted/[0.025] px-4 py-3">
                    <div className="space-y-3">
                      {providerDetails?.description && (
                        <p className="text-xs leading-relaxed text-muted-foreground">{providerDetails.description}</p>
                      )}

                      <div className="flex flex-wrap gap-2">
                        <span className="rounded-full bg-primary/10 px-2 py-1 text-[10px] font-medium text-primary">{authLabel(authType)}</span>
                        {providerDetails?.defaultModel && (
                          <span className="rounded-full bg-secondary px-2 py-1 text-[10px] font-medium text-secondary-foreground">
                            {providerDetails.defaultModel}
                          </span>
                        )}
                        {p.signupUrl && (
                          <button
                            onClick={() => window.open(p.signupUrl, '_blank', 'noopener,noreferrer')}
                            className="inline-flex items-center gap-1 rounded-full border px-2 py-1 text-[10px] font-medium hover:bg-muted"
                          >
                            Sign up <ArrowUpRight className="size-2.5" />
                          </button>
                        )}
                      </div>

                      {authType === 'oauth' && (
                        <div className="rounded-xl border bg-background p-3 text-xs text-muted-foreground">
                          This provider supports login-style auth. Use the provider OAuth flow instead of pasting an API key.
                        </div>
                      )}

                      {authType === 'aws_sdk' && (
                        <div className="rounded-xl border bg-background p-3 text-xs text-muted-foreground">
                          This provider reads AWS SDK credentials from the environment. No API key field is needed here.
                        </div>
                      )}

                      {authType === 'none' && (
                        <div className="rounded-xl border bg-background p-3 text-xs text-muted-foreground">
                          No credentials are required for this provider.
                        </div>
                      )}

                      {authType === 'api_key' && (
                        <div className="space-y-2">
                          {!showKeyField ? (
                            <div className="rounded-xl border bg-background p-3 text-xs text-muted-foreground">
                              API key is already configured. Open it only if you need to override it.
                              <div className="mt-2">
                                <Button type="button" variant="outline" size="sm" onClick={() => setShowKeyFieldFor(prev => ({ ...prev, [p.id]: true }))}>
                                  <Key className="size-3 mr-1" />
                                  Change key
                                </Button>
                              </div>
                            </div>
                          ) : (
                            <div>
                              <label className="block text-[10px] text-muted-foreground mb-1 font-medium">API Key</label>
                              <div className="relative">
                                <input
                                  type={showKeyFor[p.id] ? 'text' : 'password'}
                                  value={apiKeys[p.id] ?? ''}
                                  onChange={(e) => setApiKeys(prev => ({ ...prev, [p.id]: e.target.value }))}
                                  placeholder={hasKey ? 'Override existing key…' : 'Enter API key…'}
                                  className="w-full rounded-md border border-border bg-background px-3 py-2 text-xs outline-none focus:ring-2 focus:ring-primary/40 focus:border-primary transition"
                                />
                                <button
                                  onClick={() => setShowKeyFor(prev => ({ ...prev, [p.id]: !prev[p.id] }))}
                                  className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                                >
                                  {showKeyFor[p.id] ? <EyeOff className="size-3.5" /> : <Eye className="size-3.5" />}
                                </button>
                              </div>
                            </div>
                          )}

                          {showEndpointField ? (
                            <div>
                              <label className="block text-[10px] text-muted-foreground mb-1 font-medium">Endpoint override</label>
                              <input
                                type="text"
                                value={baseUrls[p.id] ?? providerDetails?.configOverrides?.baseUrl ?? ''}
                                onChange={(e) => setBaseUrls(prev => ({ ...prev, [p.id]: e.target.value }))}
                                placeholder="https://api.example.com"
                                className="w-full rounded-md border border-border bg-background px-3 py-2 text-xs outline-none focus:ring-2 focus:ring-primary/40 focus:border-primary transition"
                              />
                            </div>
                          ) : (
                            <Button type="button" variant="ghost" size="sm" onClick={() => setShowEndpointFor(prev => ({ ...prev, [p.id]: true }))}>
                              <Globe className="size-3 mr-1" />
                              Optional endpoint
                            </Button>
                          )}
                        </div>
                      )}

                      {providerDetails?.envVars?.length ? (
                        <div className="rounded-xl border bg-background p-3">
                          <p className="text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold mb-2">Env readiness</p>
                          <div className="flex flex-wrap gap-1.5">
                            {providerDetails.envVars.map(envVar => (
                              <span key={envVar} className="inline-flex items-center gap-1 rounded-full border px-2 py-1 text-[10px] font-mono text-muted-foreground">
                                <span className={cn('size-1.5 rounded-full', providerDetails.envStatus?.[envVar] ? 'bg-success' : 'bg-muted-foreground/30')} />
                                {envVar}
                              </span>
                            ))}
                          </div>
                        </div>
                      ) : null}

                      <div className="flex items-center justify-between gap-2 pt-1">
                        <div className="flex items-center gap-2">
                          <Button
                            size="sm"
                            onClick={() => handleSetActive(p.id)}
                            disabled={saving === p.id || p.id === data.activeProvider}
                          >
                            {saving === p.id ? <Loader2 className="size-3 mr-1 animate-spin" /> : <PlugZap className="size-3 mr-1" />}
                            {p.id === data.activeProvider ? 'Active' : 'Use'}
                          </Button>
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => handleSave(p.id)}
                            disabled={saving === p.id}
                          >
                            <Save className="size-3 mr-1" />
                            Save
                          </Button>
                        </div>
                        {saveMsg && saveMsg.id === p.id && (
                          <span className={cn('text-[10px]', saveMsg.type === 'ok' ? 'text-success' : 'text-destructive')}>
                            {saveMsg.text}
                          </span>
                        )}
                      </div>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
  );
}

