function getStatusMeta(status: string) {
  switch (status) {
    case "running":
      return { label: "Running", tone: "good" as const, icon: CheckCircle2 };
    case "error":
      return { label: "Error", tone: "bad" as const, icon: AlertCircle };
    case "starting":
      return { label: "Starting", tone: "warn" as const, icon: Loader2 };
    case "disabled":
      return { label: "Disabled", tone: "muted" as const, icon: PauseCircle };
    default:
      return { label: "Stopped", tone: "muted" as const, icon: PlayCircle };
  }
}

function getServiceIcon(name: ServiceName) {
  switch (name) {
    case "google":
      return { icon: Mail, color: "from-red-500 to-orange-500" };
    case "github":
      return {
        icon: Github,
        color:
          "from-slate-800 to-slate-950 dark:from-slate-100 dark:to-slate-300 dark:text-slate-950",
      };
    case "slack":
      return { icon: MessageCircle, color: "from-purple-500 to-pink-500" };
  }
}

function getServiceStatusMeta(status: ServiceStatus) {
  switch (status) {
    case "connected":
      return { label: "Connected", tone: "good" as const, icon: CheckCircle2 };
    case "needs_config":
      return {
        label: "Needs config",
        tone: "warn" as const,
        icon: AlertCircle,
      };
    default:
      return { label: "Disconnected", tone: "muted" as const, icon: Link };
  }
}

function formatTime(value?: string) {
  if (!value) return undefined;
  try {
    return new Intl.DateTimeFormat(undefined, {
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
    }).format(new Date(value));
  } catch {
    return undefined;
  }
}

function scopeLabel(scope: string) {
  const labels: Record<string, string> = {
    openid: "OpenID",
    email: "Email",
    profile: "Profile",
    "https://www.googleapis.com/auth/gmail.readonly": "Gmail read",
    "https://www.googleapis.com/auth/gmail.send": "Gmail send",
    "https://www.googleapis.com/auth/calendar": "Calendar",
    "https://www.googleapis.com/auth/drive": "Drive",
    "https://www.googleapis.com/auth/documents": "Documents",
    "https://www.googleapis.com/auth/spreadsheets": "Spreadsheets",
    "https://www.googleapis.com/auth/presentations": "Slides",
    "https://www.googleapis.com/auth/tasks": "Tasks",
    "https://www.googleapis.com/auth/contacts": "Contacts",
  };

  return (
    labels[scope] ||
    scope
      .replace(/^https:\/\/www\.googleapis\.com\/auth\//, "")
      .replaceAll(".", " ")
      .replaceAll(/[_-]+/g, " ")
  );
}

function linesToArray(value: string) {
  return value
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean);
}

function linesToObject(value: string) {
  return Object.fromEntries(
    linesToArray(value)
      .map((line) => {
        const idx = line.indexOf("=");
        if (idx === -1) return [line, ""];
        return [line.slice(0, idx).trim(), line.slice(idx + 1).trim()];
      })
      .filter(([key]) => key),
  );
}

function envValue(env: Record<string, string>, key: string, fallback = "") {
  return env[key] || fallback;
}

function objectToLines(value: Record<string, string> = {}) {
  return Object.entries(value)
    .map(([key, child]) => `${key}=${child}`)
    .join("\n");
}

export function MergedMcpSkills() {
  const queryClient = useQueryClient();

  const { data: serviceData, isLoading: servicesLoading } = useQuery({
    queryKey: ["service-connections"],
    queryFn: async () => {
      const res = await api.get<ServiceConnectionsResponse>(
        "/api/service-connections",
      );
      return Object.values(res.connections || {}) as ServiceConnection[];
    },
    refetchInterval: 15_000,
  });

  const { data: mcpData, isLoading: mcpLoading } = useQuery({
    queryKey: ["mcp-servers"],
    queryFn: async () => {
      const res = await api.get<{ status: McpServer[] }>("/ui/mcp");
      return res.status ?? [];
    },
    refetchInterval: 15_000,
  });

  const { data: skillsData } = useQuery({
    queryKey: ["skills"],
    queryFn: async () => {
      const res = await api.get<{ skills: Skill[] }>("/api/skills");
      return (res.skills ?? []).map((skill) => ({
        ...skill,
        category: skill.category || (skill.trigger ? "automation" : "general"),
      }));
    },
    refetchInterval: 15_000,
  });

  const { data: globalEnvData } = useQuery({
    queryKey: ["mcp-global-env"],
    queryFn: async () => {
      const res = await api.get<{ env: McpGlobalEnvVar[] }>("/api/mcp-env");
      return res.env ?? [];
    },
  });

  const googleAuth = useMutation({
    mutationFn: async (email?: string) => {
      const res = await api.post<{ authUrl: string }>(
        "/api/service-connections/google/auth",
        { email },
      );
      return res.authUrl;
    },
    onSuccess: (authUrl) => {
      const popup = window.open(authUrl, "_blank", "width=520,height=760");
      if (!popup) {
        queryClient.invalidateQueries({ queryKey: ["service-connections"] });
      }
    },
  });

  const disconnect = useMutation({
    mutationFn: async (name: ServiceName) => {
      await api.delete(`/api/service-connections/${name}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["service-connections"] });
    },
  });

  const connectGithub = useMutation({
    mutationFn: async ({ token }: { token: string }) => {
      await api.post("/api/service-connections/github", { token });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["service-connections"] });
    },
  });

  const connectSlack = useMutation({
    mutationFn: async ({
      botToken,
      teamId,
    }: {
      botToken: string;
      teamId: string;
    }) => {
      await api.post("/api/service-connections/slack", { botToken, teamId });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["service-connections"] });
    },
  });

  const saveMcpServer = useMutation({
    mutationFn: async (server: McpServer) => {
      await api.post("/ui/mcp", server);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["mcp-servers"] });
      queryClient.invalidateQueries({ queryKey: ["mcp-global-env"] });
    },
  });

  const restartMcpServers = useMutation({
    mutationFn: async () => {
      await api.post("/ui/mcp/restart");
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["mcp-servers"] });
    },
  });

  const saveGlobalMcpEnv = useMutation({
    mutationFn: async (envText: string) => {
      const env = Object.entries(linesToObject(envText)).map(
        ([key, value]) => ({ key, value }),
      );
      await api.post("/api/mcp-env", { env });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["mcp-global-env"] });
      restartMcpServers.mutate();
    },
  });

  const [globalEnvText, setGlobalEnvText] = useState("");

  useEffect(() => {
    if (!globalEnvData) return;
    setGlobalEnvText(
      globalEnvData.map((item) => `${item.key}=${item.value}`).join("\n"),
    );
  }, [globalEnvData]);

  useEffect(() => {
    const onMessage = (event: MessageEvent) => {
      if (event.origin !== window.location.origin) return;
      if (event.data?.type === "august-service-connection") {
        queryClient.invalidateQueries({ queryKey: ["service-connections"] });
      }
    };
    window.addEventListener("message", onMessage);
    return () => window.removeEventListener("message", onMessage);
  }, [queryClient]);

  const services =
    serviceData && serviceData.length > 0 ? serviceData : FALLBACK_SERVICES;
  const servers = mcpData ?? [];
  const skills = skillsData ?? [];
  const [filter, setFilter] = useState<McpSkillsFilter>("all");
  const showImport = filter !== "skills";
  const showAccounts = filter === "all";
  const showServers = filter === "all" || filter === "mcp";
  const showSkills = filter === "all" || filter === "skills";
  const connectedServices = services.filter((s) => s.connected).length;
  const runningServerCount = servers.filter(
    (s) => s.status === "running",
  ).length;

  return (
    <div className="p-6 space-y-6">
      <SectionHeader
        title="MCP & Skills"
        subtitle={`${connectedServices} connected · ${runningServerCount} MCP servers running · ${servers.length} total MCP servers`}
        actions={
          <div className="flex items-center gap-1 rounded-full border bg-muted/30 p-1">
            {(
              [
                ["all", "All"],
                ["mcp", "MCP"],
                ["skills", "Skills"],
              ] as const
            ).map(([key, label]) => (
              <button
                key={key}
                type="button"
                onClick={() => setFilter(key)}
                className={cn(
                  "rounded-full px-2.5 py-1 text-xs font-medium transition",
                  filter === key
                    ? "bg-primary text-primary-foreground"
                    : "text-muted-foreground hover:text-foreground",
                )}
              >
                {label}
              </button>
            ))}
          </div>
        }
      />
      {showImport && <LinkImportPanel />}

      {showAccounts && (
        <div>
          <div className="flex items-center justify-between gap-3">
            <div>
              <h3 className="text-[10px] uppercase tracking-widest text-muted-foreground/60 font-semibold px-1">
                Accounts & logins
              </h3>
              <p className="px-1 text-xs text-muted-foreground">
                Connect the accounts August can use through tools and MCP
                servers.
              </p>
            </div>
          </div>
          <div className="space-y-3">
            {(servicesLoading || mcpLoading) && services.length === 0
              ? Array.from({ length: 3 }).map((_, i) => (
                  <div
                    key={i}
                    className="h-20 rounded-2xl border bg-muted/30 animate-pulse"
                  />
                ))
              : services.map((service) => (
                  <ServiceConnectionCard
                    key={service.name}
                    service={service}
                    onAuth={() =>
                      googleAuth.mutate(
                        service.name === "google" ? service.account : undefined,
                      )
                    }
                    onDisconnect={() => disconnect.mutate(service.name)}
                    onConnectGithub={(token) => connectGithub.mutate({ token })}
                    onConnectSlack={(botToken, teamId) =>
                      connectSlack.mutate({ botToken, teamId })
                    }
                    envText={globalEnvText}
                    onEnvTextChange={setGlobalEnvText}
                    onSaveGoogleEnv={() =>
                      saveGlobalMcpEnv.mutate(globalEnvText)
                    }
                    onRestartGoogleEnv={() => restartMcpServers.mutate()}
                    isGoogleEnvBusy={
                      saveGlobalMcpEnv.isPending || restartMcpServers.isPending
                    }
                    isBusy={
                      googleAuth.isPending ||
                      disconnect.isPending ||
                      connectGithub.isPending ||
                      connectSlack.isPending
                    }
                  />
                ))}
          </div>
        </div>
      )}

      {showServers && (
        <div>
          <div className="flex items-center justify-between gap-3">
            <div>
              <h3 className="text-[10px] uppercase tracking-widest text-muted-foreground/60 font-semibold px-1">
                MCP tools
              </h3>
              <p className="px-1 text-xs text-muted-foreground">
                Servers that expose Gmail, Drive, search, browser, Blender, and
                other tools.
              </p>
            </div>
            <Button
              type="button"
              variant="outline"
              size="sm"
              onClick={() => restartMcpServers.mutate()}
              disabled={restartMcpServers.isPending || saveMcpServer.isPending}
            >
              <RotateCcw
                className={cn(
                  "size-3.5",
                  restartMcpServers.isPending && "animate-spin",
                )}
              />
              Restart all
            </Button>
          </div>
          {servers.length === 0 ? (
            <p className="text-sm text-muted-foreground text-center py-8">
              No MCP servers configured.
            </p>
          ) : (
            <div className="space-y-3">
              {servers.map((s) => (
                <ServerCard
                  key={s.name}
                  server={s}
                  onSave={(server) => saveMcpServer.mutate(server)}
                  isBusy={saveMcpServer.isPending}
                />
              ))}
            </div>
          )}
        </div>
      )}

      {showSkills && (
        <div>
          <div className="flex items-center justify-between gap-3">
            <div>
              <h3 className="text-[10px] uppercase tracking-widest text-muted-foreground/60 font-semibold px-1">
                Skills
              </h3>
              <p className="px-1 text-xs text-muted-foreground">
                Curated skills that can be enabled for August.
              </p>
            </div>
          </div>
          {skills.length === 0 ? (
            <p className="text-sm text-muted-foreground text-center py-8">
              No skills loaded.
            </p>
          ) : (
            <div className="grid gap-2 sm:grid-cols-2">
              {skills.map((skill) => (
                <Card key={skill.name} className="overflow-hidden rounded-2xl">
                  <CardContent className="p-4">
                    <div className="flex items-start justify-between gap-2">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <h3 className="text-sm font-semibold font-mono truncate">
                            {skill.name}
                          </h3>
                          {skill.category && (
                            <span className="inline-flex items-center rounded-full border px-1.5 py-0.5 text-[9px] text-muted-foreground">
                              {skill.category}
                            </span>
                          )}
                        </div>
                        <p className="text-xs text-muted-foreground mt-1">
                          {skill.description}
                        </p>
                        {skill.trigger && (
                          <p className="text-[10px] text-muted-foreground mt-0.5 font-mono">
                            trigger: {skill.trigger}
                          </p>
                        )}
                      </div>
                      <button
                        type="button"
                        aria-label={
                          skill.enabled ? "Disable skill" : "Enable skill"
                        }
                        className={`relative w-9 h-5 rounded-full transition ${skill.enabled ? "bg-primary" : "bg-muted"}`}
                      >
                        <span
                          className={`absolute top-0.5 size-4 rounded-full bg-white transition ${skill.enabled ? "left-[18px]" : "left-0.5"}`}
                        />
                      </button>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

export function Services() {
  return <MergedMcpSkills />;
}

/* ── "Where do I get this?" inline link ────────────────────────────── */
/* Always-visible helper anchor that opens the relevant docs / console
 * in a new tab. Used next to OAuth/API credential fields so users
 * don't have to leave the app to Google the answer. */
function HelpLink({ href, children }: { href: string; children: React.ReactNode }) {
  return (
    <a
      href={href}
      target="_blank"
      rel="noopener noreferrer"
      className="inline-flex items-center gap-1 text-[10px] text-muted-foreground hover:text-foreground hover:underline transition mt-0.5"
    >
      {children}
      <ExternalLink className="size-2.5" />
    </a>
  );
}

function ServiceConnectionCard({
  service,
  onAuth,
  onDisconnect,
  onConnectGithub,
  onConnectSlack,
  envText,
  onEnvTextChange,
  onSaveGoogleEnv,
  onRestartGoogleEnv,
  isGoogleEnvBusy,
  isBusy,
}: {
  service: ServiceConnection;
  onAuth: () => void;
  onDisconnect: () => void;
  onConnectGithub: (token: string) => void;
  onConnectSlack: (botToken: string, teamId: string) => void;
  envText: string;
  onEnvTextChange: (value: string) => void;
  onSaveGoogleEnv: () => void;
  onRestartGoogleEnv: () => void;
  isGoogleEnvBusy: boolean;
  isBusy: boolean;
}) {
  const meta = getServiceStatusMeta(service.status);
  const Icon = getServiceIcon(service.name);
  const StatusIcon = meta.icon;
  const [expanded, setExpanded] = useState(false);
  const [githubToken, setGithubToken] = useState("");
  const [slackToken, setSlackToken] = useState("");
  const [slackTeamId, setSlackTeamId] = useState(service.teamId || "");
  const [showToken, setShowToken] = useState(false);
  const [showTokenField, setShowTokenField] = useState(!service.connected);
  const [error, setError] = useState<string | null>(null);

  const env = linesToObject(envText);
  const googleClientId = envValue(env, "GOOGLE_OAUTH_CLIENT_ID");
  const googleClientSecret = envValue(env, "GOOGLE_OAUTH_CLIENT_SECRET");
  const googleRedirectUri = envValue(env, "GOOGLE_OAUTH_REDIRECT_URI");

  function updateGoogleEnv(key: string, value: string) {
    const next = { ...env, [key]: value };
    onEnvTextChange(objectToLines(next));
  }

  const isGoogle = service.name === "google";
  const isSlack = service.name === "slack";
  const token = isSlack ? slackToken : githubToken;
  const setToken = isSlack ? setSlackToken : setGithubToken;
  const teamId = isSlack ? slackTeamId : "";
  const tokenLabel = isSlack ? "Slack bot token" : "GitHub token";
  const tokenPlaceholder = isSlack ? "xoxb-..." : "ghp_...";
  const hasRequiredInputs = isGoogle
    ? true
    : isSlack
      ? Boolean(token.trim() && teamId.trim())
      : Boolean(token.trim());
  const showTokenInput = showTokenField || !service.connected;
  const authBadge = service.connected
    ? { label: "configured", tone: "good" as const }
    : service.status === "needs_config"
      ? { label: "needs config", tone: "warn" as const }
      : { label: "needs auth", tone: "muted" as const };

  function handleConnect() {
    setError(null);
    if (isSlack) {
      onConnectSlack(token, teamId);
    } else {
      onConnectGithub(token);
    }
  }

  return (
    <Card
      className={cn(
        "overflow-hidden rounded-2xl transition-all hover:border-primary/30 hover:bg-card",
        expanded && "border-primary/40 shadow-lg shadow-primary/5",
      )}
    >
      <button
        onClick={() => setExpanded((value) => !value)}
        className="w-full flex items-center justify-between gap-3 px-4 py-3 text-left"
        type="button"
      >
        <div className="flex items-center gap-3 min-w-0">
          <span
            className={cn(
              "inline-block size-2.5 rounded-full shrink-0",
              meta.tone === "good" &&
                "bg-success shadow-[0_0_16px_rgba(16,185,129,.45)]",
              meta.tone === "warn" && "bg-warning",
              meta.tone === "muted" && "bg-muted-foreground/30",
            )}
          />
          <div className="min-w-0">
            <div className="flex items-center gap-2">
              <span className="truncate text-sm font-semibold">
                {service.label}
              </span>
              {service.connected && (
                <span className="inline-flex items-center gap-1 text-[9px] font-medium text-primary bg-primary/10 px-1.5 py-0.5 rounded-full">
                  <CheckCircle2 className="size-2.5" />
                  connected
                </span>
              )}
            </div>
            <div className="mt-0.5 flex items-center gap-2 text-[10px] text-muted-foreground">
              <Icon.icon className="size-3" />
              <span className="truncate">{service.description}</span>
            </div>
          </div>
        </div>
        <div className="flex items-center gap-2 shrink-0">
          <span
            className={cn(
              "inline-flex items-center gap-1 rounded-full border px-2 py-0.5 text-[10px] font-medium",
              authBadge.tone === "good" &&
                "border-success/20 bg-success/10 text-success",
              authBadge.tone === "warn" &&
                "border-warning/20 bg-warning/10 text-warning",
              authBadge.tone === "muted" &&
                "border-border bg-muted/40 text-muted-foreground",
            )}
          >
            <StatusIcon className="size-3" />
            {authBadge.label}
          </span>
          {expanded ? (
            <ChevronDown className="size-3 text-muted-foreground" />
          ) : (
            <ChevronRight className="size-3 text-muted-foreground" />
          )}
        </div>
      </button>

      {expanded && (
        <div className="border-t bg-muted/[0.025] px-4 py-3">
          <div className="space-y-3">
            <div className="flex flex-wrap gap-1">
              {service.scopes.slice(0, 9).map((scope) => (
                <span
                  key={scope}
                  className="inline-flex items-center rounded bg-secondary px-1.5 py-0.5 text-[9px] font-medium text-secondary-foreground"
                >
                  {scopeLabel(scope)}
                </span>
              ))}
              {service.scopes.length > 9 && (
                <span className="text-[9px] text-muted-foreground">
                  +{service.scopes.length - 9}
                </span>
              )}
            </div>

            {service.account && (
              <div className="rounded-lg border bg-muted/30 px-3 py-2">
                <p className="text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">
                  Account
                </p>
                <p
                  className="mt-1 text-xs font-mono truncate"
                  title={service.account}
                >
                  {service.account}
                </p>
              </div>
            )}

            {!showTokenInput && service.maskedToken && (
              <div className="rounded-lg border bg-muted/30 px-3 py-2">
                <p className="text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">
                  Stored login
                </p>
                <p
                  className="mt-1 text-xs font-mono truncate"
                  title={service.maskedToken}
                >
                  {service.maskedToken}
                </p>
              </div>
            )}

            {!showTokenInput && service.teamId && (
              <div className="rounded-lg border bg-muted/30 px-3 py-2">
                <p className="text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">
                  Team
                </p>
                <p className="mt-1 text-xs font-mono">{service.teamId}</p>
              </div>
            )}

            {service.missingConfig && (
              <div className="rounded-lg border border-warning/30 bg-warning/10 px-3 py-2 text-xs text-warning">
                Google login is not available yet. Add the Google OAuth secret
                in Google login setup, save, restart August, then connect here.
              </div>
            )}

            {!isGoogle && (
              <div className="space-y-2">
                {!showTokenInput ? (
                  <div className="rounded-xl border bg-background p-3 text-xs text-muted-foreground">
                    {tokenLabel} is already configured. Open it only if you need
                    to override it.
                    <div className="mt-2">
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        onClick={() => setShowTokenField(true)}
                      >
                        <KeyRound className="size-3 mr-1" />
                        Change token
                      </Button>
                    </div>
                  </div>
                ) : (
                  <div>
                    <label className="block text-[10px] text-muted-foreground mb-1 font-medium">
                      {tokenLabel}
                    </label>
                    <HelpLink
                      href={isSlack ? SERVICE_LINKS.slack.botToken : SERVICE_LINKS.github.token}
                    >
                      Where do I get this?
                    </HelpLink>
                    <div className="relative mt-1">
                      <Input
                        type={showToken ? "text" : "password"}
                        value={token}
                        onChange={(e) => setToken(e.target.value)}
                        placeholder={
                          service.connected
                            ? `Override existing ${tokenLabel}…`
                            : tokenPlaceholder
                        }
                        className="w-full rounded-md border border-border bg-background px-3 py-2 pr-9 text-xs outline-none focus:ring-2 focus:ring-primary/40 focus:border-primary transition"
                      />
                      <button
                        onClick={() => setShowToken((value) => !value)}
                        className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                        type="button"
                      >
                        {showToken ? (
                          <EyeOff className="size-3.5" />
                        ) : (
                          <Eye className="size-3.5" />
                        )}
                      </button>
                    </div>
                  </div>
                )}

                {isSlack && (
                  <div>
                    <label className="block text-[10px] text-muted-foreground mb-1 font-medium">
                      Slack team ID
                    </label>
                    <HelpLink href={SERVICE_LINKS.slack.teamId}>
                      Where do I find this?
                    </HelpLink>
                    <Input
                      value={teamId}
                      onChange={(e) => setSlackTeamId(e.target.value)}
                      placeholder="T0000000000"
                      className="w-full rounded-md border border-border bg-background px-3 py-2 text-xs outline-none focus:ring-2 focus:ring-primary/40 focus:border-primary transition"
                    />
                  </div>
                )}

                <div className="flex items-center justify-between gap-2">
                  <p className="text-[10px] text-muted-foreground">
                    Use an API key, personal token, or bot token. Stored secrets
                    stay saved when left unchanged.
                  </p>
                  <Button
                    type="button"
                    size="sm"
                    onClick={handleConnect}
                    disabled={isBusy || !hasRequiredInputs}
                  >
                    <Save className="size-3 mr-1" />
                    {service.connected ? "Save token" : "Connect"}
                  </Button>
                </div>
              </div>
            )}

            {isGoogle && (
              <div className="space-y-3">
                <div className="space-y-2">
                  <div>
                    <label className="block text-[10px] text-muted-foreground mb-1 font-medium">
                      Google client ID
                    </label>
                    <HelpLink href={SERVICE_LINKS.google.clientIdAndSecret}>
                      Where do I get this?
                    </HelpLink>
                    <Input
                      value={googleClientId}
                      onChange={(e) =>
                        updateGoogleEnv(
                          "GOOGLE_OAUTH_CLIENT_ID",
                          e.target.value,
                        )
                      }
                      placeholder="Google OAuth client ID"
                      className="w-full rounded-md border border-border bg-background px-3 py-2 text-xs outline-none focus:ring-2 focus:ring-primary/40 focus:border-primary transition"
                    />
                  </div>
                  <div>
                    <label className="block text-[10px] text-muted-foreground mb-1 font-medium">
                      Google client secret
                    </label>
                    <HelpLink href={SERVICE_LINKS.google.clientIdAndSecret}>
                      Where do I get this?
                    </HelpLink>
                    <Input
                      type="password"
                      value={googleClientSecret}
                      onChange={(e) =>
                        updateGoogleEnv(
                          "GOOGLE_OAUTH_CLIENT_SECRET",
                          e.target.value,
                        )
                      }
                      placeholder="Google OAuth client secret"
                      className="w-full rounded-md border border-border bg-background px-3 py-2 text-xs outline-none focus:ring-2 focus:ring-primary/40 focus:border-primary transition"
                    />
                  </div>
                  <div>
                    <label className="block text-[10px] text-muted-foreground mb-1 font-medium">
                      Redirect URI
                    </label>
                    <HelpLink href={SERVICE_LINKS.google.redirectUriDocs}>
                      How do I set this in Google?
                    </HelpLink>
                    <Input
                      value={googleRedirectUri}
                      onChange={(e) =>
                        updateGoogleEnv(
                          "GOOGLE_OAUTH_REDIRECT_URI",
                          e.target.value,
                        )
                      }
                      placeholder="https://your-domain/oauth/callback"
                      className="w-full rounded-md border border-border bg-background px-3 py-2 text-xs outline-none focus:ring-2 focus:ring-primary/40 focus:border-primary transition"
                    />
                  </div>
                </div>

                {service.missingConfig && (
                  <div className="rounded-lg border border-warning/30 bg-warning/10 px-3 py-2 text-xs text-warning">
                    Google login is not available yet. Add the Google OAuth
                    secret above, save, restart August, then connect here.
                  </div>
                )}

                <div className="flex items-center justify-between gap-2">
                  <p className="text-[10px] text-muted-foreground">
                    Save these, restart August, then sign in with the Workspace
                    account August should use.
                  </p>
                  <div className="flex items-center gap-2">
                    <Button
                      type="button"
                      variant="outline"
                      size="sm"
                      onClick={onRestartGoogleEnv}
                      disabled={isGoogleEnvBusy}
                    >
                      <RotateCcw
                        className={cn(
                          "size-3.5",
                          isGoogleEnvBusy && "animate-spin",
                        )}
                      />
                      Restart
                    </Button>
                    <Button
                      type="button"
                      size="sm"
                      onClick={onSaveGoogleEnv}
                      disabled={isGoogleEnvBusy}
                    >
                      <Save className="size-3 mr-1" />
                      Save
                    </Button>
                    <Button
                      type="button"
                      variant="outline"
                      size="sm"
                      onClick={onAuth}
                      disabled={isBusy || service.missingConfig}
                    >
                      <ExternalLink className="size-3.5" />
                      {service.connected ? "Re-auth" : "Connect"}
                    </Button>
                    <Button
                      type="button"
                      variant="destructive"
                      size="sm"
                      onClick={onDisconnect}
                      disabled={isBusy || !service.connected}
                    >
                      <Trash2 className="size-3.5" />
                      Disconnect
                    </Button>
                  </div>
                </div>
              </div>
            )}

            {service.updatedAt && (
              <p className="text-[10px] text-muted-foreground">
                Updated {formatTime(service.updatedAt)}
              </p>
            )}
          </div>
        </div>
      )}
    </Card>
  );
}

function LinkImportPanel() {
  const queryClient = useQueryClient();
  const [link, setLink] = useState("");
  const [enableMcp, setEnableMcp] = useState(true);
  const [result, setResult] = useState<ImportLinkResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const importLink = useMutation({
    mutationFn: async (url: string) => {
      const res = await api.post("/ui/import-link", { url, enableMcp });
      return res as ImportLinkResult;
    },
    onSuccess: (data) => {
      setResult(data);
      setError(null);
      queryClient.invalidateQueries({ queryKey: ["mcp-servers"] });
    },
    onError: (e) => {
      setError(e instanceof Error ? e.message : String(e));
      setResult(null);
    },
  });

  return (
    <Card>
      <CardHeader className="pb-3">
        <div>
          <CardTitle>Paste a GitHub or MCP link</CardTitle>
          <CardDescription>
            Paste a repo, raw file, or capability link. August will look for
            skills, plugins, or MCP server metadata.
          </CardDescription>
        </div>
      </CardHeader>
      <CardContent className="space-y-3">
        <div className="flex gap-2">
          <Input
            className="h-10 text-xs font-mono"
            placeholder="https://github.com/owner/repo"
            value={link}
            onChange={(e) => setLink(e.target.value)}
          />
          <Button
            type="button"
            size="sm"
            onClick={() => importLink.mutate(link.trim())}
            disabled={importLink.isPending || !link.trim()}
          >
            <Link className="size-3.5" />
            Import
          </Button>
        </div>

        <label className="flex items-center gap-2 text-xs text-muted-foreground">
          <input
            type="checkbox"
            className="rounded border-border bg-background"
            checked={enableMcp}
            onChange={(e) => setEnableMcp(e.target.checked)}
            disabled={importLink.isPending}
          />
          enable MCP servers found in the link
        </label>

        {error && (
          <p className="rounded-lg border border-danger/30 bg-danger/10 p-3 text-xs text-danger/90">
            {error}
          </p>
        )}
        {result && (
          <div className="rounded-xl border bg-success/10 p-3 text-xs text-success space-y-2">
            <p className="font-medium">Imported successfully</p>
            {result.resolvedUrl && (
              <p className="truncate">Source: {result.resolvedUrl}</p>
            )}
            {result.enabledMcpServers?.length ? (
              <p>MCP servers: {result.enabledMcpServers.join(", ")}</p>
            ) : (
              <p>No MCP server was imported from this link.</p>
            )}
            {result.skills?.length ? (
              <p>
                Skills:{" "}
                {result.skills
                  .map((s) => s.name)
                  .filter(Boolean)
                  .join(", ")}
              </p>
            ) : null}
            {result.plugins?.length ? (
              <p>
                Plugins:{" "}
                {result.plugins
                  .map((p) => p.name)
                  .filter(Boolean)
                  .join(", ")}
              </p>
            ) : null}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

function ServerCard({
  server,
  onSave,
  isBusy,
}: {
  server: McpServer;
  onSave: (server: McpServer) => void;
  isBusy: boolean;
}) {
  const meta = getStatusMeta(server.status);
  const StatusIcon = meta.icon;
  const [enabled, setEnabled] = useState(server.enabled);
  const [command, setCommand] = useState(server.command || "");
  const [url, setUrl] = useState(server.url || "");
  const [argsText, setArgsText] = useState(
    server.argsText ?? (server.args || []).join("\n"),
  );
  const [envText, setEnvText] = useState(
    server.envText ?? objectToLines(server.env),
  );
  const [headersText, setHeadersText] = useState(
    server.headersText ?? objectToLines(server.headers),
  );
  const [cwd, setCwd] = useState(server.cwd || "");
  const [timeoutMs, setTimeoutMs] = useState(String(server.timeoutMs || 15000));
  const [advanced, setAdvanced] = useState(false);
  const [expanded, setExpanded] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [saved, setSaved] = useState(false);
  const isUrlServer = url.trim().length > 0;
  const isStdioServer = !isUrlServer;
  const hasOptionalInputs =
    envText.trim() || headersText.trim() || argsText.trim() || cwd.trim();
  const showAdvanced = advanced || Boolean(hasOptionalInputs);
  const showUrlInput =
    isUrlServer || !command || advanced || !hasOptionalInputs;
  const showCommandInput =
    !isUrlServer || !url || advanced || !hasOptionalInputs;
  const showArgs = isStdioServer || showAdvanced;
  const showEnv = isStdioServer || showAdvanced;
  const showHeaders = isUrlServer || showAdvanced;
  const showCwd = isStdioServer || showAdvanced;

  const setupHint = !enabled
    ? "Turned off. Toggle on if you want August to start this MCP server."
    : server.status === "running"
      ? "Ready. August can call tools from this server."
      : "Needs setup. Check the command, URL, env, or headers, then save to restart it.";

  function buildServerPayload(): McpServer {
    return {
      ...server,
      enabled,
      command,
      url,
      args: linesToArray(argsText),
      env: linesToObject(envText),
      headers: linesToObject(headersText),
      cwd: cwd.trim() || undefined,
      timeoutMs: Math.max(1000, Number(timeoutMs) || 15000),
    };
  }

  function handleSave() {
    setError(null);
    setSaved(false);
    try {
      onSave(buildServerPayload());
      setSaved(true);
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    }
  }

  return (
    <Card
      className={cn(
        "overflow-hidden rounded-2xl transition-all hover:border-primary/30 hover:bg-card",
        expanded && "border-primary/40 shadow-lg shadow-primary/5",
      )}
    >
      <button
        onClick={() => setExpanded((value) => !value)}
        className="w-full flex items-center justify-between gap-3 px-4 py-3 text-left"
        type="button"
      >
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <h3 className="text-sm font-semibold font-mono truncate">
              {server.name}
            </h3>
            <span
              className={cn(
                "inline-flex items-center gap-1 text-[9px] font-medium px-1.5 py-0.5 rounded-full",
                meta.tone === "good" && "bg-success/10 text-success",
                meta.tone === "bad" && "bg-danger/10 text-danger",
                meta.tone === "warn" && "bg-warning/10 text-warning",
                meta.tone === "muted" && "bg-muted text-muted-foreground",
              )}
            >
              <StatusIcon
                className={cn(
                  "size-2.5",
                  meta.tone === "warn" && "animate-spin",
                )}
              />
              {meta.label}
            </span>
          </div>

          {server.toolCount > 0 && (
            <p className="text-[10px] text-muted-foreground mt-1 font-mono flex items-center gap-1">
              <Wrench className="size-2.5" /> {server.toolCount} tools
            </p>
          )}

          {server.error && (
            <p
              className="text-[10px] text-danger/80 mt-1 truncate"
              title={server.error}
            >
              {server.error}
            </p>
          )}

          {server.tools && server.tools.length > 0 && (
            <div className="flex flex-wrap gap-1 mt-2">
              {server.tools.slice(0, 3).map((tool) => (
                <span
                  key={tool}
                  className="inline-flex items-center rounded bg-secondary text-secondary-foreground px-1.5 py-0.5 text-[9px] font-mono truncate max-w-[120px]"
                >
                  {tool}
                </span>
              ))}
              {server.tools.length > 3 && (
                <span className="text-[9px] text-muted-foreground">
                  +{server.tools.length - 3}
                </span>
              )}
            </div>
          )}
        </div>
        {expanded ? (
          <ChevronDown className="size-3 text-muted-foreground shrink-0" />
        ) : (
          <ChevronRight className="size-3 text-muted-foreground shrink-0" />
        )}
      </button>

      {expanded && (
        <CardContent className="p-4">
          <div className="mt-4 rounded-xl border bg-muted/20 p-3">
            <div className="flex items-start gap-2">
              <div
                className={cn(
                  "mt-0.5 size-2 rounded-full shrink-0",
                  server.status === "running"
                    ? "bg-success"
                    : server.status === "error"
                      ? "bg-danger"
                      : "bg-warning",
                )}
              />
              <p className="text-xs leading-relaxed text-muted-foreground">
                {setupHint}
              </p>
            </div>
          </div>

          <div className="mt-4 rounded-lg border bg-muted/20 p-3 space-y-3">
            <div className="flex items-center justify-between gap-3">
              <div>
                <p className="text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">
                  Server setup
                </p>
                <p className="text-[10px] text-muted-foreground mt-0.5">
                  {isUrlServer
                    ? "URL transport. Headers are only needed when the remote MCP asks for auth."
                    : "Command transport. Env/args are only needed when this server needs them."}
                </p>
              </div>
              <div className="flex items-center gap-2">
                {!showAdvanced && (
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    onClick={() => setAdvanced(true)}
                    disabled={isBusy}
                  >
                    <Plus className="size-3.5" />
                    Optional setup
                  </Button>
                )}
                <label className="flex items-center gap-2 text-xs text-muted-foreground">
                  <input
                    type="checkbox"
                    className="rounded border-border bg-background"
                    checked={enabled}
                    onChange={(e) => setEnabled(e.target.checked)}
                    disabled={isBusy}
                  />
                  enabled
                </label>
              </div>
            </div>

            <div className="grid gap-2 sm:grid-cols-2">
              {showUrlInput && (
                <Input
                  className="h-8 text-xs font-mono"
                  placeholder="https://host/mcp"
                  value={url}
                  onChange={(e) => setUrl(e.target.value)}
                  disabled={isBusy}
                />
              )}
              {showCommandInput && (
                <Input
                  className="h-8 text-xs font-mono"
                  placeholder={
                    isUrlServer
                      ? "leave empty for URL MCP"
                      : "node / uvx / npx command"
                  }
                  value={command}
                  onChange={(e) => setCommand(e.target.value)}
                  disabled={isBusy}
                />
              )}
            </div>

            {showArgs && (
              <textarea
                className="min-h-16 w-full rounded-md border bg-background px-3 py-2 text-xs font-mono outline-none focus:ring-2 focus:ring-ring/40 disabled:opacity-50"
                placeholder="args, one per line"
                value={argsText}
                onChange={(e) => setArgsText(e.target.value)}
                disabled={isBusy}
              />
            )}

            {showEnv && (
              <textarea
                className="min-h-16 w-full rounded-md border bg-background px-3 py-2 text-xs font-mono outline-none focus:ring-2 focus:ring-ring/40 disabled:opacity-50"
                placeholder="KEY=VALUE env vars, one per line"
                value={envText}
                onChange={(e) => setEnvText(e.target.value)}
                disabled={isBusy}
              />
            )}

            {showHeaders && (
              <textarea
                className="min-h-16 w-full rounded-md border bg-background px-3 py-2 text-xs font-mono outline-none focus:ring-2 focus:ring-ring/40 disabled:opacity-50"
                placeholder="Authorization=Bearer ... headers, one per line"
                value={headersText}
                onChange={(e) => setHeadersText(e.target.value)}
                disabled={isBusy}
              />
            )}

            {showCwd && (
              <Input
                className="h-8 text-xs font-mono"
                placeholder="cwd"
                value={cwd}
                onChange={(e) => setCwd(e.target.value)}
                disabled={isBusy}
              />
            )}

            <Input
              className="h-8 text-xs font-mono"
              type="number"
              min="1000"
              value={timeoutMs}
              onChange={(e) => setTimeoutMs(e.target.value)}
              disabled={isBusy}
            />

            {showAdvanced && (
              <p className="rounded-md bg-muted/50 px-2.5 py-2 text-[10px] leading-relaxed text-muted-foreground">
                Env key-value means process variables like{" "}
                <span className="font-mono">BRAVE_API_KEY=abc123</span>. Header
                key-value means HTTP headers like{" "}
                <span className="font-mono">Authorization=Bearer abc123</span>.
                Use one per line.
              </p>
            )}

            {error && <p className="text-[10px] text-danger/80">{error}</p>}
            {saved && (
              <p className="text-[10px] text-success">
                Saved. Backend restarted MCP servers.
              </p>
            )}

            <div className="flex items-center justify-between gap-2">
              <p className="text-[10px] text-muted-foreground">
                Masked secrets stay saved when left unchanged.
              </p>
              <Button
                type="button"
                size="sm"
                onClick={handleSave}
                disabled={isBusy}
              >
                <Save className="size-3.5" />
                Save inputs
              </Button>
            </div>
          </div>
        </CardContent>
      )}
    </Card>
  );
}

/* ── AuditTimeline — vertical timeline of audit entries with filters ── */

import { useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Filter, ChevronDown, ChevronRight } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { SettingsEmptyState } from '@/components/settings/SettingsEmptyState';
import { StatusPill, variantForResult } from '@/components/workspace/StatusPill';
import { getAuditLog, getObservationUrl, type AuditEntry } from '@/api/api-client';
import { formatTimeAgo } from '@/lib/utils';
import { cn } from '@/lib/utils';

const CATEGORIES = ['', 'august_api', 'system', 'computer', 'ui', 'general'] as const;

export function AuditTimeline() {
    const [category, setCategory] = useState<string>('');
    const [actor, setActor] = useState<string>('');
    const [sinceDays, setSinceDays] = useState<number>(7);
    const [expanded, setExpanded] = useState<Set<string>>(new Set());

    const sinceISO = useMemo(() => {
        const d = new Date();
        d.setDate(d.getDate() - sinceDays);
        return d.toISOString();
    }, [sinceDays]);

    const query = useQuery({
        queryKey: ['audit', { category, actor, since: sinceISO, limit: 200 }],
        queryFn: () => getAuditLog({ limit: 200, category: category || undefined, actor: actor || undefined, since: sinceISO }),
        refetchInterval: 30_000
    });

    const entries = query.data?.entries ?? [];

    function toggle(id: string) {
        setExpanded(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id); else next.add(id);
            return next;
        });
    }

    return (
        <div className="space-y-4">
            {/* Filter bar */}
            <Card>
                <CardContent className="py-3 flex items-center gap-2 flex-wrap text-sm">
                    <Filter className="size-4 text-muted-foreground" />
                    <select
                        value={category}
                        onChange={e => setCategory(e.target.value)}
                        className="rounded-md border border-white/[0.08] bg-secondary px-2 py-1 text-sm text-foreground"
                        aria-label="Category filter"
                    >
                        {CATEGORIES.map(c => <option key={c} value={c}>{c || 'all categories'}</option>)}
                    </select>
                    <input
                        type="text"
                        value={actor}
                        onChange={e => setActor(e.target.value)}
                        placeholder="actor (e.g. august)"
                        className="rounded-md border border-white/[0.08] bg-secondary px-2 py-1 text-sm text-foreground placeholder:text-muted-foreground"
                    />
                    <select
                        value={String(sinceDays)}
                        onChange={e => setSinceDays(Number(e.target.value))}
                        className="rounded-md border border-white/[0.08] bg-secondary px-2 py-1 text-sm text-foreground"
                        aria-label="Time range"
                    >
                        <option value="1">last 24h</option>
                        <option value="7">last 7 days</option>
                        <option value="30">last 30 days</option>
                    </select>
                    <span className="ml-auto text-muted-foreground">{entries.length} entries</span>
                </CardContent>
            </Card>

            {/* Timeline */}
            {query.isLoading ? (
                <SettingsEmptyState title="Loading…" description="Fetching audit entries." />
            ) : entries.length === 0 ? (
                <SettingsEmptyState title="No entries match" description="Try widening the filters." />
            ) : (
                <div className="relative">
                    <div className="absolute left-[7px] top-0 bottom-0 w-px bg-white/[0.06]" aria-hidden="true" />
                    <ul className="space-y-2">
                        {entries.slice().reverse().map(e => (
                            <TimelineRow
                                key={e.id}
                                entry={e}
                                expanded={expanded.has(e.id)}
                                onToggle={() => toggle(e.id)}
                            />
                        ))}
                    </ul>
                </div>
            )}
        </div>
    );
}

function TimelineRow({ entry, expanded, onToggle }: { entry: AuditEntry; expanded: boolean; onToggle: () => void }) {
    const hasPostObs = !!entry.postObservation?.screenshotPath;
    return (
        <li>
            <button
                type="button"
                onClick={onToggle}
                className={cn(
                    'group relative w-full text-left pl-6 pr-3 py-2 rounded-md transition',
                    'hover:bg-white/[0.04] focus:bg-white/[0.06] focus:outline-none',
                    expanded && 'bg-white/[0.04]'
                )}
            >
                <span className={cn(
                    'absolute left-0 top-3 size-[15px] rounded-full border-2',
                    entry.critical === true ? 'border-danger bg-danger/20' :
                    entry.critical === false ? 'border-success bg-success/20' :
                    'border-white/30 bg-card'
                )} aria-hidden="true" />
                <div className="flex items-center gap-2 text-sm">
                    {expanded ? <ChevronDown className="size-3.5 text-muted-foreground" /> : <ChevronRight className="size-3.5 text-muted-foreground" />}
                    <span className="font-mono text-xs text-muted-foreground">{formatTimeAgo(new Date(entry.at))}</span>
                    <span className="text-foreground/90 font-medium truncate">{entry.action}</span>
                    {entry.target && <code className="text-xs text-muted-foreground truncate">{entry.target}</code>}
                    <span className="ml-auto flex items-center gap-1">
                        {entry.category && <StatusPill label={entry.category} variant="muted" />}
                        <StatusPill label={entry.result || 'unknown'} variant={variantForResult(entry.result)} />
                        {entry.critical === true && <StatusPill label="critical" variant="danger" />}
                    </span>
                </div>
                {expanded && (
                    <div className="mt-2 pl-5 text-xs space-y-2 text-muted-foreground">
                        <Row k="ID" v={<code>{entry.id}</code>} />
                        <Row k="Actor" v={entry.actor} />
                        <Row k="Mode" v={entry.mode || '—'} />
                        {hasPostObs && (
                            <div className="flex items-start gap-2">
                                <span className="text-muted-foreground w-20 shrink-0">post-obs</span>
                                <a
                                    href={getObservationUrl(entry.postObservation!.screenshotPath!.split(/[\\/]/).pop()!.replace(/\.png$/, ''))}
                                    target="_blank"
                                    rel="noreferrer"
                                    className="text-primary hover:underline"
                                >
                                    View screenshot →
                                </a>
                            </div>
                        )}
                        {entry.inputSummary !== undefined && entry.inputSummary !== null && (
                            <JsonBlock label="input" value={entry.inputSummary} />
                        )}
                        {entry.beforeSummary !== undefined && entry.beforeSummary !== null && (
                            <JsonBlock label="before" value={entry.beforeSummary} />
                        )}
                        {entry.afterSummary !== undefined && entry.afterSummary !== null && (
                            <JsonBlock label="after" value={entry.afterSummary} />
                        )}
                        {entry.error && <Row k="error" v={<span className="text-rose-300">{entry.error}</span>} />}
                    </div>
                )}
            </button>
        </li>
    );
}

function Row({ k, v }: { k: string; v: React.ReactNode }) {
    return (
        <div className="flex items-start gap-2">
            <span className="w-20 shrink-0 text-muted-foreground">{k}</span>
            <span className="font-mono text-foreground/80 break-all">{v}</span>
        </div>
    );
}

function JsonBlock({ label, value }: { label: string; value: unknown }) {
    return (
        <div className="rounded-md border border-white/[0.06] bg-background/40 p-2">
            <div className="text-[10px] uppercase tracking-widest text-muted-foreground mb-1">{label}</div>
            <pre className="text-[11px] leading-snug whitespace-pre-wrap break-all font-mono">
                {typeof value === 'string' ? value : JSON.stringify(value, null, 2)}
            </pre>
        </div>
    );
}

/* ── BackendMonitorSection — real-time log dashboard ───────────────── */
/* One-screen Settings surface that streams live backend events over a
 * WebSocket. Filter chips + search narrow what renders; the stat strip
 * summarises the current visible window. The virtualized list handles
 * 10k+ rows without freezing the UI. */

import { useEffect, useMemo, useRef, useState } from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';
import {
  Activity,
  AlertTriangle,
  CircleDot,
  Download,
  Filter,
  Pause,
  Play,
  Radio,
  Search,
  Trash2,
  Inbox,
} from 'lucide-react';
import { SettingsCard } from '@/components/settings/SettingsCard';
import { SettingsEmptyState } from '@/components/settings/SettingsEmptyState';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import { useLogStream, type StreamStatus } from '@/hooks/useLogStream';
import { useBackendStatus } from '@/hooks/useBackendStatus';
import type { LogEvent } from '@/api/api-client';

/* ── Category → visual mapping ─────────────────────────────────────── */

const CATEGORY_META: Record<string, { label: string; chip: string; row: string; icon: typeof Activity }> = {
    proxy_incoming:        { label: 'Incoming',      chip: 'bg-sky-500/10 text-sky-300 border-sky-500/30',            row: 'text-sky-300',                       icon: Activity },
    proxy_upstream:        { label: 'Upstream',      chip: 'bg-blue-500/10 text-blue-300 border-blue-500/30',          row: 'text-blue-300',                      icon: Activity },
    proxy_debug:           { label: 'Debug',         chip: 'bg-cyan-500/10 text-cyan-300 border-cyan-500/30',          row: 'text-cyan-300',                      icon: Activity },
    proxy_model_route:     { label: 'Model Route',   chip: 'bg-warning/10 text-warning border-warning/30',             row: 'text-warning',                       icon: Activity },
    proxy_context:         { label: 'Context',       chip: 'bg-indigo-500/10 text-indigo-300 border-indigo-500/30',     row: 'text-indigo-300',                    icon: Activity },
    proxy_tools:           { label: 'Tools',         chip: 'bg-pink-500/10 text-pink-300 border-pink-500/30',           row: 'text-pink-300',                      icon: Activity },
    proxy_system_prompt:   { label: 'Sys Prompt',    chip: 'bg-fuchsia-500/10 text-fuchsia-300 border-fuchsia-500/30', row: 'text-fuchsia-300',                   icon: Activity },
    auto_memory:           { label: 'Auto-Memory',   chip: 'bg-purple-500/10 text-purple-300 border-purple-500/30',     row: 'text-purple-300',                    icon: Activity },
    scheduler:             { label: 'Scheduler',     chip: 'bg-orange-500/10 text-orange-300 border-orange-500/30',     row: 'text-orange-300',                    icon: Activity },
    security:              { label: 'Security',      chip: 'bg-danger/10 text-danger border-danger/30',                 row: 'text-danger font-semibold',           icon: AlertTriangle },
    error:                 { label: 'Error',         chip: 'bg-danger/10 text-danger border-danger/30',                 row: 'text-danger font-semibold',           icon: AlertTriangle },
    info:                  { label: 'Info',          chip: 'bg-muted text-muted-foreground border-border',              row: 'text-foreground/80',                 icon: CircleDot },
};

const ALL_CATEGORIES: string[] = Object.keys(CATEGORY_META);

function metaFor(category: string) {
    return CATEGORY_META[category] || CATEGORY_META.info;
}

function redactForCopy(value: unknown): unknown {
    if (value == null) return value;
    if (typeof value === 'object') {
        if (Array.isArray(value)) return value.map(redactForCopy);
        const out: Record<string, unknown> = {};
        for (const [k, v] of Object.entries(value)) {
            if (/key|token|secret|password|authorization|cookie/i.test(k)) out[k] = '[REDACTED]';
            else out[k] = redactForCopy(v);
        }
        return out;
    }
    return value;
}

function statusBadge(status: StreamStatus, retryInMs: number | null) {
    if (status === 'live') return { cls: 'bg-success/15 text-success ring-success/30', label: 'Live', dot: 'bg-success' };
    if (status === 'paused') return { cls: 'bg-warning/15 text-warning ring-warning/30', label: 'Paused', dot: 'bg-warning' };
    if (status === 'connecting') return { cls: 'bg-white/[0.06] text-muted-foreground ring-white/10', label: 'Connecting…', dot: 'bg-zinc-400 animate-pulse' };
    return {
        cls: 'bg-rose-400/15 text-rose-300 ring-rose-400/30',
        label: retryInMs ? `Disconnected · retry in ${Math.round(retryInMs / 1000)}s` : 'Disconnected',
        dot: 'bg-rose-400 animate-pulse',
    };
}

function formatTime(ts: number): string {
    const d = new Date(ts);
    return d.toLocaleTimeString('en-GB', { hour12: false }) + '.' + String(d.getMilliseconds()).padStart(3, '0');
}

function exportEvents(events: LogEvent[]) {
    const blob = new Blob([JSON.stringify(events, redactForCopy, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `backend-monitor-${new Date().toISOString().replace(/[:.]/g, '-')}.json`;
    a.click();
    setTimeout(() => URL.revokeObjectURL(url), 1000);
}

export function BackendMonitorSection() {
    const { events, status, retryInMs, pause, resume, clear } = useLogStream();
    const { status: backend, isTauri } = useBackendStatus();
    const [enabled, setEnabled] = useState<Set<string>>(() => new Set(ALL_CATEGORIES));
    const [search, setSearch] = useState('');
    const [expanded, setExpanded] = useState<Set<string>>(new Set());
    const [autoScroll, setAutoScroll] = useState(true);

    const parentRef = useRef<HTMLDivElement | null>(null);

    const visible = useMemo(() => {
        const q = search.trim().toLowerCase();
        const KNOWN = CATEGORY_META;
        return events.filter((e) => {
            // Known categories honor the filter set; unknown ones are shown
            // by default (styled as `info`) so new emitter categories are
            // never silently hidden.
            if (e.category in KNOWN && !enabled.has(e.category)) return false;
            if (!q) return true;
            if (e.message.toLowerCase().includes(q)) return true;
            if (e.metadata) {
                try {
                    if (JSON.stringify(e.metadata).toLowerCase().includes(q)) return true;
                } catch { /* circular ref */ }
            }
            return false;
        });
    }, [events, enabled, search]);

    const stats = useMemo(() => {
        const errors = visible.filter((e) => e.level === 'error' || e.category === 'security').length;
        const autoMem = visible.filter((e) => e.category === 'auto_memory').length;
        const mdOf = (e: LogEvent) => (e.metadata || {}) as Record<string, unknown>;
        const tokensIn = visible.reduce((s, e) => s + Number(mdOf(e).tokensIn ?? mdOf(e).inputTokens ?? 0), 0);
        const tokensOut = visible.reduce((s, e) => s + Number(mdOf(e).tokensOut ?? mdOf(e).outputTokens ?? 0), 0);
        const schedTicks = visible.filter((e) => e.category === 'scheduler').length;
        const upstream = visible.filter((e) => e.category === 'proxy_upstream').length;
        const lastProvider = [...visible].reverse().find((e) => e.category === 'proxy_model_route');
        const provider = (lastProvider?.metadata as Record<string, unknown> | null)?.provider as string | undefined;
        return {
            total: visible.length,
            errors,
            autoMem,
            tokensIn,
            tokensOut,
            schedTicks,
            upstream,
            provider: provider || '—',
        };
    }, [visible]);

    const rowVirtualizer = useVirtualizer({
        count: visible.length,
        getScrollElement: () => parentRef.current,
        estimateSize: () => 28,
        overscan: 24,
    });

    useEffect(() => {
        if (autoScroll && parentRef.current) {
            parentRef.current.scrollTop = 0;
        }
    }, [visible.length, autoScroll]);

    const toggleCategory = (cat: string) => {
        setEnabled((prev) => {
            const next = new Set(prev);
            if (next.has(cat)) next.delete(cat); else next.add(cat);
            return next;
        });
    };

    const toggleExpanded = (id: string) => {
        setExpanded((prev) => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id); else next.add(id);
            return next;
        });
    };

    const badge = statusBadge(status, retryInMs);

    return (
        <div className="px-8 py-10 max-w-7xl space-y-6">
            <header className="flex items-start justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-semibold tracking-tight flex items-center gap-2">
                        <Radio className="size-5 text-primary" />
                        Backend Monitor
                    </h1>
                    <p className="mt-2 text-sm text-muted-foreground max-w-2xl">
                        Live stream of proxy calls, memory operations, scheduler ticks, and tool events emitted by the August backend.
                        Events arrive over WebSocket; the most recent 500 entries are backfilled on connect.
                    </p>
                </div>
                <span className={cn('inline-flex items-center gap-1.5 rounded-full px-3 py-1 text-xs font-medium ring-1 ring-inset', badge.cls)}>
                    <span className={cn('size-1.5 rounded-full', badge.dot)} />
                    {badge.label}
                </span>
                {isTauri && (
                  <span
                    className={
                      'inline-flex items-center gap-1.5 rounded-full px-3 py-1 text-xs font-medium ring-1 ring-inset ' +
                      (backend.proxy === 'up'
                        ? 'bg-success/15 text-success ring-success/30'
                        : backend.proxy === 'down'
                          ? 'bg-rose-400/15 text-rose-300 ring-rose-400/30'
                          : 'bg-white/[0.06] text-muted-foreground ring-white/10')
                    }
                  >
                    <span
                      className={
                        'size-1.5 rounded-full ' +
                        (backend.proxy === 'up'
                          ? 'bg-success'
                          : backend.proxy === 'down'
                            ? 'bg-rose-400 animate-pulse'
                            : 'bg-zinc-400')
                      }
                    />
                    {backend.proxy === 'up'
                      ? 'Backend: up'
                      : backend.proxy === 'down'
                        ? 'Backend: down'
                        : 'Backend: …'}
                  </span>
                )}
            </header>

            <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-3">
                <Stat label="Events" value={stats.total.toLocaleString()} />
                <Stat label="Errors" value={String(stats.errors)} accent={stats.errors > 0 ? 'text-rose-300' : undefined} />
                <Stat label="Auto-Memory" value={String(stats.autoMem)} />
                <Stat label="Tokens in/out" value={`${formatNum(stats.tokensIn)} / ${formatNum(stats.tokensOut)}`} />
                <Stat label="Scheduler ticks" value={String(stats.schedTicks)} />
                <Stat label="Upstream calls" value={String(stats.upstream)} sub={`Last: ${stats.provider}`} />
            </div>

            <SettingsCard
                icon={Filter}
                title="Live log feed"
                description="Filter by category, search, pause, export, or clear. Auto-scroll keeps the newest row pinned to the top."
                actions={
                    <div className="flex items-center gap-2">
                        <Button size="sm" variant="ghost" onClick={() => (status === 'paused' ? resume() : pause())}>
                            {status === 'paused' ? <Play className="size-3.5" /> : <Pause className="size-3.5" />}
                            {status === 'paused' ? 'Resume' : 'Pause'}
                        </Button>
                        <Button size="sm" variant="ghost" onClick={() => setAutoScroll((v) => !v)}>
                            {autoScroll ? 'Auto-scroll on' : 'Auto-scroll off'}
                        </Button>
                        <Button size="sm" variant="ghost" onClick={clear} disabled={visible.length === 0}>
                            <Trash2 className="size-3.5" /> Clear
                        </Button>
                        <Button size="sm" variant="outline" onClick={() => exportEvents(visible)} disabled={visible.length === 0}>
                            <Download className="size-3.5" /> Export
                        </Button>
                    </div>
                }
            >
                <div className="flex flex-wrap items-center gap-1.5 pb-3">
                    {ALL_CATEGORIES.map((cat) => {
                        const m = metaFor(cat);
                        const on = enabled.has(cat);
                        return (
                            <button
                                key={cat}
                                onClick={() => toggleCategory(cat)}
                                className={cn(
                                    'rounded-md border px-2 py-1 text-[10px] font-mono uppercase tracking-wider transition',
                                    on ? m.chip : 'bg-muted/40 text-muted-foreground/50 border-transparent hover:bg-muted',
                                )}
                            >
                                {m.label}
                            </button>
                        );
                    })}
                    <div className="relative ml-auto max-w-xs flex-1 min-w-[180px]">
                        <Search className="absolute left-2 top-1/2 -translate-y-1/2 size-3.5 text-muted-foreground" />
                        <input
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            placeholder="Search messages and JSON…"
                            aria-label="Search logs"
                            className="w-full pl-7 pr-2 py-1.5 text-xs bg-secondary rounded-md border border-transparent focus:border-border focus:bg-background outline-none transition"
                        />
                    </div>
                </div>

                <div
                    ref={parentRef}
                    className="relative max-h-[60vh] overflow-auto rounded-md border border-border/60 bg-zinc-950/50 font-mono text-[11px]"
                >
                    {visible.length === 0 ? (
                        <SettingsEmptyState
                            icon={Inbox}
                            title={events.length === 0 ? 'Waiting for events…' : 'No events match the current filters'}
                            description={events.length === 0 ? 'Trigger any proxy call, memory extraction, or wait for the next scheduler tick to see events stream in.' : 'Try clearing the search box or enabling more categories.'}
                            className="py-12"
                        />
                    ) : (
                        <div style={{ height: `${rowVirtualizer.getTotalSize()}px`, position: 'relative' }}>
                            {rowVirtualizer.getVirtualItems().map((virtualRow) => {
                                const event = visible[virtualRow.index];
                                const m = metaFor(event.category);
                                const isExpanded = expanded.has(event.id);
                                const Icon = m.icon;
                                return (
                                    <div
                                        key={event.id}
                                        data-index={virtualRow.index}
                                        ref={rowVirtualizer.measureElement}
                                        style={{
                                            position: 'absolute',
                                            top: 0,
                                            left: 0,
                                            right: 0,
                                            transform: `translateY(${virtualRow.start}px)`,
                                        }}
                                    >
                                        <button
                                            onClick={() => toggleExpanded(event.id)}
                                            className={cn(
                                                'group flex w-full items-start gap-2 px-2 py-1 text-left hover:bg-white/[0.04] transition border-b border-border/30',
                                                event.level === 'error' && 'bg-rose-500/[0.04]',
                                            )}
                                        >
                                            <span className="shrink-0 text-muted-foreground/70 w-28 tabular-nums">{formatTime(event.timestamp)}</span>
                                            <span className={cn('shrink-0 rounded border px-1.5 py-px text-[9px] uppercase tracking-wider w-20 text-center', m.chip)}>
                                                {m.label}
                                            </span>
                                            <Icon className={cn('size-3 shrink-0 mt-0.5', m.row)} />
                                            <span className={cn('flex-1 whitespace-pre-wrap break-all', m.row)}>{event.message}</span>
                                        </button>
                                        {isExpanded && (
                                            <div className="border-b border-border/30 bg-black/30 px-3 py-2 text-[10px] text-muted-foreground space-y-1">
                                                <div className="grid grid-cols-[80px_1fr] gap-2">
                                                    <span className="text-muted-foreground/70 uppercase tracking-wider">ID</span>
                                                    <span className="text-foreground/80 break-all">{event.id}</span>
                                                </div>
                                                <div className="grid grid-cols-[80px_1fr] gap-2">
                                                    <span className="text-muted-foreground/70 uppercase tracking-wider">Time</span>
                                                    <span className="text-foreground/80">{new Date(event.timestamp).toISOString()}</span>
                                                </div>
                                                {event.metadata && (
                                                    <div className="grid grid-cols-[80px_1fr] gap-2">
                                                        <span className="text-muted-foreground/70 uppercase tracking-wider">Metadata</span>
                                                        <pre className="text-foreground/80 whitespace-pre-wrap break-all">{JSON.stringify(event.metadata, null, 2)}</pre>
                                                    </div>
                                                )}
                                                {event.raw && (
                                                    <div className="grid grid-cols-[80px_1fr] gap-2">
                                                        <span className="text-muted-foreground/70 uppercase tracking-wider">Raw</span>
                                                        <pre className="text-foreground/80 whitespace-pre-wrap break-all">{event.raw}</pre>
                                                    </div>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>

                <p className="pt-2 text-[9px] text-muted-foreground font-mono">
                    Secret-shaped fields (keys, tokens, cookies) are redacted on export. Up to 10,000 events are retained; the ring is FIFO.
                </p>
            </SettingsCard>
        </div>
    );
}

function Stat({ label, value, sub, accent }: { label: string; value: string; sub?: string; accent?: string }) {
    return (
        <div className="rounded-lg border border-border/60 bg-card/60 px-3 py-2.5">
            <div className="text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">{label}</div>
            <div className={cn('mt-0.5 text-base font-semibold tabular-nums', accent || 'text-foreground')}>{value}</div>
            {sub && <div className="text-[9px] text-muted-foreground/60 truncate">{sub}</div>}
        </div>
    );
}

function formatNum(n: number): string {
    if (!n) return '0';
    if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
    if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
    return String(n);
}

export default BackendMonitorSection;

/* ── Computer Access — Filesystem scope + Computer-use app allowlist ── */
/* Task 8: surfaces the runtime security configuration that Task 1's
 * permission-profiles and Task 6's app-allowlist write to.
 *
 * Persists via:
 *   - /ui/august/settings/update     (security.allowedRoots, security.filesystemScope)
 *   - august__app_policy tool        (per-app allow/ask/deny)
 *
 * Locked decision 1: default scope is 'allowlist'. Setting scope to 'root'
 * widens host filesystem access — explicitly opt-in.
 */

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { ShieldCheck, FolderTree, Cpu, Camera, Eye } from 'lucide-react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import {
  getAugustSnapshot,
  setAugustAppPolicy,
  listAugustAppPolicies,
  deleteAugustAppPolicy,
  putSecurity,
  getHostAgentHealth,
  type AugustSnapshot,
} from '@/api/api-client';
import { SettingsToggle } from '@/components/settings/SettingsToggle';

interface ComputerRoots {
  allowedRoots: string[];
  filesystemScope: 'allowlist' | 'root';
  postObservationScreenshot?: boolean;
}

interface AppPolicyMap {
  [app: string]: 'allow' | 'ask' | 'deny';
}

async function fetchComputerRoots(): Promise<ComputerRoots> {
  const snap = await getAugustSnapshot();
  const sec = snap.config?.security;
  return sec || { allowedRoots: [], filesystemScope: 'allowlist', postObservationScreenshot: true };
}

async function saveComputerRoots(next: Partial<ComputerRoots>): Promise<ComputerRoots> {
  // Persist via /ui/august/settings/update which writes security.* sub-keys.
  if (next.filesystemScope) {
    await setAugustSetting({ keyPath: 'security.filesystemScope', value: next.filesystemScope });
  }
  if (next.allowedRoots) {
    await setAugustSetting({ keyPath: 'security.allowedRoots', value: next.allowedRoots });
  }
  if (typeof next.postObservationScreenshot === 'boolean') {
    await setAugustSetting({ keyPath: 'security.postObservationScreenshot', value: next.postObservationScreenshot });
  }
  return fetchComputerRoots();
}

async function setAugustSetting(payload: { keyPath: string; value: unknown }): Promise<unknown> {
  const { updateAugustSetting } = await import('@/api/api-client');
  return updateAugustSetting(payload);
}

async function fetchAppPolicies(): Promise<AppPolicyMap> {
  const res = await listAugustAppPolicies();
  return res.policies || {};
}

export function ComputerAccessSettings() {
  const qc = useQueryClient();
  const rootsQuery = useQuery({ queryKey: ['computer-roots'], queryFn: fetchComputerRoots });
  const appsQuery = useQuery({ queryKey: ['computer-apps'], queryFn: fetchAppPolicies });

  const [newRoot, setNewRoot] = useState('');
  const [newApp, setNewApp] = useState('');
  const [newAppPolicy, setNewAppPolicy] = useState<'allow' | 'ask' | 'deny'>('ask');

  const saveMutation = useMutation({
    mutationFn: (next: Partial<ComputerRoots>) => saveComputerRoots(next),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['computer-roots'] }),
  });
  const setPolicyMutation = useMutation({
    mutationFn: ({ app, policy }: { app: string; policy: 'allow' | 'ask' | 'deny' }) =>
      setAugustAppPolicy({ app, policy }),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['computer-apps'] }),
  });
  const deletePolicyMutation = useMutation({
    mutationFn: (app: string) => deleteAugustAppPolicy(app),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['computer-apps'] }),
  });

  const roots = rootsQuery.data?.allowedRoots ?? [];
  const scope = rootsQuery.data?.filesystemScope ?? 'allowlist';
  const postObs = rootsQuery.data?.postObservationScreenshot !== false;
  const apps = appsQuery.data ?? {} as AppPolicyMap;

  const healthQuery = useQuery({ queryKey: ['host-agent', 'health'], queryFn: getHostAgentHealth, refetchInterval: 30_000 });
  const observationCount = healthQuery.data?.postObservationCount ?? 0;
  const lastObsAt = healthQuery.data?.lastObservationAt;

  const toggleMutation = useMutation({
    mutationFn: (next: boolean) => putSecurity({ postObservationScreenshot: next }),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['computer-roots'] }),
  });

  function addRoot() {
    if (!newRoot.trim()) return;
    const next = Array.from(new Set([...roots, newRoot.trim()]));
    saveMutation.mutate({ allowedRoots: next });
    setNewRoot('');
  }

  function removeRoot(root: string) {
    saveMutation.mutate({ allowedRoots: roots.filter(r => r !== root) });
  }

  function addApp() {
    const trimmed = newApp.trim();
    if (!trimmed) return;
    setPolicyMutation.mutate({ app: trimmed, policy: newAppPolicy });
    setNewApp('');
  }

  function changeAppPolicy(app: string, policy: 'allow' | 'ask' | 'deny') {
    setPolicyMutation.mutate({ app, policy });
  }

  function removeApp(app: string) {
    deletePolicyMutation.mutate(app);
  }

  return (
    <div className="px-8 py-12 max-w-3xl space-y-10">
      <header>
        <h1 className="text-2xl font-semibold tracking-tight">Computer Access</h1>
        <p className="mt-2 text-sm text-muted-foreground">
          Controls which directories August may read, write, or modify, and which
          desktop applications August may control through the host computer agent.
        </p>
      </header>

      {/* Computer Security — post-observation screenshots (Task 9) */}
      <section className="space-y-4">
        <div className="flex items-center gap-2">
          <Camera className="size-4 text-foreground/70" />
          <h2 className="text-base font-medium">Computer security</h2>
        </div>
        <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4 space-y-4">
          <div className="flex items-start justify-between gap-4">
            <div className="min-w-0">
              <div className="text-sm font-medium">Capture post-observation screenshots</div>
              <p className="mt-1 text-xs text-muted-foreground">
                After every mutating computer_* action, August saves a screenshot
                to <code className="font-mono">data/computer-observations/</code> and
                links it to the audit entry. Disable to reduce disk usage.
              </p>
            </div>
            <SettingsToggle
              checked={postObs}
              onCheckedChange={(v) => toggleMutation.mutate(v)}
              label={postObs ? 'enabled' : 'disabled'}
            />
          </div>
          <div className="flex items-center justify-between border-t border-white/[0.06] pt-3">
            <div className="text-xs text-muted-foreground">
              {observationCount === 0
                ? 'No observations captured yet.'
                : `${observationCount} observation${observationCount === 1 ? '' : 's'}`}
              {lastObsAt && ` · last ${new Date(lastObsAt).toLocaleString()}`}
            </div>
            <Link
              to="/settings/observability"
              className="inline-flex items-center gap-1.5 text-xs text-primary hover:underline"
            >
              <Eye className="size-3.5" /> View observation gallery →
            </Link>
          </div>
        </div>
      </section>

      {/* Filesystem scope */}
      <section className="space-y-4">
        <div className="flex items-center gap-2">
          <ShieldCheck className="size-4 text-foreground/70" />
          <h2 className="text-base font-medium">Filesystem scope</h2>
        </div>
        <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4 space-y-3">
          <label className="flex items-center gap-3">
            <input
              type="radio"
              name="scope"
              value="allowlist"
              checked={scope === 'allowlist'}
              onChange={() => saveMutation.mutate({ filesystemScope: 'allowlist' })}
            />
            <div>
              <div className="font-medium">Allowlist (recommended)</div>
              <div className="text-xs text-muted-foreground">
                August may only read/write files inside the project working directory,
                August data dir, tmp, and the roots listed below.
              </div>
            </div>
          </label>
          <label className="flex items-center gap-3">
            <input
              type="radio"
              name="scope"
              value="root"
              checked={scope === 'root'}
              onChange={() => saveMutation.mutate({ filesystemScope: 'root' })}
            />
            <div>
              <div className="font-medium text-warning">Full machine (root)</div>
              <div className="text-xs text-muted-foreground">
                August may read/write any path on the host. Critical actions still
                require explicit confirmation. Use with care.
              </div>
            </div>
          </label>
        </div>
      </section>

      {/* Allowed roots */}
      <section className="space-y-4">
        <div className="flex items-center gap-2">
          <FolderTree className="size-4 text-foreground/70" />
          <h2 className="text-base font-medium">Allowed filesystem roots</h2>
        </div>
        <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4 space-y-3">
          <ul className="space-y-1">
            {roots.length === 0 && (
              <li className="text-xs text-muted-foreground italic">
                No custom roots configured. Project cwd, August data dir, and tmp are always allowed.
              </li>
            )}
            {roots.map(r => (
              <li key={r} className="flex items-center justify-between text-sm">
                <code className="text-foreground/80">{r}</code>
                <button
                  className="text-xs text-muted-foreground hover:text-foreground"
                  onClick={() => removeRoot(r)}
                >
                  remove
                </button>
              </li>
            ))}
          </ul>
          <div className="flex items-center gap-2">
            <input
              type="text"
              value={newRoot}
              onChange={e => setNewRoot(e.target.value)}
              placeholder="C:\Users\me\Projects"
              className="flex-1 rounded-md border border-white/[0.08] bg-background/40 px-3 py-1.5 text-sm"
            />
            <button
              className="rounded-md bg-foreground/10 px-3 py-1.5 text-sm hover:bg-foreground/15"
              onClick={addRoot}
            >
              Add root
            </button>
          </div>
        </div>
      </section>

      {/* Computer-use app allowlist */}
      <section className="space-y-4">
        <div className="flex items-center gap-2">
          <Cpu className="size-4 text-foreground/70" />
          <h2 className="text-base font-medium">Computer-use app policy</h2>
        </div>
        <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4 space-y-3">
          <p className="text-xs text-muted-foreground">
            Per-app policy enforced at Workbench dispatch. Unknown apps default to
            <span className="font-medium"> ask</span>.
          </p>
          {Object.keys(apps).length === 0 && (
            <p className="text-xs text-muted-foreground italic">No app-specific policies yet.</p>
          )}
          <ul className="space-y-1">
            {Object.entries(apps).map(([app, policy]) => (
              <li key={app} className="flex items-center justify-between text-sm">
                <code className="text-foreground/80">{app}</code>
                <div className="flex items-center gap-2">
                  <select
                    value={policy}
                    onChange={(e) => changeAppPolicy(app, e.target.value as 'allow' | 'ask' | 'deny')}
                    className="rounded-md border border-white/[0.08] bg-background/40 px-2 py-0.5 text-xs"
                  >
                    <option value="allow">allow</option>
                    <option value="ask">ask</option>
                    <option value="deny">deny</option>
                  </select>
                  <button
                    className="text-xs text-muted-foreground hover:text-foreground"
                    onClick={() => removeApp(app)}
                  >
                    remove
                  </button>
                </div>
              </li>
            ))}
          </ul>
          <div className="flex items-center gap-2">
            <input
              type="text"
              value={newApp}
              onChange={e => setNewApp(e.target.value)}
              placeholder="notepad.exe"
              className="flex-1 rounded-md border border-white/[0.08] bg-background/40 px-3 py-1.5 text-sm"
            />
            <select
              value={newAppPolicy}
              onChange={e => setNewAppPolicy(e.target.value as 'allow' | 'ask' | 'deny')}
              className="rounded-md border border-white/[0.08] bg-background/40 px-2 py-1.5 text-sm"
            >
              <option value="allow">allow</option>
              <option value="ask">ask</option>
              <option value="deny">deny</option>
            </select>
            <button
              className="rounded-md bg-foreground/10 px-3 py-1.5 text-sm hover:bg-foreground/15"
              onClick={addApp}
            >
              Add app
            </button>
          </div>
        </div>
      </section>
    </div>
  );
}

export default ComputerAccessSettings;

/* ── Computer Use — Desktop automation settings ────────────────────── */
/* Manages computer use backend, health diagnostics, and approval workflows. */

import { useState, useEffect, useCallback } from 'react';
import {
  Monitor,
  RefreshCw,
  CheckCircle,
  AlertCircle,
  Info,
  Shield,
  MousePointer,
  Keyboard,
} from 'lucide-react';
import { Badge } from '@/components/ui/badge';

interface HealthCheck {
  name: string;
  status: 'ok' | 'warning' | 'error';
  message: string;
  details: Record<string, any>;
}

interface HealthReport {
  platform: string;
  overall: 'ok' | 'warning' | 'error';
  checks: HealthCheck[];
  timestamp: string;
}

interface ComputerUseConfig {
  enabled: boolean;
  backend: string;
  autoApprove: string[];
  blocklistKeys: string[];
  blocklistPatterns: string[];
}

export function ComputerUseSection() {
  const [health, setHealth] = useState<HealthReport | null>(null);
  const [config, setConfig] = useState<ComputerUseConfig | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchHealth = useCallback(async () => {
    try {
      const res = await fetch('/api/desktop-automation/health');
      if (!res.ok) throw new Error('Failed to fetch health status');
      const data = await res.json();
      setHealth(data);
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Unknown error');
    }
  }, []);

  const fetchConfig = useCallback(async () => {
    try {
      const res = await fetch('/api/desktop-automation/config');
      if (!res.ok) throw new Error('Failed to fetch config');
      const data = await res.json();
      setConfig(data);
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Unknown error');
    }
  }, []);

  useEffect(() => {
    Promise.all([fetchHealth(), fetchConfig()]).finally(() => setLoading(false));
  }, [fetchHealth, fetchConfig]);

  const handleRefresh = async () => {
    setLoading(true);
    await Promise.all([fetchHealth(), fetchConfig()]);
    setLoading(false);
  };

  if (loading) {
    return (
      <div className="flex h-full items-center justify-center">
        <RefreshCw className="size-6 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="px-8 py-6 space-y-6 h-full flex flex-col overflow-auto">
      <header className="shrink-0">
        <h1 className="text-2xl font-semibold tracking-tight text-foreground">
          Computer Use
        </h1>
        <p className="mt-1 text-sm text-muted-foreground">
          Desktop automation with SOM overlay, cross-platform support, and safe approval workflows.
        </p>
      </header>

      {error && (
        <div className="rounded-lg border border-destructive/50 bg-destructive/10 p-3 text-sm text-destructive">
          {error}
        </div>
      )}

      {/* Status Overview */}
      <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
        <StatusCard
          icon={<Monitor className="size-4" />}
          label="Status"
          value={config?.enabled ? 'Enabled' : 'Disabled'}
          tone={config?.enabled ? 'good' : 'muted'}
        />
        <StatusCard
          icon={<Shield className="size-4" />}
          label="Health"
          value={health?.overall || 'Unknown'}
          tone={health?.overall === 'ok' ? 'good' : health?.overall === 'warning' ? 'warn' : 'muted'}
        />
        <StatusCard
          icon={<MousePointer className="size-4" />}
          label="Backend"
          value={config?.backend || 'cua'}
          tone="muted"
        />
        <StatusCard
          icon={<Keyboard className="size-4" />}
          label="Platform"
          value={health?.platform || 'Unknown'}
          tone="muted"
        />
      </div>

      {/* Health Checks */}
      <div className="rounded-xl border border-white/[0.06] bg-card/60 p-5 space-y-4">
        <div className="flex items-center justify-between">
          <h3 className="text-sm font-semibold">Health Checks</h3>
          <button
            onClick={handleRefresh}
            className="text-sm text-muted-foreground hover:text-foreground"
          >
            <RefreshCw className="size-4" />
          </button>
        </div>
        <div className="space-y-3">
          {health?.checks.map((check, i) => (
            <div
              key={i}
              className="flex items-start gap-3 rounded-lg border border-white/[0.06] bg-card/40 p-3"
            >
              {check.status === 'ok' ? (
                <CheckCircle className="size-4 text-success mt-0.5 shrink-0" />
              ) : check.status === 'warning' ? (
                <AlertCircle className="size-4 text-warning mt-0.5 shrink-0" />
              ) : (
                <AlertCircle className="size-4 text-destructive mt-0.5 shrink-0" />
              )}
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium">{check.name}</p>
                <p className="text-xs text-muted-foreground mt-0.5">{check.message}</p>
                {check.details.solution && (
                  <p className="text-xs text-muted-foreground mt-1 italic">
                    Solution: {check.details.solution}
                  </p>
                )}
              </div>
              <Badge
                variant="outline"
                className={
                  check.status === 'ok'
                    ? 'bg-success/20 text-success'
                    : check.status === 'warning'
                    ? 'bg-warning/20 text-warning'
                    : 'bg-destructive/20 text-destructive'
                }
              >
                {check.status}
              </Badge>
            </div>
          ))}
          {(!health?.checks || health.checks.length === 0) && (
            <p className="text-sm text-muted-foreground text-center py-4">
              No health checks available
            </p>
          )}
        </div>
      </div>

      {/* Configuration */}
      <div className="rounded-xl border border-white/[0.06] bg-card/60 p-5 space-y-4">
        <h3 className="text-sm font-semibold">Configuration</h3>
        <div className="grid gap-4 sm:grid-cols-2">
          <div>
            <p className="text-xs text-muted-foreground mb-1">Auto-approve actions</p>
            <div className="flex flex-wrap gap-1">
              {config?.autoApprove.map((action) => (
                <Badge key={action} variant="outline" className="text-xs">
                  {action}
                </Badge>
              ))}
              {(!config?.autoApprove || config.autoApprove.length === 0) && (
                <span className="text-xs text-muted-foreground">None</span>
              )}
            </div>
          </div>
          <div>
            <p className="text-xs text-muted-foreground mb-1">Blocked key combos</p>
            <div className="flex flex-wrap gap-1">
              {config?.blocklistKeys.map((key) => (
                <Badge key={key} variant="outline" className="text-xs bg-destructive/10">
                  {key}
                </Badge>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Info */}
      <div className="rounded-lg border border-white/[0.06] bg-card/40 p-4 text-sm text-muted-foreground">
        <div className="flex items-start gap-2">
          <Info className="size-4 mt-0.5 shrink-0" />
          <div>
            <p className="font-medium text-foreground mb-1">How it works</p>
            <ul className="space-y-1 list-disc list-inside">
              <li>Computer use captures your screen and identifies interactable elements</li>
              <li>SOM (Set of Mark) overlay numbers each element for reliable clicking</li>
              <li>Safe actions (capture) are auto-approved; dangerous actions require confirmation</li>
              <li>Works on macOS, Windows, and Linux with platform-specific optimizations</li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ── Sub-components ─────────────────────────────────────────────────── */

function StatusCard({
  icon,
  label,
  value,
  tone,
}: {
  icon: React.ReactNode;
  label: string;
  value: string;
  tone: 'good' | 'warn' | 'muted';
}) {
  return (
    <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4">
      <div className="flex items-center gap-2 mb-2">
        <span className="text-muted-foreground">{icon}</span>
        <span className="text-sm font-medium text-muted-foreground">{label}</span>
      </div>
      <p className="text-lg font-semibold">{value}</p>
    </div>
  );
}

/* ── API Access settings page ───────────────────────────────────────── */
/* Lets the user open (or close) the proxy gateway for external clients
 * (Claude Code, OpenAI SDKs, Cursor, codex CLI, custom scripts, etc.)
 *
 * Behaviour:
 * - Toggle ON + key configured → /v1/* requires Authorization: Bearer <key>
 * - Toggle OFF                → /v1/* returns 403 (closed)
 * - Toggle ON but no key      → 400 from the server, banner shown below
 *
 * The GATEWAY_API_KEY itself lives in the user's .env file and is never
 * written from the UI — only its masked preview is displayed here.
 */
import { useState } from 'react';
import {
  Link2,
  KeyRound,
  Radio,
  Plug,
  Copy,
  Check,
  AlertTriangle,
  Code2,
  Sparkles,
} from 'lucide-react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import {
  getExternalAccessConfig,
  updateExternalAccessConfig,
  type ExternalAccessConfig,
} from '@/api/api-client';
import { SettingsToggle } from '@/components/settings/SettingsToggle';
import { Badge } from '@/components/ui/badge';
import { PageLoader } from '@/components/PageLoader';

/* ── Small reusable bits ─────────────────────────────────────────────── */

function useExtAccessQuery() {
  return useQuery({
    queryKey: ['external-access'],
    queryFn: getExternalAccessConfig,
    refetchInterval: 5000,
  });
}

function CopyButton({ value, label = 'copy' }: { value: string; label?: string }) {
  const [copied, setCopied] = useState(false);
  function copy() {
    navigator.clipboard?.writeText(value);
    setCopied(true);
    setTimeout(() => setCopied(false), 1200);
  }
  return (
    <button
      onClick={copy}
      className="inline-flex items-center gap-1 rounded-md border border-white/[0.08] bg-background px-2 py-1 text-[10px] font-mono hover:bg-accent transition shrink-0"
      title="Copy"
    >
      {copied ? <Check className="size-3 text-success" /> : <Copy className="size-3" />}
      {copied ? 'copied' : label}
    </button>
  );
}

function CodeBlock({ code, language = 'bash' }: { code: string; language?: string }) {
  return (
    <div className="rounded-md border border-white/[0.06] bg-black/40 overflow-hidden">
      <div className="flex items-center justify-between gap-2 px-3 py-1.5 border-b border-white/[0.06] bg-white/[0.02]">
        <span className="text-[10px] uppercase tracking-wider text-muted-foreground font-mono">
          {language}
        </span>
        <CopyButton value={code} />
      </div>
      <pre className="overflow-x-auto p-3 text-[11px] font-mono text-foreground/90 leading-relaxed">
        <code>{code}</code>
      </pre>
    </div>
  );
}

function StatusDot({ tone }: { tone: 'success' | 'warning' | 'muted' }) {
  const bg =
    tone === 'success' ? 'bg-success' : tone === 'warning' ? 'bg-warning' : 'bg-muted-foreground/40';
  return <span className={`inline-block size-2 rounded-full ${bg}`} aria-hidden="true" />;
}

/* ── Main export ─────────────────────────────────────────────────────── */

export function ExternalAccessSection() {
  const qc = useQueryClient();
  const query = useExtAccessQuery();
  const mutation = useMutation({
    mutationFn: (next: boolean) => updateExternalAccessConfig({ enabled: next }),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['external-access'] });
      qc.invalidateQueries({ queryKey: ['health', 'detailed'] });
    },
  });

  if (query.isLoading || !query.data) {
    return <PageLoader label="Loading API access…" />;
  }
  const cfg: ExternalAccessConfig = query.data;

  const enabled = cfg.enabled;
  const hasKey = cfg.hasKey;
  const healthy = enabled && hasKey;

  const baseUrl = cfg.endpoints.openai.replace(/\/v1\/.*$/, '');
  const keyForDisplay = cfg.keyPreview ?? 'AUG••••••••••••';
  const bearerLine = `Authorization: Bearer ${keyForDisplay}`;

  const curlExample =
    `curl -X POST ${cfg.endpoints.openai} \\
  -H "${bearerLine}" \\
  -H "Content-Type: application/json" \\
  -d '{"model":"gpt-4o","messages":[{"role":"user","content":"Hello"}]}'`;

  const pythonExample =
    `from openai import OpenAI\n\n` +
    `client = OpenAI(\n` +
    `    base_url="${baseUrl}/v1",\n` +
    `    api_key="${keyForDisplay}",\n` +
    `)\n\n` +
    `resp = client.chat.completions.create(\n` +
    `    model="gpt-4o",\n` +
    `    messages=[{"role": "user", "content": "Hello"}],\n` +
    `)`;

  const jsExample =
    `import OpenAI from 'openai';\n\n` +
    `const client = new OpenAI({\n` +
    `    baseURL: "${baseUrl}/v1",\n` +
    `    apiKey: "${keyForDisplay}",\n` +
    `});\n\n` +
    `const resp = await client.chat.completions.create({\n` +
    `    model: "gpt-4o",\n` +
    `    messages: [{ role: "user", content: "Hello" }],\n` +
    `});`;

  const anthropicExample =
    `curl -X POST ${cfg.endpoints.anthropic} \\
  -H "${bearerLine}" \\
  -H "anthropic-version: 2023-06-01" \\
  -H "Content-Type: application/json" \\
  -d '{"model":"claude-sonnet-4-5","max_tokens":256,"messages":[{"role":"user","content":"Hello"}]}'`;

  return (
    <div className="px-8 py-12 max-w-3xl space-y-10">
      <header>
        <h1 className="text-2xl font-semibold tracking-tight">API Access</h1>
        <p className="mt-2 text-sm text-muted-foreground">
          Open or close the proxy gateway for external clients. When open, apps
          like Claude Code, Cursor, OpenAI SDKs, and the{' '}
          <code className="font-mono">codex</code> CLI can route requests
          through August. When closed,{' '}
          <code className="font-mono">/v1/*</code> returns 403.
        </p>
      </header>

      {/* ── Toggle ────────────────────────────────────────────────────── */}
      <section className="space-y-4">
        <div className="flex items-center gap-2">
          <Plug className="size-4 text-foreground/70" />
          <h2 className="text-base font-medium">External API Access</h2>
        </div>
        <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4 space-y-3">
          <SettingsToggle
            checked={enabled}
            onCheckedChange={(next) => mutation.mutate(next)}
            label={enabled ? 'Enabled' : 'Disabled'}
            description={
              enabled
                ? 'External clients can hit /v1/* when they send the correct Bearer key.'
                : 'External clients are rejected with 403 on /v1/*.'
            }
            disabled={mutation.isPending}
          />
          {mutation.isError && (
            <p className="flex items-start gap-2 rounded-md border border-destructive/40 bg-destructive/10 px-3 py-2 text-xs text-destructive">
              <AlertTriangle className="size-3.5 mt-0.5 shrink-0" />
              <span>
                Could not update: {(mutation.error as Error)?.message ?? 'unknown error'}
              </span>
            </p>
          )}
        </div>
      </section>

      {/* ── API Key ───────────────────────────────────────────────────── */}
      <section className="space-y-4">
        <div className="flex items-center gap-2">
          <KeyRound className="size-4 text-foreground/70" />
          <h2 className="text-base font-medium">Gateway API Key</h2>
        </div>
        <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4 space-y-3">
          {hasKey ? (
            <div className="flex items-center justify-between gap-3 rounded-md border border-white/[0.06] bg-white/[0.02] px-3 py-2">
              <code className="text-sm font-mono">{cfg.keyPreview}</code>
              <CopyButton value={cfg.keyPreview ?? ''} label="copy" />
            </div>
          ) : (
            <div className="flex items-start gap-2 rounded-md border border-warning/40 bg-warning/10 px-3 py-2 text-xs text-warning">
              <AlertTriangle className="size-3.5 mt-0.5 shrink-0" />
              <div>
                No API key configured. Add{' '}
                <code className="font-mono">GATEWAY_API_KEY=&lt;your-key&gt;</code>{' '}
                to your <code className="font-mono">.env</code> file and restart
                the proxy. Without a key, external access cannot be enabled.
              </div>
            </div>
          )}
          <p className="text-xs text-muted-foreground">
            Set <code className="font-mono">GATEWAY_API_KEY</code> in{' '}
            <code className="font-mono">.env</code> at the project root (or
            export it as an environment variable). The key is loaded at
            startup and never displayed in full here.
          </p>
        </div>
      </section>

      {/* ── Connection status ─────────────────────────────────────────── */}
      <section className="space-y-4">
        <div className="flex items-center gap-2">
          <Radio className="size-4 text-foreground/70" />
          <h2 className="text-base font-medium">Connection Status</h2>
        </div>
        <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4 space-y-2">
          <div className="flex items-center justify-between">
            <span className="text-sm text-muted-foreground">Proxy gateway</span>
            <Badge variant="success">OPEN</Badge>
          </div>
          <div className="flex items-center justify-between">
            <span className="text-sm text-muted-foreground">External access</span>
            {enabled ? (
              <Badge variant={hasKey ? 'success' : 'warning'}>
                <StatusDot tone={hasKey ? 'success' : 'warning'} />
                {hasKey ? 'OPEN' : 'ENABLED (no key)'}
              </Badge>
            ) : (
              <Badge variant="secondary">
                <StatusDot tone="muted" />
                CLOSED
              </Badge>
            )}
          </div>
          <div className="flex items-center justify-between">
            <span className="text-sm text-muted-foreground">API key configured</span>
            {hasKey ? (
              <Badge variant="success">YES</Badge>
            ) : (
              <Badge variant="warning">NO</Badge>
            )}
          </div>
          {!healthy && (
            <p className="mt-2 text-[11px] text-muted-foreground">
              Requests on <code className="font-mono">/v1/*</code> will be
              rejected{!hasKey && enabled ? ' with 503 (no key configured)' : enabled ? ' with 401' : ' with 403'}.
            </p>
          )}
        </div>
      </section>

      {/* ── Endpoints ─────────────────────────────────────────────────── */}
      <section className="space-y-4">
        <div className="flex items-center gap-2">
          <Link2 className="size-4 text-foreground/70" />
          <h2 className="text-base font-medium">Proxy Endpoints</h2>
        </div>
        <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4 space-y-3">
          <EndpointRow
            url={cfg.endpoints.anthropic}
            label="Anthropic Messages"
            hint="ANTHROPIC_BASE_URL — Claude Code, Anthropic SDKs."
          />
          <EndpointRow
            url={cfg.endpoints.openai}
            label="OpenAI Chat Completions"
            hint="OPENAI_API_BASE — OpenAI SDKs, Cursor, codex CLI."
          />
          <EndpointRow
            url={cfg.endpoints.models}
            label="Model List"
            hint="GET /v1/models — list models across providers."
          />
        </div>
      </section>

      {/* ── Usage examples ────────────────────────────────────────────── */}
      <section className="space-y-4">
        <div className="flex items-center gap-2">
          <Code2 className="size-4 text-foreground/70" />
          <h2 className="text-base font-medium">Usage Examples</h2>
        </div>
        <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4 space-y-4">
          <div className="space-y-1.5">
            <div className="flex items-center gap-1.5">
              <Sparkles className="size-3 text-muted-foreground" />
              <span className="text-xs font-medium">OpenAI (Chat Completions)</span>
            </div>
            <CodeBlock code={curlExample} language="bash" />
            <CodeBlock code={pythonExample} language="python" />
            <CodeBlock code={jsExample} language="javascript" />
          </div>
          <div className="space-y-1.5 pt-2 border-t border-white/[0.06]">
            <div className="flex items-center gap-1.5">
              <Sparkles className="size-3 text-muted-foreground" />
              <span className="text-xs font-medium">Anthropic (Messages)</span>
            </div>
            <CodeBlock code={anthropicExample} language="bash" />
          </div>
        </div>
      </section>

      <p className="text-[10px] text-muted-foreground/80 font-mono">
        🔒 The proxy server binds to your local network. Anyone able to reach
        the port can attempt authentication — keep{' '}
        <code>GATEWAY_API_KEY</code> private.
      </p>
    </div>
  );
}

/* ── A re-usable "endpoint URL row" ──────────────────────────────────── */

function EndpointRow({ url, label, hint }: { url: string; label: string; hint: string }) {
  return (
    <div className="rounded-md border border-white/[0.06] bg-white/[0.02] px-3 py-2.5">
      <div className="flex items-center justify-between gap-3">
        <span className="text-sm font-medium">{label}</span>
        <CopyButton value={url} />
      </div>
      <code className="block mt-1.5 text-[11px] font-mono text-foreground break-all">{url}</code>
      <p className="text-[10px] text-muted-foreground mt-1">{hint}</p>
    </div>
  );
}

export default ExternalAccessSection;

/* ── LogsSubtab — merged activity + request log feed ───────────────── */
/* Extracted from the old Traffic & Activity section. Renders the period +
 * level filter chips and a chronological log feed. No token or summary
 * stats — those live in ObservabilityOverview.
 */

import { useState } from 'react';
import { Copy, Check, ScrollText, Search, Inbox } from 'lucide-react';
import { SettingsCard } from '@/components/settings/SettingsCard';
import { SettingsEmptyState } from '@/components/settings/SettingsEmptyState';
import { StatusPill } from '@/components/StatusPill';
import { Badge } from '@/components/ui/badge';
import { formatTimeAgo, cn } from '@/lib/utils';
import { useTrafficActivity, type Period, type LogLine } from './useTrafficActivity';

const PERIODS: { key: Period; label: string }[] = [
    { key: 'today', label: 'Today' },
    { key: 'yesterday', label: 'Yesterday' },
    { key: 'week', label: '7d' },
    { key: 'month', label: '30d' },
    { key: 'all', label: 'All' },
];

const LEVEL_FILTERS: { key: 'all' | 'info' | 'warn' | 'error'; label: string }[] = [
    { key: 'all',   label: 'All' },
    { key: 'info',  label: 'Info' },
    { key: 'warn',  label: 'Warn' },
    { key: 'error', label: 'Error' },
];

function FilterChips<T extends string>({ items, value, onChange, label }: { items: { key: T; label: string }[]; value: T; onChange: (v: T) => void; label: string }) {
    return (
        <div className="flex items-center gap-1 text-[10px]">
            <span className="flex items-center gap-1 px-1 text-muted-foreground/70 uppercase tracking-wider">
                {label}
            </span>
            {items.map((p) => (
                <button
                    key={p.key}
                    onClick={() => onChange(p.key)}
                    className={cn(
                        'rounded-md px-2 py-1 font-mono transition',
                        value === p.key
                            ? 'bg-primary text-primary-foreground'
                            : 'text-muted-foreground hover:bg-accent',
                    )}
                >
                    {p.label}
                </button>
            ))}
        </div>
    );
}

export function LogsSubtab() {
    const [period, setPeriod] = useState<Period>('today');
    const [level, setLevel] = useState<'all' | 'info' | 'warn' | 'error'>('all');
    const [filter, setFilter] = useState('');
    const [copied, setCopied] = useState<string | null>(null);

    const data = useTrafficActivity(period);
    const lines = data.lines;

    const visible = lines.filter((l) => {
        if (level !== 'all' && l.level !== level) return false;
        if (filter && !l.message.toLowerCase().includes(filter.toLowerCase())) return false;
        return true;
    });

    const counts = {
        error: lines.filter((l) => l.level === 'error').length,
        warn: lines.filter((l) => l.level === 'warn').length,
        info: lines.filter((l) => l.level === 'info').length,
    };

    function copyLine(l: LogLine) {
        const safe = JSON.stringify(l.raw, (k, v) => {
            if (/key|token|secret|password|authorization|cookie/i.test(k)) return '[REDACTED]';
            return v;
        }, 2);
        navigator.clipboard?.writeText(safe);
        setCopied(l.id);
        setTimeout(() => setCopied(null), 1200);
    }

    return (
        <div className="space-y-3">
            <div className="flex flex-wrap items-center gap-3 p-3 rounded-xl border border-white/[0.06] bg-card/60">
                <FilterChips items={PERIODS} value={period} onChange={setPeriod} label="Period" />
            </div>

            <SettingsCard
                icon={ScrollText}
                title="Log feed"
                description="Activity events, request lifecycle, and pending requests merged into one chronological stream."
                status={
                    <div className="flex items-center gap-1.5 text-[10px] font-mono">
                        <span className="rounded-full bg-muted px-2 py-0.5 text-muted-foreground">{counts.info} info</span>
                        <span className="rounded-full bg-amber-500/10 px-2 py-0.5 text-amber-600">{counts.warn} warn</span>
                        <span className="rounded-full bg-destructive/10 px-2 py-0.5 text-destructive">{counts.error} error</span>
                    </div>
                }
            >
                <div className="flex flex-wrap items-center gap-2 pb-2">
                    <div className="flex items-center gap-1 text-[10px]">
                        {LEVEL_FILTERS.map((f) => (
                            <button
                                key={f.key}
                                onClick={() => setLevel(f.key)}
                                className={cn(
                                    'rounded-md px-2 py-1 font-mono transition',
                                    level === f.key ? 'bg-primary text-primary-foreground' : 'text-muted-foreground hover:bg-accent',
                                )}
                            >
                                {f.label}
                            </button>
                        ))}
                    </div>
                    <div className="relative ml-auto max-w-xs flex-1 min-w-[180px]">
                        <Search className="absolute left-2 top-1/2 -translate-y-1/2 size-3.5 text-muted-foreground" />
                        <input
                            value={filter}
                            onChange={(e) => setFilter(e.target.value)}
                            placeholder="Filter logs…"
                            aria-label="Filter logs"
                            className="w-full pl-7 pr-2 py-1.5 text-xs bg-secondary rounded-md border border-transparent focus:border-border focus:bg-background outline-none transition"
                        />
                    </div>
                </div>

                {visible.length === 0 ? (
                    <SettingsEmptyState
                        icon={Inbox}
                        title="No log entries match"
                        description="Try a different level filter or clear the search box."
                        className="py-8"
                    />
                ) : (
                    <div className="max-h-[60vh] overflow-auto font-mono text-[11px] divide-y divide-border/40">
                        {visible.map((l) => (
                            <div key={l.id} className="flex items-start gap-2 px-2 py-1.5 hover:bg-accent/20 group">
                                <span className="text-muted-foreground/70 shrink-0 w-28">{formatTimeAgo(l.time)}</span>
                                <span className="shrink-0 w-16">
                                    <LevelBadge level={l.level} />
                                </span>
                                <span className="shrink-0 w-16 text-muted-foreground">{l.source}</span>
                                <span className="flex-1 break-all whitespace-pre-wrap">{l.message}</span>
                                <button
                                    onClick={() => copyLine(l)}
                                    className="opacity-0 group-hover:opacity-100 text-muted-foreground hover:text-foreground transition shrink-0"
                                    title="Copy redacted entry"
                                >
                                    {copied === l.id ? <Check className="size-3" /> : <Copy className="size-3" />}
                                </button>
                            </div>
                        ))}
                    </div>
                )}
            </SettingsCard>
            <p className="text-[9px] text-muted-foreground font-mono">
                🔒 Secret-shaped fields (keys, tokens, cookies) are redacted on copy. Pending requests surface as warnings.
            </p>
        </div>
    );
}

function LevelBadge({ level }: { level: 'info' | 'warn' | 'error' }) {
    if (level === 'error') return <StatusPill tone="bad" label="error" />;
    if (level === 'warn') return <Badge variant="outline" className="border-amber-500/50 text-amber-600">{level}</Badge>;
    return <Badge variant="outline">{level}</Badge>;
}

export default LogsSubtab;

/* ── ObservabilityOverview — at-a-glance tab ─────────────────────────── */

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Activity, AlertTriangle, Camera, History, ShieldCheck, Wifi } from 'lucide-react';
import { SettingsEmptyState } from '@/components/settings/SettingsEmptyState';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { StatusPill, variantForHostStatus, variantForAppPolicy } from '@/components/workspace/StatusPill';
import { WorkspaceDonut, modelColor, type DonutSlice } from '@/components/workspace/WorkspaceDonut';
import { usageApi } from '@/api/usage';
import {
    getObservabilityOverview,
    getModelAliases,
    getUserModelAliases,
    type ObservabilityOverview as OverviewPayload
} from '@/api/api-client';
import { cn, formatTimeAgo } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { ErrorBoundary } from '@/components/ErrorBoundary';

export function ObservabilityOverview({ onNavigate }: { onNavigate?: (subtab: 'overview' | 'audit' | 'rollback' | 'observations') => void }) {
    // Poll every 5s so the "Tokens per day" bar for today grows in real time
    // and the model-usage donut + stats stay current as new events land.
    const refetchMs = 5000;
    const overview = useQuery({ queryKey: ['observability', 'overview'], queryFn: () => getObservabilityOverview('30d'), refetchInterval: refetchMs });
    const usage = useQuery({ queryKey: ['usage', 'stats', '30d'], queryFn: () => usageApi.stats('30d'), refetchInterval: refetchMs });
    const byDay = useQuery({ queryKey: ['usage', 'byDay', '30d'], queryFn: () => usageApi.byDay('30d'), refetchInterval: refetchMs });
    const byModel = useQuery({ queryKey: ['usage', 'byModel', '30d'], queryFn: () => usageApi.byModel('30d'), refetchInterval: refetchMs });
    // Alias lookups so we can show "alias(backend)" next to the alias the
    // usage events recorded. Both catalog aliases (e.g. short names set in
    // model-catalog.json) and user-defined aliases from /api/config are
    // merged into one map keyed by the alias string.
    const catalogAliases = useQuery({ queryKey: ['models', 'aliases'], queryFn: () => getModelAliases(), refetchInterval: refetchMs });
    const userAliases = useQuery({ queryKey: ['models', 'userAliases'], queryFn: () => getUserModelAliases(), refetchInterval: refetchMs });

    if (overview.isLoading || usage.isLoading) {
        return <SettingsEmptyState title="Loading…" description="Fetching the at-a-glance view." />;
    }

    const o = overview.data;
    if (!o) return <SettingsEmptyState title="No data" description="Could not load observability overview." />;

    const totalTokens30d = usage.data?.totalTokens ?? 0;
    const activeDays = usage.data?.activeDays ?? 0;
    const currentStreak = usage.data?.currentStreak ?? 0;
    const criticalCount = o.audit.byCritical.true ?? 0;
    const observations = o.hostAgent.postObservationCount;
    const allowedApps = o.appPolicy.counts.allow;
    const deniedApps = o.appPolicy.counts.deny;

    // Build alias -> backend model id map. We only add entries where the
    // alias resolves to a different model id, otherwise the suffix would
    // be redundant (e.g. when an alias just renames itself).
    const aliasBackendMap = new Map<string, string>();
    for (const a of catalogAliases.data?.aliases ?? []) {
        if (a.alias && a.resolvesTo && a.alias !== a.resolvesTo) {
            aliasBackendMap.set(a.alias, a.resolvesTo);
        }
    }
    for (const a of userAliases.data?.aliases ?? []) {
        if (!a.alias || !a.targetModel || a.alias === a.targetModel) continue;
        // Index by the canonical id (e.g. "claude-opus-4.7") so calls that
        // record the alias id directly still resolve.
        aliasBackendMap.set(a.alias, a.targetModel);
        // Index by the prettified display alias (e.g. "Opus 4.7-Alias")
        // — that's the string recorded in usage events when the user picks
        // the alias from the chat dropdown.
        if (a.displayAlias && a.displayAlias !== a.alias) {
            aliasBackendMap.set(a.displayAlias, a.targetModel);
        }
    }
    const formatModelLabel = (model: string): string => {
        const backend = aliasBackendMap.get(model);
        return backend ? `${model}(${backend})` : model;
    };

    // Model-usage donut slices (from usageApi.byModel) + center label.
    // We compute `color` here so the donut and the Tokens-per-day chart
