                </Card>
            </div>

            {/* Model-usage donut + Tokens-per-day bar chart (matches Usage screenshot) */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                <Card>
                    <CardHeader>
                        <CardTitle>Model usage</CardTitle>
