 * The old Inspector/Conversations/Thinking components each fetched their
 * own slice of /ui/details + /ui/conversations independently — and the old
 * Inspector also issued an extra /ui/detail/:reqId call when a row was
 * selected, even though the same data was already in the list response.
 *
 * This hook fetches /ui/details + /ui/conversations once for the chosen
 * period, exposes the unified row list, the selected request, a normalized
 * transcript for the Readable tab, and an extracted thinking-traces list
 * for the Thinking tab. The three old sub-sections now read from one
 * poll cycle and share a single selected-request state. */

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import {
  getRequestDetails,
  getConversations,
  type RequestDetailEntry,
  type ConversationsResponse,
  type Period,
  type RequestEntry,
} from '@/api/api-client';

export interface MessageItem {
  role: string;
  content: string;
}

export interface ConversationItem {
  reqId: string;
  clientType: string;
  model: string;
  status: string;
  date?: string;
  messages: MessageItem[];
  response?: unknown;
  finishReason?: string | null;
  error?: string | null;
}

export interface ThinkingTrace {
  reqId: string;
  date?: string;
  thinking: string;
  finishReason?: string | null;
}

export interface InspectorRow {
  reqId: string;
  clientType: string;
  model: string;
  status: string;
  date?: string;
  requestType?: string;
  /** True if the captured detail includes any non-empty thinking trace. */
  hasThinking: boolean;
  /** True if the detail is in an error state. */
  isError: boolean;
}

function toMessages(raw: unknown): MessageItem[] {
  if (!Array.isArray(raw)) return [];
  return raw
    .map((m: any) => {
      const role = m?.role || 'unknown';
      let content = '';
      if (typeof m?.content === 'string') content = m.content;
      else if (Array.isArray(m?.content)) {
        content = m.content
          .map((b: any) => (typeof b === 'string' ? b : b?.text || b?.content || b?.type || ''))
          .filter(Boolean)
          .join('\n');
      } else if (m?.content && typeof m.content === 'object') {
        content = String(m.content.text || m.content.content || '');
      }
      return { role, content };
    })
    .filter((m) => m.content);
}

function normalizeConversations(grouped: ConversationsResponse | undefined): ConversationItem[] {
  const items: ConversationItem[] = [];
  for (const [clientType, entries] of Object.entries(grouped || {})) {
    for (const e of entries as Array<RequestEntry & {
      details: { messages: unknown; response: unknown; finishReason?: string | null; error?: string | null } | null;
    }>) {
      items.push({
        reqId: e.reqId,
        clientType,
        model: e.model || 'unknown',
        status: e.status || 'unknown',
        date: e.date,
        messages: toMessages(e.details?.messages),
        response: e.details?.response,
        finishReason: e.details?.finishReason,
        error: e.details?.error,
      });
    }
  }
  return items.sort((a, b) => (b.date || '').localeCompare(a.date || ''));
}

function stringifyThinking(v: unknown): string {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  try {
    if (Array.isArray(v)) {
      // Anthropic thinking blocks: [{ type: 'thinking', thinking: '...' }]
      return v
        .map((b: any) => (typeof b === 'string' ? b : b?.thinking || b?.text || ''))
        .filter(Boolean)
        .join('\n');
    }
    if (typeof v === 'object') {
      const o = v as Record<string, unknown>;
      return String(o.thinking || o.text || o.content || '');
    }
  } catch { /* ignore */ }
  return String(v);
}

function extractTraces(details: RequestDetailEntry[] | undefined): ThinkingTrace[] {
  if (!details) return [];
  const traces: ThinkingTrace[] = [];
  for (const d of details) {
    const text = stringifyThinking(d.thinking);
    if (!text || !text.trim()) continue;
    traces.push({ reqId: d.reqId, date: d.date, thinking: text, finishReason: d.finishReason });
  }
  return traces;
}

/** Safe JSON pretty-printer that never throws and pretty-prints JSON strings. */
function safeStringify(v: unknown): string {
  if (v == null || v === '') return '';
  if (typeof v === 'string') {
    try {
      const parsed = JSON.parse(v);
      return JSON.stringify(parsed, null, 2);
    } catch {
      return v;
    }
  }
  try {
    return JSON.stringify(v, null, 2);
  } catch {
    return String(v);
  }
}

export function useConversationInspector(period: Period) {
  const detailsQuery = useQuery({
    queryKey: ['ci-details', period],
    queryFn: () => getRequestDetails(period),
    refetchInterval: 3_000,
  });
  const conversationsQuery = useQuery({
    queryKey: ['ci-conversations', period],
    queryFn: () => getConversations(period),
    refetchInterval: 5_000,
  });

  const details = detailsQuery.data ?? [];
  const conversations = useMemo(() => normalizeConversations(conversationsQuery.data), [conversationsQuery.data]);
  const thinking = useMemo(() => extractTraces(details), [details]);

  /** Unified row list: every request that has either detail or a transcript. */
  const rows = useMemo<InspectorRow[]>(() => {
    const byReq = new Map<string, InspectorRow>();
    for (const d of details) {
      byReq.set(d.reqId, {
        reqId: d.reqId,
        clientType: 'unknown',
        model: 'unknown',
        status: d.status || 'unknown',
        date: d.date,
        requestType: d.requestType,
        hasThinking: !!stringifyThinking(d.thinking).trim(),
        isError: d.status === 'error' || !!d.error,
      });
    }
    for (const c of conversations) {
      const existing = byReq.get(c.reqId);
      if (existing) {
        existing.clientType = c.clientType;
        existing.model = c.model;
      } else {
        byReq.set(c.reqId, {
          reqId: c.reqId,
          clientType: c.clientType,
          model: c.model,
          status: c.status,
          date: c.date,
          hasThinking: false,
          isError: c.status === 'error' || !!c.error,
        });
      }
    }
    return Array.from(byReq.values()).sort((a, b) => (b.date || '').localeCompare(a.date || ''));
  }, [details, conversations]);

  return {
    rows,
    details,
    conversations,
    thinking,
    isLoading: detailsQuery.isLoading && conversationsQuery.isLoading,
    /** Find the selected detail, conversation, and trace by reqId. */
    select: (reqId: string | null) => {
      const detail = reqId ? details.find((d) => d.reqId === reqId) ?? null : null;
      const conversation = reqId ? conversations.find((c) => c.reqId === reqId) ?? null : null;
      const trace = reqId ? thinking.find((t) => t.reqId === reqId) ?? null : null;
      return { detail, conversation, trace };
    },
    safeStringify,
  };
}

/* ── useToolsConnections — shared data layer for the Tools & Connections
 *   section ──────────────────────────────────────────────────────────
 * The old Services.tsx and Connections.tsx components each independently
 * polled /api/service-connections (and Connections also polled
 * /ui/host-agent/status). This hook is the only fetcher; both the new
 * Overview cards and the modern Accounts subtab read from one cycle. The
 * Servers subtab still mounts the existing <Mcp /> component (a 1200-line
 * CRUD UI we deliberately preserve rather than rewrite) which keeps its
 * own internal polling for MCP server configs. */

import { useQuery } from '@tanstack/react-query';
import { getHostAgentStatus, type HostAgentStatus } from '@/api/api-client';
import { api } from '@/api/client';

export type ServiceName = 'google' | 'github' | 'slack';
export type ServiceStatus = 'connected' | 'disconnected' | 'needs_config';

export interface ServiceConnection {
  name: ServiceName;
  label: string;
  description: string;
  services: string[];
  scopes: string[];
  status: ServiceStatus;
  connected: boolean;
  account?: string;
  maskedToken?: string;
  teamId?: string;
  missingConfig?: boolean;
  updatedAt?: string;
}

interface ServiceConnectionsResponse {
  connections: Partial<Record<ServiceName, ServiceConnection>>;
}

const SERVICE_LABELS: Record<ServiceName, string> = {
  google: 'Google Workspace',
  github: 'GitHub',
  slack: 'Slack',
};

const SERVICE_DESCRIPTIONS: Record<ServiceName, string> = {
  google: 'Gmail, Calendar, Drive, Docs, Sheets, Slides, Tasks, Contacts.',
  github: 'Repositories, issues, pull requests, and code search.',
  slack: 'Channels, messages, threads, and reactions.',
};

export function useToolsConnections() {
  const connsQuery = useQuery({
    queryKey: ['tc-connections'],
    queryFn: () => api.get<ServiceConnectionsResponse>('/api/service-connections'),
    refetchInterval: 8_000,
  });
  const hostQuery = useQuery({
    queryKey: ['tc-host-agent'],
    queryFn: () => getHostAgentStatus(),
    refetchInterval: 5_000,
  });

  const connections: ServiceConnection[] = Object.values(connsQuery.data?.connections ?? {}).map(
    (c) => ({
      ...(c as ServiceConnection),
      // Fill in label/description if the backend omits them.
      label: c.label ?? SERVICE_LABELS[c.name as ServiceName] ?? c.name,
      description: c.description ?? SERVICE_DESCRIPTIONS[c.name as ServiceName] ?? '',
    }),
  );
  const hostStatus = hostQuery.data?.status ?? 'unknown';
  const hostConnected = hostStatus === 'connected' || hostStatus === 'open';
  const connectedCount = connections.filter((c) => c.connected).length;
  const totalCount = connections.length;

  return {
    connections,
    connectedCount,
    totalCount,
    host: (hostQuery.data ?? { status: 'unknown' }) as HostAgentStatus,
    hostConnected,
    hostStatus,
    isLoading: connsQuery.isLoading && hostQuery.isLoading,
  };
}

/* ── useTrafficActivity — shared data layer for Traffic & Activity ──── */
/* The old Overview/Traffic/Usage/Logs sections each polled /ui/requests,
 * /ui/stats, /ui/activity, and /api/usage/* independently — up to 4x the
 * network calls for the same data. This hook fetches each source once and
 * exposes normalized rows + stats + a merged log feed so every tab in the
 * section reads from one poll cycle. */

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import {
  getRequests,
  getStats,
  getActivity,
  type RequestEntry,
  type PendingRequest,
  type ActivityEntry,
  type StatsResponse,
} from '@/api/api-client';

export type Period = 'all' | 'today' | 'yesterday' | 'week' | 'month' | 'year';
export type StatusFilter = 'all' | 'ok' | 'err';

/** Normalized row so renderers stay mock-shape-agnostic. */
export interface TrafficRow {
  reqId: string;
  clientType: string;
  endpoint: string;
  model: string;
  status: string;
  durationMs: number;
  inputTokens: number;
  outputTokens: number;
  totalCost: number;
  timestamp: number | string;
  error?: string | null;
}

function toRow(r: RequestEntry): TrafficRow {
  return {
    reqId: r.reqId,
    clientType: r.clientType || 'unknown',
    endpoint: r.endpoint || '',
    model: r.model || 'unknown',
    status: r.status || 'unknown',
    durationMs: r.durationMs || 0,
    inputTokens: r.inputTokens || 0,
    outputTokens: r.outputTokens || 0,
    totalCost: r.totalCost || 0,
    timestamp: r.timestamp || r.date || r.time || Date.now(),
    error: r.error,
  };
}

export type LogLevel = 'info' | 'warn' | 'error';

export interface LogLine {
  id: string;
  time: string;
  level: LogLevel;
  source: 'activity' | 'request' | 'pending';
  message: string;
  raw?: unknown;
}

function levelFromEntry(a: ActivityEntry): LogLevel {
  const t = (a.type || '').toLowerCase();
  if (t.includes('error') || t.includes('fail')) return 'error';
  if (t.includes('warn') || t.includes('pending')) return 'warn';
  return 'info';
}

export interface TrafficActivityData {
  rows: TrafficRow[];
  pending: PendingRequest[];
  stats: StatsResponse | undefined;
  activity: ActivityEntry[];
  lines: LogLine[];
  counts: { info: number; warn: number; error: number };
  isLoading: boolean;
}

export function useTrafficActivity(period: Period) {
  const reqQuery = useQuery({
    queryKey: ['ta-requests', period],
    queryFn: () => getRequests(period),
    refetchInterval: 3_000,
  });
  const statsQuery = useQuery({
    queryKey: ['ta-stats', period],
    queryFn: () => getStats(period),
    refetchInterval: 5_000,
  });
  const activityQuery = useQuery({
    queryKey: ['ta-activity'],
    queryFn: () => getActivity(),
    refetchInterval: 5_000,
  });

  // ── Defensive normalization ──────────────────────────────────────
  // The backend may return a 404, an error envelope ({ error, ... }), or a
  // wrapper object ({ entries: [...] }) instead of the bare array/shape the
  // UI expects. `?? []` only guards null/undefined — a truthy object would
  // reach the `for...of` below and throw "activity is not iterable", crashing
  // the whole Observability section (black screen). Coerce every source to a
  // real array before any iteration.
  const asArray = <T,>(v: unknown): T[] => (Array.isArray(v) ? v : []);

  const reqData = reqQuery.data as { pending?: unknown; completed?: unknown } | undefined;
  const pending = asArray<PendingRequest>(reqData?.pending);
  const rows = useMemo(() => asArray<RequestEntry>(reqData?.completed).map(toRow), [reqQuery.data]);
  const activity = asArray<ActivityEntry>(activityQuery.data);
  const stats = statsQuery.data;

  const lines = useMemo<LogLine[]>(() => {
    const out: LogLine[] = [];
    for (const a of activity) {
      out.push({
        id: `act-${a.time}-${a.type}`,
        time: a.time,
        level: levelFromEntry(a),
        source: 'activity',
        message: a.detail || a.type,
        raw: a,
      });
    }
    for (const p of pending) {
      out.push({
        id: `pend-${p.reqId}`,
        time: new Date(Date.now() - p.elapsedMs).toISOString(),
        level: 'warn',
        source: 'pending',
        message: `[pending ${p.reqId}] ${p.clientType} ${p.endpoint} (${p.model})`,
        raw: p,
      });
    }
    for (const r of rows) {
      const isError = r.status === 'error';
      out.push({
        id: `req-${r.reqId}`,
        time: String(r.timestamp),
        level: isError ? 'error' : 'info',
        source: 'request',
        message: `[${r.reqId}] ${r.clientType} ${r.endpoint} → ${r.status} (${r.durationMs}ms${r.error ? `, ${r.error}` : ''})`,
        raw: r,
      });
    }
    return out.sort((a, b) => b.time.localeCompare(a.time));
  }, [activity, pending, rows]);

  const counts = useMemo(
    () => ({
      error: lines.filter((l) => l.level === 'error').length,
      warn: lines.filter((l) => l.level === 'warn').length,
      info: lines.filter((l) => l.level === 'info').length,
    }),
    [lines],
  );

  return {
    rows,
    pending,
    stats,
    activity,
    lines,
    counts,
    isLoading: reqQuery.isLoading && statsQuery.isLoading,
  };
}

export function applyStatusFilter(rows: TrafficRow[], filter: StatusFilter): TrafficRow[] {
  if (filter === 'all') return rows;
  if (filter === 'err') return rows.filter((r) => r.status === 'error');
  return rows.filter((r) => r.status !== 'error');
}

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { SectionHeader } from '@/components/SectionHeader';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { TerminalSquare, Plus, ShieldAlert, Check, X, Loader2, Inbox } from 'lucide-react';
import {
  getTerminalSessions,
  submitTerminalCommand,
  approveTerminalRequest,
  type TerminalSession,
  type TerminalApproval,
} from '@/api/api-client';
import { api } from '@/api/client';

/**
 * Approval-aware terminal. Per the migration plan, this ships after Workbench
 * chat is stable. Dangerous commands require explicit approval before they
 * run; the backend returns `approval_required` instead of executing, and the
 * pending request appears in the approvals list.
 */
export function Terminal() {
  const qc = useQueryClient();
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [command, setCommand] = useState('');

  const { data, isLoading } = useQuery({
    queryKey: ['terminal-sessions'],
    queryFn: () => getTerminalSessions(),
    refetchInterval: 3_000,
  });

  const sessions = data?.sessions ?? [];
  const approvals = data?.approvals ?? [];
  const activeId = selectedId ?? sessions[0]?.id ?? null;
  const active = sessions.find((s) => s.id === activeId) ?? null;

  const { data: buffer } = useQuery({
    queryKey: ['terminal-buffer', activeId],
    queryFn: () => (activeId ? api.get<{ buffer: string } & TerminalSession>(`/ui/terminal/buffer?id=${activeId}`) : Promise.resolve(null)),
    enabled: !!activeId,
    refetchInterval: 2_000,
  });

  const run = useMutation({
    mutationFn: () => submitTerminalCommand(activeId || '', command),
    onSuccess: (res: any) => {
      setCommand('');
      qc.invalidateQueries({ queryKey: ['terminal-sessions'] });
      if (res?.status === 'approval_required') {
        // Approval will surface in the approvals list.
      }
    },
  });

  const approve = useMutation({
    mutationFn: (requestId: string) => approveTerminalRequest(requestId, true),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['terminal-sessions'] }),
  });
  const reject = useMutation({
    mutationFn: (requestId: string) => approveTerminalRequest(requestId, false),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['terminal-sessions'] }),
  });
  const createSession = useMutation({
    mutationFn: () => api.post('/ui/terminal/sessions', {}),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['terminal-sessions'] }),
  });

  return (
    <div className="p-6 space-y-4 flex flex-col h-full">
      <SectionHeader
        title="Terminal"
        subtitle="Approval-aware command runner. Dangerous commands require explicit approval."
        actions={
          <Button size="sm" variant="outline" onClick={() => createSession.mutate()} disabled={createSession.isPending}>
            <Plus className="size-3" /> New session
          </Button>
        }
      />

      {/* Pending approvals */}
      {approvals.length > 0 && (
        <Card className="border-warning/50 bg-warning/5">
          <CardContent className="p-3 space-y-2">
            <p className="text-[10px] uppercase tracking-wider text-warning font-semibold flex items-center gap-1">
              <ShieldAlert className="size-3" /> {approvals.length} approval{approvals.length > 1 ? 's' : ''} required
            </p>
            {approvals.map((a) => (
              <div key={a.requestId} className="flex items-start justify-between gap-3 rounded-md bg-card/70 border border-warning/30 px-3 py-2">
                <div className="min-w-0">
                  <pre className="text-xs font-mono whitespace-pre-wrap break-all">{a.command || a.inputPreview || '(no command)'}</pre>
                  <p className="text-[10px] text-muted-foreground mt-1">{a.reason || a.cwd}</p>
                </div>
                <div className="flex items-center gap-1 shrink-0">
                  <Button size="sm" onClick={() => approve.mutate(a.requestId)} disabled={approve.isPending}>
                    <Check className="size-3" /> Approve
                  </Button>
                  <Button size="sm" variant="outline" onClick={() => reject.mutate(a.requestId)} disabled={reject.isPending}>
                    <X className="size-3" />
                  </Button>
                </div>
              </div>
            ))}
          </CardContent>
        </Card>
      )}

      <div className="flex-1 flex gap-3 min-h-0">
        {/* Session list */}
        <div className="w-52 shrink-0 border-r border-border pr-3 overflow-auto">
          <p className="text-[10px] uppercase tracking-wider text-muted-foreground mb-1 font-mono">Sessions</p>
          {sessions.length === 0 && !isLoading && (
            <p className="text-xs text-muted-foreground py-4">No sessions</p>
          )}
          {sessions.map((s) => (
            <button
              key={s.id}
              onClick={() => setSelectedId(s.id)}
              className={`w-full text-left rounded-md px-2 py-1.5 text-xs transition mb-0.5 ${
                activeId === s.id ? 'bg-accent' : 'hover:bg-accent/50'
              }`}
            >
              <div className="flex items-center gap-1.5">
                <TerminalSquare className="size-3 shrink-0 text-muted-foreground" />
                <span className="font-mono truncate">{s.title || s.id}</span>
              </div>
              {s.cwd && <p className="text-[10px] text-muted-foreground/60 font-mono truncate mt-0.5">{s.cwd}</p>}
            </button>
          ))}
        </div>

        {/* Active session */}
        <div className="flex-1 flex flex-col min-w-0">
          {active ? (
            <>
              <div className="flex items-center gap-2 mb-2 text-xs text-muted-foreground font-mono">
                <Badge variant="secondary" className="text-[9px]">{active.id}</Badge>
                <span className="truncate">{active.cwd}</span>
              </div>
              <div className="flex-1 rounded-md bg-black/80 dark:bg-black/60 border border-border overflow-auto p-3 min-h-[180px]">
                <pre className="text-[11px] font-mono whitespace-pre-wrap break-all text-green-400/90">
                  {buffer?.buffer || '(empty buffer — run a command)'}
                </pre>
              </div>
              <form
                className="mt-2 flex items-center gap-2"
                onSubmit={(e) => {
                  e.preventDefault();
                  if (command.trim()) run.mutate();
                }}
              >
                <span className="text-xs font-mono text-muted-foreground">$</span>
                <Input
                  value={command}
                  onChange={(e) => setCommand(e.target.value)}
                  placeholder="Type a command…"
                  className="font-mono text-sm"
                  disabled={run.isPending}
                />
                <Button type="submit" size="sm" disabled={!command.trim() || run.isPending}>
                  {run.isPending ? <Loader2 className="size-3 animate-spin" /> : 'Run'}
                </Button>
              </form>
            </>
          ) : (
            <div className="flex-1 grid place-items-center text-muted-foreground text-sm">
              {isLoading ? (
                <Loader2 className="size-5 animate-spin" />
              ) : (
                <div className="text-center">
                  <Inbox className="size-8 text-muted-foreground/40 mx-auto mb-2" />
                  Create a session to start running commands.
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { SectionHeader } from '@/components/SectionHeader';
import { Card, CardContent } from '@/components/ui/card';
import { Check, Loader2, Brain, Inbox } from 'lucide-react';
import { formatTimeAgo } from '@/lib/utils';
import { getRequestDetails, type RequestDetailEntry, type Period } from '@/api/api-client';

/**
 * Thinking traces are not a standalone endpoint — they ride along on each
 * captured request in /ui/details (the `thinking` field, set by the
 * anthropic adapter when extended thinking is enabled). We surface the most
 * recent traces here. When no thinking is available, we show a clear empty
 * state instead of fake/mock data.
 */

interface ThinkingTrace {
  reqId: string;
  date?: string;
  thinking: string;
  finishReason?: string | null;
}

function extractTraces(details: RequestDetailEntry[] | undefined): ThinkingTrace[] {
  if (!details) return [];
  const traces: ThinkingTrace[] = [];
  for (const d of details) {
    const text = stringifyThinking(d.thinking);
    if (!text || !text.trim()) continue;
    traces.push({
      reqId: d.reqId,
      date: d.date,
      thinking: text,
      finishReason: d.finishReason,
    });
  }
  return traces;
}

function stringifyThinking(v: unknown): string {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  try {
    if (Array.isArray(v)) {
      // Anthropic thinking blocks: [{ type: 'thinking', thinking: '...' }]
      return v
        .map((b: any) => (typeof b === 'string' ? b : b?.thinking || b?.text || ''))
        .filter(Boolean)
        .join('\n');
    }
    if (typeof v === 'object') {
      const o = v as Record<string, unknown>;
      return String(o.thinking || o.text || o.content || '');
    }
  } catch {
    /* ignore */
  }
  return String(v);
}

const PERIODS: { key: Period; label: string }[] = [
  { key: 'today', label: 'Today' },
  { key: 'yesterday', label: 'Yesterday' },
  { key: 'week', label: '7d' },
  { key: 'all', label: 'All' },
];

export function Thinking() {
  const [periodIndex, setPeriodIndex] = useState(0);
  const period = PERIODS[periodIndex].key;

  const { data: details, isLoading } = useQuery({
    queryKey: ['request-details-thinking', period],
    queryFn: () => getRequestDetails(period),
    refetchInterval: 4_000,
  });

  const traces = extractTraces(details);
  const active = traces.find((t) => !t.finishReason);

  return (
    <div className="p-6 space-y-6">
      <SectionHeader
        title="Thinking"
        subtitle={
          isLoading
            ? 'Loading thinking traces…'
            : traces.length
              ? `${traces.length} reasoning trace${traces.length > 1 ? 's' : ''} captured`
              : 'No reasoning traces yet — extended thinking is off or no requests have used it'
        }
        actions={
          <div className="flex items-center gap-3">
            {active && (
              <span className="inline-flex items-center gap-1.5 text-[10px] text-warning font-mono">
                <Loader2 className="size-3 animate-spin" /> processing
              </span>
            )}
            <div className="flex items-center gap-1 text-[10px]">
              {PERIODS.map((p, i) => (
                <button
                  key={p.key}
                  onClick={() => setPeriodIndex(i)}
                  className={`rounded-md px-2 py-1 font-mono transition ${
                    periodIndex === i ? 'bg-primary text-primary-foreground' : 'text-muted-foreground hover:bg-accent'
                  }`}
                >
                  {p.label}
                </button>
              ))}
            </div>
          </div>
        }
      />

      {traces.length === 0 ? (
        <EmptyThinking isLoading={isLoading} />
      ) : (
        <div className="space-y-3">
          {traces.map((t, i) => (
            <ThinkingCard key={t.reqId} index={i + 1} trace={t} />
          ))}
        </div>
      )}
    </div>
  );
}

function ThinkingCard({ index, trace }: { index: number; trace: ThinkingTrace }) {
  const isActive = !trace.finishReason;
  const preview = trace.thinking.length > 400 ? trace.thinking.slice(0, 400) + '…' : trace.thinking;
  return (
    <Card className={isActive ? 'border-warning/50 bg-warning/5' : ''}>
      <CardContent className="p-4">
        <div className="flex items-start gap-3">
          <StepIcon status={isActive ? 'active' : 'done'} />
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2 flex-wrap">
              <h3 className="text-sm font-semibold">Trace {index}</h3>
              <span className="text-[10px] text-muted-foreground font-mono">{trace.reqId}</span>
              {trace.date && (
                <span className="text-[10px] text-muted-foreground ml-auto">{formatTimeAgo(trace.date)}</span>
              )}
            </div>
            <pre className="text-xs text-muted-foreground mt-2 whitespace-pre-wrap break-words font-mono leading-relaxed">
              {preview}
            </pre>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

function StepIcon({ status }: { status: 'done' | 'active' }) {
  if (status === 'active') {
    return (
      <div className="size-6 rounded-full bg-warning/20 text-warning grid place-items-center shrink-0">
        <Loader2 className="size-3.5 animate-spin" />
      </div>
    );
  }
  return (
    <div className="size-6 rounded-full bg-primary/20 text-primary grid place-items-center shrink-0">
      <Check className="size-3.5" />
    </div>
  );
}

function EmptyThinking({ isLoading }: { isLoading: boolean }) {
  return (
    <Card className="border-dashed">
      <CardContent className="p-10 grid place-items-center text-center">
        {isLoading ? (
          <>
            <Brain className="size-8 text-muted-foreground/40 mb-3" />
            <p className="text-sm text-muted-foreground">Loading…</p>
          </>
        ) : (
          <>
            <Inbox className="size-8 text-muted-foreground/40 mb-3" />
            <p className="text-sm font-medium">No thinking traces available</p>
            <p className="text-xs text-muted-foreground mt-1 max-w-sm">
              Extended thinking traces appear here when a provider returns them.
              Send a message that uses a reasoning model to populate this view.
            </p>
          </>
        )}
      </CardContent>
    </Card>
  );
}

/* ── Usage ─ Settings → Usage tab (ZCode reference) ────────────── */
/* Stat cards (3×2 grid) + GitHub-style activity heatmap + model-share */
/* donut chart. Reads from /api/usage/{stats,heatmap,by-model}.            */
/*                                                                          */
/* Layout:                                                                   */
/*   • Time-range toggle (Last 7 days / Last 30 days) at the top-right      */
/*   • 3×2 stat card grid: Tokens, Sessions, Messages, Active days,         */
/*     Current streak, Favorite model                                         */
/*   • Activity heatmap (5 rows × N cols of 9-px squares, 4 intensity levels) */
/*   • Model share donut + legend on the right                                */

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { Activity, BarChart3, Flame, Hash, MessageSquare, Sparkles, Star } from 'lucide-react';
import { SectionHeader } from '@/components/SectionHeader';
import { PageLoader } from '@/components/PageLoader';
import { usageApi, type UsageRange } from '@/api/usage';
import { cn } from '@/lib/utils';

function formatNumber(n: number): string {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
  return n.toLocaleString();
}

interface StatCardProps {
  icon: React.ComponentType<{ size?: number; className?: string }>;
  label: string;
  value: string;
  sub?: string;
  accent?: 'default' | 'emerald' | 'amber' | 'blue';
}
function StatCard({ icon: Icon, label, value, sub, accent = 'default' }: StatCardProps) {
  const accentColor = {
    default: 'text-muted-foreground',
    emerald: 'text-success',
    amber: 'text-warning',
    blue: 'text-info',
  }[accent];
  return (
    <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4 flex flex-col gap-1.5">
      <div className="flex items-center gap-1.5 text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">
        <Icon size={11} className={accentColor} />
        {label}
      </div>
      <div className="text-[22px] font-semibold tabular-nums leading-none">
        {value}
      </div>
      {sub && <div className="text-[10.5px] text-muted-foreground/70">{sub}</div>}
    </div>
  );
}

/** GitHub-style 5-row × N-col activity heatmap. */
function Heatmap({ cells }: { cells: { date: string; count: number }[] }) {
  // 5 rows × ceil(N/7) cols, oldest at top-left
  const max = Math.max(1, ...cells.map(c => c.count));
  const cols = Math.ceil(cells.length / 5);
  const grid: { count: number; date: string }[][] = Array.from({ length: 5 }, () => []);
  cells.forEach((cell, i) => {
    const col = Math.floor(i / 5);
    grid[col].push(cell);
  });

  const intensity = (count: number): string => {
    if (count === 0) return 'bg-white/[0.025]';
    const ratio = count / max;
    if (ratio < 0.25) return 'bg-success/40';
    if (ratio < 0.5)  return 'bg-success/60';
    if (ratio < 0.75) return 'bg-success/80';
    return 'bg-success';
  };

  return (
    <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4">
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-1.5 text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">
          <Activity size={11} className="text-success" />
          Activity heatmap
        </div>
        <div className="flex items-center gap-1 text-[10px] text-muted-foreground/60">
          <span>Less</span>
          {[0, 0.25, 0.5, 0.75, 1].map((p) => (
            <span
              key={p}
              className={cn('size-[9px] rounded-[2px]', intensity(p * max))}
            />
          ))}
          <span>More</span>
        </div>
      </div>
      <div className="flex gap-[2px] overflow-x-auto pb-1">
        {grid.map((col, ci) => (
          <div key={ci} className="flex flex-col gap-[2px]">
            {col.map((cell, ri) => (
              <div
                key={`${ci}-${ri}`}
                className={cn('size-[9px] rounded-[2px]', intensity(cell.count))}
                title={`${cell.date}: ${cell.count} messages`}
              />
            ))}
          </div>
        ))}
      </div>
    </div>
  );
}

/** SVG donut chart for model share. */
function Donut({ data, total }: { data: { model: string; tokens: number; percent: number }[]; total: number }) {
  const R = 36;
  const C = 2 * Math.PI * R;
  let offset = 0;
  const palette = ['#3b7eff', '#4ade80', '#f59e0b', '#f87171', '#a78bfa', '#06b6d4', '#ec4899', '#84cc16'];

  return (
    <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4 flex flex-col gap-3">
      <div className="flex items-center gap-1.5 text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">
        <BarChart3 size={11} className="text-blue-500" />
        Model share
      </div>
      <div className="flex items-center gap-5">
        <svg width={96} height={96} viewBox="0 0 96 96" className="shrink-0">
          <circle cx={48} cy={48} r={R} fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth={14} />
          {data.map((slice, i) => {
            const length = (slice.percent / 100) * C;
            const dashArray = `${length} ${C}`;
            const seg = (
              <circle
                key={slice.model + i}
                cx={48}
                cy={48}
                r={R}
                fill="none"
                stroke={palette[i % palette.length]}
                strokeWidth={14}
                strokeDasharray={dashArray}
                strokeDashoffset={-offset}
                transform="rotate(-90 48 48)"
                style={{ transition: 'stroke-dasharray 0.3s ease' }}
              />
            );
            offset += length;
            return seg;
          })}
          <text x={48} y={46} textAnchor="middle" className="fill-foreground" style={{ fontSize: 13, fontWeight: 600 }} fontFamily="ui-monospace, monospace">
            {formatNumber(total)}
          </text>
          <text x={48} y={60} textAnchor="middle" className="fill-muted-foreground" style={{ fontSize: 7 }} fontFamily="ui-monospace, monospace">
            tokens
          </text>
        </svg>
        <div className="flex-1 min-w-0 space-y-1">
          {data.length === 0 && <div className="text-[11px] text-muted-foreground/60">No usage yet.</div>}
          {data.slice(0, 6).map((slice, i) => (
            <div key={slice.model + i} className="flex items-center gap-2 text-[11.5px] min-w-0">
              <span className="size-2 rounded-full shrink-0" style={{ backgroundColor: palette[i % palette.length] }} />
              <span className="truncate flex-1 text-foreground/90">{slice.model || 'unknown'}</span>
              <span className="font-mono tabular-nums text-muted-foreground shrink-0">{slice.percent.toFixed(1)}%</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export function Usage() {
  const [range, setRange] = useState<UsageRange>('30d');

  // Poll every 5s so stats, heatmap, and by-model stay current as new
  // usage events land. Stops on unmount.
  const refetchMs = 5000;
  const stats = useQuery({
    queryKey: ['usage', 'stats', range],
    queryFn: () => usageApi.stats(range),
    refetchInterval: refetchMs,
  });
  const heatmap = useQuery({
    queryKey: ['usage', 'heatmap', range],
    queryFn: () => usageApi.heatmap(range),
    refetchInterval: refetchMs,
  });
  const byModel = useQuery({
    queryKey: ['usage', 'by-model', range],
    queryFn: () => usageApi.byModel(range),
    refetchInterval: refetchMs,
  });

  if (stats.isLoading || heatmap.isLoading || byModel.isLoading) {
    return (
      <div className="p-6">
        <PageLoader />
      </div>
    );
  }

  const s = stats.data;
  const total = s?.totalTokens || 0;

  return (
    <div className="p-6 space-y-6">
      <SectionHeader
        title="Usage"
        actions={
          <div className="inline-flex rounded-lg border border-white/[0.06] bg-card/60 p-0.5 text-[11.5px]">
            {(['7d', '30d'] as UsageRange[]).map((r) => (
              <button
                key={r}
                type="button"
                onClick={() => setRange(r)}
                className={cn(
                  'px-2.5 py-1 rounded-md transition-colors',
                  range === r ? 'bg-primary/15 text-foreground' : 'text-muted-foreground hover:text-foreground'
                )}
              >
                {r === '7d' ? 'Last 7 days' : 'Last 30 days'}
              </button>
            ))}
          </div>
        }
      />

      {!s || total === 0 ? (
        <div className="rounded-xl border border-white/[0.06] bg-card/60 p-8 text-center text-muted-foreground/60 text-sm">
          No usage data yet. Once you start a few sessions, your tokens, sessions, and model share will appear here.
        </div>
      ) : (
        <>
          {/* Stat card grid (3 × 2) */}
          <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
            <StatCard icon={Hash}        label="Token usage"        value={formatNumber(s.totalTokens)}      sub={s.range === '7d' ? 'last 7 days' : 'last 30 days'} accent="blue" />
            <StatCard icon={MessageSquare} label="Sessions"         value={String(s.sessions)}             sub="distinct sessions" accent="emerald" />
            <StatCard icon={Sparkles}    label="Messages"           value={formatNumber(s.messages)}        sub="across all sessions" />
            <StatCard icon={Activity}    label="Active days"        value={String(s.activeDays)}           sub="with at least one session" accent="emerald" />
            <StatCard icon={Flame}       label="Current streak"     value={String(s.currentStreak)}        sub="consecutive days" accent="amber" />
            <StatCard
              icon={Star}
              label="Favorite model"
              value={s.favoriteModel ? s.favoriteModel : '—'}
              sub={s.favoriteModel ? `${s.favoriteModelShare.toFixed(1)}% share` : 'no model data'}
              accent="blue"
            />
          </div>

          {/* Heatmap + donut */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-3">
            <div className="lg:col-span-2">
              <Heatmap cells={heatmap.data?.results || []} />
            </div>
            <Donut data={byModel.data?.results || []} total={total} />
          </div>
        </>
      )}
    </div>
  );
}

/* v4.2 — Live settings tab: pick STT/TTS provider/model/voice.
   Empty values mean "use provider default". Providers and models are
   sourced from the aggregated model list and provider availability,
   replacing the old text-input approach with <select> dropdowns.
   See spec §14. */
import { useState, useMemo } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { WorkspaceField } from '@/components/workspace/WorkspaceField';
import {
  getLiveConfig,
  updateLiveConfig,
  type LiveConfig,
} from '@/api/api-client';
import { useProviderAvailability } from '@/hooks/useProviderAvailability';
import { useModels, type ModelItem } from '@/hooks/useModels';

interface Field<T = string> {
  key: keyof LiveConfig;
  label: string;
  hint: string;
  inputType: 'select' | 'text';
  testid: string;
  /** For 'select' fields: provide options. For provider fields, use
   *  the provider-availability hook; for model fields, filter by
   *  the selected provider. */
  dependsOn?: 'provider' | 'model';
}

const FIELDS: Field[] = [
  {
    key: 'sttProvider',
    label: 'STT provider',
    hint: 'Speech-to-text provider. Empty = browser Web Speech API.',
    inputType: 'select',
    testid: 'live-stt-provider',
  },
  {
    key: 'sttModel',
    label: 'STT model',
    hint: 'Provider-specific model id. Empty = provider default.',
    inputType: 'select',
    testid: 'live-stt-model',
    dependsOn: 'provider',
  },
  {
    key: 'ttsProvider',
    label: 'TTS provider',
    hint: 'Text-to-speech provider. Empty = browser speechSynthesis.',
    inputType: 'select',
    testid: 'live-tts-provider',
  },
  {
    key: 'ttsModel',
    label: 'TTS model',
    hint: 'Provider-specific model id. Empty = provider default.',
    inputType: 'select',
    testid: 'live-tts-model',
    dependsOn: 'provider',
  },
  {
    key: 'ttsVoice',
    label: 'TTS voice',
    hint: 'Voice name or id (e.g. "alloy", "nova", "shimmer").',
    inputType: 'text',
    testid: 'live-tts-voice',
  },
];

export function LiveSettingsTab() {
  const qc = useQueryClient();

  const liveQ = useQuery({
    queryKey: ['live-config'],
    queryFn: () => getLiveConfig(),
  });

  const { providers: availableProviders } = useProviderAvailability();
  const { models } = useModels();

  const initial: LiveConfig = liveQ.data ?? {
    sttProvider: '',
    sttModel: '',
    ttsProvider: '',
    ttsModel: '',
    ttsVoice: '',
  };
  const [editCfg, setEditCfg] = useState<LiveConfig | null>(null);
  const [saving, setSaving] = useState(false);

  const active = editCfg ?? initial;
  const dirty =
    editCfg !== null && JSON.stringify(editCfg) !== JSON.stringify(initial);

  /** All unique provider names from the availability list. */
  const providerOptions = useMemo(
    () => [
      { value: '', label: '(use browser default)' },
      ...availableProviders.map((p) => ({
        value: p.id,
        label: p.name,
      })),
    ],
    [availableProviders],
  );

  /** Models filtered by the currently-selected provider for a given group. */
  const getModelOptions = (providerKey: keyof LiveConfig) => {
    const selectedProvider = active[providerKey === 'sttModel' ? 'sttProvider' : 'ttsProvider'] as string;
    if (!selectedProvider) return [{ value: '', label: '(use provider default)' }];

    const filtered = models.filter(
      (m: ModelItem) => m.provider.toLowerCase() === selectedProvider.toLowerCase(),
    );
    return [
      { value: '', label: '(use provider default)' },
      ...filtered.map((m: ModelItem) => ({
        value: m.id,
        label: `${m.name} (${m.contextWindow?.toLocaleString() ?? '?'} ctx)`,
      })),
    ];
  };

  const handleSave = async () => {
    if (!editCfg) return;
    setSaving(true);
    try {
      await updateLiveConfig(editCfg);
      setEditCfg(null);
      qc.invalidateQueries({ queryKey: ['live-config'] });
      toast.success('Saved Live settings');
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Save failed');
    } finally {
      setSaving(false);
    }
  };

  const handleReset = () => {
    setEditCfg({
      sttProvider: '',
      sttModel: '',
      ttsProvider: '',
      ttsModel: '',
      ttsVoice: '',
    });
  };

  const handleFieldChange = (key: keyof LiveConfig, value: string) => {
    const next = { ...active, [key]: value } as LiveConfig;
    // If provider changed, clear the model selection
    if (key === 'sttProvider') next.sttModel = '';
    if (key === 'ttsProvider') next.ttsModel = '';
    setEditCfg(next);
  };

  if (liveQ.isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="size-6 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="space-y-6 max-w-2xl">
      <div className="rounded-xl border border-white/[0.06] bg-card/60 p-5 space-y-4">
        <div>
          <p className="text-sm font-semibold">Live (STT/TTS) settings</p>
          <p className="text-xs text-muted-foreground mt-0.5">
            Choose speech-to-text and text-to-speech providers for August Live.
            Leave any field empty to use the default. Selecting a provider
            upgrades transcription and voice quality.
          </p>
        </div>

        <div className="space-y-4">
          {FIELDS.map(({ key, label, hint, inputType, testid, dependsOn }) => (
            <div key={key} data-testid={`${testid}-field`}>
              <WorkspaceField label={label} hint={hint}>
                {inputType === 'select' ? (
                  <select
                    value={active[key] ?? ''}
                    onChange={(e) =>
                      handleFieldChange(key, e.target.value)
                    }
                    data-testid={`${testid}-input`}
                    className="w-full bg-black/20 border border-white/[0.06] rounded px-3 py-1.5 text-sm text-foreground focus:border-primary outline-none"
                  >
                    {dependsOn === 'provider'
                      ? (key === 'sttModel' || key === 'ttsModel'
                          ? getModelOptions(key)
                          : providerOptions
                        ).map((opt) => (
                          <option key={opt.value} value={opt.value}>
                            {opt.label}
                          </option>
                        ))
                      : providerOptions.map((opt) => (
                          <option key={opt.value} value={opt.value}>
                            {opt.label}
                          </option>
                        ))}
                  </select>
                ) : (
                  <input
                    type="text"
                    value={active[key] ?? ''}
                    onChange={(e) =>
                      setEditCfg({ ...active, [key]: e.target.value } as LiveConfig)
                    }
                    placeholder="(use browser default)"
                    data-testid={`${testid}-input`}
                    className="w-full bg-black/20 border border-white/[0.06] rounded px-3 py-1.5 text-sm text-foreground placeholder:text-muted-foreground/40 focus:border-primary outline-none"
                  />
                )}
              </WorkspaceField>
            </div>
          ))}
        </div>

        <div className="flex items-center justify-between pt-2 border-t border-white/[0.06]">
          <button
            type="button"
            onClick={handleReset}
            className="text-xs text-muted-foreground hover:text-foreground underline"
            data-testid="live-reset"
          >
            Reset to defaults
          </button>
          <div className="flex items-center gap-2">
            <button
              type="button"
              onClick={() => setEditCfg(null)}
              disabled={!dirty}
              className="px-3 py-1.5 text-xs rounded border border-white/[0.06] hover:bg-white/[0.06] disabled:opacity-50"
            >
              Cancel
            </button>
            <button
              type="button"
              onClick={handleSave}
              disabled={!dirty || saving}
              className="px-3 py-1.5 text-xs rounded bg-primary text-primary-foreground hover:opacity-90 disabled:opacity-50"
              data-testid="live-save"
            >
              {saving ? 'Saving…' : 'Save changes'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

/* v4.1 — Model Fleet tab: maps the four cognitive roles (cortex /
   cerebellum / hippocampus / prefrontal) to models. Plainly edits the
   `auxiliary.model_fleet` slice of config.json via /api/config/model-fleet. */
import { useState } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { WorkspaceField } from '@/components/workspace/WorkspaceField';
import { ModelPickerDropdown } from '@/components/overlays/ModelPickerDropdown';
import {
  getModelFleet,
  updateModelFleet,
  getAggregatedModels,
  type ModelFleetConfig,
  type AggregatedModel,
} from '@/api/api-client';

const ROLE_META: Array<{
  key: keyof ModelFleetConfig;
  label: string;
  hint: string;
}> = [
  {
    key: 'cortex',
    label: 'Cortex model',
    hint: 'Main reasoning model for the conscious chat loop. Empty = use the session model.',
  },
  {
    key: 'cerebellum',
    label: 'Cerebellum model',
    hint: 'Fast, cheap model for background daemons and watchers.',
  },
  {
    key: 'hippocampus',
    label: 'Hippocampus model',
    hint: 'Model for memory consolidation and preference inference (sleep cycle, delta engine).',
  },
  {
    key: 'prefrontal',
    label: 'Prefrontal model',
    hint: 'Highest-reasoning model for skill genesis and /Exam authoring.',
  },
];

export function ModelFleetTab() {
  const qc = useQueryClient();

  const fleetQ = useQuery({
    queryKey: ['model-fleet-config'],
    queryFn: () => getModelFleet(),
  });
  const modelsQ = useQuery({
    queryKey: ['aggregated-models'],
    queryFn: () => getAggregatedModels(),
  });

  const fleet: ModelFleetConfig = fleetQ.data ?? {
    cortex: '',
    cerebellum: '',
    hippocampus: '',
    prefrontal: '',
  };
  const [editFleet, setEditFleet] = useState<ModelFleetConfig | null>(null);
  const [saving, setSaving] = useState(false);

  const active = editFleet ?? fleet;
  const dirty =
    editFleet !== null && JSON.stringify(editFleet) !== JSON.stringify(fleet);

  // De-dupe model list (the aggregator can repeat ids across providers)
  const seen = new Set<string>();
  const models: AggregatedModel[] = (modelsQ.data?.models ?? []).filter((m) => {
    if (seen.has(m.id)) return false;
    seen.add(m.id);
    return true;
  });

  const handleSave = async () => {
    if (!editFleet) return;
    setSaving(true);
    try {
      await updateModelFleet(editFleet);
      setEditFleet(null);
      qc.invalidateQueries({ queryKey: ['model-fleet-config'] });
      toast.success('Saved Model Fleet settings');
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Save failed');
    } finally {
      setSaving(false);
    }
  };

  const handleReset = () => {
    const cleared: ModelFleetConfig = {
      cortex: '',
      cerebellum: '',
      hippocampus: '',
      prefrontal: '',
    };
    setEditFleet(cleared);
  };

  if (fleetQ.isLoading || modelsQ.isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="size-6 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="space-y-6 max-w-2xl">
      <div className="rounded-xl border border-white/[0.06] bg-card/60 p-5 space-y-4">
        <div>
          <p className="text-sm font-semibold">Model Fleet</p>
          <p className="text-xs text-muted-foreground mt-0.5">
            Choose a model for each cognitive role. The Cortex is the main
            conscious loop; Cerebellum, Hippocampus, and Prefrontal serve
            the subconscious daemons, memory consolidation, and skill
            genesis respectively. Leaving a field empty falls back to the
            chat session's primary model.
          </p>
        </div>

        <div className="space-y-4">
          {ROLE_META.map(({ key, label, hint }) => (
            <div key={key} data-testid={`fleet-${key}-field`}>
              <WorkspaceField label={label} hint={hint}>
                <div className="flex items-center gap-2">
                  <ModelPickerDropdown
                    models={models}
                    value={active[key] ?? ''}
                    onChange={(modelId) =>
                      setEditFleet({ ...active, [key]: modelId })
                    }
                  />
                  <button
                    type="button"
                    onClick={() => setEditFleet({ ...active, [key]: '' })}
                    disabled={active[key] === '' || active[key] === undefined}
                    className="text-[11px] text-muted-foreground hover:text-foreground underline disabled:opacity-30 disabled:cursor-not-allowed"
                    data-testid={`fleet-${key}-clear`}
                  >
                    Clear (use session model)
                  </button>
                </div>
              </WorkspaceField>
            </div>
          ))}
        </div>

        <div className="flex items-center justify-between pt-2 border-t border-white/[0.06]">
          <button
            type="button"
            onClick={handleReset}
            className="text-xs text-muted-foreground hover:text-foreground underline"
            data-testid="fleet-reset"
          >
            Reset to defaults
          </button>
          <div className="flex items-center gap-2">
            <button
              type="button"
              onClick={() => setEditFleet(null)}
              disabled={!dirty}
              className="px-3 py-1.5 text-xs rounded border border-white/[0.06] hover:bg-white/[0.06] disabled:opacity-50"
              data-testid="fleet-cancel"
            >
              Cancel
            </button>
            <button
              type="button"
              onClick={handleSave}
              disabled={!dirty || saving}
              className="px-3 py-1.5 text-xs rounded bg-primary text-primary-foreground hover:opacity-90 disabled:opacity-50"
              data-testid="fleet-save"
            >
              {saving ? 'Saving…' : 'Save changes'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

/* ── WorkspaceInspectorSection — inspector inside the workspace panel ── */
/* Reuses useConversationInspector hook for shared polling. Two-column
 * layout: left rail of requests, right pane with Readable / Raw /
 * Thinking tabs. */

import { useMemo, useState } from 'react';
import {
  MessagesSquare,
  Search,
  Brain,
  Inbox,
  ScrollText,
  Activity,
} from 'lucide-react';
import { useConversationInspector } from '@/sections/settings/useConversationInspector';
import { SettingsTabs } from '@/components/settings/SettingsTabs';
import { SettingsEmptyState } from '@/components/settings/SettingsEmptyState';
import { SettingsCard } from '@/components/settings/SettingsCard';
import { WorkspaceStatCard } from '@/components/workspace/WorkspaceStatCard';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { StatusPill } from '@/components/StatusPill';
import { formatTimeAgo, cn } from '@/lib/utils';
import { type Period } from '@/api/api-client';

const PERIODS: { key: Period; label: string }[] = [
  { key: 'today', label: 'Today' },
  { key: 'week', label: '7d' },
  { key: 'all', label: 'All' },
];

export function WorkspaceInspectorSection() {
  const [period, setPeriod] = useState<Period>('today');
  const [tab, setTab] = useState<string>('readable');
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [filter, setFilter] = useState('');

  const data = useConversationInspector(period);

  const rows = useMemo(() => {
    const f = filter.trim().toLowerCase();
    if (!f) return data.rows;
    return data.rows.filter((r) =>
      r.reqId.toLowerCase().includes(f) ||
      r.clientType.toLowerCase().includes(f) ||
      r.model.toLowerCase().includes(f),
    );
  }, [data.rows, filter]);

  const selected = data.select(selectedId);
  const errorCount = data.rows.filter((r) => r.isError).length;
  const thinkingCount = data.rows.filter((r) => r.hasThinking).length;

  return (
    <div className="px-8 py-6 space-y-6">
      <div className="flex items-start justify-between gap-4 flex-wrap">
        <div>
          <h1 className="text-2xl font-semibold tracking-tight text-foreground">Inspector</h1>
          <p className="mt-1 text-sm text-muted-foreground">
            Read a request as a conversation, inspect raw bodies, or view the model&apos;s thinking.
          </p>
        </div>
        <div className="flex items-center gap-1 text-[10px]">
          <span className="text-muted-foreground/70 uppercase tracking-wider mr-1">Period</span>
          {PERIODS.map((p) => (
            <button
              key={p.key}
              onClick={() => setPeriod(p.key)}
              className={cn(
                'rounded-md px-2 py-1 font-mono transition',
                period === p.key ? 'bg-primary text-primary-foreground' : 'text-muted-foreground hover:bg-accent',
              )}
            >
              {p.label}
            </button>
          ))}
        </div>
      </div>

      <div className="grid gap-3 sm:grid-cols-3">
        <WorkspaceStatCard icon={Activity} label="Requests" value={data.rows.length} sub={`${data.details.length} with detail`} accent="blue" />
        <WorkspaceStatCard icon={Inbox} label="Errors" value={errorCount} sub={errorCount > 0 ? 'Investigate on Raw tab' : 'No errors'} accent={errorCount > 0 ? 'amber' : 'default'} />
        <WorkspaceStatCard icon={Brain} label="With thinking" value={thinkingCount} sub="Reasoning traces captured" accent="default" />
      </div>

      <SettingsTabs
        value={tab}
        onChange={setTab}
        items={[
          { key: 'readable', label: 'Conversation', icon: MessagesSquare },
          { key: 'raw', label: 'Raw', icon: Search },
          { key: 'thinking', label: 'Thinking', icon: Brain },
        ]}
        label="Inspector views"
      />

      <div className="flex gap-4 min-h-[400px]">
        {/* Left rail: request list */}
        <aside className="w-72 shrink-0 rounded-xl border border-white/[0.06] bg-card/60 overflow-hidden flex flex-col">
          <div className="p-2 border-b border-white/[0.06]">
            <div className="relative">
              <Search className="absolute left-2 top-1/2 -translate-y-1/2 size-3.5 text-muted-foreground" />
              <input
                value={filter}
                onChange={(e) => setFilter(e.target.value)}
                placeholder="Filter by id, client, model…"
                aria-label="Filter requests"
                className="w-full pl-7 pr-2 py-1.5 text-xs bg-white/[0.04] rounded-md border border-white/[0.06] outline-none focus:border-primary/60"
              />
            </div>
          </div>
          <div className="flex-1 overflow-y-auto p-2 space-y-1">
            {rows.length === 0 ? (
              <div className="grid place-items-center py-8 text-center text-xs text-muted-foreground">
                {filter ? `No requests match "${filter}"` : 'No requests captured.'}
              </div>
            ) : (
              rows.slice(0, 80).map((r) => (
                <button
                  key={r.reqId}
                  onClick={() => setSelectedId(r.reqId)}
                  className={cn(
                    'w-full text-left rounded-md border px-2.5 py-2 transition',
                    selectedId === r.reqId ? 'border-primary bg-primary/5' : 'border-transparent hover:bg-white/[0.04]',
                  )}
                >
                  <div className="flex items-center gap-2">
                    <StatusPill tone={r.isError ? 'bad' : r.status === 'completed' ? 'good' : 'muted'} label={r.status.slice(0, 8)} />
                    <span className="text-sm font-medium truncate flex-1">{r.clientType}</span>
                    {r.hasThinking && <Brain className="size-3 text-warning shrink-0" />}
                  </div>
                  <p className="text-[10px] text-muted-foreground font-mono truncate mt-1">{r.reqId}</p>
                  <div className="flex items-center gap-1.5 mt-0.5 text-[10px] text-muted-foreground">
                    <span>{r.date ? formatTimeAgo(r.date) : '—'}</span>
                    <span>·</span>
                    <span className="truncate">{r.model}</span>
                  </div>
                </button>
              ))
            )}
          </div>
        </aside>

        {/* Right pane: selected request */}
        <div className="flex-1 min-w-0">
          {!selectedId || (!selected.detail && !selected.conversation) ? (
            <SettingsEmptyState icon={Inbox} title="Select a request" description="Click a row on the left to inspect its transcript, raw bodies, or thinking trace." />
          ) : (
            <div className="space-y-4">
              {tab === 'readable' && <ReadableTab conversation={selected.conversation} />}
              {tab === 'raw' && <RawTab detail={selected.detail} safeStringify={data.safeStringify} />}
              {tab === 'thinking' && <ThinkingTab trace={selected.trace} safeStringify={data.safeStringify} />}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function ReadableTab({ conversation }: { conversation: import('@/sections/settings/useConversationInspector').ConversationItem | null }) {
  if (!conversation || conversation.messages.length === 0) {
    return <SettingsEmptyState icon={Inbox} title="No transcript captured" description="The request has no readable messages." />;
  }
  return (
    <div className="space-y-3">
      {conversation.error && (
        <Card className="border-destructive/50">
          <CardContent className="p-3">
            <p className="text-[10px] uppercase tracking-wider text-destructive mb-1 font-semibold">Error</p>
            <pre className="text-[11px] font-mono whitespace-pre-wrap break-all bg-destructive/5 text-destructive p-2 rounded">{conversation.error}</pre>
          </CardContent>
        </Card>
      )}
      {conversation.messages.map((m, i) => (
        <div key={i} className={cn('flex', m.role === 'user' ? 'justify-end' : 'justify-start')}>
          <Card className={cn('max-w-[85%]', m.role === 'user' ? 'bg-white/[0.04]' : 'bg-card')}>
            <CardContent className="py-2.5 px-3">
              <div className="text-[10px] text-muted-foreground font-mono mb-1 font-semibold">{m.role}</div>
              <p className="text-sm whitespace-pre-wrap break-words">{m.content}</p>
            </CardContent>
          </Card>
        </div>
      ))}
      {conversation.finishReason && (
        <p className="text-[10px] text-muted-foreground font-mono px-1">finish_reason: {conversation.finishReason}</p>
      )}
    </div>
  );
}

function RawTab({ detail, safeStringify }: { detail: import('@/api/api-client').RequestDetailEntry | null; safeStringify: (v: unknown) => string }) {
  if (!detail) {
    return <SettingsEmptyState icon={Inbox} title="No captured detail" description="The request didn't make it into the detail log." />;
  }
  return (
    <div className="space-y-3">
      {detail.error && (
        <Card className="border-destructive/50">
          <CardContent className="p-3">
            <p className="text-[10px] uppercase tracking-wider text-destructive mb-1 font-semibold">Error</p>
            <pre className="text-[11px] font-mono whitespace-pre-wrap break-all bg-destructive/5 text-destructive p-2 rounded">{detail.error}</pre>
          </CardContent>
        </Card>
      )}
      <SettingsCard title="Request body" description="Sanitized request payload.">
        <pre className="text-[11px] font-mono whitespace-pre-wrap break-all bg-white/[0.04] p-3 rounded">{safeStringify(detail.requestBody) || <span className="text-muted-foreground italic">Not captured</span>}</pre>
      </SettingsCard>
      <SettingsCard title="Response body" description="Sanitized response payload.">
        <pre className="text-[11px] font-mono whitespace-pre-wrap break-all bg-white/[0.04] p-3 rounded">{safeStringify(detail.responseBody) || <span className="text-muted-foreground italic">Pending or not captured</span>}</pre>
      </SettingsCard>
    </div>
  );
}

function ThinkingTab({ trace, safeStringify }: { trace: import('@/sections/settings/useConversationInspector').ThinkingTrace | null; safeStringify: (v: unknown) => string }) {
  if (!trace) {
    return <SettingsEmptyState icon={Brain} title="No thinking trace" description="Reasoning traces appear when a provider returns them." />;
  }
  return (
    <SettingsCard
      icon={Brain}
      title={trace.finishReason ? 'Thinking trace' : 'Thinking (in progress)'}
      description="The reasoning the model produced before its final answer."
      status={<Badge variant={trace.finishReason ? 'success' : 'warning'} className="text-[9px]">{trace.finishReason ? 'done' : 'active'}</Badge>}
    >
      <pre className="text-xs font-mono whitespace-pre-wrap break-words bg-white/[0.04] p-3 rounded leading-relaxed">
        {safeStringify(trace.thinking)}
      </pre>
    </SettingsCard>
  );
}

/* ── WorkspaceMemorySection — Memory dashboard in the workspace panel ── */
/* Shows the Memory dashboard cards (store, vectors, facts, graph,
 * learning, guidelines) using the new WorkspaceStatCard primitive.
 * Below the cards, the existing Memory component is rendered for the
 * Facts / Vectors / Graph / Search / Prompt tabs. */

import { useQuery } from '@tanstack/react-query';
import { Database, Tag, Network, Activity, Shield, Sparkles } from 'lucide-react';
import { api } from '@/api/client';
import { Memory } from '@/sections/memory/Memory';
import { WorkspaceStatCard } from '@/components/workspace/WorkspaceStatCard';
import { Badge } from '@/components/ui/badge';
import { cn } from '@/lib/utils';

interface StoreStatus {
  count?: number;
  driver?: string;
  available?: boolean;
}
interface VectorData { entries?: unknown[] }
interface MemoryItems { items?: unknown[] }
interface GraphStats { stats?: { counts?: { entities?: number; relations?: number; observations?: number } } }
interface LearningStatus { status?: string; lastTopic?: string }
interface BrainDiagnostics { guidelines?: number; semanticFacts?: number; vectorEntries?: number }

export function WorkspaceMemorySection() {
  const storeStatus = useQuery<StoreStatus>({
    queryKey: ['ws-mem-store'],
    queryFn: () => api.get<StoreStatus>('/api/brain/status'),
    refetchInterval: 30_000,
  });
  const vectorData = useQuery<VectorData>({
    queryKey: ['ws-mem-vector'],
    queryFn: () => api.get<VectorData>('/api/brain/vectors'),
    refetchInterval: 30_000,
  });
  const memoryItems = useQuery<MemoryItems>({
    queryKey: ['ws-mem-items'],
    queryFn: () => api.get<MemoryItems>('/api/brain/items'),
    refetchInterval: 30_000,
  });
  const graphData = useQuery<GraphStats>({
    queryKey: ['ws-mem-graph'],
    queryFn: () => api.get<GraphStats>('/api/brain/graph'),
    refetchInterval: 60_000,
  });
  const brainData = useQuery<BrainDiagnostics>({
    queryKey: ['ws-mem-brain'],
    queryFn: () => api.get<BrainDiagnostics>('/api/brain/diagnostics'),
    refetchInterval: 30_000,
  });
  const learningData = useQuery<LearningStatus>({
    queryKey: ['ws-mem-learning'],
    queryFn: () => api.get<LearningStatus>('/api/brain/learning'),
    refetchInterval: 15_000,
  });

  const counts = graphData.data?.stats?.counts;
  const learning = learningData.data?.status ?? 'idle';
  const learningTone =
    learning === 'learning' ? 'warning'
    : learning === 'evolved' ? 'success'
    : learning === 'failed' ? 'destructive'
    : 'secondary';

  return (
    <div className="px-8 py-6 space-y-6">
      <div>
        <h1 className="text-2xl font-semibold tracking-tight text-foreground">Memory</h1>
        <p className="mt-1 text-sm text-muted-foreground">
          The self-evolving knowledge store, semantic facts, vector entries, and learning status.
        </p>
      </div>

      <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
        <WorkspaceStatCard
          icon={Database}
          label="Store"
          value={storeStatus.data?.count ?? '—'}
          sub={`${storeStatus.data?.driver ?? '—'}`}
          accent="emerald"
        />
        <WorkspaceStatCard
          icon={Database}
          label="Vector entries"
          value={vectorData.data?.entries?.length ?? 0}
          sub="embedding chunks"
          accent="blue"
        />
        <WorkspaceStatCard
          icon={Tag}
          label="Memory items"
          value={memoryItems.data?.items?.length ?? 0}
          sub="facts & integrations"
          accent="emerald"
        />
        <WorkspaceStatCard
          icon={Network}
          label="Knowledge graph"
          value={counts?.entities ?? '—'}
          sub={`${counts?.relations ?? 0} relations · ${counts?.observations ?? 0} obs`}
          accent="default"
        />
        <WorkspaceStatCard
          icon={Shield}
          label="Guidelines"
          value={brainData.data?.guidelines ?? 0}
          sub="learned rules"
          accent="default"
        />
        <WorkspaceStatCard
          icon={Sparkles}
          label="Learning"
          value={<Badge variant={learningTone}>{learning}</Badge>}
          sub={learningData.data?.lastTopic ?? 'No active topic'}
          accent="amber"
        />
      </div>

      {/* Existing Memory component (Facts / Vectors / Graph / Search / Prompt) */}
      <div className={cn('rounded-xl border border-white/[0.06] bg-card/40 overflow-hidden')}>
        <Memory />
      </div>
    </div>
  );
}

/* ── WorkspaceModelsSection — full Model settings CRUD ───────────────── */
