];

function fmtContextWindow(n?: number) {
  if (!n) return null;
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(0)}M`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(0)}K`;
  return n.toString();
}

export function WorkspaceModelsSection() {
  const [subtab, setSubtab] = useState<'providers' | 'aliases' | 'quotas' | 'all-models' | 'fallback' | 'reflection' | 'fleet' | 'live'>('providers');

  return (
    <div className="px-8 py-6 space-y-4 h-full flex flex-col">
      {/* Page header */}
      <div className="flex items-start justify-between gap-4 shrink-0">
        <div>
          <h1 className="text-2xl font-semibold tracking-tight text-foreground">Model settings</h1>
          <p className="mt-1 text-sm text-muted-foreground">
            Manage custom model providers. Once configured, they can be selected during chat.
          </p>
        </div>
      </div>

      <div className="shrink-0">
        <WorkspaceTabs
          value={subtab}
          onChange={(k) => setSubtab(k as 'providers' | 'aliases' | 'quotas' | 'all-models' | 'fallback' | 'reflection' | 'fleet')}
          items={SUBTABS}
          label="Model settings subtabs"
        />
      </div>

      <div className="flex-1 min-h-0 overflow-auto">
        {subtab === 'providers' && <ProvidersTab />}
        {subtab === 'all-models' && <AllModelsTab />}
        {subtab === 'aliases'   && <AliasesTab />}
        {subtab === 'fallback'  && <FallbackTab />}
        {subtab === 'reflection' && <BackgroundReflectionTab />}
        {subtab === 'fleet'     && <ModelFleetTab />}
        {subtab === 'live'      && <LiveSettingsTab />}
        {subtab === 'quotas'    && <QuotasTab />}
      </div>
    </div>
  );
}

/* ── Providers subtab — existing two-column CRUD ────────────────────── */

function ProvidersTab() {
  const qc = useQueryClient();
  const listQ = useQuery({
    queryKey: ['ws-providers'],
    queryFn: () => providersApi.list(),
  });
  const providers = listQ.data ?? [];

  const [mode, setMode] = useState<'add' | 'edit' | 'empty'>('empty');
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [showAddModel, setShowAddModel] = useState(false);
  // Track whether the initial auto-select has happened so the effect
  // doesn't run again when the user clicks "Add provider" (which sets
  // selectedId to null) and immediately re-selects the first provider.
  const didInitRef = useRef(false);

  // Auto-select the first provider on the initial load only.
  useEffect(() => {
    if (didInitRef.current) return;
    if (listQ.isLoading) return;
    didInitRef.current = true;
    if (providers.length > 0) {
      setSelectedId(providers[0].id);
      setMode('edit');
    } else {
      setMode('add');
    }
    // Only re-run when the providers query transitions out of loading.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [listQ.isLoading]);

  const selected = providers.find((p) => p.id === selectedId) ?? null;

  const invalidate = () => {
    qc.invalidateQueries({ queryKey: ['ws-providers'] });
    qc.invalidateQueries({ queryKey: ['aggregated-models'] });
    qc.invalidateQueries({ queryKey: ['mp-aggregated-models'] });
  };

  function selectProvider(id: string) {
    setSelectedId(id);
    setMode('edit');
    setShowAddModel(false);
  }

  function openAddProvider() {
    setMode('add');
    setSelectedId(null);
    setShowAddModel(false);
  }

  return (
    <div className="space-y-3 h-full flex flex-col">
      <div className="grid grid-cols-[260px_1fr] gap-4 flex-1 min-h-0">
        {/* LEFT: provider list */}
        <div className="rounded-xl border border-white/[0.06] bg-card/60 flex flex-col overflow-hidden">
          <div className="px-3 py-2 border-b border-white/[0.06] flex items-center justify-between">
            <p className="text-[10px] uppercase tracking-widest text-muted-foreground/70 font-semibold">Providers</p>
            <button
              onClick={() => listQ.refetch()}
              aria-label="Refresh providers"
              className="text-muted-foreground hover:text-foreground transition"
            >
              <RefreshCw className={cn('size-3', listQ.isFetching && 'animate-spin')} />
            </button>
          </div>
          <div className="flex-1 overflow-y-auto p-1 space-y-0.5">
            {providers.length === 0 ? null : (
              providers.map((p) => (
                <button
                  key={p.id}
                  onClick={() => selectProvider(p.id)}
                  className={cn(
                    'w-full flex items-center gap-2 rounded-md px-3 py-2 text-sm text-left transition',
                    selectedId === p.id
                      ? 'bg-white/[0.06] text-foreground'
                      : 'text-muted-foreground hover:bg-white/[0.03] hover:text-foreground',
                  )}
                >
                  <Server className="size-3.5 shrink-0" />
                  <span className="flex-1 truncate">{p.name}</span>
                  {p.enabled && <span className="size-2 rounded-full bg-success" title="enabled" />}
                </button>
              ))
            )}
          </div>
          <div className="border-t border-white/[0.06] p-2">
            <button
              onClick={openAddProvider}
              className="w-full flex items-center justify-center gap-1.5 rounded-md border border-white/[0.08] px-3 py-2 text-sm text-muted-foreground hover:text-foreground hover:bg-white/[0.04] transition"
            >
              <Plus className="size-3.5" />
              Add provider
            </button>
          </div>
        </div>

        {/* RIGHT: editor / add form / empty state */}
        <div className="rounded-xl border border-white/[0.06] bg-card/60 flex flex-col overflow-hidden">
          {mode === 'add' ? (
            <AddProviderForm
              onCancel={() => {
                if (selected) {
                  setMode('edit');
                } else {
                  setMode('empty');
                }
              }}
              onCreated={(p) => {
                invalidate();
                selectProvider(p.id);
              }}
            />
          ) : mode === 'edit' && selected ? (
            <ProviderEditor
              key={selected.id}
              provider={selected}
              onChanged={invalidate}
              showAddModel={showAddModel}
              setShowAddModel={setShowAddModel}
            />
          ) : null}
        </div>
      </div>
    </div>
  );
}

/* ── Quotas subtab — lifted from the old Models section ─────────────── */

function QuotasTab() {
  return <QuotasPanel />;
}

/* ── All models subtab — every model from every provider, with Discover all */

interface AllModelRow {
  id: string;
  name?: string;
  contextWindow?: number;
  reasoning?: boolean;
  free?: boolean;
  source: 'manual' | 'fetched';
  providerId: string;
  providerName: string;
  enabled: boolean;
  apiKeySet: boolean;
  baseUrl: string;
}

function AllModelsTab() {
  const qc = useQueryClient();
  const listQ = useQuery({
    queryKey: ['ws-providers'],
    queryFn: () => providersApi.list(),
  });
  const [query, setQuery] = useState('');
  const [discovering, setDiscovering] = useState(false);

  const rows = useMemo<AllModelRow[]>(() => {
    const out: AllModelRow[] = [];
    for (const p of listQ.data ?? []) {
      for (const m of p.models ?? []) {
        out.push({
          id: m.id,
          name: m.name,
          contextWindow: m.contextWindow,
          reasoning: !!m.reasoning,
          free: !!m.free,
          source: m.source,
          providerId: p.id,
          providerName: p.name,
          enabled: !!p.enabled,
          apiKeySet: !!p.apiKeySet,
          baseUrl: p.baseUrl,
        });
      }
    }
    out.sort((a, b) => {
      if (a.providerName !== b.providerName) return a.providerName.localeCompare(b.providerName);
      return a.id.localeCompare(b.id);
    });
    return out;
  }, [listQ.data]);

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return rows;
    return rows.filter(
      (r) =>
        r.id.toLowerCase().includes(q) ||
        (r.name?.toLowerCase().includes(q) ?? false) ||
        r.providerName.toLowerCase().includes(q) ||
        r.providerId.toLowerCase().includes(q),
    );
  }, [rows, query]);

  // Group filtered rows by provider for display
  const grouped = useMemo(() => {
    const map = new Map<string, AllModelRow[]>();
    for (const r of filtered) {
      if (!map.has(r.providerId)) map.set(r.providerId, []);
      map.get(r.providerId)!.push(r);
    }
    return Array.from(map.entries());
  }, [filtered]);

  const totalModels = rows.length;
  const fetchedCount = rows.filter((r) => r.source === 'fetched').length;
  const manualCount = rows.filter((r) => r.source === 'manual').length;
  const reasoningCount = rows.filter((r) => r.reasoning).length;

  const refreshAll = useMutation({
    mutationFn: async () => {
      const providers = (listQ.data ?? []).filter(
        (p) => p.enabled && p.apiKeySet && p.baseUrl,
      );
      const results: Array<{ provider: string; added: number; updated: number; removed: number; error?: string }> = [];
      for (const p of providers) {
        try {
          const res = await providersApi.refreshModels(p.id);
          results.push({ provider: p.name, added: res.added.length, updated: res.updated.length, removed: res.removed.length });
        } catch (e: unknown) {
          results.push({
            provider: p.name,
            added: 0,
            updated: 0,
            removed: 0,
            error: e instanceof Error ? e.message : 'refresh failed',
          });
        }
      }
      return results;
    },
    onSuccess: (results) => {
      const ok = results.filter((r) => !r.error);
      const fail = results.filter((r) => r.error);
      if (ok.length) {
        const totalAdded = ok.reduce((s, r) => s + r.added, 0);
        const totalUpdated = ok.reduce((s, r) => s + r.updated, 0);
        toast.success(
          `Discovered: +${totalAdded} new, ${totalUpdated} updated across ${ok.length} provider${ok.length === 1 ? '' : 's'}`,
        );
      }
      if (fail.length) {
        toast.error(`Failed for ${fail.length} provider${fail.length === 1 ? '' : 's'}: ${fail.map((f) => f.provider).join(', ')}`);
      }
      qc.invalidateQueries({ queryKey: ['ws-providers'] });
      qc.invalidateQueries({ queryKey: ['aggregated-models'] });
      setDiscovering(false);
    },
    onError: () => {
      setDiscovering(false);
      toast.error('Discover all failed');
    },
  });

  function startDiscoverAll() {
    if (!providersDiscoverable(listQ.data ?? [])) {
      toast.error('No providers are configured yet. Add a provider and a key first.');
      return;
    }
    setDiscovering(true);
    refreshAll.mutate();
  }

  return (
    <div className="space-y-3 h-full flex flex-col">
      {/* Summary + actions */}
      <div className="rounded-xl border border-white/[0.06] bg-card/60 p-4 flex items-center justify-between gap-3 flex-wrap shrink-0">
        <div className="flex items-center gap-6 flex-wrap">
          <div>
            <p className="text-[10px] uppercase tracking-wider text-muted-foreground">All models</p>
            <p className="text-xl font-semibold tabular-nums">{totalModels.toLocaleString()}</p>
          </div>
          <div>
            <p className="text-[10px] uppercase tracking-wider text-muted-foreground">Discovered</p>
            <p className="text-xl font-semibold tabular-nums text-blue-400">{fetchedCount.toLocaleString()}</p>
          </div>
          <div>
            <p className="text-[10px] uppercase tracking-wider text-muted-foreground">Manual</p>
            <p className="text-xl font-semibold tabular-nums">{manualCount.toLocaleString()}</p>
          </div>
          <div>
            <p className="text-[10px] uppercase tracking-wider text-muted-foreground">Reasoning</p>
            <p className="text-xl font-semibold tabular-nums text-warning">{reasoningCount.toLocaleString()}</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <div className="relative">
            <Search className="absolute left-2 top-1/2 -translate-y-1/2 size-3.5 text-muted-foreground" />
            <Input
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Filter by id, name, or provider…"
              aria-label="Filter models"
              className="pl-7 w-64"
            />
          </div>
          <Button
            onClick={startDiscoverAll}
            disabled={discovering || refreshAll.isPending}
            title="Fetch every provider's /v1/models and merge into the catalog"
          >
            {discovering || refreshAll.isPending ? (
              <Loader2 className="size-3.5 animate-spin" />
            ) : (
              <Sparkles className="size-3.5" />
            )}
            {discovering || refreshAll.isPending ? 'Discovering…' : 'Discover all'}
          </Button>
        </div>
      </div>

      {/* Table */}
      {totalModels === 0 ? (
        <WorkspaceEmptyState
          icon={Boxes}
          title="No models yet"
          description={
            providersDiscoverable(listQ.data ?? [])
              ? 'Click Discover all to fetch /v1/models from every configured provider. Manual models can also be added per provider.'
              : 'No providers configured yet. Add a provider on the Providers tab first, then come back here to discover models.'
          }
          action={
            providersDiscoverable(listQ.data ?? []) ? (
              <Button onClick={startDiscoverAll}>
                <Sparkles className="size-3.5" /> Discover all
              </Button>
            ) : null
          }
          className="py-8"
        />
      ) : (
        <div className="rounded-xl border border-white/[0.06] bg-card/60 flex-1 overflow-auto">
          {grouped.length === 0 ? (
            <div className="p-8 text-center text-sm text-muted-foreground">
              No models match "{query}".
            </div>
          ) : (
            <div className="divide-y divide-white/[0.06]">
              {grouped.map(([providerId, providerRows]) => {
                const first = providerRows[0];
                return (
                  <div key={providerId}>
                    <div className="sticky top-0 z-10 bg-card/95 backdrop-blur px-4 py-2 border-b border-white/[0.06] flex items-center gap-3">
                      <Server className="size-3.5 text-muted-foreground" />
                      <span className="text-sm font-semibold">{first.providerName}</span>
                      <span className="text-[10px] font-mono text-muted-foreground/70">{providerId}</span>
                      {!first.enabled && (
                        <span className="rounded bg-white/[0.06] px-1.5 py-0.5 text-[10px] font-mono text-muted-foreground">
                          disabled
                        </span>
                      )}
                      <span className="ml-auto text-[10px] text-muted-foreground/70 font-mono">
                        {providerRows.length} model{providerRows.length === 1 ? '' : 's'}
                      </span>
                    </div>
                    <div className="divide-y divide-white/[0.06]/50">
                      {providerRows.map((r) => (
                        <AllModelRow key={`${r.providerId}::${r.id}`} row={r} />
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function AllModelRow({ row }: { row: AllModelRow }) {
  const ctx = fmtContextWindow(row.contextWindow);
  return (
    <div className="grid grid-cols-[1fr_80px_90px_90px_70px] gap-3 items-center px-4 py-2 text-sm">
      <div className="min-w-0">
        <span className="font-mono truncate block">{row.name || row.id}</span>
        {row.name && row.name !== row.id && (
          <span className="font-mono text-[10px] text-muted-foreground/70 truncate block">{row.id}</span>
        )}
      </div>
      {ctx ? (
        <span className="rounded bg-white/[0.06] px-1.5 py-0.5 text-[10px] font-mono text-muted-foreground text-center">
          {ctx}
        </span>
      ) : (
        <span className="text-[10px] text-muted-foreground/40 text-center">—</span>
      )}
      <span
        className={cn(
          'rounded px-1.5 py-0.5 text-[10px] font-mono text-center',
          row.source === 'fetched'
            ? 'bg-blue-500/15 text-blue-400'
            : 'bg-white/[0.06] text-muted-foreground',
        )}
        title={`source: ${row.source}`}
      >
        {row.source}
      </span>
      <span className="text-[10px] text-muted-foreground text-center font-mono">
        {row.providerId}
      </span>
      <span className="text-center">
        {row.reasoning ? (
          <span className="rounded bg-warning/15 px-1.5 py-0.5 text-[10px] font-mono text-warning">
            reasoning
          </span>
        ) : (
          <span className="text-[10px] text-muted-foreground/40">—</span>
        )}
      </span>
    </div>
  );
}

function providersDiscoverable(providers: Provider[]): boolean {
  return providers.some((p) => p.enabled && p.apiKeySet && !!p.baseUrl);
}

/* ── Aliases subtab — user-defined model aliases (replaces lost feature) */

function AliasesTab() {
  const qc = useQueryClient();
  const aliasQ = useQuery({
    queryKey: ['user-model-aliases'],
    queryFn: () => getUserModelAliases(),
  });
  const modelsQ = useQuery({
    queryKey: ['aggregated-models'],
    queryFn: () => getAggregatedModels(),
  });

  // Local edits buffer — only persisted on Save.
  const [edits, setEdits] = useState<UserModelAlias[] | null>(null);
  const [aliases, setAliases] = useState<UserModelAlias[]>([]);
  useEffect(() => {
    if (aliasQ.data && edits === null) {
      setAliases(aliasQ.data.aliases ?? []);
    }
  }, [aliasQ.data, edits]);
  const visible = edits ?? aliases;
  const dirty = edits !== null && JSON.stringify(edits) !== JSON.stringify(aliases);
  const [saving, setSaving] = useState(false);
  const [restarting, setRestarting] = useState(false);

  const restartMut = useMutation({
    mutationFn: () => restartBackend(),
    onSuccess: () => toast.success('Backend restart requested'),
    onError: (e: unknown) => toast.error(e instanceof Error ? e.message : 'Restart failed'),
  });

  function startEdit() {
    setEdits(aliases.map((a) => ({ ...a })));
  }
  function cancelEdit() {
    setEdits(null);
  }
  function commitAliasChange(idx: number, patch: Partial<UserModelAlias>) {
    const base = edits ?? aliases;
    const next = base.map((a, i) => (i === idx ? { ...a, ...patch } : a));
    if (edits === null) setEdits(next);
    else setEdits(next);
  }
  function addAlias() {
    const next = [...(edits ?? aliases), { alias: '', targetModel: '', targetProvider: '' }];
    if (edits === null) setEdits(next);
    else setEdits(next);
  }
  function removeAlias(idx: number) {
    const base = edits ?? aliases;
    const next = base.filter((_, i) => i !== idx);
    if (edits === null) setEdits(next);
    else setEdits(next);
  }

  async function save() {
    const payload = (edits ?? aliases).filter((a) => a.alias.trim() && a.targetModel.trim());
    setSaving(true);
    try {
      await updateUserModelAliases(payload);
      setAliases(payload);
      setEdits(null);
      qc.invalidateQueries({ queryKey: ['user-model-aliases'] });
      qc.invalidateQueries({ queryKey: ['aggregated-models'] });
      toast.success(`Saved ${payload.length} alias${payload.length === 1 ? '' : 'es'}`);
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Save failed');
    } finally {
      setSaving(false);
    }
  }

  async function handleRestart() {
    if (!window.confirm('Restart the backend? This will briefly interrupt active requests.')) return;
    setRestarting(true);
    try {
      await restartMut.mutateAsync();
    } finally {
      setRestarting(false);
    }
  }

  const models: AggregatedModel[] = (modelsQ.data?.models ?? []).map((m) => ({
    ...m,
    isFree: m.isFree ?? false,
  }));
  const seen = new Set<string>();
  const availableModels = models.filter((m) => {
    if (seen.has(m.id)) return false;
    seen.add(m.id);
    return true;
  });

  return (
    <div className="space-y-3 h-full flex flex-col">
      <div className="rounded-xl border border-white/[0.06] bg-card/60 p-5 space-y-3 flex-1 overflow-auto">
        <div className="flex items-center justify-between gap-3 flex-wrap">
          <div>
            <p className="text-sm font-semibold">User-defined model aliases</p>
            <p className="text-xs text-muted-foreground mt-0.5">
              Map a custom alias (e.g. <code className="text-[10px] font-mono">my-claude-opus</code>) to
              any real model. The alias shows up in the chat dropdown and proxies to the target provider.
            </p>
          </div>
          <div className="flex items-center gap-2 shrink-0">
            <Button size="sm" variant="outline" onClick={() => aliasQ.refetch()} title="Refresh model list">
              <RefreshCw className="size-3" /> Refresh
            </Button>
            {!dirty && (
              <Button size="sm" variant="outline" onClick={startEdit}>
                <Pencil className="size-3" /> Edit
              </Button>
            )}
            <Button size="sm" variant="outline" onClick={addAlias} disabled={!edits && false}>
              <Plus className="size-3" /> Add alias
            </Button>
            {dirty && (
              <>
                <Button size="sm" variant="outline" onClick={cancelEdit}>
                  Cancel
                </Button>
                <Button size="sm" onClick={save} disabled={saving}>
                  {saving ? <Loader2 className="size-3 animate-spin" /> : <Check className="size-3" />}
                  {saving ? 'Saving…' : 'Save'}
                </Button>
              </>
            )}
            <Button size="sm" variant="destructive" onClick={handleRestart} disabled={restarting} title="Restart backend to pick up alias changes">
              <RefreshCw className="size-3" /> {restarting ? 'Restarting…' : 'Restart'}
            </Button>
          </div>
        </div>

        {visible.length === 0 ? (
          <WorkspaceEmptyState
            icon={ArrowRightLeft}
            title="No aliases yet"
            description="Click 'Add alias' to create one. Useful for naming a specific model+provider combo behind a memorable id."
            className="py-6"
          />
        ) : (
          <div className="rounded-lg border border-white/[0.06] overflow-hidden">
            <div className="grid grid-cols-[1fr_2fr_120px_36px] gap-2 px-3 py-2 text-[10px] uppercase tracking-wider text-muted-foreground border-b border-white/[0.06] font-mono">
              <span>Alias name</span>
              <span>Target model</span>
              <span>Provider</span>
              <span />
            </div>
            <div className="divide-y divide-white/[0.06]">
              {visible.map((a, i) => {
                const editing = edits !== null;
                return (
                  <div key={i} className="grid grid-cols-[1fr_2fr_120px_36px] gap-2 px-3 py-2 text-xs items-center font-mono">
                    <Input
                      value={a.alias}
                      onChange={(e) => commitAliasChange(i, { alias: e.target.value })}
                      placeholder="my-fake-model"
                      className="h-7 text-xs font-mono"
                      disabled={!editing}
                    />
                    <ModelPickerDropdown
                      models={availableModels}
                      value={a.targetModel}
                      onChange={(modelId, provider) => commitAliasChange(i, { targetModel: modelId, targetProvider: provider })}
                      disabled={!editing}
                    />
                    <span className="text-muted-foreground truncate text-[10px]">
                      {a.targetProvider || '—'}
                    </span>
                    <Button
                      variant="ghost"
                      size="icon-sm"
                      onClick={() => removeAlias(i)}
                      disabled={!editing}
                      className="text-destructive/60 hover:text-destructive"
                      aria-label="Remove alias"
                    >
                      <Trash2 className="size-3" />
                    </Button>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {!dirty && aliases.length > 0 && (
          <p className="text-[10px] text-muted-foreground font-mono">
            Aliases persist to <code className="text-[10px]">config.json → modelAliases</code>.
            Restart the backend for changes to take effect.
          </p>
        )}
        {dirty && (
          <Badge variant="warning" className="text-[10px]">unsaved changes</Badge>
        )}
      </div>
    </div>
  );
}

/* ── Fallback subtab — sub-agent fallback settings ──────────────────── */

function FallbackTab() {
  const qc = useQueryClient();
  const fallbackQ = useQuery({
    queryKey: ['subagent-fallback-config'],
    queryFn: () => getSubAgentFallback(),
  });
  const modelsQ = useQuery({
    queryKey: ['aggregated-models'],
    queryFn: () => getAggregatedModels(),
  });

  const [fallbackConfig, setFallbackConfig] = useState<SubAgentFallbackConfig>({
    enabled: false,
    mode: 'session_only',
    provider: '',
    model: '',
  });
  const [fallbackEdits, setFallbackEdits] = useState<SubAgentFallbackConfig | null>(null);
  const [testing, setTesting] = useState(false);

  useEffect(() => {
    if (fallbackQ.data && fallbackEdits === null) {
      setFallbackConfig(fallbackQ.data);
    }
  }, [fallbackQ.data, fallbackEdits]);

  const activeFallback = fallbackEdits ?? fallbackConfig;
  const fallbackDirty = fallbackEdits !== null && JSON.stringify(fallbackEdits) !== JSON.stringify(fallbackConfig);

  const models: AggregatedModel[] = (modelsQ.data?.models ?? []).map((m) => ({
    ...m,
    isFree: m.isFree ?? false,
  }));
  const seen = new Set<string>();
  const availableModels = models.filter((m) => {
    if (seen.has(m.id)) return false;
    seen.add(m.id);
    return true;
  });

  async function testFallback() {
    if (!activeFallback.enabled) {
      toast.warning('Enable fallback before testing');
      return;
    }
    setTesting(true);
    try {
      const res = await fetch('/api/config/subagent-fallback/test', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ model: 'probe-non-alias' }),
      });
      const data = await res.json();
      if (data?.translationWarning) toast.warning(data.translationWarning);
      if (data?.ok && data.result?.resolution) {
        toast.success(`Resolves to ${data.result.resolution.model} via ${data.result.resolution.provider}`);
      } else if (data?.result?.action && data.result.action.startsWith('reject')) {
        toast.error(`Fallback rejected: ${data.result.action}`);
      } else {
        toast.warning('Fallback did not resolve — check config or catalog state');
      }
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Test failed');
    } finally {
      setTesting(false);
    }
  }

  return (
    <div className="space-y-3 h-full flex flex-col">
      <div className="rounded-xl border border-white/[0.06] bg-card/60 p-5 space-y-4 flex-1 overflow-auto">
        <div>
          <p className="text-sm font-semibold">Sub-agent fallback settings</p>
          <p className="text-xs text-muted-foreground mt-0.5">
            Configure a fallback model for incoming sub-agent/tool-call requests when there are no active alias sessions.
          </p>
        </div>

        <div className="flex items-center justify-between p-3 rounded-lg border border-white/[0.06] bg-black/10">
          <div>
            <p className="text-xs font-semibold">Enable fallback</p>
            <p className="text-[10px] text-muted-foreground">Route unknown/non-alias model requests to the fallback model.</p>
          </div>
          <WorkspaceToggle
            enabled={activeFallback.enabled}
            onToggle={(checked) => {
              const next = { ...activeFallback, enabled: checked };
              setFallbackEdits(next);
            }}
            disabled={fallbackQ.isFetching}
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <WorkspaceField label="Fallback mode">
            <WorkspaceSelect
              value={activeFallback.mode}
              onChange={(e) => {
                const next = { ...activeFallback, mode: e.target.value as any };
                setFallbackEdits(next);
              }}
              options={[
                { value: 'session_only', label: 'Session only (highly recommended)' },
                { value: 'marked_subagent_only', label: 'Marked sub-agent only' },
                { value: 'always', label: 'Always' },
                { value: 'off', label: 'Off' }
              ]}
              disabled={!activeFallback.enabled}
            />
          </WorkspaceField>

          <WorkspaceField label="Fallback model">
            <ModelPickerDropdown
              models={availableModels}
              value={activeFallback.model}
              onChange={(modelId, provider) => {
                const next = { ...activeFallback, model: modelId, provider };
                setFallbackEdits(next);
              }}
              disabled={!activeFallback.enabled}
            />
          </WorkspaceField>
        </div>

        {activeFallback.enabled && activeFallback.mode === 'always' && (
          <div className="p-3 rounded-lg border border-yellow-500/20 bg-yellow-500/5 text-yellow-500 text-xs flex gap-2">
            <span className="font-semibold shrink-0">Warning:</span>
            <span>Always mode may route misspelled model names to the fallback instead of failing with an error.</span>
          </div>
        )}

        {activeFallback.enabled && activeFallback.model && (
          <p className="text-[10px] text-muted-foreground font-mono">
            Unknown sub-agent model requests will route to <code className="text-[10px] text-foreground">{activeFallback.model}</code>
            {activeFallback.provider && (
              <> via <code className="text-[10px] text-foreground">{activeFallback.provider}</code></>
            )}.
          </p>
        )}

        <div className="flex items-center justify-end gap-2 pt-2">
          <Button
            size="sm"
            variant="outline"
            onClick={testFallback}
            disabled={testing || !activeFallback.enabled}
          >
            {testing ? <Loader2 className="size-3 animate-spin" /> : <Bot className="size-3" />}
            Test fallback
          </Button>
          {fallbackDirty && (
            <>
              <Button size="sm" variant="outline" onClick={() => setFallbackEdits(null)}>
                Cancel
              </Button>
              <Button size="sm" onClick={async () => {
                try {
                  await updateSubAgentFallback(activeFallback);
                  setFallbackConfig(activeFallback);
                  setFallbackEdits(null);
                  qc.invalidateQueries({ queryKey: ['subagent-fallback-config'] });
                  toast.success('Saved fallback settings');
                } catch (e: unknown) {
                  toast.error(e instanceof Error ? e.message : 'Save failed');
                }
              }}>
                <Check className="size-3" /> Save fallback settings
              </Button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

/* ── Background & Reflection subtab ────────────────────────────────── */

const DEFAULT_BG_CONFIG: ReviewBackgroundConfig = {
  enabled: false,
  reviewModel: '',
  reflectionModel: '',
  autoMemoryModel: '',
};

function BackgroundReflectionTab() {
  const qc = useQueryClient();

  const bgQ = useQuery({
    queryKey: ['review-background-config'],
    queryFn: () => getReviewBackgroundConfig(),
  });
  const modelsQ = useQuery({
    queryKey: ['aggregated-models'],
    queryFn: () => getAggregatedModels(),
  });

  const config: ReviewBackgroundConfig = bgQ.data ?? DEFAULT_BG_CONFIG;
  const [editConfig, setEditConfig] = useState<ReviewBackgroundConfig | null>(null);
  const [saving, setSaving] = useState(false);

  const activeConfig = editConfig ?? config;
  const dirty = editConfig !== null && JSON.stringify(editConfig) !== JSON.stringify(config);

  // Show ALL models from ALL providers — the ModelPickerDropdown groups them
  // by provider automatically. No provider pre-filter needed.
  const models: AggregatedModel[] = (modelsQ.data?.models ?? []).map((m) => ({
    ...m,
    isFree: m.isFree ?? false,
  }));
  const seen = new Set<string>();
  const availableModels = models.filter((m) => {
    if (seen.has(m.id)) return false;
    seen.add(m.id);
    return true;
  });

  const handleSave = async () => {
    if (!editConfig) return;
    setSaving(true);
    try {
      await updateReviewBackgroundConfig(editConfig);
      setEditConfig(null);
      qc.invalidateQueries({ queryKey: ['review-background-config'] });
      toast.success('Saved background review settings');
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Save failed');
    } finally {
      setSaving(false);
    }
  };

  if (bgQ.isLoading || modelsQ.isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="size-6 animate-spin text-muted-foreground" />
      </div>
    );
  }

  const noModels = availableModels.length === 0;

  return (
    <div className="space-y-6 max-w-2xl">
      <div className="rounded-xl border border-white/[0.06] bg-card/60 p-5 space-y-4">
        <div>
          <p className="text-sm font-semibold">Background review & reflection</p>
          <p className="text-xs text-muted-foreground mt-0.5">
            Configure separate models for background review, reflection, and auto‑memory extraction.
            When a task has no model selected (or background tasks are disabled), the chat session model is used automatically.
          </p>
        </div>

        <div className="flex items-center justify-between p-3 rounded-lg border border-white/[0.06] bg-black/10">
          <div>
            <p className="text-xs font-semibold">Enable background tasks</p>
            <p className="text-[10px] text-muted-foreground">Route background tasks to the models configured below.</p>
          </div>
          <WorkspaceToggle
            enabled={activeConfig.enabled}
            onToggle={(checked) => setEditConfig({ ...activeConfig, enabled: checked })}
            disabled={bgQ.isFetching}
          />
        </div>

        {noModels ? (
          <div className="p-3 rounded-lg border border-white/[0.06] bg-black/10 text-xs text-muted-foreground">
            No models available. Please add a provider first.
          </div>
        ) : (
          <div className="space-y-4">
            <WorkspaceField
              label="Review model"
              hint="Used for reviewing and summarising conversations."
            >
              <ModelPickerDropdown
                models={availableModels}
                value={activeConfig.reviewModel}
                onChange={(modelId) => setEditConfig({ ...activeConfig, reviewModel: modelId })}
                disabled={!activeConfig.enabled}
              />
            </WorkspaceField>

            <WorkspaceField
              label="Reflection model"
              hint="Used for the agent's self‑evaluation and learning loop."
            >
              <ModelPickerDropdown
                models={availableModels}
                value={activeConfig.reflectionModel}
                onChange={(modelId) => setEditConfig({ ...activeConfig, reflectionModel: modelId })}
                disabled={!activeConfig.enabled}
              />
            </WorkspaceField>

            <WorkspaceField
              label="Auto‑memory extraction model"
              hint="Used for extracting facts and storing them in memory."
            >
              <ModelPickerDropdown
                models={availableModels}
                value={activeConfig.autoMemoryModel}
                onChange={(modelId) => setEditConfig({ ...activeConfig, autoMemoryModel: modelId })}
                disabled={!activeConfig.enabled}
              />
            </WorkspaceField>
          </div>
        )}

        <p className="text-xs text-muted-foreground">
          If no model is selected for a task, the system will automatically use the chat session's model.
        </p>
      </div>

      <div className="flex items-center gap-2">
        {dirty && (
          <>
            <Button size="sm" onClick={handleSave} disabled={saving}>
              {saving ? 'Saving...' : 'Save'}
            </Button>
            <Button size="sm" variant="secondary" onClick={() => setEditConfig(null)}>
              Cancel
            </Button>
          </>
        )}
      </div>
    </div>
  );
}

/* ── Add provider form (matches the screenshot "Add model provider") ──── */

function AddProviderForm({
  onCancel,
  onCreated,
}: {
  onCancel: () => void;
  onCreated: (p: Provider) => void;
}) {
  const [name, setName] = useState('');
  const [baseUrl, setBaseUrl] = useState('');
  const [apiKey, setApiKey] = useState('');
  const [showKey, setShowKey] = useState(false);
  const [apiFormat, setApiFormat] = useState<ApiFormat>(DEFAULT_API_FORMAT);

  const create = useMutation({
    mutationFn: () =>
      providersApi.create({ name, baseUrl, apiFormat, apiKey, enabled: true }),
    onSuccess: (p) => {
      toast.success(`Created ${p.name}`);
      onCreated(p);
    },
    onError: (e: unknown) => {
      toast.error(e instanceof Error ? e.message : 'Failed to create provider');
    },
  });

  const valid = name.trim() && baseUrl.trim();

  return (
    <div className="flex-1 overflow-y-auto">
      {/* Header — matches screenshot */}
      <div className="px-5 pt-4 pb-3 border-b border-white/[0.06] flex items-center justify-between gap-3">
        <div>
          <h3 className="text-base font-semibold">Add model provider</h3>
          <p className="mt-0.5 text-xs text-muted-foreground">
            Configure a custom API endpoint and initial model.
          </p>
        </div>
        <Button variant="ghost" size="sm" onClick={onCancel}>
          Cancel
        </Button>
      </div>

      <div className="p-5 space-y-4">
        <WorkspaceField label="Name">
          <Input
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="e.g. DeepSeek"
            autoFocus
          />
        </WorkspaceField>

        <WorkspaceField label="Base URL">
          <Input
            value={baseUrl}
            onChange={(e) => setBaseUrl(e.target.value)}
            placeholder="https://api.example.com/v1"
          />
        </WorkspaceField>

        <WorkspaceField label="API key">
          <div className="relative">
            <Input
              type={showKey ? 'text' : 'password'}
              value={apiKey}
              onChange={(e) => setApiKey(e.target.value)}
              placeholder="Enter API key"
              autoComplete="off"
            />
            <button
              type="button"
              onClick={() => setShowKey((v) => !v)}
              aria-label={showKey ? 'Hide API key' : 'Show API key'}
              className="absolute right-2 top-1/2 -translate-y-1/2 grid size-7 place-items-center rounded text-muted-foreground hover:text-foreground transition"
            >
              {showKey ? <EyeOff className="size-3.5" /> : <Eye className="size-3.5" />}
            </button>
          </div>
        </WorkspaceField>

        <WorkspaceField label="API format">
          <WorkspaceSelect
            value={apiFormat}
            onChange={(e) => setApiFormat(e.target.value as ApiFormat)}
            options={API_FORMATS}
          />
        </WorkspaceField>

        {/* Footer — matches screenshot: Create filled + Add provider outline */}
        <div className="flex items-center justify-end gap-2 pt-4">
          <Button
            variant="outline"
            onClick={() => create.mutate()}
            disabled={!valid || create.isPending}
          >
            {create.isPending ? <Loader2 className="size-3.5 animate-spin" /> : <Plus className="size-3.5" />}
            Add provider
          </Button>
          <Button onClick={() => create.mutate()} disabled={!valid || create.isPending}>
            {create.isPending ? <Loader2 className="size-3.5 animate-spin" /> : <Check className="size-3.5" />}
            Create
          </Button>
        </div>
      </div>
    </div>
  );
}

/* ── Provider editor (right pane) ────────────────────────────────────── */

function ProviderEditor({
  provider,
  onChanged,
  showAddModel,
  setShowAddModel,
}: {
  provider: Provider;
  onChanged: () => void;
  showAddModel: boolean;
  setShowAddModel: (v: boolean) => void;
}) {
  const [name, setName] = useState(provider.name);
  const [baseUrl, setBaseUrl] = useState(provider.baseUrl);
  const [apiFormat, setApiFormat] = useState<ApiFormat>(provider.apiFormat);
  const [apiKey, setApiKey] = useState(provider.apiKey ?? '');
  const [showKey, setShowKey] = useState(false);
  const [confirmClearKey, setConfirmClearKey] = useState(false);
  const [autoFetch, setAutoFetch] = useState(!!provider.autoFetch);
  const [editingName, setEditingName] = useState(false);

  // Re-sync local state when the selected provider changes.
  useEffect(() => {
    setName(provider.name);
    setBaseUrl(provider.baseUrl);
    setApiFormat(provider.apiFormat);
    setApiKey(provider.apiKey ?? '');
    setAutoFetch(!!provider.autoFetch);
    setShowAddModel(false);
    setConfirmClearKey(false);
  }, [provider.id, provider.name, provider.baseUrl, provider.apiFormat, provider.apiKey, provider.autoFetch, setShowAddModel]);

  const update = useMutation({
    mutationFn: (patch: Partial<{ name: string; baseUrl: string; apiFormat: ApiFormat; apiKey: string; enabled: boolean; autoFetch: boolean }>) =>
      providersApi.update(provider.id, patch),
    onSuccess: () => {
      toast.success('Saved');
      onChanged();
    },
    onError: (e: unknown) => {
      toast.error(e instanceof Error ? e.message : 'Save failed');
    },
  });

  const remove = useMutation({
    mutationFn: () => providersApi.remove(provider.id),
    onSuccess: () => {
      toast.success(`Deleted ${provider.name}`);
      onChanged();
    },
  });

  const refresh = useMutation({
    mutationFn: () => providersApi.refreshModels(provider.id),
    onSuccess: (res) => {
      toast.success(`Refreshed: ${res.added.length} added, ${res.updated.length} updated, ${res.removed.length} removed`);
      onChanged();
    },
    onError: (e: unknown) => {
      toast.error(e instanceof Error ? e.message : 'Refresh failed');
    },
  });

  const clearKeyMutation = useMutation({
    mutationFn: () => providersApi.update(provider.id, { apiKey: '' }),
    onSuccess: () => {
      toast.success('API key cleared');
      setConfirmClearKey(false);
      onChanged();
    },
    onError: (e: unknown) => {
      toast.error(e instanceof Error ? e.message : 'Failed to clear key');
    },
  });

  // Auto-fetch when the toggle is turned on.
  useEffect(() => {
    if (autoFetch && provider.apiKeySet && provider.baseUrl && !refresh.isPending) {
      refresh.mutate();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [autoFetch]);

  function flushField<K extends 'name' | 'baseUrl' | 'apiKey'>(field: K, value: string) {
    if (field === 'name') setName(value);
    if (field === 'baseUrl') setBaseUrl(value);
    if (field === 'apiKey') setApiKey(value);
    update.mutate({ [field]: value } as never);
  }

  return (
    <div className="flex-1 overflow-y-auto">
      {/* Provider header */}
      <div className="px-5 pt-4 pb-3 border-b border-white/[0.06] flex items-center justify-between gap-3">
        <div className="flex items-center gap-2">
          {editingName ? (
            <Input
              value={name}
              onChange={(e) => setName(e.target.value)}
              onBlur={() => { setEditingName(false); flushField('name', name); }}
              onKeyDown={(e) => { if (e.key === 'Enter') { setEditingName(false); flushField('name', name); } }}
              className="h-7 text-base font-semibold w-48"
              autoFocus
            />
          ) : (
            <>
              <span className="text-base font-semibold">{name || provider.name}</span>
              <button
                onClick={() => setEditingName(true)}
                aria-label="Edit provider name"
                title="Edit provider name"
                className="grid size-7 place-items-center rounded text-muted-foreground hover:bg-white/[0.06] hover:text-foreground transition"
              >
                <Pencil className="size-3.5" />
              </button>
            </>
          )}
        </div>
        <div className="flex items-center gap-2">
          <WorkspaceToggle
            enabled={provider.enabled}
            onToggle={(next) => update.mutate({ enabled: next })}
            disabled={update.isPending}
          />
          <button
            onClick={() => {
              if (confirm(`Delete provider "${provider.name}" and all its models?`)) remove.mutate();
            }}
            aria-label="Delete provider"
            className="grid size-8 place-items-center rounded-md text-muted-foreground hover:bg-destructive/10 hover:text-destructive transition"
          >
            <Trash2 className="size-4" />
          </button>
        </div>
      </div>

      <div className="p-5 space-y-4">
        <WorkspaceField label="Base URL">
          <Input
            value={baseUrl}
            onChange={(e) => setBaseUrl(e.target.value)}
            onBlur={() => baseUrl !== provider.baseUrl && flushField('baseUrl', baseUrl)}
            placeholder="https://api.example.com/v1"
          />
        </WorkspaceField>

        <WorkspaceField label="API format">
          <WorkspaceSelect
            value={apiFormat}
            onChange={(e) => {
              const v = e.target.value as ApiFormat;
              setApiFormat(v);
              update.mutate({ apiFormat: v });
            }}
            options={API_FORMATS}
          />
        </WorkspaceField>

        <WorkspaceField
          label="API key"
          hint={provider.apiKeySet ? 'A key is set. Enter a new one to replace it. Stored keys take precedence over environment variables.' : undefined}
        >
          <div className="space-y-2">
            <div className="relative">
              <Input
                type={showKey ? 'text' : 'password'}
                value={apiKey}
                onChange={(e) => setApiKey(e.target.value)}
                onBlur={() => apiKey && flushField('apiKey', apiKey)}
                placeholder={provider.apiKeySet ? '••••••••••••••••' : 'sk-…'}
                autoComplete="off"
              />
              {provider.apiKeySet && (
                <button
                  type="button"
                  onClick={() => setConfirmClearKey(true)}
                  className="absolute right-9 top-1/2 -translate-y-1/2 inline-flex items-center gap-1 rounded px-1.5 py-1 text-[11px] text-muted-foreground hover:text-destructive transition"
                  aria-label="Clear stored API key"
                >
                  <Trash2 className="size-3" />
                  Clear
                </button>
              )}
              <button
                type="button"
                onClick={async () => {
                  // If the key isn't loaded yet (e.g. stale cache), fetch it
                  if (!apiKey && provider.apiKeySet) {
                    try {
                      const full = await providersApi.get(provider.id);
                      if (full.apiKey) setApiKey(full.apiKey);
                    } catch {
                      // Best-effort; key stays empty
                    }
                  }
                  setShowKey((v) => !v);
                }}
                aria-label={showKey ? 'Hide API key' : 'Show API key'}
                className="absolute right-2 top-1/2 -translate-y-1/2 grid size-7 place-items-center rounded text-muted-foreground hover:text-foreground transition"
              >
                {showKey ? <EyeOff className="size-3.5" /> : <Eye className="size-3.5" />}
              </button>
            </div>
            {confirmClearKey && provider.apiKeySet && (
              <div className="rounded-lg border border-warning/40 bg-warning/10 p-3 space-y-2">
                <p className="text-xs text-warning">
                  Clear the stored API key? The provider will fall back to the
                  <code className="mx-1 px-1 rounded bg-black/30 text-[10px] font-mono">
                    {provider.id.toUpperCase().replace(/-/g, '_')}_API_KEY
                  </code>
                  environment variable if it is set.
                </p>
                <div className="flex items-center justify-end gap-2">
                  <Button
                    size="sm"
                    variant="ghost"
                    onClick={() => setConfirmClearKey(false)}
                    disabled={clearKeyMutation.isPending}
                  >
                    Cancel
                  </Button>
                  <Button
                    size="sm"
                    variant="destructive"
                    onClick={() => clearKeyMutation.mutate()}
                    disabled={clearKeyMutation.isPending}
                  >
                    {clearKeyMutation.isPending ? (
                      <Loader2 className="size-3 animate-spin" />
                    ) : (
                      <Trash2 className="size-3" />
                    )}
                    Clear key
                  </Button>
                </div>
              </div>
            )}
          </div>
        </WorkspaceField>

        {/* Model discovery */}
        <div className="flex items-center justify-between rounded-lg border border-white/[0.06] p-3">
          <div>
            <p className="text-sm font-medium">Model discovery from <code className="text-xs font-mono">/v1/models</code></p>
            <p className="text-xs text-muted-foreground mt-0.5">
              When on, August finds every model the provider exposes and adds them here.
              Use the refresh icon to re-discover now.
            </p>
          </div>
          <div className="flex items-center gap-2">
            <button
              onClick={() => refresh.mutate()}
              disabled={refresh.isPending || !provider.apiKeySet}
              aria-label="Refresh models now"
              className="text-muted-foreground hover:text-foreground transition disabled:opacity-50"
            >
              <RefreshCw className={cn('size-3.5', refresh.isPending && 'animate-spin')} />
            </button>
            <button
              type="button"
              role="switch"
              aria-checked={autoFetch}
              onClick={() => {
                const next = !autoFetch;
                setAutoFetch(next);
                update.mutate({ autoFetch: next });
              }}
              className={cn(
                'relative inline-flex h-5 w-9 shrink-0 items-center rounded-full transition',
                autoFetch ? 'bg-primary' : 'bg-white/[0.15]',
              )}
            >
              <span
                className={cn(
                  'inline-block size-4 transform rounded-full bg-white shadow transition',
                  autoFetch ? 'translate-x-4' : 'translate-x-0.5',
                )}
              />
            </button>
          </div>
        </div>

        {/* Model list */}
        <div>
          <p className="text-sm font-medium mb-2">Model list</p>
          {provider.models.length === 0 ? (
            <p className="text-xs text-muted-foreground italic py-4">No models yet. Add one below or enable Model discovery.</p>
          ) : (
            <div className="rounded-lg border border-white/[0.06] divide-y divide-white/[0.06] overflow-hidden">
              {provider.models.map((m) => (
                <ModelRow
                  key={m.id}
                  providerId={provider.id}
                  model={m}
                  onChanged={onChanged}
                />
              ))}
            </div>
          )}
          <div className="mt-2 flex">
            <button
              onClick={() => setShowAddModel(true)}
              className="inline-flex items-center gap-1.5 rounded-md border border-dashed border-white/[0.15] px-3 py-1.5 text-xs text-muted-foreground hover:text-foreground hover:border-white/[0.3] transition"
            >
              <Plus className="size-3" />
              Add model
            </button>
          </div>
          {showAddModel && (
            <AddModelForm
              providerId={provider.id}
              onCancel={() => setShowAddModel(false)}
              onCreated={() => {
                onChanged();
                setShowAddModel(false);
              }}
            />
          )}
        </div>
      </div>
    </div>
  );
}

/* ── Model row ───────────────────────────────────────────────────────── */

function ModelRow({
  providerId,
  model,
  onChanged,
}: {
  providerId: string;
  model: Provider['models'][number];
  onChanged: () => void;
}) {
  const [editing, setEditing] = useState(false);
  const [name, setName] = useState(model.name ?? model.id);
  const [contextWindow, setContextWindow] = useState(model.contextWindow?.toString() ?? '');
  const [reasoning, setReasoning] = useState(!!model.reasoning);
  const [testResult, setTestResult] = useState<null | { ok: boolean; error?: string; latencyMs: number }>(null);

  const update = useMutation({
    mutationFn: () => providersApi.updateModel(providerId, model.id, {
      name,
      contextWindow: contextWindow ? Number(contextWindow) : undefined,
      reasoning,
    }),
    onSuccess: () => {
      setEditing(false);
      onChanged();
      toast.success('Saved');
    },
  });
  const remove = useMutation({
    mutationFn: () => providersApi.removeModel(providerId, model.id),
    onSuccess: () => {
      onChanged();
      toast.success(`Removed ${model.id}`);
    },
  });
  const connect = useMutation({
    mutationFn: () => providersApi.connectModel(providerId, model.id),
    onSuccess: (res) => {
      setTestResult({ ok: res.success, error: res.error, latencyMs: res.latencyMs });
      if (res.success) toast.success(`${model.id} responded in ${res.latencyMs}ms`);
    },
    onError: (e: unknown) => {
      setTestResult({ ok: false, error: e instanceof Error ? e.message : 'Connection failed', latencyMs: 0 });
    },
  });

  const ctx = fmtContextWindow(model.contextWindow);

  if (editing) {
    return (
      <div
        className="px-3 py-3 space-y-2 bg-primary/5 border-l-2 border-primary"
        data-editing="true"
      >
        <div className="flex items-center gap-2">
          <Pencil className="size-3 text-primary" />
          <span className="text-[11px] uppercase tracking-caps font-semibold text-primary">
            Editing
          </span>
          <span className="text-xs font-mono text-muted-foreground truncate">{model.id}</span>
        </div>
        <div className="border-t border-border/30 pt-2 space-y-2">
          <div className="grid grid-cols-[1fr_120px] gap-2">
            <Input
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Display name"
              aria-label="Display name"
            />
            <Input
              value={contextWindow}
              onChange={(e) => setContextWindow(e.target.value)}
              placeholder="context window"
              type="number"
              aria-label="Context window"
            />
          </div>
          <label className="flex items-center gap-2 text-xs">
            <input type="checkbox" checked={reasoning} onChange={(e) => setReasoning(e.target.checked)} />
            Supports reasoning
          </label>
          <div className="flex gap-2">
            <Button size="sm" onClick={() => update.mutate()} disabled={update.isPending}>
              {update.isPending ? 'Saving…' : 'Save changes'}
            </Button>
            <Button size="sm" variant="ghost" onClick={() => setEditing(false)}>
              Cancel
            </Button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="px-3 py-2.5 text-sm">
      <div className="flex items-center gap-3">
        <div className="flex-1 min-w-0">
          <span className="font-medium truncate">{model.name || model.id}</span>
        </div>
        <span
          className={cn(
            'inline-flex items-center rounded px-1.5 py-0.5 text-[10px] font-mono',
            model.source === 'fetched'
              ? 'bg-blue-500/15 text-blue-400'
              : 'bg-white/[0.06] text-muted-foreground',
          )}
          title={`source: ${model.source}`}
        >
          {model.source}
        </span>
        {ctx && (
          <span className="rounded bg-white/[0.06] px-1.5 py-0.5 text-[10px] font-mono text-muted-foreground">
            {ctx}
          </span>
        )}
        {model.reasoning && (
          <span className="rounded bg-warning/15 px-1.5 py-0.5 text-[10px] font-mono text-warning">
            reasoning
          </span>
        )}
        <button
          onClick={() => connect.mutate()}
          disabled={connect.isPending}
          aria-label="Test model connection"
          title="Test connection to this model"
          className="grid size-7 place-items-center rounded text-muted-foreground hover:bg-white/[0.06] hover:text-foreground transition disabled:opacity-50"
        >
          {connect.isPending ? (
            <Loader2 className="size-3.5 animate-spin" />
          ) : (
            <Plug className="size-3.5" />
          )}
        </button>
        <button
          onClick={() => setEditing(true)}
          aria-label="Edit model"
          title="Edit display name and metadata"
          className="grid size-7 place-items-center rounded text-muted-foreground hover:bg-white/[0.06] hover:text-foreground transition"
        >
          <Pencil className="size-3.5" />
        </button>
        <button
          onClick={() => {
            if (confirm(`Remove model "${model.id}"?`)) remove.mutate();
          }}
          aria-label="Delete model"
          title="Remove this model"
          className="grid size-7 place-items-center rounded text-muted-foreground hover:bg-destructive/10 hover:text-destructive transition"
        >
          <Trash2 className="size-3.5" />
        </button>
      </div>
      {testResult && (
        <div
          className={cn(
            'flex items-center gap-1.5 text-[11px] mt-1.5 pl-0.5',
            testResult.ok ? 'text-success' : 'text-danger',
          )}
          role={testResult.ok ? 'status' : 'alert'}
          aria-live="polite"
        >
          {testResult.ok ? (
            <>
              <CheckCircle2 className="size-3" />
              <span>Working · {testResult.latencyMs}ms</span>
            </>
          ) : (
            <>
              <AlertCircle className="size-3" />
              <span className="truncate" title={testResult.error}>
                {testResult.error || 'Connection failed'}
              </span>
            </>
          )}
        </div>
      )}
    </div>
  );
}

/* ── Add model form ──────────────────────────────────────────────────── */

function AddModelForm({
  providerId,
  onCancel,
  onCreated,
}: {
  providerId: string;
  onCancel: () => void;
  onCreated: () => void;
}) {
  const [id, setId] = useState('');
  const [name, setName] = useState('');
  const [contextWindow, setContextWindow] = useState('');
  const [reasoning, setReasoning] = useState(false);

  const create = useMutation({
    mutationFn: () =>
      providersApi.addModel(providerId, {
        id,
        name: name || undefined,
        contextWindow: contextWindow ? Number(contextWindow) : undefined,
        reasoning,
      }),
    onSuccess: () => {
      toast.success(`Added ${id}`);
      onCreated();
    },
    onError: (e: unknown) => {
      toast.error(e instanceof Error ? e.message : 'Failed to add model');
    },
  });

  return (
    <div className="mt-2 rounded-lg border border-white/[0.06] bg-white/[0.02] p-3 space-y-2">
      <div className="grid grid-cols-[1fr_1fr_120px] gap-2">
        <Input value={id} onChange={(e) => setId(e.target.value)} placeholder="model-id" />
        <Input value={name} onChange={(e) => setName(e.target.value)} placeholder="Display name (optional)" />
        <Input value={contextWindow} onChange={(e) => setContextWindow(e.target.value)} placeholder="context" type="number" />
      </div>
      <label className="flex items-center gap-2 text-xs">
        <input type="checkbox" checked={reasoning} onChange={(e) => setReasoning(e.target.checked)} />
        Supports reasoning
      </label>
      <div className="flex gap-2">
        <Button size="sm" onClick={() => create.mutate()} disabled={!id.trim() || create.isPending}>
          {create.isPending ? <Loader2 className="size-3 animate-spin" /> : <Check className="size-3" />}
          Add
        </Button>
        <Button size="sm" variant="ghost" onClick={onCancel}>
          Cancel
        </Button>
      </div>
    </div>
  );
}

/* ── WorkspaceUsageSection — Usage dashboard with the screenshot style ─ */
/* 6 stat cards, activity heatmap, tokens-per-day bar chart, model-usage
 * donut. All three visualizations read from /api/usage/* endpoints;
 * the bar chart uses the new /api/usage/by-day endpoint. */

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import {
  Hash,
  MessageSquare,
  Sparkles,
  Activity,
  Flame,
  Star,
  RefreshCw,
} from 'lucide-react';
import { usageApi, type UsageRange } from '@/api/usage';
import { WorkspaceStatCard } from '@/components/workspace/WorkspaceStatCard';
import { WorkspaceHeatmap } from '@/components/workspace/WorkspaceHeatmap';
import { WorkspaceBarChart } from '@/components/workspace/WorkspaceBarChart';
import { WorkspaceDonut } from '@/components/workspace/WorkspaceDonut';
import { SettingsTabs } from '@/components/settings/SettingsTabs';
import { cn } from '@/lib/utils';

const RANGES: { key: UsageRange; label: string }[] = [
  { key: '7d', label: 'Last 7 days' },
  { key: '30d', label: 'Last 30 days' },
];

export function WorkspaceUsageSection() {
  const [range, setRange] = useState<UsageRange>('30d');
  const [subtab, setSubtab] = useState<string>('app');

  const statsQ = useQuery({
    queryKey: ['ws-usage-stats', range],
    queryFn: () => usageApi.stats(range),
    refetchInterval: 30_000,
  });
  const heatmapQ = useQuery({
    queryKey: ['ws-usage-heatmap', range],
    queryFn: () => usageApi.heatmap(range),
    refetchInterval: 60_000,
  });
  const byModelQ = useQuery({
    queryKey: ['ws-usage-by-model', range],
    queryFn: () => usageApi.byModel(range),
    refetchInterval: 60_000,
  });
  const byDayQ = useQuery({
    queryKey: ['ws-usage-by-day', range],
    queryFn: () => usageApi.byDay(range),
    refetchInterval: 60_000,
  });

  const stats = statsQ.data;
  const heatmap = heatmapQ.data?.results ?? [];
  const byModel = byModelQ.data?.results ?? [];
  const byDay = (byDayQ.data?.results ?? []).map((d) => ({ date: d.date, value: d.tokens }));

  return (
    <div className="px-8 py-6 space-y-6">
      <div className="flex items-start justify-between gap-4 flex-wrap">
        <div>
          <h1 className="text-2xl font-semibold tracking-tight text-foreground">Usage</h1>
          <p className="mt-1 text-sm text-muted-foreground">App usage</p>
        </div>
        <div className="flex items-center gap-3">
          <span className="text-xs text-muted-foreground/70 uppercase tracking-wider">Time range</span>
          <div className="flex items-center gap-1 rounded-md bg-white/[0.04] p-0.5 border border-white/[0.06]">
            {RANGES.map((r) => (
              <button
                key={r.key}
                onClick={() => setRange(r.key)}
                className={cn(
                  'rounded px-3 py-1 text-xs font-medium transition',
                  range === r.key
                    ? 'bg-white/[0.08] text-foreground'
                    : 'text-muted-foreground hover:text-foreground',
                )}
              >
                {r.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      <SettingsTabs
        value={subtab}
        onChange={setSubtab}
        items={[
          { key: 'app', label: 'App usage', icon: Activity },
          { key: 'per-model', label: 'Per model', icon: Star },
        ]}
        label="Usage subviews"
      />

      {subtab === 'app' && (
        <>
          {/* 6 stat cards in 3 columns × 2 rows */}
          <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
            <WorkspaceStatCard
              icon={Hash}
              label="Token usage"
              value={stats ? stats.totalTokens.toLocaleString() : '—'}
              sub={`Across ${stats?.sessions ?? 0} sessions`}
              accent="blue"
            />
            <WorkspaceStatCard
              icon={MessageSquare}
              label="Sessions"
              value={stats?.sessions.toLocaleString() ?? '—'}
              sub={`${stats?.messages.toLocaleString() ?? 0} messages`}
              accent="emerald"
            />
            <WorkspaceStatCard
              icon={Activity}
              label="Active days"
              value={stats?.activeDays.toLocaleString() ?? '—'}
              sub={`Current streak: ${stats?.currentStreak ?? 0}`}
              accent="default"
            />
            <WorkspaceStatCard
              icon={Sparkles}
              label="Messages"
              value={stats?.messages.toLocaleString() ?? '—'}
              sub="in this period"
              accent="default"
            />
            <WorkspaceStatCard
              icon={Flame}
              label="Current streak"
              value={stats?.currentStreak.toLocaleString() ?? '—'}
              sub="consecutive days"
              accent="amber"
            />
            <WorkspaceStatCard
              icon={Star}
              label="Favorite model"
              value={stats?.favoriteModel ?? '—'}
              sub={stats ? `${stats.favoriteModelShare.toFixed(1)}% share` : '—'}
              accent="blue"
            />
          </div>

          {/* Activity heatmap */}
          <div className="rounded-xl border border-white/[0.06] bg-card/60 p-5 space-y-3">
            <div className="flex items-center justify-between">
              <span className="text-sm font-semibold">Activity heatmap</span>
              <button
                onClick={() => heatmapQ.refetch()}
                aria-label="Refresh heatmap"
                className="text-muted-foreground hover:text-foreground transition"
              >
                <RefreshCw className="size-3.5" />
              </button>
            </div>
            <WorkspaceHeatmap cells={heatmap} />
          </div>

          {/* Tokens-per-day bar chart */}
          <div className="rounded-xl border border-white/[0.06] bg-card/60 p-5 space-y-3">
            <div className="flex items-center justify-between">
              <span className="text-sm font-semibold">Tokens per day</span>
              <button
                onClick={() => byDayQ.refetch()}
                aria-label="Refresh bar chart"
                className="text-muted-foreground hover:text-foreground transition"
              >
                <RefreshCw className="size-3.5" />
              </button>
            </div>
            <WorkspaceBarChart bars={byDay} unit="tokens" />
          </div>
        </>
      )}

      {subtab === 'per-model' && (
        <div className="rounded-xl border border-white/[0.06] bg-card/60 p-5">
          <div className="text-sm font-semibold mb-4">Model usage</div>
          <WorkspaceDonut
            slices={byModel.map((m) => ({
              label: m.model,
              value: m.tokens,
              percent: m.percent,
            }))}
            centerLabel={stats?.totalTokens.toLocaleString() ?? '—'}
            centerSub="tokens"
          />
        </div>
      )}
    </div>
  );
}

/* ── WorkspaceModelsSection regression tests for black-screen bugs ────── */
/* These tests render the Fallback and Background & Reflection subtabs via
 * the main section and assert that no full-viewport overlay element or
 * Provider field/select is present.
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import { WorkspaceModelsSection } from '../WorkspaceModelsSection';

const mockAggregatedModels = {
  models: [
    { id: 'gpt-4o', name: 'GPT-4o', provider: 'openai', contextWindow: 128000, isFree: false },
    { id: 'claude-sonnet', name: 'Claude Sonnet', provider: 'anthropic', contextWindow: 200000, isFree: false },
  ],
};

const mockFallbackConfig = {
  config: {
    enabled: false,
    mode: 'session_only',
    provider: '',
    model: '',
  },
};

const mockBackgroundConfig = {
  enabled: false,
  provider: '',
  model: '',
};

let fallbackMock: any = { data: mockFallbackConfig, isLoading: false, isFetching: false };
let backgroundMock: any = { data: mockBackgroundConfig, isLoading: false, isFetching: false };
let modelsMock: any = { data: mockAggregatedModels, isLoading: false };

vi.mock('@tanstack/react-query', async (importOriginal) => {
  const actual = await importOriginal<typeof import('@tanstack/react-query')>();
  return {
    ...actual,
    useQuery: (opts: any) => {
      const key = JSON.stringify(opts.queryKey);
      if (key.includes('subagent-fallback-config')) return fallbackMock;
      if (key.includes('review-background-config')) return backgroundMock;
      if (key.includes('aggregated-models')) return modelsMock;
      return { data: null, isLoading: false };
    },
    useMutation: (opts: any) => ({
      mutate: vi.fn(),
      mutateAsync: vi.fn(),
      isPending: false,
      isIdle: true,
      isError: false,
      error: null,
    }),
    useQueryClient: () => ({ invalidateQueries: vi.fn() }),
  };
});

vi.mock('sonner', () => ({ toast: { success: vi.fn(), error: vi.fn(), warning: vi.fn() } }));

beforeEach(() => {
  fallbackMock = { data: mockFallbackConfig, isLoading: false, isFetching: false };
  backgroundMock = { data: mockBackgroundConfig, isLoading: false, isFetching: false };
  modelsMock = { data: mockAggregatedModels, isLoading: false };
});

describe('WorkspaceModelsSection — Fallback subtab', () => {
  it('renders the Fallback subtab without a full-screen overlay', async () => {
    render(<WorkspaceModelsSection />);
    fireEvent.click(screen.getByRole('tab', { name: 'Fallback' }));

    await waitFor(() => {
      expect(screen.getByText(/sub-agent fallback settings/i)).toBeInTheDocument();
    });

    const overlays = document.querySelectorAll('.fixed.inset-0, [class*="fixed inset-0"]');
    expect(overlays.length).toBe(0);

    const fullScreenCandidates = document.querySelectorAll('[class*="fixed"]');
    for (const el of Array.from(fullScreenCandidates)) {
      const rect = el.getBoundingClientRect();
      // No fixed element should cover the whole viewport
      const coversViewport = rect.width >= window.innerWidth && rect.height >= window.innerHeight;
      expect(coversViewport).toBe(false);
    }
  });
});

describe('WorkspaceModelsSection — Background & Reflection subtab', () => {
  it('does not render a Provider select/WorkspaceField within the Background panel', async () => {
    render(<WorkspaceModelsSection />);
    fireEvent.click(screen.getByRole('tab', { name: 'Background & Reflection' }));

    const panel = await screen.findByText(/background review & reflection/i);
    expect(panel).toBeInTheDocument();

    // Scope assertions to the Background panel so global page chrome (the
    // "Providers" tab and the "providers" mention in the page description)
    // does not produce false positives. The Background tab must not carry its
    // own Provider field/select.
    const panelRoot = panel.closest('div.rounded-xl') ?? panel.parentElement ?? document.body;

    const providerLabels = (panelRoot as HTMLElement).querySelectorAll('label');
    const providerLabelMatches = Array.from(providerLabels).filter((l) =>
      /provider/i.test(l.textContent ?? ''),
    );
    expect(providerLabelMatches.length).toBe(0);

    const selects = (panelRoot as HTMLElement).querySelectorAll('select');
    expect(selects.length).toBe(0);
  });
});

/* ── Settings registry — single source of truth for the Settings IA ── */
/* Drives the left rail, global search, route resolution, and the
 * parallel chat-side workspace panel.
 *
 * 5 categories, 16 sections, balanced 3–5 items per category.
 * Sections are tagged `tier: 'basic' | 'advanced'` so the rail can show
 * a short beginner list by default and reveal advanced surfaces behind
 * a "Show advanced" toggle (persisted to localStorage by
 * `useSettingsAdvancedPreference`).
 *
 * See `docs/settings-audit.md` for the rationale + section movement
 * history.
 *
 * Hard rules (enforced by the audit at the bottom of this file):
 *   • Every section id is immutable — deep links and legacy aliases
 *     resolve to it forever. To rename a section, change only the
 *     `label` and add the old name to `legacyAliases`.
 *   • Every icon is unique within the registry. The previous brain-icon
 *     triplet broke user scanning; we no longer allow it.
 *   • Every keyword is owned by exactly one section. (Tags like
 *     `usage`, `error`, `host` are no longer claimed by the largest
 *     section just because it has room.)
 *   • Every section declares a valid `tier` (`basic` or `advanced`).
 */
import type { LucideIcon } from 'lucide-react';
import {
  Activity,
  Boxes,
  BookOpen,
  Bot,
  ClipboardList,
  Cpu,
  Globe,
  LineChart,
  MessagesSquare,
  Monitor,
  Network,
  Plug,
  Radio,
  Search as SearchIcon,
  ShieldCheck,
  SlidersHorizontal,
  TerminalSquare,
} from 'lucide-react';

/** Visibility tier for the rail. `basic` items are always shown; the
 *  `advanced` tier is hidden until the user toggles "Show advanced". */
export type SettingsTier = 'basic' | 'advanced';

/**
 * A single settings screen. `id` doubles as the URL param (`?tab=<id>`),
 * `keywords` power global search, and `legacyAliases` keep old deep links
 * (`/settings/traffic`, `/settings/connections`, ...) resolving to the
 * correct section.
 */
export interface SettingsSection {
  id: string;
  label: string;
  description: string;
  icon: LucideIcon;
  category: string;
  /** Beginner-friendliness tier. `basic` items are always shown in the
   *  rail; `advanced` items are hidden until the user enables the
   *  "Show advanced" toggle. Deep links always resolve and reveal the
   *  targeted section even when advanced is off. */
  tier: SettingsTier;
  keywords: string[];
  /** Old tab keys that should now open this section. */
  legacyAliases?: string[];
}

export interface SettingsCategory {
  id: string;
  label: string;
  description: string;
}

/**
 * Top-level categories shown as group headers in the sidebar. Order
 * here is the order they render. Sections reference categories by
 * `category` id.
 *
 * v3 IA (2026-07): replaces the prior 7-category scheme that had
 * singleton categories (memory, activity), a junk drawer ("Advanced"
 * with 5 mixed sections), and duplicate Brain icons across 3 sections.
 */
export const SETTINGS_CATEGORIES: readonly SettingsCategory[] = [
  {
    id: 'general',
    label: 'General',
    description: 'App-level basics: health, appearance, and conversation history.',
  },
  {
    id: 'intelligence',
    label: 'Intelligence',
    description: 'The cognitive core: providers, brain orchestration, and memory.',
  },
  {
    id: 'tools',
    label: 'Tools & Skills',
    description: 'Capabilities the agent can use: MCP servers, skills, computer use, agents.',
  },
  {
    id: 'activity',
    label: 'Activity',
    description: 'Telemetry and observability surfaces: traffic, logs, inspectors.',
  },
  {
    id: 'security',
    label: 'Security & Access',
    description: 'Gating surfaces: API access, filesystem permissions, developer surfaces.',
  },
] as const;

/**
 * The 16 sections of the Settings left rail.
 *
 * Every section's `id` is immutable for legacy-alias support. To rename
 * a section, change the `label` and re-export the old label as an
 * alias.
 *
 * `tier: 'basic'` items are shown by default. `tier: 'advanced'` items
 * are hidden until the user enables the "Show advanced" toggle.
 */
export const SETTINGS_SECTIONS: readonly SettingsSection[] = [
  /* ── General ───────────────────────────────────────────────────── */
  {
    id: 'system-health',
    label: 'System & Health',
    description: 'Gateway status, uptime, RAM, endpoint URLs, and connect-an-app URLs.',
    icon: Activity,
    category: 'general',
    tier: 'basic',
    // Note: 'gateway' is owned by api-access (the action surface for
    // opening/closing it). 'connect' is owned by api-access.
    // 'connection' is owned by tools-connections. 'ram' is used in
    // lieu of 'memory' to avoid colliding with memory-knowledge.
    keywords: ['health', 'provider status', 'uptime', 'endpoints', 'host', 'port', 'ram'],
    legacyAliases: ['health'],
  },
  {
    id: 'profile-preferences',
    label: 'Profile & Preferences',
    description: 'Theme, appearance, text size, presets, keyboard shortcuts, and onboarding.',
    icon: SlidersHorizontal,
    category: 'general',
    tier: 'basic',
    keywords: ['profile', 'theme', 'appearance', 'shortcuts', 'hotkeys', 'presets', 'onboarding', 'tour', 'language'],
